window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_3"] = {"1501":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَمَّنْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ ذَاتِ الرِّقَاعِ صَلَاةَ الْخَوْفِأَنَّ طَائِفَةً صَفَّتْ مَعَهُ وَطَائِفَةٌ وِجَاهَ الْعَدُوِّ فَصَلَّى بِالَّذِينَ مَعَهُ رَكْعَةً ثُمَّ ثَبَتَ قَائِمًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ انْصَرَفُوا فَصَفُّوا وِجَاهَ الْعَدُوِّ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَصَلَّى بِهِمْ الرَّكْعَةَ الَّتِي بَقِيَتْ مِنْ صَلَاتِهِ ثُمَّ ثَبَتَ جَالِسًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ سَلَّمَ بِهِمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Yazid bin Ruman] dari [Shalih bin Khawwat] dari [orang yang pernah melaksanakan shalat Khauf] bersama Rasulullah Shalallahu 'Alaihi Wa Sallam pada perang Dzatur Riqa', bahwa ada sekelompok orang yang berbaris bersamanya, dan kelompok lain berhadapan dengan musuh. Rasulullah shalat satu rakaat bersama orang-orang yang bersamanya, kemudian tetap berdiri, sedangkan mereka menyempurnakan shalatnya sendirian. Lalu mereka pergi dan berbaris berhadapan dengan musuh. Kemudian datang kelompok lainnya, lalu Rasulullah shallallahu 'alaihi wasallam mengerjakan sisa shalatnya bersama mereka (yang tadinya berhadapan dengan musuh), kemudian beliau tetap saja duduk sedangkan mereka menyempurnakan shalatnya sendirian. Setelah itu Rasulullah mengucapkan salam bersama mereka."},"1502":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِإِحْدَى الطَّائِفَتَيْنِ رَكْعَةً وَالطَّائِفَةُ الْأُخْرَى مُوَاجِهَةُ الْعَدُوِّ ثُمَّ انْطَلَقُوا فَقَامُوا فِي مَقَامِ أُولَئِكَ وَجَاءَ أُولَئِكَ فَصَلَّى بِهِمْ رَكْعَةً أُخْرَى ثُمَّ سَلَّمَ عَلَيْهِمْ فَقَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْ وَقَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [bapaknya] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam shalat satu rakaat dengan salah satu dari dua kelompok, sedangkan kelompok yang lain berhadapan dengan musuh. Kemudian kelompok yang shalat bersama Rasulullah pergi menuju posisi kelompok yang berhadapan dengan musuh, lalu mereka (yang berhadapan dengan musuh) menuju Rasulullah. Beliau shalat untuk rakaat selanjutnya bersama mereka, kemudian salam. Setelah itu mereka berdiri untuk menyempurnakan rakaatnya. Mereka (yang berhadapan dengan musuh) juga menyempurnakan rakaatnya."},"1503":{"ar":"أَخْبَرَنِي كَثِيرُ بْنُ عُبَيْدٍ عَنْ بَقِيَّةَ عَنْ شُعَيْبٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ نَجْدٍ فَوَازَيْنَا الْعَدُوَّ وَصَافَفْنَاهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا فَقَامَتْ طَائِفَةٌ مِنَّا مَعَهُ وَأَقْبَلَ طَائِفَةٌ عَلَى الْعَدُوِّ فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ مَعَهُ رَكْعَةً وَسَجَدَ سَجْدَتَيْنِ ثُمَّ انْصَرَفُوا فَكَانُوا مَكَانَ أُولَئِكَ الَّذِينَ لَمْ يُصَلُّوا وَجَاءَتْ الطَّائِفَةُ الَّتِي لَمْ تُصَلِّ فَرَكَعَ بِهِمْ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ كُلُّ رَجُلٍ مِنْ الْمُسْلِمِينَ فَرَكَعَ لِنَفْسِهِ رَكْعَةً وَسَجْدَتَيْنِ","id":"Telah mengabarkan kepadaku [Katsir bin 'Ubaid] dari [Baqiyyah] dari [Syu'aib] dia berkata; telah menceritakan kepadaku [Az Zuhri] dia berkata; telah menceritakan kepada kami [Salim bin 'Abdullah] dari [bapaknya] dia berkata; \"Aku pernah berperang bersama Rasulullah Shalallahu 'Alaihi Wa Sallam di arah Najed. Kami bertemu musuh, maka beliau menyuruh kami berbaris, lalu beliau shalat bersama kami. Sebagian dari kami berdiri bersamanya dan sebagian yang lain menghadap ke arah musuh. Kemudian beliau Shalallahu 'Alaihi Wa Sallam ruku' satu kali, dan ikut ruku' pula orang yang bersamanya, lalu beliau sujud dua kali, kemudian mereka pergi menuju kelompok yang belum shalat. Setelah itu datanglah kelompok yang belum shalat, lalu Rasulullah ruku' satu kali dan sujud dua kali bersama mereka. Kemudian beliau mengucapkan salam, dan berdirilah semua kaum muslimin dan semuanya ruku' satu kali dan sujud dua kali sendiri-sendiri.\""},"1504":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ عَنْ الْعَلَاءِ وَأَبِي أَيُّوبَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ قَامَ فَكَبَّرَ فَصَلَّى خَلْفَهُ طَائِفَةٌ مِنَّا وَطَائِفَةٌ مُوَاجِهَةَ الْعَدُوِّ فَرَكَعَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً وَسَجَدَ سَجْدَتَيْنِ ثُمَّ انْصَرَفُوا وَلَمْ يُسَلِّمُوا وَأَقْبَلُوا عَلَى الْعَدُوِّ فَصَفُّوا مَكَانَهُمْ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَصَفُّوا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِهِمْ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَتَمَّ رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ ثُمَّ قَامَتْ الطَّائِفَتَانِ فَصَلَّى كُلُّ إِنْسَانٍ مِنْهُمْ لِنَفْسِهِ رَكْعَةً وَسَجْدَتَيْنِقَالَ أَبُو بَكْرِ بْنُ السُّنِّيِّ الزُّهْرِيُّ سَمِعَ مِنْ ابْنِ عُمَرَ حَدِيثَيْنِ وَلَمْ يَسْمَعْ هَذَا مِنْهُ","id":"Telah mengabarkan kepadaku ['Imran bin Bakkar] dia berkata; telah menceritakan kepada kami [Muhammad bin Al Mubarak] dia berkata; telah memberitakan kepada kami [Al Haitsam bin Humaid] dari [Al 'Ala] dan [Abu Ayyub] dari [Az Zuhri] dari ['Abdullah bin 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat Khauf. Beliau berdiri lalu bertakbir, maka sekelompok dari kami membuat barisan di belakangnya, sedangkan sekelompok yang lain menghadapi musuh. Kemudian beliau ruku' satu kali dan sujud dua kali bersama mereka. Lalu mereka pergi untuk menghadapi musuh, dan mereka belum salam. Kemudian kelompok yang belum shalat (yang menghadap ke musuh) berbaris di belakang Rasulullah, lalu beliau shalat bersama mereka dengan satu kali ruku' dan dua kali sujud. Kemudian beliau mengucapkan salam dan telah menyempurnakan shalatnya dengan dua kali ruku' dan empat kali sujud. Kedua kelompok tadi lalu berdiri dan semuanya shalat sendiri-sendiri dengan satu kali ruku' dan dua kali sujud.\" Abu Bakr bin As Suni; Az Zuhri mendengar dua Hadist dari Ibnu Umar, dan dia tidak mendengar Hadist ini dari Ibnu Umar."},"1505":{"ar":"أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فِي بَعْضِ أَيَّامِهِ فَقَامَتْ طَائِفَةٌ مَعَهُ وَطَائِفَةٌ بِإِزَاءِ الْعَدُوِّ فَصَلَّى بِالَّذِينَ مَعَهُ رَكْعَةً ثُمَّ ذَهَبُوا وَجَاءَ الْآخَرُونَ فَصَلَّى بِهِمْ رَكْعَةً ثُمَّ قَضَتْ الطَّائِفَتَانِ رَكْعَةً رَكْعَةً","id":"Telah mengabarkan kepada kami ['Abdul A'la bin Washil bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam mengerjakan shalat Khauf pada sebagian hari-harinya (peperangan). Sebagian kelompok berdiri bersamanya dan sebagian lain menghadap kearah musuh. Lalu beliau shalat satu rakaat dengan orang-orang yang bersamanya, lalu mereka pergi (menempati posisi yang menghadap kearah musuh) sedangkan kelompok (yang menghadap ke musuh) menempati (posisi yang baru shalat), dan Rasulullah shalat satu rakaat bersama mereka. Setelah itu kedua kelompok tersebut menyempurnakan satu rakaat satu rakaat.\""},"1506":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ لِأَهْلِ الْجَاهِلِيَّةِ يَوْمَانِ فِي كُلِّ سَنَةٍ يَلْعَبُونَ فِيهِمَا فَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ قَالَ كَانَ لَكُمْ يَوْمَانِ تَلْعَبُونَ فِيهِمَا وَقَدْ أَبْدَلَكُمْ اللَّهُ بِهِمَا خَيْرًا مِنْهُمَا يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] dia berkata; \"Orang-orang Jahiliyah mempunyai dua hari dalam setiap tahun untuk bermain-main. Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam datang ke Madinah, beliau Shalallahu 'Alaihi Wa Sallam bersabda: 'Kalian dahulu mempunyai dua hari untuk bermain-main, sungguh Allah telah menggantinya dengan yang lebih baik dari keduanya, yakni hari (raya) Fitri dan hari (raya) Adha (Kurban) '.\""},"1507":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَبُو بِشْرٍ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسٍ عَنْ عُمُومَةٍ لَهُأَنَّ قَوْمًا رَأَوْا الْهِلَالَ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُمْ أَنْ يُفْطِرُوا بَعْدَ مَا ارْتَفَعَ النَّهَارُ وَأَنْ يَخْرُجُوا إِلَى الْعِيدِ مِنْ الْغَدِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Abu Bisyr] dari [Abu 'Umair bin Anas] dari [bibinya], bahwa ada suatu kaum yang melihat hilal (bulan Sabit, masuknya bulan Syawal), lalu mereka datang kepada Rasulullah Shalallahu 'Alaihi Wa Sallam. Kemudian beliau Shalallahu 'Alaihi Wa Sallam memerintahkan mereka untuk berbuka puasa setelah hari agak siang dan keluar ke tempat shalat Id (hari raya) besoknya."},"1508":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ حَفْصَةَ قَالَتْكَانَتْ أُمُّ عَطِيَّةَ لَا تَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَالَتْ بِأَبَا فَقُلْتُ أَسَمِعْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ كَذَا وَكَذَا فَقَالَتْ نَعَمْ بِأَبَا قَالَ لِيَخْرُجْ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ وَالْحُيَّضُ وَيَشْهَدْنَ الْعِيدَ وَدَعْوَةَ الْمُسْلِمِينَ وَلْيَعْتَزِلْ الْحُيَّضُ الْمُصَلَّى","id":"Telah mengabarkan kepada kami ['Amr bin Zurarah] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Hafshah] dia berkata; \"Tidaklah [Ummu Athiyyah] menyebut Rasulullah Shalallahu 'Alaihi Wa Sallam melainkan dia berkata; 'Biaba (bapakku jadi jaminan) '. Maka aku bertanya kepadanya; 'Apakah engkau pernah mendengar Rasulullah Shalallahu 'Alaihi Wa Sallam menyebutkan hal ini dan itu? ' Dia menjawab, 'Ya, bapakku jadi jaminan. Beliau pernah bersabda; \"Hendaknya perempuan yang tidak dipingit dan perempuan yang dipingit, serta perempuan yang sedang haid keluar untuk menyaksikan hari raya dan seruan kaum muslim, dan perempuan yang sedang haid hendaknya menjauh dari tempat shalat.\""},"1509":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَلَقِيتُ أُمَّ عَطِيَّةَ فَقُلْتُ لَهَا هَلْ سَمِعْتِ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ إِذَا ذَكَرَتْهُ قَالَتْ بِأَبَا قَالَ أَخْرِجُوا الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ فَيَشْهَدْنَ الْعِيدَ وَدَعْوَةَ الْمُسْلِمِينَ وَلْيَعْتَزِلْ الْحُيَّضُ مُصَلَّى النَّاسِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad] dia berkata; \"Aku pernah berjumpa [Ummu Athiyyah], lalu aku bertanya kepadanya; 'Apakah engkau pernah mendengarnya dari Rasulullah Shalallahu 'Alaihi Wa Sallam yang mana Ummu Athiyah bila mengingatnya dia berkata; \"Bapakku jadi jaminannya\" Beliau bersabda: 'Hendaknya perempuan yang tidak dipingit dan perempuan yang dipingit keluar untuk menyaksikan hari raya dan seruan kaum muslim, dan perempuan yang sedang haid hendaknya menjauh dari tempat shalat.'"},"1510":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ وَعَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَوَجَدَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ حُلَّةً مِنْ إِسْتَبْرَقٍ بِالسُّوقِ فَأَخَذَهَا فَأَتَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ ابْتَعْ هَذِهِ فَتَجَمَّلْ بِهَا لِلْعِيدِ وَالْوَفْدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذِهِ لِبَاسُ مَنْ لَا خَلَاقَ لَهُ أَوْ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فَلَبِثَ عُمَرُ مَا شَاءَ اللَّهُ ثُمَّ أَرْسَلَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجُبَّةِ دِيبَاجٍ فَأَقْبَلَ بِهَا حَتَّى جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ قُلْتَ إِنَّمَا هَذِهِ لِبَاسُ مَنْ لَا خَلَاقَ لَهُ ثُمَّ أَرْسَلْتَ إِلَيَّ بِهَذِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْهَا وَتُصِبْ بِهَا حَاجَتَكَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus bin Yazid] dan ['Amr bin Al Harits] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] dia berkata; \"Umar bin Khaththab Radliallahu? nhu pernah mendapatkan jubah dari sutra di pasar, lalu ia mengambilnya dan membawanya kepada Rasulullah Shalallahu 'Alaihi Wa Sallam. Kemudian Umar berkata; `Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, belilah ini lalu berhiaslah dengannya untuk hari raya atau untuk menyambut tamu yang datang'. Beliau menjawab, Ini pakaian orang yang tidak mempunyai bagian di akhirat atau ini adalah pakaian yang dikenakan kepada orang yang tidak mempunyai bagian di akhirat '. Lalu Umar berdiam diri selama waktu yang dikehendaki oleh Allah. Kemudian Rasulullah shallallahu 'alaihi wasallam mengirimkan baju sutra halus, maka ia menghadap beliau. Ketika sampai kepada beliau shallallahu 'alaihi wasallam, ia berkata; `Wahai Rasulullah, engkau mengatakan bahwa ini adalah pakaian orang yang tidak mempunyai bagian, tetapi mengapa engkau mengirimkan baju sutra ini kepadaku? Rasulullah Shalallahu 'Alaihi Wa Sallam lalu berkata: `Juallah. Kamu bisa memenuhi kebutuhanmu dari hasil menjual pakaian tersebut'.\""},"1511":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ الْأَشْعَثِ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍأَنَّ عَلِيًّا اسْتَخْلَفَ أَبَا مَسْعُودٍ عَلَى النَّاسِ فَخَرَجَ يَوْمَ عِيدٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّهُ لَيْسَ مِنْ السُّنَّةِ أَنْ يُصَلَّى قَبْلَ الْإِمَامِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Al Asy'ats] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam] bahwa Ali mengangkat [Abu Mas'ud] sebagai wakilnya, lalu ia keluar pada hari raya, kemudian berkata; \"Wahai manusia, bukan termasuk Sunnah seseorang mengerjakan shalat sebelum imam.\""},"1512":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عِيدٍ قَبْلَ الْخُطْبَةِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Abdul Malik bin Abu Sulaiman] dari ['Atha] dari [Jabir] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam shalat hari raya bersama kami sebelum khutbah, tanpa adzan dan iqamah.\""},"1513":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي زُبَيْدٌ قَالَ سَمِعْتُ الشَّعْبِيَّ يَقُولُ حَدَّثَنَا الْبَرَاءُ بْنُ عَازِبٍ عِنْدَ سَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ فَقَالَ إِنَّ أَوَّلَ مَا نَبْدَأُ بِهِ فِي يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَذْبَحَ فَمَنْ فَعَلَ ذَلِكَ فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ ذَبَحَ قَبْلَ ذَلِكَ فَإِنَّمَا هُوَ لَحْمٌ يُقَدِّمُهُ لِأَهْلِهِ فَذَبَحَ أَبُو بُرْدَةَ بْنُ دِينَارٍ فَقَالَ يَا رَسُولَ اللَّهِ عِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ قَالَ اذْبَحْهَا وَلَنْ تُوفِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Utsman] dia berkata; telah menceritakan kepada kami [Bahz] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Zubaid] dia berkata; aku mendengar [Asy Sya'bi] berkata; telah menceritakan kepada kami [Al Barra' bin 'Azib] saat berada (bersandar) di salah satu tiang masjid dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam pernah khutbah saat hari raya Kurban dengan bersabda: 'Yang pertama kali kita lakukan pada hari ini adalah mengerjakan shalat, kemudian menyembelih. Barangsiapa melakukan hal itu, maka ia sesuai dengan Sunnah kami, dan barangsiapa menyembelih sebelum Shalat, maka itu hanya daging biasa yang disuguhkan untuk keluarganya'. Abu Burdah bin Dinar pun menyembelih, lalu ia berkata; 'Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, aku mempunyai Jadza'ah yang lebih baik dari musinnah! Rasulullah Shalallahu 'Alaihi Wa Sallam menjawab: `Sembelihlah, dan hal itu tidak mencukupi salah seorang setelah kamu (tidak boleh dilakukan) '. "},"1514":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا كَانُوا يُصَلُّونَ الْعِيدَيْنِ قَبْلَ الْخُطْبَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdah bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam, Abu Bakar, dan Umar Radliallahu? nhum mengerjakan shalat dua hari raya sebelum khutbah."},"1515":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُخْرِجُ الْعَنَزَةَ يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى يُرْكِزُهَا فَيُصَلِّي إِلَيْهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam keluar pada hari Idul Fitri dan Idul Adha dengan membawa tombak, lalu beliau menancapkannya, kemudian shalat menghadap ke arahnya."},"1516":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ سَعِيدٍ عَنْ زُبَيْدٍ الْأَيَامِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى ذَكَرَهُ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَاةُ الْأَضْحَى رَكْعَتَانِ وَصَلَاةُ الْفِطْرِ رَكْعَتَانِ وَصَلَاةُ الْمُسَافِرِ رَكْعَتَانِ وَصَلَاةُ الْجُمُعَةِ رَكْعَتَانِ تَمَامٌ لَيْسَ بِقَصْرٍ عَلَى لِسَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Sufyan bin Sa'id] dari [Zubaid Al Ayami] dari ['Abdurrahman bin Abu Laila] menyebutkannya dari ['Umar bin Al Khaththab radliallahu 'anhu] dia berkata; \"Shalat Idul Adha dua rakaat, shalat Idul Fitri dua rakaat, shalat musafir dua rakaat, dan shalat Jum'at dua rakaat. Semua itu sempurna, bukan qashar (diringkas) menurut sabda Rasulullah shallallahu 'alaihi wasallam."},"1517":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا سُفْيَانُ قَالَ حَدَّثَنِي ضَمْرَةُ بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَوْمَ عِيدٍ فَسَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي هَذَا الْيَوْمِ فَقَالَ بِقَافْ وَاقْتَرَبَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah memberitakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Dhamrah bin Sa'id] dari ['Ubaidullah bin 'Abdullah] dia berkata; \"[Umar] radliallahu 'anhu keluar pada hari raya, lalu ia bertanya kepada Abu Waqid AI Laitsi, 'Surat apakah yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari seperti ini'? ' la menjawab; `Surah Qaaf dan Iqtarobat (Al Qamar) '.\""},"1518":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْعِيدَيْنِ وَيَوْمِ الْجُمُعَةِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَا فِي يَوْمٍ وَاحِدٍ فَيَقْرَأُ بِهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [bapaknya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam membaca surat Al A'laa dan Al Ghaasyiyah ketika shalat Jum'at. Kadang hari raya dan Jum'at berkumpul dalam satu hari, maka beliau membaca keduanya.\""},"1519":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ أَيُّوبَ يُخْبِرُ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُأَشْهَدُ أَنِّي شَهِدْتُ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; Aku mendengar [Ayyub] mengabarkan dari ['Atha] dia berkata; Aku mendengar [Ibnu 'Abbas] berkata; \"Aku bersaksi bahwa aku pernah ikut shalat hari raya bersama Rasulullah Shalallahu 'Alaihi Wa Sallam. Beliau memulai shalat sebelum khutbah, kemudian berkhutbah.\""},"1520":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Manshur] dari [Asy Sya'bi] dari [Al Barra' bin 'Azib] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam berkhutbah kepada kami pada hari raya Kurban setelah shalat.\""},"1521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْعِيدَ قَالَ مَنْ أَحَبَّ أَنْ يَنْصَرِفَ فَلْيَنْصَرِفْ وَمَنْ أَحَبَّ أَنْ يُقِيمَ لِلْخُطْبَةِ فَلْيُقِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub] dia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha] dari ['Abdullah bin As Saib] bahwa Nabi Shalallahu 'Alaihi Wa Sallam pernah shalat Id, dan beliau bersabda: \"Barangsiapa ingin pulang, maka hendaklah ia pulang, dan barangsiapa ingin tetap tinggal untuk mendengar khutbah maka hendaklah ia tetap tinggal mendengarkannya.\""},"1522":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ عَنْ أَبِيهِ عَنْ أَبِي رِمْثَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَعَلَيْهِ بُرْدَانِ أَخْضَرَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin Iyad] dari [bapaknya] dari [Abu Rimtsah] dia berkata; \"Aku melihat Rasulullah Shalallahu 'Alaihi Wa Sallam berkhutbah dengan memakai dua selendang yang berwarna hijau.\""},"1523":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ أَخْبَرَنِي إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ أَخِيهِ عَنْ أَبِي كَاهِلٍ الْأَحْمَسِيِّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى نَاقَةٍ وَحَبَشِيٌّ آخِذٌ بِخِطَامِ النَّاقَةِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu Abu Zaidah] dia berkata; telah mengabarkan kepadaku [Isma'il bin Abu Khalid] dari [saudaranya] dari [Abu Kahil Al Ahmasi] dia berkata; \"Aku pernah melihat Nabi Shalallahu 'Alaihi Wa Sallam menyampaikan khutbah di atas untanya, dan seorang Habsyi yang memegangi tali kekang untanya.\""},"1524":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ قَالَسَأَلْتُ جَابِرًا أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَقْعُدُ قَعْدَةً ثُمَّ يَقُومُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Simak] dia berkata; \"Aku pernah bertanya kepada [Jabir], 'Apakah Rasulullah Shalallahu 'Alaihi Wa Sallam khutbah sambil berdiri? ' la menjawab; \"Rasulullah Shalallahu 'Alaihi Wa Sallam berkhutbah sambil berdiri, kemudian duduk sebentar, lalu berdiri lagi'.\""},"1525":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَالَ حَدَّثَنَا عَطَاءٌ عَنْ جَابِرٍ قَالَشَهِدْتُ الصَّلَاةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عِيدٍ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ فَلَمَّا قَضَى الصَّلَاةَ قَامَ مُتَوَكِّئًا عَلَى بِلَالٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَوَعَظَ النَّاسَ وَذَكَّرَهُمْ وَحَثَّهُمْ عَلَى طَاعَتِهِ ثُمَّ مَالَ وَمَضَى إِلَى النِّسَاءِ وَمَعَهُ بِلَالٌ فَأَمَرَهُنَّ بِتَقْوَى اللَّهِ وَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ حَثَّهُنَّ عَلَى طَاعَتِهِ ثُمَّ قَالَ تَصَدَّقْنَ فَإِنَّ أَكْثَرَكُنَّ حَطَبُ جَهَنَّمَ فَقَالَتْ امْرَأَةٌ مِنْ سَفِلَةِ النِّسَاءِ سَفْعَاءُ الْخَدَّيْنِ بِمَ يَا رَسُولَ اللَّهِ قَالَ تُكْثِرْنَ الشَّكَاةَ وَتَكْفُرْنَ الْعَشِيرَ فَجَعَلْنَ يَنْزِعْنَ قَلَائِدَهُنَّ وَأَقْرُطَهُنَّ وَخَوَاتِيمَهُنَّ يَقْذِفْنَهُ فِي ثَوْبِ بِلَالٍ يَتَصَدَّقْنَ بِهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdul Malik bin Abu Sulaiman] dia berkata; telah menceritakan kepada kami ['Atha] dari [Jabir] dia berkata; \"Aku pernah shalat Id bersama Rasulullah Shalallahu 'Alaihi Wa Sallam. Beliau memulainya dengan shalat, sebelum khutbah tanpa adzan dan iqamah Setelah selesai shalat beliau berdiri dengan bersandar kepada Bilal, lalu beliau memuji Allah dan menyanjung-Nya, kemudian menasihati, memperingatkan, dan menganjurkan mereka untuk menaatinya. Selanjutnya beliau dan bilal bergeser dan beralih ke arah para perempuan, lalu memerintahkan mereka untuk bertakwa kepada Allah, dan menasihati serta memperingatkannya. kemudian beliau memuji dan menyanjung-Nya, serta menganjurkan mereka untuk menaatinya. Setelah itu beliau bersabda: \"Bersedekahlah kalian, karena sebagian besar kalian adalah bahan bakar api neraka.\" Lalu ada seorang perempuan biasa bangkit berdiri -dengan pipi yang memerah- berkata; \"Apa penyebabnya wahai Rasulullah shallallahu 'alaihi wasallam?\" Beliau bersabda: \"Kalian banyak mengeluh dan mengingkari kebaikan suami.\" Lalu mereka segera melepaskan kalung, anting, serta cincin mereka dan melemparkannya ke kain (yang dibentangkan) Bilal sebagai sedekah."},"1526":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ دَاوُدَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى إِلَى الْمُصَلَّى فَيُصَلِّي بِالنَّاسِ فَإِذَا جَلَسَ فِي الثَّانِيَةِ وَسَلَّمَ قَامَ فَاسْتَقْبَلَ النَّاسَ بِوَجْهِهِ وَالنَّاسُ جُلُوسٌ فَإِنْ كَانَتْ لَهُ حَاجَةٌ يُرِيدُ أَنْ يَبْعَثَ بَعْثًا ذَكَرَهُ لِلنَّاسِ وَإِلَّا أَمَرَ النَّاسَ بِالصَّدَقَةِ قَالَ تَصَدَّقُوا ثَلَاثَ مَرَّاتٍ فَكَانَ مِنْ أَكْثَرِ مَنْ يَتَصَدَّقُ النِّسَاءُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari [Dawud] dari ['Iyadh bin 'Abdullah] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam pada hari Idul Fitri dan Idul Adha ke Mushalla (lapangan tempat shalat) lalu Beliau shalat bersama manusia. Bila beliau telah duduk pada rakaat kedua maka beliau mengucapkan salam, kemudian menghadap kepada manusia dengan wajahnya, sedangkan manusia duduk. Bila beliau mempunyai suatu keperluan, yakni hendak mengutus pasukan, maka beliau menyebutkannya, dan jika tidak ada keperluan maka beliau memerintahkan manusia untuk sedekah dengan bersabda \"Bersedekahlah.\" Beliau mengucapkannya sebanyak tiga kali. Sebagian besar yang bersedekah adalah wanita."},"1527":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya lafazh ini darinya dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Ibnul Musayyab] dari [Abu Hurairah] Bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Jika kamu berkata kepada temanmu, 'Diamlah' ketika imam sedang khutbah, maka kamu telah berbuat sia-sia.\""},"1528":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي خُطْبَتِهِ يَحْمَدُ اللَّهَ وَيُثْنِي عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ يَقُولُ مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْهُ فَلَا هَادِيَ لَهُ إِنَّ أَصْدَقَ الْحَدِيثِ كِتَابُ اللَّهِ وَأَحْسَنَ الْهَدْيِ هَدْيُ مُحَمَّدٍ وَشَرُّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلُّ مُحْدَثَةٍ بِدْعَةٌ وَكُلُّ بِدْعَةٍ ضَلَالَةٌ وَكُلُّ ضَلَالَةٍ فِي النَّارِ ثُمَّ يَقُولُ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ وَكَانَ إِذَا ذَكَرَ السَّاعَةَ احْمَرَّتْ وَجْنَتَاهُ وَعَلَا صَوْتُهُ وَاشْتَدَّ غَضَبُهُ كَأَنَّهُ نَذِيرُ جَيْشٍ يَقُولُ صَبَّحَكُمْ مَسَّاكُمْ ثُمَّ قَالَ مَنْ تَرَكَ مَالًا فَلِأَهْلِهِ وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَإِلَيَّ أَوْ عَلَيَّ وَأَنَا أَوْلَى بِالْمُؤْمِنِينَ","id":"Telah mengabarkan kepada kami ['Utbah bin 'Abdullah] dia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dari [Sufyan] dari [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin 'Abdullah] dia berkata; \"Apabila Rasulullah Shalallahu 'Alaihi Wa Sallam berkhutbah, maka beliau memuji dan menyanjung Allah dengan hal-hal yang menjadi hak-Nya, kemudian bersabda: 'Barangsiapa telah diberi petunjuk oleh Allah, maka tidak ada yang bisa menyesatkannya. Barangsiapa telah disesatkan oleh Allah, maka tidak ada yang bisa memberikan petunjuk kepadanya. Sebenar-benar perkataan adalah kitabullah (Al Qur'an), sebaik-baik petunjuk adalah petunjuk Muhammad shallallahu 'alaihi wasallam, dan sejelek jelek perkara adalah hal-hal yang baru, setiap hal yang baru adalah bid'ah dan setiap bid'ah adalah sesat, dan setiap kesesatan di dalam neraka'. Kemudian beliau bersabda lagi, 'Ketika aku diutus, jarak antara aku dan hari Kiamat seperti jarak dua jari ini'. Bila beliau menyebutkan hari Kiamat maka kedua pipinya memerah, suaranya meninggi, dan amarahnya bertambah, seolah-olah beliau memperingatkan pasukan. Beliau bersabda: 'Hati-hati pada pagi kalian dan sorenya'. Barangsiapa meninggalkan harta, maka itu buat keluarganya dan barangsiapa meninggalkan utang atau sesuatu yang hilang maka itu tanggunganku. Aku adalah wali bagi orang-orang yang beriman '.\""},"1529":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ قَالَ حَدَّثَنِي عِيَاضٌ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ يَوْمَ الْعِيدِ فَيُصَلِّي رَكْعَتَيْنِ ثُمَّ يَخْطُبُ فَيَأْمُرُ بِالصَّدَقَةِ فَيَكُونُ أَكْثَرَ مَنْ يَتَصَدَّقُ النِّسَاءُ فَإِنْ كَانَتْ لَهُ حَاجَةٌ أَوْ أَرَادَ أَنْ يَبْعَثَ بَعْثًا تَكَلَّمَ وَإِلَّا رَجَعَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Dawud bin Qais] dia berkata; telah menceritakan kepada kami ['Iyadh] dari [Abu Sa'id] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam keluar pada hari raya, lalu shalat dua rakaat. Kemudian beliau berkhutbah, memerintahkan manusia untuk sedekah, maka sebagian besar yang bersedekah adalah wanita. Jika beliau mempunyai pasukan atau hendak mengutus seseorang maka beliau berbicara, dan jika tidak ada maka beliau pulang."},"1530":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ هَارُونَ قَالَ أَنْبَأَنَا حُمَيْدٌ عَنْ الْحَسَنِأَنَّ ابْنَ عَبَّاسٍ خَطَبَ بِالْبَصْرَةِ فَقَالَ أَدُّوا زَكَاةَ صَوْمِكُمْ فَجَعَلَ النَّاسُ يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالَ مَنْ هَاهُنَا مِنْ أَهْلِ الْمَدِينَةِ قُومُوا إِلَى إِخْوَانِكُمْ فَعَلِّمُوهُمْ فَإِنَّهُمْ لَا يَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ صَدَقَةَ الْفِطْرِ عَلَى الصَّغِيرِ وَالْكَبِيرِ وَالْحُرِّ وَالْعَبْدِ وَالذَّكَرِ وَالْأُنْثَى نِصْفَ صَاعٍ مِنْ بُرٍّ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ شَعِيرٍ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Humaid] dari [Al Hasan] bahwasanya [Ibnu 'Abbas] pernah khutbah di Bashrah, dia berkata; \"Tunaikanlah zakat puasa kalian.\" Orang-orangpun saling melihat satu sama lain. Lalu ia pun berkata; \"Siapakah orang Madinah yang bersama kalian di sini? Bangkitlah kepada saudara kalian lalu ajarilah, karena mereka tidak mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah mewajibkan zakat fitri atas anak kecil dan orang dewasa, yang merdeka dan hamba sahaya, lelaki dan perempuan, sebanyak setengah Sha' gandum atau satu Sha' kurma atau sya'ir (jenis gandum).\""},"1531":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ ثُمَّ قَالَ مَنْ صَلَّى صَلَاتَنَا وَنَسَكَ نُسُكَنَا فَقَدْ أَصَابَ النُّسُكَ وَمَنْ نَسَكَ قَبْلَ الصَّلَاةِ فَتِلْكَ شَاةُ لَحْمٍ فَقَالَ أَبُو بُرْدَةَ بْنُ نِيَارٍ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ نَسَكْتُ قَبْلَ أَنْ أَخْرُجَ إِلَى الصَّلَاةِ عَرَفْتُ أَنَّ الْيَوْمَ يَوْمُ أَكْلٍ وَشُرْبٍ فَتَعَجَّلْتُ فَأَكَلْتُ وَأَطْعَمْتُ أَهْلِي وَجِيرَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ شَاةُ لَحْمٍ قَالَ فَإِنَّ عِنْدِي جَذَعَةً خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَهَلْ تُجْزِي عَنِّي قَالَ نَعَمْ وَلَنْ تُجْزِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Manshur] dari [Asy Sya'bi] dari [Al Barra'] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam khutbah pada hari raya Kurban setelah shalat, lalu bersabda: 'Barangsiapa shalat (seperti) shalat kami, dan berkurban (seperti) kurban kami, maka ia telah berkurban dengan benar, dan barangsiapa berkurban sebelum shalat, maka itu hanya daging kambing (bukan kurban) '. Abu Burdah bin Niyar berkata, 'Wahai Rasulullah demi Allah, aku telah menyembelih (kurban) sebelum keluar untuk shalat (id), karena aku mengetahui bahwa hari ini adalah hari (untuk) makan dan minum, maka aku menyegerakan menyembelih (kurban) lalu aku makan dan aku berikan kepada keluarga dan tetanggaku, \" maka Rasulullah bersabda: \"Itu adalah daging kambing (bukan kurban) '.\" Abu Burdah berkata; \"Sesungguhnya aku mempunyai jadza'ah yang lebih baik dari dua kambing daging, maka apakah itu mencukupi bagiku (sebagai gantinya)? Nabi menjawab: \"Ya, \" tetapi ia tidak mencukupi bagi seorang setelahmu.\""},"1532":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنْتُ أُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ صَلَاتُهُ قَصْدًا وَخُطْبَتُهُ قَصْدًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Aku pernah shalat bersama Rasulullah Shalallahu 'Alaihi Wa Sallam. Shalat beliau sederhana dan khutbahnya juga sederhana.\" (Tidak terlalu cepat dan tidak terlalu panjang)."},"1533":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَقْعُدُ قَعْدَةً لَا يَتَكَلَّمُ فِيهَا ثُمَّ قَامَ فَخَطَبَ خُطْبَةً أُخْرَى فَمَنْ خَبَّرَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ قَاعِدًا فَلَا تُصَدِّقْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Aku pernah melihat Rasulullah Shalallahu 'Alaihi Wa Sallam khutbah pada hari Jum'at sambil berdiri, kemudian duduk sejenak tanpa berbicara. Kemudian berdiri lagi untuk menyampaikan khutbah yang kedua. Barangsiapa menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam menyampaikan khutbah sambil duduk maka janganlah kamu mempercayainya.\""},"1534":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ وَيَقْرَأُ آيَاتٍ وَيَذْكُرُ اللَّهَ وَكَانَتْ خُطْبَتُهُ قَصْدًا وَصَلَاتُهُ قَصْدًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam menyampaikan khutbah sambil berdiri, kemudian duduk, lalu berdiri dan membaca beberapa ayat serta berdzikir kepada Allah. Khutbah beliau sederhana (tidak lama dan tidak sebentar), dan shalatnya juga sederhana (tidak lama dan tidak sebentar).\""},"1535":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَخْطُبُ إِذْ أَقْبَلَ الْحَسَنُ وَالْحُسَيْنُ عَلَيْهِمَا السَّلَام عَلَيْهِمَا قَمِيصَانِ أَحْمَرَانِ يَمْشِيَانِ وَيَعْثُرَانِ فَنَزَلَ وَحَمَلَهُمَا فَقَالَ صَدَقَ اللَّهُ إِنَّمَا أَمْوَالُكُمْ وَأَوْلَادُكُمْ فِتْنَةٌ رَأَيْتُ هَذَيْنِ يَمْشِيَانِ وَيَعْثُرَانِ فِي قَمِيصَيْهِمَا فَلَمْ أَصْبِرْ حَتَّى نَزَلْتُ فَحَمَلْتُهُمَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Abu Tumailah] dari [Al Husain bin Waqid] dari [Ibnu Buraidah] dari [bapaknya] dia berkata; \"Pada saat Rasulullah Shalallahu 'Alaihi Wa Sallam khutbah di atas mimbar, tiba-tiba Hasan dan Husain Radliallahu? nhuma datang dengan memakai baju merah. Keduanya berjalan, lalu terjatuh. Maka Rasulullah Shalallahu 'Alaihi Wa Sallam turun dari mimbar, lalu menggendong keduanya, kemudian bersabda: `Allah Maha Benar (firman-Nya), 'Sesungguhnya hartamu dan anak-anakmu adalah fitnah'. (Qs. Al Anfaal (8): 28). Aku melihat dua anak ini terjatuh dalam kedua bajunya, maka aku tidak sabar hingga aku turun lalu kugendong keduanya'.\""},"1536":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ قَالَسَمِعْتُ ابْنَ عَبَّاسٍ قَالَ لَهُ رَجُلٌ شَهِدْتَ الْخُرُوجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا مَكَانِي مِنْهُ مَا شَهِدْتُهُ يَعْنِي مِنْ صِغَرِهِ أَتَى الْعَلَمَ الَّذِي عِنْدَ دَارِ كَثِيرِ بْنِ الصَّلْتِ فَصَلَّى ثُمَّ خَطَبَ ثُمَّ أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ أَنْ يَتَصَدَّقْنَ فَجَعَلَتْ الْمَرْأَةُ تُهْوِي بِيَدِهَا إِلَى حَلَقِهَا تُلْقِي فِي ثَوْبِ بِلَالٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin 'Abis] dia berkata; \"Aku pernah mendengar seseorang berkata kepada [lbnu Abbas], 'Apakah engkau pernah ikut keluar bersama Rasulullah Shalallahu 'Alaihi Wa Sallam? ' la menjawab, `Ya pernah, kalaulah bukan karena posisiku (yang masih kerabat) dan usiaku yang masih kecil, maka aku tidak bisa ikut. Beliau mendatangi bendera yang berada di rumah Katsir bin Ash-Shalt, lalu beliau mengerjakan shalat kemudian menyampaikan khutbah. -Beliau- lalu mendatangi, menasihati, mengingatkan, dan memerintahkan para wanita untuk bersedekah. Maka para wanita pun melepaskan kalung-kalungnya dan melemparkannya ke baju (kain) Bilal'.\""},"1537":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْأَشَجُّ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَدِيٍّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ الْعِيدِ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا","id":"Telah mengabarkan kepada kami ['Abdullah bin Sa'id Al Asyaj] dia berkata; telah menceritakan kepada kami [Ibnu Idris] dia berkata; telah memberitakan kepada kami [Syu'bah] dari ['Adi] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas], bahwa Nabi Shalallahu 'Alaihi Wa Sallam keluar pada hari raya, lalu beliau shalat dua rakaat tanpa mengerjakan shalat apapun sebelum maupun sesudahnya."},"1538":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أَضْحًى وَانْكَفَأَ إِلَى كَبْشَيْنِ أَمْلَحَيْنِ فَذَبَحَهُمَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Hatim bin Wardan] dari [Ayyub] dari [Muhammad bin Sirin] dari [Anas bin Malik], dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam menyampaikan khutbah kepada kami pada hari raya Kurban, lalu beliau menuju kepada dua kambing yang putih, kemudian menyembelihnya.\""},"1539":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ عَنْ كَثِيرِ بْنِ فَرْقَدٍ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَذْبَحُ أَوْ يَنْحَرُ بِالْمُصَلَّى","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dari [Al Laits] dari [Katsir bin Farqad] dari [Nafi'], ['Abdullah bin 'Umar] mengabarkan kepadanya, bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam menyembelih di tempat shalat hari raya."},"1540":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ قُلْتُ عَنْ أَبِيهِ قَالَ نَعَمْ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْجُمُعَةِ وَالْعِيدِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَإِذَا اجْتَمَعَ الْجُمُعَةُ وَالْعِيدُ فِي يَوْمٍ قَرَأَ بِهِمَا","id":"Telah mengabarkan kepadaku [Muhammad bin Qudamah] dari [Jarir] dari [Ibrahim bin Muhammad bin Al Muntasyir], -aku berkata-; 'Dari [bapaknya]? ' dia berkata; 'Benar'- dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam pada shalat Jum'at dan shalat 'Id membaca surah Al A'laa dan Al Ghaasyiyah. Bila terjadi hari raya dan Jum'at dalam satu hari, maka beliau membaca keduanya.\""},"1541":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ إِيَاسِ بْنِ أَبِي رَمْلَةَ قَالَسَمِعْتُ مُعَاوِيَةَ سَأَلَ زَيْدَ بْنَ أَرْقَمَ أَشَهِدْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِيدَيْنِ قَالَ نَعَمْ صَلَّى الْعِيدَ مِنْ أَوَّلِ النَّهَارِ ثُمَّ رَخَّصَ فِي الْجُمُعَةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami [Israil] dari ['Utsman bin Al Mughirah] dari [Iyas bin Abu Ramlah] dia berkata; aku mendengar Mu'awiyah bertanya kepada [Zaid bin Arqam], 'Apakah engkau pernah mengerjakan shalat dua hari raya bersama Rasulullah shallallahu 'alaihi wasallam? ' la menjawab, `Ya, beliau shallallahu 'alaihi wasallam mengerjakan shalat hari raya pada permulaan slang (pagi hari), lalu beliau memberi rukhsah kewajiban jumat (boleh melakukannya, boleh juga tidak) '.\" "},"1542":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي وَهْبُ بْنُ كَيْسَانَ قَالَاجْتَمَعَ عِيدَانِ عَلَى عَهْدِ ابْنِ الزُّبَيْرِ فَأَخَّرَ الْخُرُوجَ حَتَّى تَعَالَى النَّهَارُ ثُمَّ خَرَجَ فَخَطَبَ فَأَطَالَ الْخُطْبَةَ ثُمَّ نَزَلَ فَصَلَّى وَلَمْ يُصَلِّ لِلنَّاسِ يَوْمَئِذٍ الْجُمُعَةَ فَذُكِرَ ذَلِكَ لِابْنِ عَبَّاسٍ فَقَالَ أَصَابَ السُّنَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami ['Abdul Hamid bin Ja'far] dia berkata; telah menceritakan kepadaku [Wahb bin Kaisan] dia berkata; \"Pada masa Ibnu Zubair, pernah terjadi dua hari raya (hari raya & Jum'at) dalam satu hari. Ibnu Zubair mengakhirkan keluar untuk shalat 'Id agak siang, lalu ia keluar dan menyampaikan khutbah dengan khutbah yang lama. Kemudian ia turun dan mengerjakan shalat. Pada hari itu ia tidak mengerjakan shalat Jum'at bersama manusia. Hal tersebut diceritakan kepada [Ibnu Abbas], dan dia mengatakan bahwa Ibnu Zubair sudah melakukan sesuai dengan Sunnah.\""},"1543":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا جَارِيَتَانِ تَضْرِبَانِ بِدُفَّيْنِ فَانْتَهَرَهُمَا أَبُو بَكْرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُنَّ فَإِنَّ لِكُلِّ قَوْمٍ عِيدًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Muhammad Ja'far] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam masuk ke tempatnya dan di sisinya ada dua anak perempuan yang sedang menabuh dua rebana, maka Abu Bakar membentak kedua budak tadi'. Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Biarkan saja mereka, sesungguhnya bagi tiap-tiap kaum mempunyai hari raya.'"},"1544":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَ السُّودَانُ يَلْعَبُونَ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عِيدٍ فَدَعَانِي فَكُنْتُ أَطَّلِعُ إِلَيْهِمْ مِنْ فَوْقِ عَاتِقِهِ فَمَا زِلْتُ أَنْظُرُ إِلَيْهِمْ حَتَّى كُنْتُ أَنَا الَّتِي انْصَرَفْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam] dari [bapaknya] dari ['Aisyah] dia berkata; \"Beberapa orang hitam datang lalu bermain di depan Rasulullah Shalallahu 'Alaihi Wa Sallam pada hari raya. Beliau lalu memanggilku, dan saat itu aku melihat dari atas pundak beliau. Aku terus melihat mereka sampai akhirnya aku pergi meninggalkan mereka."},"1545":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي بِرِدَائِهِ وَأَنَا أَنْظُرُ إِلَى الْحَبَشَةِ يَلْعَبُونَ فِي الْمَسْجِدِ حَتَّى أَكُونَ أَنَا أَسْأَمُ فَاقْدُرُوا قَدْرَ الْجَارِيَةِ الْحَدِيثَةِ السِّنِّ الْحَرِيصَةِ عَلَى اللَّهْوِ","id":"Telah mengabarkan kepada kami ['Ali bin Khasyram] dia berkata; telah menceritakan kepada kami [Al Walid] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Aku pernah melihat Rasulullah Shalallahu 'Alaihi Wa Sallam menutupiku dengan serbannya, dan aku melihat orang-orang Habasyah bermain di masjid, hingga aku merasa bosan. Maka, lihatlah dan jagalah dua anak perempuan kecil yang senang bermain.\""},"1546":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مُوسَى قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَدَخَلَ عُمَرُ وَالْحَبَشَةُ يَلْعَبُونَ فِي الْمَسْجِدِ فَزَجَرَهُمْ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُمْ يَا عُمَرُ فَإِنَّمَا هُمْ بَنُو أَرْفِدَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Musa] dia berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepadaku [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata; \"Umar masuk dan orang-orang Habasyah sedang bermain-main di masjid, maka Umar Radliallahu? nhum menghardiknya. Rasulullah Shalallahu 'Alaihi Wa Sallam kemudian bersabda: 'Biarkanlah mereka wahai Umar! Mereka hanyalah Bani Arfidah'.\""},"1547":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّهُ حَدَّثَهُ أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ أَبَا بَكْرٍ الصِّدِّيقَ دَخَلَ عَلَيْهَا وَعِنْدَهَا جَارِيَتَانِ تَضْرِبَانِ بِالدُّفِّ وَتُغَنِّيَانِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسَجًّى بِثَوْبِهِ وَقَالَ مَرَّةً أُخْرَى مُتَسَجٍّ ثَوْبَهُ فَكَشَفَ عَنْ وَجْهِهِ فَقَالَ دَعْهُمَا يَا أَبَا بَكْرٍ إِنَّهَا أَيَّامُ عِيدٍ وَهُنَّ أَيَّامُ مِنًى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ بِالْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin 'Abdullah] dia berkata; [bapakku] telah menceritakan kepadaku, dia berkata; telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Malik bin Anas] dari [Az Zuhri] dari ['Urwah] bahwa ia menceritakan kepadanya, ['Aisyah] telah menceritakan kepadanya, Abu Bakr Ash Shiddiq masuk kepadanya dan di sisinya ada dua anak perempuan kecil yang sedang menabuh rebana sambil bernyanyi, sedangkan Rasulullah Shalallahu 'Alaihi Wa Sallam dalam keadaan berselimut dengan bajunya -dalam lafazh lain; menutup diri dengan bajunya-lalu beliau menyingkap wajahnya dan bersabda; 'Biarkanlah mereka wahai Abu Bakr! Sesungguhnya ini adalah hari raya yang juga merupakan hari-hari Mina.' Saat itu Rasulullah Shalallahu 'Alaihi Wa Sallam berada di Madinah."},"1548":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ الْوَلِيدِ بْنِ أَبِي هِشَامٍ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا فِي بُيُوتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Telah mengabarkan kepada kami [Al 'Abbas bin 'Abdul 'Azhim] dia berkata; telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] dia berkata; telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Al Walid bin Abu Hisyam] dari [Nafi'] bahwasanya ['Abdullah bin 'Umar] berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: `Shalatlah kalian (shalat sunah) di rumah-rumah kalian dan janganlah kalian menjadikan rumah-rumah kalian seperti kuburan'.\""},"1549":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ سَمِعْتُ مُوسَى بْنَ عُقْبَةَ قَالَ سَمِعْتُ أَبَا النَّضْرِ يُحَدِّثُ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ حُجْرَةً فِي الْمَسْجِدِ مِنْ حَصِيرٍ فَصَلَّى رَسُولُ اللَّهِ صَلَّى ا��لَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا لَيَالِيَ حَتَّى اجْتَمَعَ إِلَيْهِ النَّاسُ ثُمَّ فَقَدُوا صَوْتَهُ لَيْلَةً فَظَنُّوا أَنَّهُ نَائِمٌ فَجَعَلَ بَعْضُهُمْ يَتَنَحْنَحُ لِيَخْرُجَ إِلَيْهِمْ فَقَالَ مَا زَالَ بِكُمْ الَّذِي رَأَيْتُ مِنْ صُنْعِكُمْ حَتَّى خَشِيتُ أَنْ يُكْتَبَ عَلَيْكُمْ وَلَوْ كُتِبَ عَلَيْكُمْ مَا قُمْتُمْ بِهِ فَصَلُّوا أَيُّهَا النَّاسُ فِي بُيُوتِكُمْ فَإِنَّ أَفْضَلَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Affan bin Muslim] dia berkata; telah menceritakan kepada kami [Wuhaib] dia berkata; Aku mendengar [Musa bin 'Uqbah] berkata; aku mendengar [Abu An Nadhr] menceritakan dari [Busr bin Sa'id] dari [Zaid bin Tsabit] bahwa Nabi Shalallahu 'Alaihi Wa Sallam membuat ruangan khusus dari tikar di dalam masjid. Beliau shalat malam di dalamnya hingga orang-orang berkumpul kepadanya, kemudian suaranya tak terdengar selama semalam, maka orang-orang pun mengira bahwa beliau tertidur, maka sebagian mereka berdehem-dehem supaya beliau keluar. Kemudian Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Aku senantiasa melihat perbuatan kalian hingga aku khawatir hal itu akan diwajibkan kepada kalian. Kalau sampai diwajibkan kepada kalian, maka kalian tidak mampu melakukannya. Wahai manusia, shalatlah di rumah-rumah kalian. Sesungguhnva shalat seseorang yang paling utama adalah di rumahnya, kecuali shalat wajib.\""},"1550":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ أَنْبَأَنَا إِبْرَاهِيمُ بْنُ أَبِي الْوَزِيرِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْفِطْرِيُّ عَنْ سَعْدِ بْنِ إِسْحَقَ بْنِ كَعْبِ بْنِ عُجْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْمَغْرِبِ فِي مَسْجِدِ بَنِي عَبْدِ الْأَشْهَلِ فَلَمَّا صَلَّى قَامَ نَاسٌ يَتَنَفَّلُونَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِهَذِهِ الصَّلَاةِ فِي الْبُيُوتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah memberitakan kepada kami [Ibrahim bin Abul Wazir] dia berkata; telah menceritakan kepada kami [Muhammad bin Musa Al Fithri] dari [Sa'd bin Ishaq bin Ka'b bin 'Ujrah] dari [bapaknya] dari [kakeknya], dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam melaksanakan shalat maghrib di masjid Bani Abdul Asyhal, ketika beliau selesai shalat, para sahabat mulai shalat sunnah, kemudian Nabi Shalallahu 'Alaihi Wa Sallam bersabda: \"Hendaknya kalian melaksanakan shalat ini dirumah.\""},"1551":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ سَعْدِ بْنِ هِشَامٍأَنَّهُ لَقِيَ ابْنَ عَبَّاسٍ فَسَأَلَهُ عَنْ الْوَتْرِ فَقَالَ أَلَا أُنَبِّئُكَ بِأَعْلَمِ أَهْلِ الْأَرْضِ بِوَتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ عَائِشَةُ ائْتِهَا فَسَلْهَا ثُمَّ ارْجِعْ إِلَيَّ فَأَخْبِرْنِي بِرَدِّهَا عَلَيْكَ فَأَتَيْتُ عَلَى حَكِيمِ بْنِ أَفْلَحَ فَاسْتَلْحَقْتُهُ إِلَيْهَا فَقَالَ مَا أَنَا بِقَارِبِهَا إِنِّي نَهَيْتُهَا أَنْ تَقُولَ فِي هَاتَيْنِ الشِّيعَتَيْنِ شَيْئًا فَأَبَتْ فِيهَا إِلَّا مُضِيًّا فَأَقْسَمْتُ عَلَيْهِ فَجَاءَ مَعِي فَدَخَلَ عَلَيْهَا فَقَالَتْ لِحَكِيمٍ مَنْ هَذَا مَعَكَ قُلْتُ سَعْدُ بْنُ هِشَامٍ قَالَتْ مَنْ هِشَامٌ قُلْتُ ابْنُ عَامِرٍ فَتَرَحَّمَتْ عَلَيْهِ وَقَالَتْ نِعْمَ الْمَرْءُ كَانَ عَامِرًا قَالَ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ خُلُقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَلَيْسَ تَقْرَأُ الْقُرْآنَ قَالَ قُلْتُ بَلَى قَالَتْ فَإِنَّ خُلُقَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقُرْآنُ فَهَمَمْتُ أَنْ أَقُومَ فَبَدَا لِي قِيَامُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ قِيَامِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَلَيْسَ تَقْرَأُ هَذِهِ السُّورَةَ يَا أَيُّهَا الْمُزَّمِّلُ قُلْتُ بَلَى قَالَتْ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ افْتَرَضَ قِيَامَ اللَّيْلِ فِي أَوَّلِ هَذِهِ السُّورَةِ فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَوْلًا حَتَّى انْتَفَخَتْ أَقْدَامُهُمْ وَأَمْسَكَ اللَّهُ عَزَّ وَجَلَّ خَاتِمَتَهَا اثْنَيْ عَشَرَ شَهْرًا ثُمَّ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ التَّخْفِيفَ فِي آخِرِ هَذِهِ السُّورَةِ فَصَارَ قِيَامُ اللَّيْلِ تَطَوُّعًا بَعْدَ أَنْ كَانَ فَرِيضَةً فَهَمَمْتُ أَنْ أَقُومَ فَبَدَا لِي وَتْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ وَتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنَّا نُعِدُّ لَهُ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ عَزَّ وَجَلَّ لِمَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيَتَوَضَّأُ وَيُصَلِّي ثَمَانِيَ رَكَعَاتٍ لَا يَجْلِسُ فِيهِنَّ إِلَّا عِنْدَ الثَّامِنَةِ يَجْلِسُ فَيَذْكُرُ اللَّهَ عَزَّ وَجَلَّ وَيَدْعُو ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ مَا يُسَلِّمُ ثُمَّ يُصَلِّي رَكْعَةً فَتِلْكَ إِحْدَى عَشْرَةَ رَكْعَةً يَا بُنَيَّ فَلَمَّا أَسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَ اللَّحْمَ أَوْتَرَ بِسَبْعٍ وَصَلَّى رَكْعَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ مَا سَلَّمَ فَتِلْكَ تِسْعُ رَكَعَاتٍ يَا بُنَيَّ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَحَبَّ أَنْ يَدُومَ عَلَيْهَا وَكَانَ إِذَا شَغَلَهُ عَنْ قِيَامِ اللَّيْلِ نَوْمٌ أَوْ مَرَضٌ أَوْ وَجَعٌ صَلَّى مِنْ النَّهَارِ اثْنَتَيْ عَشْرَةَ رَكْعَةً وَلَا أَعْلَمُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا قَامَ لَيْلَةً كَامِلَةً حَتَّى الصَّبَاحَ وَلَا صَامَ شَهْرًا كَامِلًا غَيْرَ رَمَضَانَفَأَتَيْتُ ابْنَ عَبَّاسٍ فَحَدَّثْتُهُ بِحَدِيثِهَا فَقَالَ صَدَقَتْ أَمَا إِنِّي لَوْ كُنْتُ أَدْخُلُ عَلَيْهَا لَأَتَيْتُهَا حَتَّى تُشَافِهَنِي مُشَافَهَةً قَالَ أَبُو عَبْد الرَّحْمَنِ كَذَا وَقَعَ فِي كِتَابِي وَلَا أَدْرِي مِمَّنْ الْخَطَأُ فِي مَوْضِعِ وَتْرِهِ عَلَيْهِ السَّلَامُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id] dari [Qatadah] dari [Zurarah] dari [Sa'ad bin Hisyam] bahwa dia pernah berjumpa dengan lbnu Abbas, dia bertanya kepadanya tentang shalat witir. Lalu ia menjawab; \"Maukah kamu aku beri tahu penghuni bumi yang paling mengetahui tentang shalat witir Rasulullah Shalallahu 'Alaihi Wa Sallam?\" Dia menjawab; \"Ya, mau.\" lbnu Abbas berkata; \"Dia adalah [Aisyah]. Datangi dan tanyakanlah hal itu kepadanya, dan kembalilah kepadaku untuk memberitahukan jawabannya kepadaku.\" Kemudian dia (Hisyam) datang kepada Hakim bin Aflah untuk meminta menemaninya datang kepada Aisyah. Lalu ia menjawab, 'Aku bukan tak mau mendekatinya. Aku pernah melarangnya untuk berbicara sesuatu tentang dua kelompok yang bertengkar, namun ia menolaknya, ia terus saja melakukan!\" Lalu ia (Hisyam) bersumpah kepadanya, dan akhirnya dia mau datang kepada Aisyah bersamanya. Lalu ia masuk ke tempat Aisyah. Kemudian Aisyah bertanya kepada Hakim, \"Siapa yang bersamamu?\" la menjawab; \"Sa'ad bin Hisyam.\" la bertanya lagi, \" Hisyam yang mana?\" la menjawab; \"Anaknya Amir.\" Lalu ia mendoakan baginya dan berkata, \"Sebaik-baik lelaki adalah`Amir!\" Hakim bertanya, \"Wahai Ummul Mukminin, kabarkanlah kepadaku tentang akhlak Rasulullah Shalallahu 'Alaihi Wa Sallam?\" Aisyah menjawab, \"Bukankah kamu membaca Al Qur'an?\" Hakim menjawab, \"Ya.\" Aisyah lalu berkata, \"Akhlak Nabi Allah Shalallahu 'Alaihi Wa Sallam adalah Al Qur'an.\" Aku ingin berdiri (pamit pulang), namun timbul keinginan untuk mengetahui cara Rasulullah Shalallahu 'Alaihi Wa Sallam melakukan shalat malam, maka ia bertanya lagi, \"Wahai Ummul Mukminin! Kabarkanlah kepadaku tentang shalat malam Rasulullah Shalallahu 'Alaihi Wa Sallam?\" Aisyah menjawab; \"Bukankah kamu membaca surah Al Muzammil?\" Hakim menjawab, \"Ya.\" Aisyah berkata; \"Allah Azza wa Jalla mewajibkan shalat malam pada permulaan surah ini, lalu Rasulullah bersama para sahabatnya menegakkan shalat malam dengan sekuat tenaga sampai telapak kaki mereka membengkak. Kemudian Allah Azza wa Jalla menahannya -yang ujungnya dua belas bulan- lalu menurunkan keringanannya pada akhir surah ini (Al Muzammil), sehingga shalat malam yang semula hukumnya wajib menjadi sunnah.\" Aku ingin berdiri, namun aku juga ingin mengetahui shalat witir Rasulullah Shalallahu 'Alaihi Wa Sallam, maka aku bertanya; \"Wahai Ummul Mukminin! Kabarkanlah kepadaku tentang shalat witir Rasulullah Shalallahu 'Alaihi Wa Sallam?\" Aisyah menerangkan, \"Kami mempersiapkan siwak dan air wudlunya, lalu Allah Azza wa Jalla membangunkannya sekehendakNya pada malam hari, kemudian beliau bersiwak dan berwudlu lalu mengerjakan shalat delapan rakaat tanpa ada duduk, kecuali pada rakaat kedelapan. Beliau berdzikir kepada Allah Azza wa Jalla dan berdoa kepada-Nya, lalu mengucapkan salam dengan salam yang terdengar oleh kami. Kemudian beliau shalat dua rakaat sambil duduk- setelah salam, dan shalat lagi satu rakaat, sehingga berjumlah sebelas rakaat. Wahai anakku, setelah Rasulullah Shalallahu 'Alaihi Wa Sallam mencapai umur senja dan mulai gemuk, beliau mengerjakan witir tujuh rakaat, lalu shalat dua rakaat sambil duduk setelah salam, sehingga semuanya menjadi sembilan rakaat. Wahai anakku, bila Rasulullah Shalallahu 'Alaihi Wa Sallam mengerjakan suatu shalat, maka beliau senang untuk melakukannya secara terus-menerus. Bila beliau berhalangan untuk shalat malam karena ketiduran atau sakit, maka beliau mengerjakan shalat dua belas rakaat pada siang harinya. Aku tidak mengetahui bahwa Nabi Allah pernah membaca Al Qur'an seluruhnya dalam satu malam. Aku juga tidak mengetahui bahwa beliau shalat malam secara sempurna hingga pagi, dan aku pun tidak mengetahui bahwa beliau berpuasa satu bulan penuh selain pada bulan Ramadlan.\" Lalu ia (Hisyam) datang kepada Ibnu Abbas dan menceritakan hal tersebut kepadanya. Dia mengomentarinya dengan berkata; \"Beliau (Aisyah) benar. Seandainya aku yang masuk (datang) kepadanya pasti aku akan menemuinya sehingga dia (Aisyah) berbicara langsung kepadaku.\" Abu Abdurrahman berkata, \"Begitulah yang tertera dalam kitabku! Aku tidak mengetahui ini kesalahan siapa, dalam posisi witir beliau shallallahu 'alaihi wasallam.\""},"1552":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Barangsiapa shalat (malam) pada bulan Ramadhan karena iman dan mengharap pahala, maka dosa-dosanya yang telah lalu akan diampuni.\""},"1553":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَبُو بَكْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ قَالَ قَالَ الزُّهْرِيُّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il Abu Bakr] dia berkata; telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] dia berkata; telah menceritakan kepada kami [Juwairiyah] dari [Malik] dia berkata; berkata [Az Zuhri]; telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] dan [Humaid bin 'Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat (malam) pada bulan Ramadhan karena iman dan mengharap pahala, maka dosa-dosanya yang telah lalu akan diampuni.\""},"1554":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَ��ْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْمَسْجِدِ ذَاتَ لَيْلَةٍ وَصَلَّى بِصَلَاتِهِ نَاسٌ ثُمَّ صَلَّى مِنْ الْقَابِلَةِ وَكَثُرَ النَّاسُ ثُمَّ اجْتَمَعُوا مِنْ اللَّيْلَةِ الثَّالِثَةِ أَوْ الرَّابِعَةِ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ قَالَ قَدْ رَأَيْتُ الَّذِي صَنَعْتُمْ فَلَمْ يَمْنَعْنِي مِنْ الْخُرُوجِ إِلَيْكُمْ إِلَّا أَنِّي خَشِيتُ أَنْ يُفْرَضَ عَلَيْكُمْ وَذَلِكَ فِي رَمَضَانَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah], bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam pada suatu malam mengerjakan shalat di masjid, dan orang-orang pun ikut shalat dengan beliau. Kemudian besoknya Rasulullah shalat lagi dan orang-orang yang ikut pun bertambah banyak. Lalu orang-orang berkumpul pada malam yang ketiga -atau keempat- namun beliau tidak keluar kepada mereka. Pada pagi harinya beliau bersabda: \"Aku telah mengetahui apa yang kalian perbuat. Tidak ada yang menghalangiku untuk keluar kepada kalian melainkan aku khawatir hal tersebut akan diwajibkan kepada kalian.\" Dan hal itu terjadi pada bulan Ramadhan."},"1555":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ذَرٍّ قَالَصُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَلَمْ يَقُمْ بِنَا حَتَّى بَقِيَ سَبْعٌ مِنْ الشَّهْرِ فَقَامَ بِنَا حَتَّى ذَهَبَ ثُلُثُ اللَّيْلِ ثُمَّ لَمْ يَقُمْ بِنَا فِي السَّادِسَةِ فَقَامَ بِنَا فِي الْخَامِسَةِ حَتَّى ذَهَبَ شَطْرُ اللَّيْلِ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ نَفَّلْتَنَا بَقِيَّةَ لَيْلَتِنَا هَذِهِ قَالَ إِنَّهُ مَنْ قَامَ مَعَ الْإِمَامِ حَتَّى يَنْصَرِفَ كَتَبَ اللَّهُ لَهُ قِيَامَ لَيْلَةٍ ثُمَّ لَمْ يُصَلِّ بِنَا وَلَمْ يَقُمْ حَتَّى بَقِيَ ثَلَاثٌ مِنْ الشَّهْرِ فَقَامَ بِنَا فِي الثَّالِثَةِ وَجَمَعَ أَهْلَهُ وَنِسَاءَهُ حَتَّى تَخَوَّفْنَا أَنْ يَفُوتَنَا الْفَلَاحُقُلْتُ وَمَا الْفَلَاحُ قَالَ السُّحُورُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Muhammad bin Al Fudhail] dari [Dawud bin Abu Hind] dari [Al Walid bin 'Abdurrahman] dari [Jubair bin Nufair] dari [Abu Dzarr] dia berkata; \"Kami puasa Ramadlan bersama Rasulullah Shalallahu 'Alaihi Wa Sallam, dan beliau tidak bangun (shalat malam) bersama kami hingga tinggal tujuh hari dari bulan Ramadlan. Lalu beliau bangun bersama kami hingga lewat sepertiga malam, kemudian pada malam keenam menjelang akhir Ramadhan beliau tidak bangun (malam)! Maka setelah malam kelima, beliau bangun bersama kami hingga hampir lewat separuh malam. Kami berkata kepada beliau, 'Wahai Rasulullah, bagaimana jika engkau shalat sunnah bersama kami malam ini? ' Beliau menjawab: 'Jika seseorang shalat bersama imam hingga usai, maka Allah menuliskan baginya pahala menegakkan shalat malam'. Kemudian beliau tidak bangun (guna shalat malam) bersama kami. Ketika bulan (Ramadhan) tinggal tiga hari lagi, beliau bangun untuk shalat malam bersama kami, lalu mengumpulkan keluarga dan para istrinya hingga kami khawatir kehilangan Al Falah ini.\" Aku lalu bertanya; \"Apakah (Al Falah) itu?\" Ia menjawab; \"Waktu sahur\"."},"1556":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ أَخْبَرَنِي مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ حَدَّثَنِي نُعَيْمُ بْنُ زِيَادٍ أَبُو طَلْحَةَ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ عَلَى مِنْبَرِ حِمْصَيَقُولُ قُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَهْرِ رَمَضَانَ لَيْلَةَ ثَلَاثٍ وَعِشْرِينَ إِلَى ثُلُثِ اللَّيْلِ الْأَوَّلِ ثُمَّ قُمْنَا مَعَهُ لَيْلَةَ خَمْسٍ وَعِشْرِينَ إِلَى نِصْفِ اللَّيْلِ ثُمَّ قُمْنَا مَعَهُ لَيْلَةَ سَبْعٍ وَعِشْرِينَ حَتَّى ظَنَنَّا أَنْ لَا نُدْرِكَ الْفَلَاحَ وَكَانُوا يُسَمُّونَهُ السُّحُورَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah mengabarkan kepadaku [Mu'awiyah bin Shalih] dia berkata; telah menceritakan kepadaku [Nu'aim bin Ziyad Abu Thalhah] dia berkata; \"Aku mendengar [Nu'man bin Basyir] berkata di atas mimbar di daerah Himsh, 'Kami bangun untuk shalat malam bersama Rasulullah Shalallahu 'Alaihi Wa Sallam di bulan Ramadlan pada malam dua puluh tiga sampai sepertiga malam pertama. Kemudian kami bangun (shalat malam) lagi bersama beliau pada malam kedua puluh lima sampai pertengahan malam. Kemudian kami bangun (shalat malam) lagi bersama beliau pada malam kedua puluh tujuh hingga kami mengira bahwa kami tidak mendapatkan kemenangan itu'. Mereka menamakan kemenangan (Al Falah) itu dengan sahur.\""},"1557":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَامَ أَحَدُكُمْ عَقَدَ الشَّيْطَانُ عَلَى رَأْسِهِ ثَلَاثَ عُقَدٍ يَضْرِبُ عَلَى كُلِّ عُقْدَةٍ لَيْلًا طَوِيلًا أَيْ ارْقُدْ فَإِنْ اسْتَيْقَظَ فَذَكَرَ اللَّهَ انْحَلَّتْ عُقْدَةٌ فَإِنْ تَوَضَّأَ انْحَلَّتْ عُقْدَةٌ أُخْرَى فَإِنْ صَلَّى انْحَلَّتْ الْعُقَدُ كُلُّهَا فَيُصْبِحُ طَيِّبَ النَّفْسِ نَشِيطًا وَإِلَّا أَصْبَحَ خَبِيثَ النَّفْسِ كَسْلَانَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Apabila salah seorang dari kalian tidur, maka syethan mengikat tiga ikatan di atas kepalanya; tiap ikatan (buhul) diikat dengan kata, 'Malam masih panjang' yakni tidurlah. Jika ia bangun lalu berdzikir kepada Allah, maka lepaslah satu ikatan. Jika ia berwudhu, maka lepaslah ikatan lainnya, dan jika ia mengerjakan shalat maka lepaslah semua ikatannya, sehingga pada pagi harinya ia berjiwa lapang dan bersemangat. Sedangkan jika ia tidak melakukan hal tersebut (bangun, berwudhu, dan shalat malam), maka pada pagi harinya jiwanya akan buruk dan malas.\""},"1558":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ نَامَ لَيْلَةً حَتَّى أَصْبَحَ قَالَ ذَاكَ رَجُلٌ بَالَ الشَّيْطَانُ فِي أُذُنَيْهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] dari ['Abdullah] dia berkata; Diceritakan kepada Rasulullah Shalallahu 'Alaihi Wa Sallam bahwa ada seorang lelaki yang tidur semalaman hingga pagi, maka beliau bersabda: \"Syaithan telah mengencingi kedua telinga laki-laki itu.\""},"1559":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانًا نَامَ عَنْ الصَّلَاةِ الْبَارِحَةَ حَتَّى أَصْبَحَ قَالَ ذَاكَ شَيْطَانٌ بَالَ فِي أُذُنَيْهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdush Shamad] dia berkata; telah menceritakan kepada kami [Manshur] dari [Abu Wa'il] dari ['Abdullah] Bahwa seorang laki-laki berkata; \"Wahai Rasulullah, tadi malam si Fulan tidur hingga pagi dan meninggalkan shalat. Beliau Shalallahu 'Alaihi Wa Sallam bersabda: Syaithan telah mengencingi kedua telinga orang itu."},"1560":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ قَالَ حَدَّثَنِي الْقَعْقَاعُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ رَجُلًا قَامَ مِنْ اللَّيْلِ فَصَلَّى ثُمَّ أَيْقَظَ امْرَأَتَهُ فَصَلَّتْ فَإِنْ أَبَتْ نَضَحَ فِي وَجْهِهَا الْمَاءَ وَرَحِمَ اللَّهُ امْرَأَةً قَامَتْ مِنْ اللَّيْلِ فَصَلَّتْ ثُمَّ أَيْقَظَتْ زَوْجَهَا فَصَلَّى فَإِنْ أَبَى نَضَحَتْ فِي وَجْهِهِ الْمَاءَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dia berkata; telah menceritakan kepadaku [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Allah merahmati seorang pemuda yang bangun untuk shalat dimalam hari, lalu ia membangunkan istrinya untuk shalat, jika ia enggan maka ia memercikkan air diwajahnya, dan Allah merahmati seorang istri yang bangun untuk shalat dimalam hari lalu ia membangunkan suaminya untuk shalat, jika ia enggan maka ia memercikkan air kewajahnya.\""},"1561":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ أَنَّ الْحُسَيْنَ بْنَ عَلِيٍّ حَدَّثَهُ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ فَقَالَ أَلَا تُصَلُّونَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَهَا بَعَثَهَا فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قُلْتُ لَهُ ذَلِكَ ثُمَّ سَمِعْتُهُ وَهُوَ مُدْبِرٌ يَضْرِبُ فَخِذَهُ وَيَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari ['Ali bin Husain] bahwasanya [Al Husain bin 'Ali] menceritakan kepadanya dari ['Ali bin Abu Thalib], bahwa Nabi Shalallahu 'Alaihi Wa Sallam pernah mendatangi dia dan Fatimah pada malam hari, lalu beliau bersabda: \"Tidakkah kalian shalat (malam)?\" Aku menjawab; `'Wahai Rasulullah, jiwa-jiwa kami ada di tangan Allah, jadi jika Dia hendak membangunkannya maka Dia akan membangunkannya.\" Kemudian beliau pergi ketika kuucapkan hal itu, dan aku mendengar beliau pergi sambil memukul pahanya dan bergumam dengan membaca ayat, 'Dan manusia adalah makhluk yang paling banyak membantah.\" (Qs. AI Kahfi (18): 54) "},"1562":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي حَكِيمُ بْنُ حَكِيمِ بْنِ عَبَّادِ بْنِ حُنَيْفٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى فَاطِمَةَ مِنْ اللَّيْلِ فَأَيْقَظَنَا لِلصَّلَاةِ ثُمَّ رَجَعَ إِلَى بَيْتِهِ فَصَلَّى هَوِيًّا مِنْ اللَّيْلِ فَلَمْ يَسْمَعْ لَنَا حِسًّا فَرَجَعَ إِلَيْنَا فَأَيْقَظَنَا فَقَالَ قُومَا فَصَلِّيَا قَالَ فَجَلَسْتُ وَأَنَا أَعْرُكُ عَيْنِي وَأَقُولُ إِنَّا وَاللَّهِ مَا نُصَلِّي إِلَّا مَا كَتَبَ اللَّهُ لَنَا إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِنْ شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا قَالَ فَوَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ وَيَضْرِبُ بِيَدِهِ عَلَى فَخِذِهِ مَا نُصَلِّي إِلَّا مَا كَتَبَ اللَّهُ لَنَا{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami dari [Ibnu Ishaq] dia berkata; telah menceritakan kepadaku [Hakim bin Hakim bin 'Abbad bin Hunaif] dari [Muhammad bin Muslim bin Syihab] dari ['Ali bin Husain] dari [bapaknya] dari kakeknya yaitu ['Ali bin Abu Thalib] dia berkata; Nabi Shalallahu 'Alaihi Wa Sallam pernah mendatangi dirinya dan Fatimah pada malam hari, lalu beliau bersabda: \"Tidakkah kalian shalat (malam) '?\" Aku menjawab, \"Wahai Rasulullah, jiwa-jiwa kami ada di tangan Allah, jadi jika Dia hendak membangunkannya maka Dia akan membangunkannya.\" Kemudian beliau pergi ketika kuucapkan hal itu, dan aku mendengar beliau pergi sambil memukul pahanya dan bergumam dengan membaca ayat, \"Dan manusia adalah makhluk yang paling banyak membantah.\" (Qs. AI Kahfi (18): 54)."},"1563":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ عَوْفٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصِّيَامِ بَعْدَ شَهْرِ رَمَضَانَ شَهْرُ اللَّهِ الْمُحَرَّمُ وَأَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ صَلَاةُ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Humaid bin 'Abdurrahman bin 'Auf] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Puasa yang paling utama setelah puasa Ramadlan adalah puasa di bulan Muharram, dan shalat yang paling utama setelah shalat wajib adalah shalat malam.\""},"1564":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ جَعْفَرِ بْنِ أَبِي وَحْشِيَّةَ أَنَّهُ سَمِعَ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ قِيَامُ اللَّيْلِ وَأَفْضَلُ الصِّيَامِ بَعْدَ رَمَضَانَ الْمُحَرَّمُأَرْسَلَهُ شُعْبَةُ بْنُ الْحَجَّاجِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr Ja'far bin Abu Wahsyiyyah] bahwasanya ia mendengar [Humaid bin 'Abdurrahman] berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Shalat yang paling utama setelah shalat wajib adalah shalat malam, dan puasa yang paling utama setelah puasa Ramadlan adalah puasa Muharram.\" Hadist ini dimursalkan oleh Syu'bah bin Hajaj."},"1565":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ رِبْعِيًّا عَنْ زَيْدِ بْنِ ظَبْيَانَ رَفَعَهُ إِلَى أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ يُحِبُّهُمْ اللَّهُ عَزَّ وَجَلَّ رَجُلٌ أَتَى قَوْمًا فَسَأَلَهُمْ بِاللَّهِ وَلَمْ يَسْأَلْهُمْ بِقَرَابَةٍ بَيْنَهُ وَبَيْنَهُمْ فَمَنَعُوهُ فَتَخَلَّفَهُمْ رَجُلٌ بِأَعْقَابِهِمْ فَأَعْطَاهُ سِرًّا لَا يَعْلَمُ بِعَطِيَّتِهِ إِلَّا اللَّهُ عَزَّ وَجَلَّ وَالَّذِي أَعْطَاهُ وَقَوْمٌ سَارُوا لَيْلَتَهُمْ حَتَّى إِذَا كَانَ النَّوْمُ أَحَبَّ إِلَيْهِمْ مِمَّا يُعْدَلُ بِهِ نَزَلُوا فَوَضَعُوا رُءُوسَهُمْ فَقَامَ يَتَمَلَّقُنِي وَيَتْلُو آيَاتِي وَرَجُلٌ كَانَ فِي سَرِيَّةٍ فَلَقُوا الْعَدُوَّ فَانْهَزَمُوا فَأَقْبَلَ بِصَدْرِهِ حَتَّى يُقْتَلَ أَوْ يُفْتَحَ لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dia berkata; aku mendengar [Rib'iyy] dari [Zaid bin Zhabyan] -dan dia merafa'kannya sampai [Abu Dzarr] -; Ada tiga orang yang Allah mencintai mereka 1). Seseorang yang mendatangi rombongan dan meminta mereka dengan menyebut nama Allah, ia meminta rombongan itu padahal tidak ada hubungan kekerabatan, namun mereka tidak mau memberi. Lantas ada salah seorang dari rombongan itu melambatkan diri. Dengan menyembunyikan rahasia, orang tadi lantas memberi si peminta, sehingga tidak seorang pun mengetahui pemberiannya selain Allah dan orang pun tidak tahu apa yang diberikannya 2). Sebuah rombongan yang berjalan di malam hari, hingga saat waktu tidur lebih mereka cintai daripada yang lain, mereka singgah dan mereka letakkan kepala mereka, namun ada seseorang yang justru mencari keutamaan dengan merendahkan diri kepada-Ku dan membaca ayat-ayat-Ku 3). Seseorang yang mengikuti ekspedisi militer, rombongan pasukannya menyerang musuh lantas mereka terpukul mundur, namun dalam kondisi ini, ia justru menghadang musuh hingga terbunuh atau mendapat kemenangan."},"1566":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْبَصْرِيُّ عَنْ بِشْرٍ هُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَأَيُّ الْأَعْمَالِ أَحَبُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ الدَّائِمُ قُلْتُ فَأَيُّ اللَّيْلِ كَانَ يَقُومُ قَالَتْ إِذَا سَمِعَ الصَّارِخَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim Al Bashri] dari [Bisyr bin Al Mufadldlal] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Asy'ats bin Muslim] dari [bapaknya] dari [Masruq] dia berkata; Aku berkata kepada ['Aisyah] 'Amalan apakah yang paling disukai Rasulullah Shalallahu 'Alaihi Wa Sallam? ' la menjawab; `Yang terus menerus (dilakukan) '. Aku bertanya lagi; 'Kapan (waktu) Rasulullah bangun untuk shalat malam? ' Ia menjawab; `Bila mendengar ayam berkokok'.\""},"1567":{"ar":"أَخْبَرَنَا عِصْمَةُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ قَالَ حَدَّثَنَا الْأَزْهَرُ بْنُ سَعِيدٍ عَنْ عَاصِمِ بْنِ حُمَيْدٍ قَالَسَأَلْتُ عَائِشَةَ بِمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَفْتِحُ قِيَامَ اللَّيْلِ قَالَتْ لَقَدْ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ قَبْلَكَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ عَشْرًا وَيَحْمَدُ عَشْرًا وَيُسَبِّحُ عَشْرًا وَيُهَلِّلُ عَشْرًا وَيَسْتَغْفِرُ عَشْرًا وَيَقُولُ اللَّهُمَّ اغْفِرْ لِي وَاهْدِنِي وَارْزُقْنِي وَعَافِنِي أَعُوذُ بِاللَّهِ مِنْ ضِيقِ الْمَقَامِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami ['Ishmah bin Al Fadhl] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dari [Mu'awiyah bin Shalih] dia berkata; telah menceritakan kepada kami [Al Azhar bin Sa'id] dari ['Ashim bin Humaid] dia berkata; Aku bertanya kepada ['Aisyah], \"Bagaimana Rasulullah memulai shalat malam?\" Aisyah berkata; \"Engkau telah bertanya tentang sesuatu yang tidak pernah ditanyakan oleh seorang pun sebelumnya. Rasulullah Shalallahu 'Alaihi Wa Sallam bertakbir sepuluh kali, bertahmid sepuluh kali, bertasbih sepuluh kali, bertahlil sepuluh kali, dan beristighfar (memohon ampunan) sepuluh kali. Lalu beliau mengucapkan doa: 'Ya Allah, ampunilah aku, berilah aku petunjuk, berilah aku rezeki dan kesehatan. Aku berlindung kepada-Mu dari sempitnya tempat pada hari Kiamat nanti'.\""},"1568":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ وَالْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ رَبِيعَةَ بْنِ كَعْبٍ الْأَسْلَمِيِّ قَالَكُنْتُ أَبِيتُ عِنْدَ حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَسْمَعُهُ إِذَا قَامَ مِنْ اللَّيْلِ يَقُولُ سُبْحَانَ اللَّهِ رَبِّ الْعَالَمِينَ الْهَوِيَّ ثُمَّ يَقُولُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ الْهَوِيَّ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ma'mar] dan [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Rabi'ah bin Ka'b Al Aslami] dia berkata; \"Aku pernah menginap di kamar Nabi Shalallahu 'Alaihi Wa Sallam, sehingga bila beliau bangun malam kami mendengarnya. Beliau mengucapkan: `Subhanallahi rabbil 'alamin (Maha Suci Allah, Tuhan semesta alam) ' beberapa lama, kemudian mengucapkan: `Subhanallahi wa bihamdih (Maha Suci Allah dan segala puji bagi-Nya) ' juga beberapa lama.\""},"1569":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَحْوَلِ يَعْنِي سُلَيْمَانَ بْنَ أَبِي مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَتَهَجَّدُ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ قَيَّامُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ مَلِكُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ حَقٌّ وَوَعْدُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَمُحَمَّدٌ حَقٌّ لَكَ أَسْلَمْتُ وَعَلَيْكَ تَوَكَّلْتُ وَبِكَ آمَنْتُ ثُمَّ ذَكَرَ قُتَيْبَةُ كَلِمَةً مَعْنَاهَا وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَعْلَنْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al Ahwal Sulaiman bin Abu Muslim] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Apabila Rasulullah Shalallahu 'Alaihi Wa Sallam bangun malam, maka beliau mengerjakan shalat tahajjud. Beliau mengucapkan: 'Ya Allah, segala puji bagi-Mu. Engkaulah (pemberi) cahaya langit dan bumi serta penghuninya. Segala puji bagi-Mu, Engkau pengatur langit dan bumi serta penghuninya. Segala puji bagi-Mu, Engkaulah penguasa langit dan bumi serta penghuninya. Segala puji bagi-Mu, Engkau benar, dan janji-Mu benar, surga itu benar, neraka itu benar, hari Kiamat itu benar, para nabi itu benar, dan Muhammad itu benar. Kepada-Mulah aku memasrahkan diri dan kepada Engkau aku bertawakal. Kepada Engkaulah aku beriman. Kemudian Qutaibah menyebutkan kalimat yang artinya, 'kepada Engkaulah aku mengadu, dan kepada Engkaulah aku berhukum. Ampunilah dosa-dosaku yang telah lalu dan yang akan datang serta yang terang-terangan. Engkaulah Yang paling dahulu dan Engkaulah yang paling Akhir. Tiada Tuhan (yang berhak disembah) kecuali Engkau, tiada daya dan kekuatan kecuali dengan (pertolongan) Allah'.\""},"1570":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي مَخْرَمَةُ بْنُ سُلَيْمَانَ عَنْ كُرَيْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ وَهِيَ خَالَتُهُ فَاضْطَجَعَ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ قَلِيلًا أَوْ بَعْدَهُ قَلِيلًا اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِيمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku [Makhramah bin Sulaiman] dari [Kuraib] bahwasanya ['Abdullah bin 'Abbas] mengabarkan kepadanya, bahwa dia pernah bermalam di rumah bibinya Maimunah (istri Nabi shallallahu 'alaihi wasallam), lalu dia berbaring di atas bantal, sementara Rasulullah shallallahu 'alaihi wasallam dan keluarganya berbaring di (tikar) yang panjang. Nabi shallallahu 'alaihi wasallam tidur hingga tengah malam -sebelum atau sesudahnya sedikit-, Rasulullah shallallahu 'alaihi wasallam bangun, terus duduk dan mengusap mukanya dengan tangan, lalu membaca sepuluh ayat terakhir surah Ali Imran. Setelah itu beliau pergi ke bejana air yang tergantung, lalu berwudlu dengan air itu. Beliau memperbagus wudlunya, kemudian mengerjakan shalat. Abdullah bin Abbas berkata; 'Aku berdiri, lalu aku mengerjakan seperti apa yang dikerjakan beliau. Kemudian aku pergi ke samping beliau, beliau memegang kepalaku dengan tangan kanannya seraya menyentil telingaku. Setelah itu beliau shalat dua raka'at, lalu dua raka'at, dua raka'at, dua raka'at, lalu dua raka'at, dan dua raka'at lagi. Kemudian mengerjakan shalat witir. Setelah itu beliau berbaring, sampai datang muadzin, lalu berdiri mengerjakan shalat dua raka'at yang ringan."},"1571":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشِ وَحُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ مِنْ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dan [Muhammad bin Al Mutsanna] dari ['Abdurrahman] dari [Sufyan] dari [Manshur] dan [Al A'masy] dan [Hushain] dari [Abu Wa'il] dari [Hudzaifah] bahwa Nabi Shalallahu 'Alaihi Wa Sallam apabila bangun untuk shalat malam beliau menggosok mulutnya dengan siwak.'"},"1572":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Hushain] dia berkata; Aku mendengar [Abu Wa'il] menceritakan dari [Hudzaifah] dia berkata; Nabi Shalallahu 'Alaihi Wa Sallam apabila bangun untuk shalat malam, beliau menggosok mulutnya dengan siwak.'"},"1573":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ إِسْحَقَ بْنِ سُلَيْمَانَ عَنْ أَبِي سِنَانٍ عَنْ أَبِي حَصِينٍ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَكُنَّا نُؤْمَرُ بِالسِّوَاكِ إِذَا قُمْنَا مِنْ اللَّيْلِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dari [Ishaq bin Sulaiman] dari [Abu Sinan] dari [Abu Hashin] dari [Syaqiq] dari [Hudzafah] dia berkata; \"Apabila kami bangun untuk shalat malam, kami diperintahkan untuk bersiwak.\""},"1574":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ شَقِيقٍ قَالَكُنَّا نُؤْمَرُ إِذَا قُمْنَا مِنْ اللَّيْلِ أَنْ نَشُوصَ أَفْوَاهَنَا بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dia berkata; telah memberitakan kepada kami [Israil] dari [Abu Hashin] dari [Syaqiq] dia berkata; \"Kami diperintahkan menggosok mulut kami dengan siwak bila hendak shalat malam.\""},"1575":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ أَنْبَأَنَا عُمَرُ بْنُ يُونُسَ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَسَأَلْتُ عَائِشَةَ بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ صَلَاتَهُ قَالَتْ كَانَ إِذَا قَامَ مِنْ اللَّيْلِ افْتَتَحَ صَلَاتَهُ قَالَ اللَّهُمَّ رَبَّ جِبْرِيلَ وَمِيكَائِيلَ وَإِسْرَافِيلَ فَاطِرَ السَّمَوَاتِ وَالْأَرْضِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ أَنْتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِيمَا كَانُوا فِيهِ يَخْتَلِفُونَ اللَّهُمَّ اهْدِنِي لِمَا اخْتُلِفَ فِيهِ مِنْ الْحَقِّ إِنَّكَ تَهْدِي مَنْ تَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin 'Abdul 'Azhim] dia berkata; telah memberitakan kepada kami ['Umar bin Yunus] dia berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] dia berkata; \"Aku pernah bertanya kepada [Aisyah]; `Dengan apa Rasulullah Shalallahu 'Alaihi Wa Sallam memulai shalat malam? ' la menjawab; `Apabila bangun malam maka beliau memulai shalat dengan mengucapkan doa: `Ya Allah, Tuhan Jibril, Mikail, dan Israfil, Sang pencipta langit dan bumi, Maha mengetahui hal-hal yang gaib dan yang nampak, Engkau menghukumi di antara hamba-hambaMu dalam perselisihan mereka. Ya Allah, tunjukilah aku kepada kebenaran yang banyak diperselisihkan. Sesungguhnya Engkau memberi petunjuk kepada siapa saja yang Engkau kehendaki menuju jalan yang benar'."},"1576":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقُلْتُ وَأَنَا فِي سَفَرٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَأَرْقُبَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَلَاةٍ حَتَّى أَرَى فِعْلَهُ فَلَمَّا صَلَّى صَلَاةَ الْعِشَاءِ وَهِيَ الْعَتَمَةُ اضْطَجَعَ هَوِيًّا مِنْ اللَّيْلِ ثُمَّ اسْتَيْقَظَ فَنَظَرَ فِي الْأُفُقِ فَقَالَ{ رَبَّنَا مَا خَلَقْتَ هَذَا بَاطِلًا حَتَّى بَلَغَ إِنَّكَ لَا تُخْلِفُ الْمِيعَادَ }ثُمَّ أَهْوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فِرَاشِهِ فَاسْتَلَّ مِنْهُ سِوَاكًا ثُمَّ أَفْرَغَ فِي قَدَحٍ مِنْ إِدَاوَةٍ عِنْدَهُ مَاءً فَاسْتَنَّ ثُمَّ قَامَ فَصَلَّى حَتَّى قُلْتُ قَدْ صَلَّى قَدْرَ مَا نَامَ ثُمَّ اضْطَجَعَ حَتَّى قُلْتُ قَدْ نَامَ قَدْرَ مَا صَلَّى ثُمَّ اسْتَيْقَظَ فَفَعَلَ كَمَا فَعَلَ أَوَّلَ مَرَّةٍ وَقَالَ مِثْلَ مَا قَالَ فَفَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Humaid bin 'Abdurrahman bin 'Auf] bahwa [seseorang dari shahabat] Nabi Shalallahu 'Alaihi Wa Sallam berkata; \"Aku pernah berkata -ketika aku dalam suatu perjalanan bersama Rasulullah shallallahu 'alaihi wasallam- `Demi Allah, aku akan mengawasi shalat Rasulullah shallallahu 'alaihi wasallam hingga aku bisa melihat -cara shalat beliau. Setelah Rasulullah mengerjakan shalat lsya' -yakni shalat 'Atamah beliau berbaring beberapa lama pada malam itu, kemudian bangun lalu memandang ke ufuk (langit), sambil membaca ayat: 'Ya Tuhan kami, tidaklah Engkau menciptakan hal ini dengan sia-sia...hingga ayat, 'Sesungguhnva engkau tidak mengingkari janji\" (Qs. Ali `lmraan (3): 191-194). Kemudian beliau menjulurkan tangannya ke kasur lalu mengeluarkan siwak. lalu beliau menuangkan air dari ember yang ada padanya, kemudian bersiwak. Selanjutnya beliau berdiri dan mengerjakan shalat. Sampai aku berkata; `Beliau mengerjakan shalat seukuran tidurnya'. Kemudian berbaring hingga aku berkata, 'Beliau tidur seukuran shalatnva'. Kemudian beliau bangun lalu mengerjakan seperti yang dikerjakan pada pertama kali, lalu bersabda seperti yang beliau sabdakan sebelumnya. Rasulullah Shalallahu 'Alaihi Wa Sallam mengerjakan hal tersebut tiga kali sebelum terbit Fajar."},"1577":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا يَزِيدُ قَالَ أَنْبَأَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَمَا كُنَّا نَشَاءُ أَنْ نَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي اللَّيْلِ مُصَلِّيًا إِلَّا رَأَيْنَاهُ وَلَا نَشَاءُ أَنْ نَرَاهُ نَائِمًا إِلَّا رَأَيْنَاهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Yazid] dia berkata; telah memberitakan kepada kami [Humaid] dari [Anas] dia berkata; \"Tidaklah kami berkehendak untuk melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat melainkan pasti kami bisa melihatnya. Dan tidaklah kami berkehendak untuk melihat Rasulullah tidur melainkan kami pasti bisa melihatnya.\""},"1578":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ عَنْ أَبِيهِ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ يَعْلَى بْنَ مَمْلَكٍ أَخْبَرَهُأَنَّهُ سَأَلَ أُمَّ سَلَمَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يُصَلِّي الْعَتَمَةَ ثُمَّ يُسَبِّحُ ثُمَّ يُصَلِّي بَعْدَهَا مَا شَاءَ اللَّهُ مِنْ اللَّيْلِ ثُمَّ يَنْصَرِفُ فَيَرْقُدُ مِثْلَ مَا صَلَّى ثُمَّ يَسْتَيْقِظُ مِنْ نَوْمِهِ ذَلِكَ فَيُصَلِّي مِثْلَ مَا نَامَ وَصَلَاتُهُ تِلْكَ الْآخِرَةُ تَكُونُ إِلَى الصُّبْحِ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; berkata [Ibnu Juraij] dari [bapaknya], telah mengabarkan kepadaku [Ibnu Abu Mulaikah] bahwasanya [Ya'la bin Mamlak] mengabarkan kepadanya bahwasanya ia bertanya kepada [Ummu Salamah] tentang shalat Nabi Shalallahu 'Alaihi Wa Sallam, maka ia menjawab; \"Beliau Shalallahu 'Alaihi Wa Sallaw shalat isya' kemudian bertasbih. Setelah itu beliau shalat lagi sebagaimana yang dikehendaki-Nya di waktu malam, lalu beliau pulang dan tidur yang lamanya sebagaimana beliau shalat. Kemudian beliau bangun kembali dan shalat yang lamanya sebagaimana beliau tidur tadi. Shalat ini adalah shalat malam beliau yang terakhir hingga subuh.\""},"1579":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍأَنَّهُ سَأَلَ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قِرَاءَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنْ صَلَاتِهِ فَقَالَتْ مَا لَكُمْ وَصَلَاتَهُ كَانَ يُصَلِّي ثُمَّ يَنَامُ قَدْرَ مَا صَلَّى ثُمَّ يُصَلِّي قَدْرَ مَا نَامَ ثُمَّ يَنَامُ قَدْرَ مَا صَلَّى حَتَّى يُصْبِحَ ثُمَّ نَعَتَتْ لَهُ قِرَاءَتَهُ فَإِذَا هِيَ تَنْعَتُ قِرَاءَةً مُفَسَّرَةً حَرْفًا حَرْفًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Abdullah bin 'Ubaidullah bin Abu Mulaikah] dari [Ya'la bin Mamlak] bahwasanya ia bertanya kepada [Ummu Salamah] -istri Nabi Shalallahu 'Alaihi Wa Sallam- tentang bacaan dan shalat beliau Shalallahu 'Alaihi Wa Sallam. Maka Ummu Salamah menjawab; 'Ada apa dengan shalat Rasulullah Shalallahu 'Alaihi Wa Sallam? Beliau shalat, kemudian tidur yang lamanya sebagaimana shalatnya. Lalu beliau beliau shalat lagi seukuran tidurnya tadi, kemudian tidur lagi seukuran shalatnya hingga shubuh. Ummu Salamah juga menyifati bacaan Nabi Shalallahu 'Alaihi Wa Sallam, ia menyifatinya dengan bacaan yang bisa terdengar dengan jelas huruf demi huruf.\""},"1580":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الصِّيَامِ إِلَى اللَّهِ عَزَّ وَجَلَّ صِيَامُ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَأَحَبُّ الصَّلَاةِ إِلَى اللَّهِ صَلَاةُ دَاوُدَ كَانَ يَنَامُ نِصْفَ اللَّيْلِ وَيَقُومُ ثُلُثَهُ وَيَنَامُ سُدُسَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari ['Amru bin Aus] bahwasanya ia mendengar ['Abdullah bin 'Amru bin Al 'Ash] berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Puasa yang paling dicintai Allah Azza wa Jalla adalah puasa Nabi Daud? laihis Salam, beliau berpuasa sehari dan berbuka sehari. Shalat yang paling dicintai Allah Azza wa Jalla adalah shalat Nabi Daud, beliau tidur separuh malam lalu bangun (untuk shalat) pada sepertiganya, lalu tidur lagi pada seperenamnya.\""},"1581":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ حَرْبٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ خَالِدٍ قَالَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَيْتُ لَيْلَةَ أُسْرِيَ بِي عَلَى مُوسَى عَلَيْهِ السَّلَام عِنْدَ الْكَثِيبِ الْأَحْمَرِ وَهُوَ قَائِمٌ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Harb] dia berkata; telah menceritakan kepada kami [Mu'adz bin Khalid] dia berkata; telah memberitakan kepada kami [Hammad bin Salamah] dari [Sulaiman At Taimi] dari [Tsabit] dari [Anas bin Malik]. Nabi Shalallahu 'Alaihi Wa Sallam bersabda: \"Pada malam Isra Mi'raj aku datang kepada Musa 'Alaihi Salam di bukit pasir merah, dan dia sedang shalat di dalam kuburannya.\""},"1582":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُلَيْمَانَ التَّيْمِيِّ وَثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَيْتُ عَلَى مُوسَى عَلَيْهِ السَّلَام عِنْدَ الْكَثِيبِ الْأَحْمَرِ وَهُوَ قَائِمٌ يُصَلِّيقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا أَوْلَى بِالصَّوَابِ عِنْدَنَا مِنْ حَدِيثِ مُعَاذِ بْنِ خَالِدٍ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Muhammad] dia berkata; telah menceritakan kepada kami [Yunus bin Muhammad] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Sulaiman At Taimi] dan [Tsabit] dari [Anas] Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Aku datang kepada Musa 'Alaihis Salam di bukit pasir merah, dan dia sedang shalat.\" Abu Abdurrahman berkata; 'Menurut kami Hadist ini lebih shahih dari pada Hadits Mu'adz bin Khalid. Wallahu Ta'ala A'lam."},"1583":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ثَابِتٌ وَسُلَيْمَانُ التَّيْمِيُّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَرَرْتُ عَلَى قَبْرِ مُوسَى عَلَيْهِ السَّلَام وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepadaku [Ahmad bin Sa'id] dia berkata; telah menceritakan kepada kami [Habban] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dia berkata; telah memberitakan kepada kami [Tsabit] dan [Sulaiman At Taimi] dari [Anas] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Aku pernah melewati kuburan Nabi Musa Alaihis Salam, dan dia sedang shalat di kuburannya.\""},"1584":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَرْتُ لَيْلَةَ أُسْرِيَ بِي عَلَى مُوسَى عَلَيْهِ السَّلَام وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami ['Ali bin Khasyram] dia berkata; telah menceritakan kepada kami ['Isa] dari [Sulaiman At Taimi] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melewati Musa Alaihis Salam, pada malam aku diisra'kan (diperjalankan) dan dia sedang shalat di kuburannya.\""},"1585":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ مَرَّ عَلَى مُوسَى عَلَيْهِ السَّلَام وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Mu'tamir] dari [Bapaknya] dari [Anas] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam saat malam diisra'kan melewati Musa? laihis Salam, dan dia sedang shalat di kuburannya.\""},"1586":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ وَإِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَا حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ أَنَسًا يَقُولُ أَخْبَرَنِي بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ مَرَّ عَلَى مُوسَى عَلَيْهِ السَّلَام وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dan [Isma'il bin Mas'ud], mereka berdua berkata; telah menceritakan kepada kami [Mu'tamir] dia berkata; Aku mendengar [bapakku] berkata; Aku mendengar [Anas] berkata; telah mengabarkan kepadaku [sebagian sahabat] Nabi shallallahu 'alaihi wasallam bahwa ketika Nabi shallallahu 'alaihi wasallam diisra'kan beliau melewati Musa? laihis Salam, dan dia sedang shalat di kuburannya.\""},"1587":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ عَنْ أَنَسٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْلَةَ أُسْرِيَ بِي مَرَرْتُ عَلَى مُوسَى وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sulaiman] dari [Anas] dari [sebagian Sahabat Nabi shallallahu 'alaihi wasallam] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Pada saat malam diisra'kan aku melewati Musa? laihis Salam, dan dia sedang shalat di kuburannya.\""},"1588":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا أَبِي وَبَقِيَّةُ قَالَا حَدَّثَنَا ابْنُ أَبِي حَمْزَةَ قَالَ حَدَّثَنِي الزُّهْرِيُّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابِ بْنِ الْأَرَتِّ عَنْ أَبِيهِ وَكَانَ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ رَاقَبَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّيْلَةَ كُلَّهَا حَتَّى كَانَ مَعَ الْفَجْرِ فَلَمَّا سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَلَاتِهِ جَاءَهُ خَبَّابٌ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي لَقَدْ صَلَّيْتَ اللَّيْلَةَ صَلَاةً مَا رَأَيْتُكَ صَلَّيْتَ نَحْوَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ إِنَّهَا صَلَاةُ رَغَبٍ وَرَهَبٍ سَأَلْتُ رَبِّي عَزَّ وَجَلَّ فِيهَا ثَلَاثَ خِصَالٍ فَأَعْطَانِي اثْنَتَيْنِ وَمَنَعَنِي وَاحِدَةً سَأَلْتُ رَبِّي عَزَّ وَجَلَّ أَنْ لَا يُهْلِكَنَا بِمَا أَهْلَكَ بِهِ الْأُمَمَ قَبْلَنَا فَأَعْطَانِيهَا وَسَأَلْتُ رَبِّي عَزَّ وَجَلَّ أَنْ لَا يُظْهِرَ عَلَيْنَا عَدُوًّا مِنْ غَيْرِنَا فَأَعْطَانِيهَا وَسَأَلْتُ رَبِّي أَنْ لَا يَلْبِسَنَا شِيَعًا فَمَنَعَنِيهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman bin Sa'id bin Katsir] dia berkata; [bapakku] dan [Baqiyyah] telah menceritakan kepada kami, mereka berkata; telah menceritakan kepada kami [Ibnu Abu Hamzah] dia berkata; telah menceritakan kepadaku [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin Al Harits bin Naufal] dari ['Abdullah bin Khabbab bin Al Arat] dari [Bapaknya] -seorang peserta perang badr bersama Rasulullah shallallahu 'alaihi wasallam- bahwa dia pernah memperhatikan cara shalat Rasulullah shallallahu 'alaihi wasallam pada semua waktu malamnya hingga Fajar. Setelah Rasulullah selesai shalat, Khabbab datang kepada beliau, lalu berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, bapak ibuku jadi jaminan, engkau telah mengerjakan shalat yang belum pernah aku lihat engkau mengerjakan sebelumnya!\" Rasulullah shallallahu 'alaihi wasallampun menjawab: \"Ya, itu adalah shalat yang penuh perasaan antara harap dan khawatir. Aku meminta kepada Rabbku tiga perkara, Dia memberiku dua perkara dan yang satu Dia menolaknya. Aku meminta kepada Rabbku Azza wa Jalla agar tidak membinasakan kita dengan bencana yang telah menyebabkan binasanya umat-umat sebelum kita, dan Allah memberikannya kepadaku. Aku juga meminta kepada Raabku Azza wa Jalla agar tidak menjadikan musuh menguasai (menang) atas kita, dan Dia juga memberikannya. Aku juga meminta agar Dia tidak mencerai beraikan kita sehingga terpisah-pisah menjadi beberapa kelompok (yang saling bertentangan), tetapi Dia tidak memberikannya.\""},"1589":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي يَعْفُورٍ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاكَانَ إِذَا دَخَلَتْ الْعَشْرُ أَحْيَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّيْلَ وَأَيْقَظَ أَهْلَهُ وَشَدَّ الْمِئْزَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ya'fur] dari [Muslim] dari [Masruq] dia berkata; ['Aisyah] berkata; \"Bila telah masuk tanggal sepuluh (Ramadlan) maka Rasulullah shallallahu 'alaihi wasallam menghidupkan malam. Beliau membangunkan keluarganya dan mengikat kainnya (menjauhi istri).\""},"1590":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ قَالَ أَتَيْتُ الْأَسْوَدَ بْنَ يَزِيدَ وَكَانَ لِي أَخًا صَدِيقًافَقُلْتُ يَا أَبَا عَمْرٍو حَدِّثْنِي مَا حَدَّثَتْكَ بِهِ أُمُّ الْمُؤْمِنِينَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَتْ كَانَ يَنَامُ أَوَّلَ اللَّيْلِ وَيُحْيِي آخِرَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dia berkata; \"Aku datang kepada [Al Aswad bin Yazid] -dia adalah teman sekaligus saudara bagiku- lalu berkata; 'Wahai Abu Amru, ceritakan kepadaku apa yang telah diceritakan oleh [Aisyah] kepadamu tentang shalat Rasulullah shallallahu 'alaihi wasallam? ' la menjawab; 'Aisyah berkata; \"Rasulullah tidur pada awal malam dan menghidupkan akhir malam dengan ibadah.\""},"1591":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَا أَعْلَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا قَامَ لَيْلَةً حَتَّى الصَّبَاحَ وَلَا صَامَ شَهْرًا كَامِلًا قَطُّ غَيْرَ رَمَضَانَ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dia berkata; telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'ad bin Hisyam] dari ['Aisyah] Radliallahu? nha dia berkata; \"Aku tidak tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah membaca Al Qur'an seluruhnya dalam satu malam. Aku juga tidak tahu bahwa beliau shalat malam secara sempurna hingga pagi, dan aku pun tidak tahu bahwa beliau berpuasa satu bulan sempurna selain bulan Ramadlan.\""},"1592":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا امْرَأَةٌ فَقَالَ مَنْ هَذِهِ قَالَتْ فُلَانَةُ لَا تَنَامُ فَذَكَرَتْ مِنْ صَلَاتِهَا فَقَالَ مَهْ عَلَيْكُمْ بِمَا تُطِيقُونَ فَوَاللَّهِ لَا يَمَلُّ اللَّهُ عَزَّ وَجَلَّ حَتَّى تَمَلُّوا وَلَكِنَّ أَحَبَّ الدِّينِ إِلَيْهِ مَا دَاوَمَ عَلَيْهِ صَاحِبُهُ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dari [Yahya] dari [Hisyam] dia berkata; [bapakku] telah mengabarkan kepadaku dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam masuk ke tempatnya dan di sisinya ada seorang perempuan. lalu beliau berkata; \"Siapa ini\" \" Aisyah menjawab; \"Dia Fulanah, dia tidak tidur.\" Lalu Aisyah menceritakan tentang shalatnya. Rasulullah bersabda: \"Cukup, kalian seharusnya mengerjakan shalat semampunya. Demi Allah, Allah tidak pernah bosan hingga kalian yang bosan. Akan tetapi sebaik-baik agama (amalan) adalah yang dilakukan secara kontinyu oleh pelakunya.\""},"1593":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى عَنْ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَرَأَى حَبْلًا مَمْدُودًا بَيْنَ سَارِيَتَيْنِ فَقَالَ مَا هَذَا الْحَبْلُ فَقَالُوا لِزَيْنَبَ تُصَلِّي فَإِذَا فَتَرَتْ تَعَلَّقَتْ بِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلُّوهُ لِيُصَلِّ أَحَدُكُمْ نَشَاطَهُ فَإِذَا فَتَرَ فَلْيَقْعُدْ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dari ['Abdul Warits] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid, dan beliau melihat seutas tali menjulur di antara dua tiang, maka beliau berkata: \"Tali apa ini?\" Mereka menjawab; \"Talinya Zainab. Bila ia letih ketika sedang shalat, maka ia berpegangan dengan tali itu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lepaskanlah tali itu. Hendaknva salah seorang dari kalian shalat pada saat segar, dan bila letih maka hendaknya ia duduk.\""},"1594":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ مَنْصُورٍ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَوَرَّمَتْ قَدَمَاهُ فَقِيلَ لَهُ قَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Manshur] -dan lafadz ini miliknya- dari [Sufyan] dari [Ziyad bin 'Ilaqah] dia berkata; Aku mendengar [Al Mughirah bin Syu'bah] berkata; \"Nabi shallallahu 'alaihi wasallam shalat malam hingga kedua kakinya bengkak, lalu dikatakan kepadanya, `Bukankah dosa-dosa engkau yang telah lewat dan yang akan datang telah diampuni! ' Beliau berkata: 'Apakah aku tidak boleh menjadi hamba yang bersyukur?\"'"},"1595":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا صَالِحُ بْنُ مِهْرَانَ وَكَانَ ثِقَةً قَالَ حَدَّثَنَا النُّعْمَانُ بْنُ عَبْدِ السَّلَامِ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حَتَّى تَزْلَعَ يَعْنِي تَشَقَّقُ قَدَمَاهُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Shalih bin Mihran] -dan dia adalah seorang yang tsiqah- dia berkata; telah menceritakan kepada kami [An Nu'man bin 'Abdus Salam] dari [Sufyan] dari ['Ashim bin Kulaib] dari [Bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat hingga kedua kakinya pecah-pecah.\""},"1596":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ بُدَيْلٍ وَأَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَيْلًا طَوِيلًا فَإِذَا صَلَّى قَائِمًا رَكَعَ قَائِمًا وَإِذَا صَلَّى قَاعِدًا رَكَعَ قَاعِدًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Budail] dan [Ayyub] dari ['Abdullah bin Syaqiq] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat malam beberapa lama, dan jika beliau shalat (diawali) dengan berdiri maka beliau juga ruku' dengan berdiri, dan jika shalatnya (diawali) dengan duduk maka beliau juga ruku' dengan duduk.\""},"1597":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَائِمًا وَقَاعِدًا فَإِذَا افْتَتَحَ الصَّلَاةَ قَائِمًا رَكَعَ قَائِمًا وَإِذَا افْتَتَحَ الصَّلَاةَ قَاعِدًا رَكَعَ قَاعِدًا","id":"Telah mengabarkan kepada kami ['Abdah bin 'Abdurrahim] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepadaku [Yazid bin Ibrahim] dari [Ibnu Sirin] dari ['Abdullah bin Syaqiq] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan berdiri, juga dengan duduk. Jika beliau mengawali shalatnya dengan berdiri maka beliau ruku' dengan berdiri, sedangkan jika beliau mengawali shalatnya dengan duduk maka beliau ruku' dengan duduk.\""},"1598":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ وَأَبُو النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهُوَ جَالِسٌ فَيَقْرَأُ وَهُوَ جَالِسٌ فَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ قَدْرَ مَا يَكُونُ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَ وَهُوَ قَائِمٌ ثُمَّ رَكَعَ ثُمَّ سَجَدَ ثُمَّ يَفْعَلُ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku ['Abdullah bin Yazid] dan [Abu An Nadlar] dari [Abu Salamah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam pernah shalat sambil duduk dan membaca surah sambil duduk. Jika bacaannya tersisa sekitar tiga puluh atau empat puluh ayat, maka beliau berdiri lalu membacanya sambil berdiri, kemudian ruku' dan sujud. Lalu pada rakaat kedua beliau juga melakukan hal seperti itu."},"1599":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى جَالِسًا حَتَّى دَخَلَ فِي السِّنِّ فَكَانَ يُصَلِّي وَهُوَ جَالِسٌ يَقْرَأُ فَإِذَا غَبَرَ مِنْ السُّورَةِ ثَلَاثُونَ أَوْ أَرْبَعُونَ آيَةً قَامَ فَقَرَأَ بِهَا ثُمَّ رَكَعَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Isa bin Yunus] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dia berkata; \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sambil duduk, kecuali saat umurnya sudah tua. Beliau juga mengerjakan shalat sambil duduk saat membaca Al Qur'an. Jika bacaan Al Qur'an tinggal tiga puluh atau empat puluh ayat, maka beliau berdiri lalu membaca surat sambil berdiri, lalu ruku'.\""},"1600":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ أَبِي هِشَامٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَهُوَ قَاعِدٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ قَدْرَ مَا يَقْرَأُ إِنْسَانٌ أَرْبَعِينَ آيَةً","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; telah menceritakan kepada kami [Al Walid bin Abu Hisyam] dari [Abu Bakr bin Muhammad] dari ['Amrah] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca (Al Qur'an dalam shalat) sambil duduk, dan bila hendak ruku' maka beliau berdiri seukuran membaca empat puluh ayat.\""},"1601":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا هِشَامٌ عَنْ الْحَسَنِ عَنْ سَعْدِ بْنِ هِشَامِ بْنِ عَامِرٍ قَالَقَدِمْتُ الْمَدِينَةَ فَدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ مَنْ أَنْتَ قُلْتُ أَنَا سَعْدُ بْنُ هِشَامِ بْنِ عَامِرٍ قَالَتْ رَحِمَ اللَّهُ أَبَاكَ قُلْتُ أَخْبِرِينِي عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ وَكَانَ قُلْتُ أَجَلْ قَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِاللَّيْلِ صَلَاةَ الْعِشَاءِ ثُمَّ يَأْوِي إِلَى فِرَاشِهِ فَيَنَامُ فَإِذَا كَانَ جَوْفُ اللَّيْلِ قَامَ إِلَى حَاجَتِهِ وَإِلَى طَهُورِهِ فَتَوَضَّأَ ثُمَّ دَخَلَ الْمَسْجِدَ فَيُصَلِّي ثَمَانِيَ رَكَعَاتٍ يُخَيَّلُ إِلَيَّ أَنَّهُ يُسَوِّي بَيْنَهُنَّ فِي الْقِرَاءَةِ وَالرُّكُوعِ وَالسُّجُودِ وَيُوتِرُ بِرَكْعَةٍ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ ثُمَّ يَضَعُ جَنْبَهُ فَرُبَّمَا جَاءَ بِلَالٌ فَآذَنَهُ بِالصَّلَاةِ قَبْلَ أَنْ يُغْفِيَ وَرُبَّمَا يُغْفِي وَرُبَّمَا شَكَكْتُ أَغْفَى أَوْ لَمْ يُغْفِ حَتَّى يُؤْذِنَهُ بِالصَّلَاةِ فَكَانَتْ تِلْكَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَسَنَّ وَلُحِمَ فَذَكَرَتْ مِنْ لَحْمِهِ مَا شَاءَ اللَّهُ قَالَتْ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ الْعِشَاءَ ثُمَّ يَأْوِي إِلَى فِرَاشِهِ فَإِذَا كَانَ جَوْفُ اللَّيْلِ قَامَ إِلَى طَهُورِهِ وَإِلَى حَاجَتِهِ فَتَوَضَّأَ ثُمَّ يَدْخُلُ الْمَسْجِدَ فَيُصَلِّي سِتَّ رَكَعَاتٍ يُخَيَّلُ إِلَيَّ أَنَّهُ يُسَوِّي بَيْنَهُنَّ فِي الْقِرَاءَةِ وَالرُّكُوعِ وَالسُّجُودِ ثُمَّ يُوتِرُ بِرَكْعَةٍ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ ثُمَّ يَضَعُ جَنْبَهُ وَرُبَّمَا جَاءَ بِلَالٌ فَآذَنَهُ بِالصَّلَاةِ قَبْلَ أَنْ يُغْفِيَ وَرُبَّمَا أَغْفَى وَرُبَّمَا شَكَكْتُ أَغْفَى أَمْ لَا حَتَّى يُؤْذِنَهُ بِالصَّلَاةِ قَالَتْ فَمَا زَالَتْ تِلْكَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dari ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Al Hasan] dari [Sa'ad bin Hisyam bin 'Amir] dia berkata; \"Aku datang ke Madinah lalu aku menemui [Aisyah] Radliallahu? nha, kemudian ia berkata; 'Siapa kamu? ' Aku menjawab; 'Sa'ad bin Hisyam bin Amir'. ia lalu berkata; 'Semoga Allah memberikan rahmat kepada ayahmu! ' Aku berkata lagi, 'Kabarkanlah kepadaku tentang cara shalat Rasulullah shallallahu 'alaihi wasallam? ' la menjawab; `Rasulullah shallallahu 'alaihi wasallam dulu begini dan begitu'. Aku berkata; \"Tentu'. Aisyah berkata; 'Rasulullah shallallahu 'alaihi wasallam shalat Isya' pada malam hari, kemudian kembali ke tempat tidurnya, lalu tidur. Pada tengah malam beliau bangun untuk hajatnya dan bersuci, lalu berwudlu dan masuk ke masjid, kemudian shalat delapan rakaat. Terbayang olehku bahwa beliau menyamakan (lama) bacaannya dan ruku' serta sujudnya. Setelah itu shalat witir satu rakaat, kemudian shalat dua rakaat sambil duduk. Kemudian beliau berbaring miring. Kadangkala Bilal datang dan mengumandangkan adzan untuk shalat sebelum beliau tidur atau sedang tidur. Mungkin juga aku ragu apakah beliau sudah tidur atau belum tidur! hingga Bilal mengumandangkan adzan untuk shalat. Begitulah cara Rasulullah shallallahu 'alaihi wasallam shalat hingga beliau tua dan bertambah gemuk.' Aisyah menceritakan daging (gemuk) nya Rasulullah shallallahu 'alaihi wasallam masya Allah. dia berkata; 'Rasulullah shallallahu 'alaihi wasallam shalat Isya' bersama para sahabat kemudian kembali ke tempat tidurnya. Pada tengah malam beliau bangun ke tempat bersucinya dan hajatnya, lalu berwudhu, kemudian masuk ke masjid lalu shalat enam rakaat. Terbayang olehku bahwa beliau menyamakan bacaannya, ruku'nya, serta sujudnya. Beliau juga shalat witir satu rakaat. Kemudian shalat dua rakaat sambil duduk, lalu berbaring miring. Kadangkala Bilal datang lalu mengumandangkan adzan untuk shalat sebelum beliau tidur atau sedang tidur. Aku juga ragu apakah beliau sudah tidur? Hingga Bilal mengumandangkan adzan untuk shalat.' Aisyah berkata; 'Maka senantiasa seperti itulah cara shalat Rasulullah shallallahu 'alaihi wasallam.'"},"1602":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ حَدِيثِ أَبِي عَاصِمٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْتَنِعُ مِنْ وَجْهِي وَهُوَ صَائِمٌ وَمَا مَاتَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ قَاعِدًا ثُمَّ ذَكَرَتْ كَلِمَةً مَعْنَاهَا إِلَّا الْمَكْتُوبَةَ وَكَانَ أَحَبُّ الْعَمَلِ إِلَيْهِ مَا دَامَ عَلَيْهِ الْإِنْسَانُ وَإِنْ كَانَ يَسِيرًاخَالَفَهُ يُونُسُ رَوَاهُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ أُمِّ سَلَمَةَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] tentang hadits [Abu 'Ashim], dia berkata; telah menceritakan kepada kami ['Umar bin Abu Zaidah] dia berkata; telah menceritakan kepadaku [Abu Ishaq] dari [Al Aswad] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tetap saja menciumku, padahal beliau sedang puasa, dan Tidaklah beliau meninggal sehingga kebanyakan shalat Rasulullah adalah sambil duduk.\" -Kemudian ia menyebutkan suatu kalimat yang maknanya adalah-: kecuali shalat wajib (beliau kerjakan sambil berdiri), dan perbuatan yang paling dicintai adalah yang dilakukan secara kontinyu oleh seseorang, walaupun sedikit. Yunus menyelisihi Hadits ini, dia meriwayatkan dari Abu Ishaq dari Al Aswad dari Ummu Salamah."},"1603":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا النَّضْرُ قَالَ أَنْبَأَنَا يُونُسُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ أُمِّ سَلَمَةَ قَالَتْمَا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ جَالِسًا إِلَّا الْمَكْتُوبَةَخَالَفَهُ شُعْبَةُ وَسُفْيَانُ وَقَالَا عَنْ أَبِي إِسْحَقَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Salim Al Balkhi] dia berkata; telah menceritakan kepada kami [An Nadlar] dia berkata; telah memberitakan kepada kami [Yunus] dari [Abu Ishaq] dari [Al Aswad] dari [Ummu Salamah] dia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam wafat hingga kebanyakan shalatnya adalah dilaksanakan sambil duduk, kecuali shalat wajib.\" Syu'bah dan Sufyan menyelisihi Hadits tersebut, mereka berdua berkata; 'Dari Abu Ishaq dari Abu Salamah dari Ummu Salamah.'"},"1604":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْمَا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ قَاعِدًا إِلَّا الْفَرِيضَةَ وَكَانَ أَحَبُّ الْعَمَلِ إِلَيْهِ أَدْوَمَهُ وَإِنْ قَلَّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar [Abu Salamah] dari [Ummu Salamah] dia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam wafat hingga kebanyakan shalatnya adalah sambil duduk, kecuali shalat fardlu. Perbuatan yang paling dicintai adalah yang dilakukan secara kontinyu, walaupun sedikit.\""},"1605":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْوَالَّذِي نَفْسِي بِيَدِهِ مَا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ قَاعِدًا إِلَّا الْمَكْتُوبَةَ وَكَانَ أَحَبُّ الْعَمَلِ إِلَيْهِ مَا دَاوَمَ عَلَيْهِ وَإِنْ قَلَّخَالَفَهُ عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ فَرَوَاهُ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ","id":"Telah mengabarkan kepada kami ['Abdullah bin 'Abdush Shamad] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Salamah] dari [Ummu Salamah] dia berkata; \"Demi Dzat yang jiwaku berada di tangan-Nya, tidaklah Rasulullah shallallahu 'alaihi wasallam wafat hingga shalatnya sering dilakukan sambil duduk, kecuali shalat wajib. Perbuatan yang sangat dicintai beliau adalah yang dilakukan secara kontinyu, walaupun- jumlahnya- sedikit.\" Utsman bin Abu Sulaiman menyelisihinya, dia meriwayatkan dari Abu Salamah, dari Aisyah."},"1606":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ عَنْ حَجَّاجٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَمُتْ حَتَّى كَانَ يُصَلِّي كَثِيرًا مِنْ صَلَاتِهِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad] dari [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Utsman bin Abu Sulaiman] [Abu Salamah] mengabarkan kepadanya bahwasanya ['Aisyah] mengabarkan kepadanya; Rasulullah shallallahu 'alaihi wasallam tidak wafat hingga sering melakukan shalatnya sambil duduk."},"1607":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ أَنْبَأَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَقُلْتُ لِعَائِشَةَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ قَاعِدٌ قَالَتْ نَعَمْ بَعْدَ مَا حَطَمَهُ النَّاسُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dari [Yazid bin Zurai'] dia berkata; telah memberitakan kepada kami [Al Jurairi] dari ['Abdullah bin Syaqiq] dia berkata; \"Aku bertanya kepada [Aisyah], `Apakah Rasulullah shallallahu 'alaihi wasallam pernah shalat sambil duduk? ' lalu Aisyah menjawab; `Ya, ketika beliau telah lanjut usia'.\""},"1608":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَنْ حَفْصَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي سُبْحَتِهِ قَاعِدًا قَطُّ حَتَّى كَانَ قَبْلَ وَفَاتِهِ بِعَامٍ فَكَانَ يُصَلِّي قَاعِدًا يَقْرَأُ بِالسُّورَةِ فَيُرَتِّلُهَا حَتَّى تَكُونَ أَطْوَلَ مِنْ أَطْوَلَ مِنْهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [As Saib bin Yazid] dari [Al Muththalib bin Abu Wada'ah] dari [Hafshah] dia berkata; \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sunnah sambil duduk, hingga menjelang setahun sebelum beliau walat, (saat itu) beliau sering shalat sambil duduk, membaca surah Al Qur'an dengan tartil, sampai-sampai beliau memperlama dalam membacanya.\""},"1609":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي جَالِسًا فَقُلْتُ حُدِّثْتُ أَنَّكَ قُلْتَ إِنَّ صَلَاةَ الْقَاعِدِ عَلَى النِّصْفِ مِنْ صَلَاةِ الْقَائِمِ وَأَنْتَ تُصَلِّي قَاعِدًا قَالَ أَجَلْ وَلَكِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepada kami [Manshur] dari [Hilal bin Yasaf] dari [Abu Yahya] dari ['Abdullah bin 'Amru] dia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sambil duduk, maka aku berkata kepada beliau; 'Aku pernah mendapatkan hadits dari engkau, bahwa engkau bersabda: \"Shalat orang sambil duduk (mendapatkan) setengah (pahala) dari shalat yang dilakukan sambil berdiri. Dan engkau shalat sambil duduk.\" Beliau shallallahu 'alaihi wasallam menjawab: `Ya, tetapi aku tidak seperti salah satu dari kalian.\""},"1610":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الَّذِي يُصَلِّي قَاعِدًا قَالَ مَنْ صَلَّى قَائِمًا فَهُوَ أَفْضَلُ وَمَنْ صَلَّى قَاعِدًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ وَمَنْ صَلَّى نَائِمًا فَلَهُ نِصْفُ أَجْرِ الْقَاعِدِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan bin Habib] dari [Husain Al Mu'allim] dari ['Abdullah bin Buraidah] dari ['Imran bin Hushain] dia berkata; \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang orang yang shalat sambil duduk, lalu beliau bersabda: \"Barangsiapa shalat dengan berdiri maka itu lebih utama. Barangsiapa shalat dengan duduk maka baginya setengah pahala dari pahala shalat yang dilakukan dengan berdiri. Barangsiapa shalat dengan tiduran maka baginya setengah pahala dari pahala shalat Yang dilakukan dengan duduk.\""},"1611":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ حَفْصٍ عَنْ حُمَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مُتَرَبِّعًاقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا رَوَى هَذَا الْحَدِيثَ غَيْرَ أَبِي دَاوُدَ وَهُوَ ثِقَةٌ وَلَا أَحْسِبُ هَذَا الْحَدِيثَ إِلَّا خَطَأً وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Abu Dawud Al Ja'fari] dari [Hafsh] dari [Humaid] dari ['Abdullah bin Syaqiq] dari ['Aisyah] dia berkata; 'Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sambil duduk dengan kaki bersilang di bawah paha (mutarabi').\" Abu Abdurrahman berkata; 'Aku tidak mengetahui seorangpun yang meriwayatkan hadits ini selain Abu Dawud dan ia adalah terpercaya dan aku menganggap hadits salah. Wallahu Ta'ala A'lam."},"1612":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ قَالَسَأَلْتُ عَائِشَةَ كَيْفَ كَانَتْ قِرَاءَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ يَجْهَرُ أَمْ يُسِرُّ قَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَفْعَلُ رُبَّمَا جَهَرَ وَرُبَّمَا أَسَرَّ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Mu'awiyah bin Shalih] dari ['Abdullah bin Abu Qais] dia berkata; \"Aku pernah bertanya kepada [Aisyah] tentang cara Rasulullah shallallahu 'alaihi wasallam membaca (Al Qur'an) di malam hari, `Beliau membacanya dengan bersuara keras atau pelan (tanpa bersuara)? ' Aisyah menjawab; 'Semuanya pernah dilakukan beliau. Kadang beliau membacanya dengan suara keras dan kadang membacanya dengan pelan (tanpa bersuara) '.\""},"1613":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ سُمَيْعٍ قَالَ حَدَّثَنَا زَيْدٌ يَعْنِي ابْنَ وَاقِدٍ عَنْ كَثِيرِ بْنِ مُرَّةَ أَنَّ عُقْبَةَ بْنَ عَامِرٍ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِي يَجْهَرُ بِالْقُرْآنِ كَالَّذِي يَجْهَرُ بِالصَّدَقَةِ وَالَّذِي يُسِرُّ بِالْقُرْآنِ كَالَّذِي يُسِرُّ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal] dia berkata; telah menceritakan kepada kami [Muhammad bin Sumai'] dia berkata; telah menceritakan kepada kami [Zaid bin Waqid] dari [Katsir bin Murrah] bahwasanya ['Uqbah bin 'Amir] menceritakan kepada mereka; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membaca Al Qur'an dengan mengeraskan suaranya seperti orang yang menampakkan sedekah, dan orang yang memelankan suaranya dalam membaca Al Qur 'an seperti orang yang menyembunyikan sedekahnya.\""},"1614":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ فَمَضَى فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَتَيْنِ فَمَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَافْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَقَالَ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَكَانَ قِيَامُهُ قَرِيبًا مِنْ رُكُوعِهِ ثُمَّ سَجَدَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ رُكُوعِهِ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdullah bin Numair] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Aku pernah shalat dengan Rasulullah shallallahu 'alaihi wasallam pada suatu malam, beliau memulainya dengan membaca surah Al Baqarah. Lalu aku berkata dalam hatiku; -Mungkin- beliau akan ruku' pada ayat ke seratus. Namun beliau malah meneruskannya'. Aku berkata dalam hatiku, '-Mungkin- beliau akan ruku' saat dua ratus ayat, namun beliau malah meneruskannya'. Aku berkata dalam hatiku, 'Beliau shalat dengan surat Al Baqarah dalam satu rakaat. Kemudian beliau meneruskan (shalatnya), dan memulainya dengan membaca surah An Nisaa'. Beliau membacanya (hingga selesai), kemudian memulai lagi dengan surah Ali 'Imraan, dan beliau membacanya (hingga selesai) dengan perlahan-perlahan. Jika beliau menjumpai ayat tasbih maka beliau bertasbih (memuji Allah), jika beliau menjumpai ayat yang menganjurkan untuk meminta maka beliau pun meminta (kepada Allah), dan jika beliau menjumpai ayat yang berkenaan dengan memohon perlindungan maka beliau memohon perlindungan. Kemudian beliau ruku dengan membaca subhana rabbiyal 'azhimi (Maha Suci Tuhanku yang Maha Agung), yang (karenanya) ruku beliau sama dengan (lamanya) berdiri. Kemudian beliau mengangkat kepalanya, lalu mengucapkan Sami'allahu liman Hamidah (Allah Maha Mendengar orang yang memuji-Nya). Dan (lamanya) berdiri beliau sama dengan (lamanya) beliau ruku'. Kemudian beliau sujud dengan membaca subhana rabbiyal a'laa (Maha Suci Tuhanku Yang Maha Tinggi). Sujud beliau sama dengan (lamanya) ruku' beliau.\""},"1615":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ ثِقَةٌ قَالَ حَدَّثَنَا الْعَلَاءُ بْنُ الْمُسَيَّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ طَلْحَةَ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ حُذَيْفَةَأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَرَكَعَ فَقَالَ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ مِثْلَ مَا كَانَ قَائِمًا ثُمَّ جَلَسَ يَقُولُ رَبِّ اغْفِرْ لِي رَبِّ اغْفِرْ لِي مِثْلَ مَا كَانَ قَائِمًا ثُمَّ سَجَدَ فَقَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى مِثْلَ مَا كَانَ قَائِمًا فَمَا صَلَّى إِلَّا أَرْبَعَ رَكَعَاتٍ حَتَّى جَاءَ بِلَالٌ إِلَى الْغَدَاةِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ عِنْدِي مُرْسَلٌ وَطَلْحَةُ بْنُ يَزِيدَ لَا أَعْلَمُهُ سَمِعَ مِنْ حُذَيْفَةَ شَيْئًا وَغَيْرُ الْعَلَاءِ بْنِ الْمُسَيَّبِ قَالَ فِي هَذَا الْحَدِيثِ عَنْ طَلْحَةَ عَنْ رَجُلٍ عَنْ حُذَيْفَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [An Nadlar bin Muhammad Al Marwazi] -seorang yang tsiqah- dia berkata; telah menceritakan kepada kami [Al 'Ala bin Al Musayyab] dari ['Amru bin Murrah] dari [Thalhah bin Yazid Al Anshari] dari [Hudzaifah] bahwa ia pernah shalat dengan Rasulullah shallallahu 'alaihi wasallam di bulan Ramadlan, beliau ruku' dengan membaca subhana rabbiyal 'azhimi (Maha Suci Tuhanku Yang Maha Agung), yang (lamanya) ruku' beliau sama dengan (lamanya) berdiri beliau. Kemudian beliau duduk dan membaca rabbighfirli, rabighfirli (Ya Tuhanku, ampunilah aku. Ya Tuhanku, ampunilah aku), yang (lamanya) duduk beliau sama dengan (lamanya) berdiri. Kemudian beliau sujud dan membaca subhana rabbiyal a'laa (Maha Suci Tuhanku Yang Maha Tinggi), yang (lamanya) sujud beliau sama dengan (lamanya) berdiri. Tidaklah beliau shalat kecuali hanya empat rakaat, hingga Bilal datang untuk shalat Subuh.\" Abu Abdurrahman berkata; 'Menurutku Hadist ini mursal, aku tidak mengetahui bahwa Thalhah bin Yazid telah mendengar dari Hudzaifah. Karena telah berkata Al 'Alla bin Musayyab mengenai Hadist ini dari seseorang, dari Hudzaifah.'"},"1616":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ أَنَّهُ سَمِعَ عَلِيًّا الْأَزْدِيَّ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَىأَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ عِنْدِي خَطَأٌ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dan ['Abdurrahman], mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha] bahwasanya ia mendengar ['Ali Al Azdi] telah mendengar [Ibnu 'Umar] menceritakan dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Shalat (sunah) malam dan siang hari adalah dua rakaat-dua rakaat. Abu Abdurrahman berkata; 'Menurutku Hadist ini salah. Wallahu Ta'ala? lam."},"1617":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ حَبِيبٍ عَنْ طَاوُسٍ قَالَ قَالَ ابْنُ عُمَرَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيتَ الصُّبْحَ فَوَاحِدَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Habib] dari [Thawus] dia berkata; berkata [Ibnu 'Umar]; \"Ada seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam? Lalu beliau bersabda: \"Dua rakaat-dua rakaat. Jika kamu khawatir akan segera datang waktu Subuh maka (cukup) satu rakaat.\""},"1618":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ وَمُحَمَّدُ بْنُ صَدَقَةَ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami ['Amru bin 'Utsman] dan [Muhammad bin Shadaqah] mereka berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari [Salim] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat malam itu dua rakaat-dua rakaat. Jika kamu khawatir akan segera Subuh maka shalat witirlah satu rakaat.\""},"1619":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يُسْأَلُ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِرَكْعَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Labid] dari [Abu Salamah] dari [Ibnu 'Umar] dia berkata; \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam saat di atas mimbar ditanya tentang shalat malam? Lalu beliau menjawab: \"Dua rakaat-dua rakaat. Jika kamu khawatir akan segera Subuh maka shalatlah witir satu rakaaat.\""},"1620":{"ar":"أَخْبَرَنَا مُوسَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ الْحُرِّ قَالَ حَدَّثَنَا نَافِعٌ أَنَّ ابْنَ عُمَرَ أَخْبَرَهُمْأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ قَالَ مَثْنَى مَثْنَى فَإِنْ خَشِيَ أَحَدُكُمْ الصُّبْحَ فَلْيُوتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Musa bin Sa'id] dia berkata; telah menceritakan kepada kami [Ahmad bin 'Abdullah bin Yunus] dia berkata; telah menceritakan kepada kami [Zuhair] dia berkata; telah menceritakan kepada kami [Al Hasan bin Al Hurr] dia berkata; telah menceritakan kepada kami [Nafi'] bahwasanya [Ibnu 'Umar] mengabarkan kepada mereka, seorang lelaki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam? Lalu beliau menjawab: \"Dua rakaat-dua rakaat. Jika salah seorang dari kalian khawatir akan segera Subuh maka shalatlah witir satu rakaat.\""},"1621":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] beliau bersabda: \"Shalat malam itu dua rakaat-dua rakaat. Jika kamu khawatir akan segera Subuh maka shalatlah witir satu rakaat.\""},"1622":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَسَأَلَ رَجُلٌ مِنْ الْمُسْلِمِينَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ صَلَاةُ اللَّيْلِ فَقَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami ['Utsman] dari [Syu'aib] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dia berkata; \"Seorang lelaki bertanya kepada Rasulullah shallallahu 'alaihi wasallam, 'Bagaimana cara shalat malam? Lalu beliau menjawab: \"Dua rakaat-dua rakaat. Jika salah seorang dari kalian khawatir akan segera Subuh maka shalatlah witir satu rakaat.\""},"1623":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خَشِيتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] dia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami keponakanku [Ibnu Syihab] dari [pamannya] dia berkata; telah mengabarkan kepadaku [Humaid bin 'Abdurrahman] bahwasanya ['Abdullah bin 'Umar] mengabarkan kepadanya; \"Seorang lelaki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam? Lalu Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dua rakaat-dua rakaat. Jika karena khawatir akan segera Subuh maka shalatlah witir satu rakaat.\""},"1624":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ الْهَيْثَمِ قَالَ حَدَّثَنَا حَرْمَلَةُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ أَنَّ سَالِمَ بْنَ عَبْدِ اللَّهِ وَحُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَاهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ صَلَاةُ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Al Haitsam] dia berkata; telah menceritakan kepada kami [Harmalah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amru bin Al Harits], [Ibnu Syihab] menceritakan kepadanya bahwasanya [Salim bin 'Abdullah] dan [Humaid bin 'Abdurrahman] menceritakan kepadanya dari ['Abdullah bin 'Umar] dia berkata; \"Ada seorang lelaki berdiri lalu bertanya; `Wahai Rasulullah, bagaimanakah cara shalat malam? ' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Dua rakaat-dua rakaat, Jika kamu khawatir akan segera subuh maka shalatlah witir satu raka'at.'"},"1625":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمٍ وَهُوَ ابْنُ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَوْتَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا أَهْلَ الْقُرْآنِ أَوْتِرُوا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ وِتْرٌ يُحِبُّ الْوِتْرَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr bin 'Ayyasy] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dari ['Ali radliallahu 'anhu] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir, kemudian bersabda: 'Wahai ahli Al Qur'an! Kerjakanlah shalat witir, karena Allah Azza wa Jalla ganjil (Esa) dan mencintai yang ganjil'.\""},"1626":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ أَبِي نُعَيْمٍ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَالْوِتْرُ لَيْسَ بِحَتْمٍ كَهَيْئَةِ الْمَكْتُوبَةِ وَلَكِنَّهُ سُنَّةٌ سَنَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepadaku [Muhammad bin Isma'il bin Ibrahim] dari [Abu Nu'aim] dari [Sufyan] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dari ['Ali radliallahu 'anhu] dia berkata; \"Shalat witir tidak harus seperti shalat wajib, tetapi witir adalah sunnah yang disunnahkan oleh Rasulullah shallallahu 'alaihi wasallam.\""},"1627":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ وَمُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ بْنِ شَقِيقٍ عَنْ النَّضْرِ بْنِ شُمَيْلٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي شِمْرٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ النَّوْمِ عَلَى وِتْرٍ وَصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَرَكْعَتَيْ الضُّحَى","id":"Telah mengabarkan kepada kami [Sulaiman bin Salim] dan [Muhammad bin 'Ali bin Al Hasan bin Syaqiq] dari [An Nadlar bin Syumail] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Abu Syimr] dari [Abu 'Utsman] dari [Abu Hurairah] dia berkata; \"Kekasihku (Rasulullah) mewasiatkan tiga perkara kepadaku, yaitu shalat witir sebelum tidur, puasa tiga hari di setiap bulan, dan shalat Dluha dua rakaat.\""},"1628":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا عَنْ عَبَّاسٍ الْجُرَيْرِيِّ قَالَ سَمِعْتُ أَبَا عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ الْوِتْرِ أَوَّلَ اللَّيْلِ وَرَكْعَتَيْ الْفَجْرِ وَصَوْمِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; [Syu'bah] -kemudian dia menyebutkan kalimat yang maknanya- dari ['Abbas Al Jurairi] dia berkata; Aku mendengar [Abu 'Utsman] dari [Abu Hurairah] dia berkata; \"Kekasihku (Rasulullah) mewasiatkan tiga perkara kepadaku, yaitu shalat witir pada permulaan malam, shalat (sunnah) Fajar dua rakaat, dan puasa tiga hari pada setiap bulan.\""},"1629":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ مُلَازِمِ بْنِ عَمْرٍو قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقٍ قَالَزَارَنَا أَبِي طَلْقُ بْنُ عَلِيٍّ فِي يَوْمٍ مِنْ رَمَضَانَ فَأَمْسَى بِنَا وَقَامَ بِنَا تِلْكَ اللَّيْلَةَ وَأَوْتَرَ بِنَا ثُمَّ انْحَدَرَ إِلَى مَسْجِدٍ فَصَلَّى بِأَصْحَابِهِ حَتَّى بَقِيَ الْوِتْرُ ثُمَّ قَدَّمَ رَجُلًا فَقَالَ لَهُ أَوْتِرْ بِهِمْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وِتْرَانِ فِي لَيْلَةٍ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Mulazim bin 'Amr] dia berkata; telah menceritakan kepadaku ['Abdullah bin Badr] dari [Qais bin Thalq] dia berkata; \"Ayahku [Thalq bin Ali] mengunjungi kami pada bulan Ramadlan, dan dia bersama kami sampai sore. Pada hari itu dia shalat malam bersama kami, lalu shalat witir bersama kami. Kemudian berangkat ke masjid dan shalat bersama para sahabatnya hingga sisa shalat witir saja. Kemudian dia memerintahkan seseorang untuk maju sambil berkata kepadanya; 'Shalatlah witir bersama mereka, karena aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada dua witir dalam satu malam.\""},"1630":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ قَالَسَأَلْتُ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَنَامُ أَوَّلَ اللَّيْلِ ثُمَّ يَقُومُ فَإِذَا كَانَ مِنْ السَّحَرِ أَوْتَرَ ثُمَّ أَتَى فِرَاشَهُ فَإِذَا كَانَ لَهُ حَاجَةٌ أَلَمَّ بِأَهْلِهِ فَإِذَا سَمِعَ الْأَذَانَ وَثَبَ فَإِنْ كَانَ جُنُبًا أَفَاضَ عَلَيْهِ مِنْ الْمَاءِ وَإِلَّا تَوَضَّأَ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dia berkata; Aku bertanya kepada ['Aisyah] tentang -cara- shalat Rasulullah shallallahu 'alaihi wasallam? Lalu ia menjawab; 'Beliau tidur pada permulaan malam, kemudian bangun. Jika waktu sudah mendekati Subuh maka beliau mengerjakan shalat witir, kemudian kembali ke tempat tidurnya. Bila beliau punya hajat terhadap istrinya maka beliau bersetubuh dengan istrinya, dan jika beliau mendengar adzan maka beliau segera beranjak. Jika beliau dalam keadaan junub, beliau menyiram diri dengan air (mandi) sedangkan jika tidak junub maka beliau hanya berwudlu kemudian keluar untuk shalat'.\""},"1631":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي حَصِينٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْأَوْتَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَوَّلِهِ وَآخِرِهِ وَأَوْسَطِهِ وَانْتَهَى وِتْرُهُ إِلَى السَّحَرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Hishn] dari [Yahya bin Watstsab] dari [Masruq] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir pada permulaan malam, akhir, dan pertengahan malam. Beliau selesai shalat witir setelah menjelang Subuh.\""},"1632":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ قَالَمَنْ صَلَّى مِنْ اللَّيْلِ فَلْيَجْعَلْ آخِرَ صَلَاتِهِ وِتْرًا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwasanya [Ibnu 'Umar] berkata; \"Barangsiapa mengerjakan shalat malam, maka jadikanlah di akhir shalatnya dengan shalat witir, karena Rasulullah shallallahu 'alaihi wasallam memerintahkan hal tersebut.\""},"1633":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدٌ وَهُوَ ابْنُ الْمُبَار��كِ قَالَ حَدَّثَنَا مُعَاوِيَةُ وَهُوَ ابْنُ سَلَّامِ بْنِ أَبِي سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو نَضْرَةَ الْعَوَقِيُّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِتْرِ فَقَالَ أَوْتِرُوا قَبْلَ الصُّبْحِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Fadlalah bin Ibrahim] dia berkata; telah memberitakan kepada kami [Muhammad bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Sallam bin Abu Sallam] dari [Yahya bin Abu Katsir] dia berkata; telah mengabarkan kepadaku [Abu Nadlrah Al 'Awaqi] bahwasanya ia mendengar [Abu Sa'id Al Khudri] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang shalat witir? Lalu beliau menjawab: 'Shalatlah witir sebelum datang Subuh'.\""},"1634":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ الْقَنَّادُ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ أَبِي كَثِيرٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوْتِرُوا قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] dia berkata; telah menceritakan kepada kami [Abu Isma'il Al Qannad] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Nadlrah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalatlah witir sebelum Subuh.\""},"1635":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عِديٍّ عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِأَنَّهُ كَانَ فِي مَسْجِدِ عَمْرِو بْنِ شُرَحْبِيلَ فَأُقِيمَتْ الصَّلَاةُ فَجَعَلُوا يَنْتَظِرُونَهُ فَجَاءَ فَقَالَ إِنِّي كُنْتُ أُوتِرُ قَالَ وَسُئِلَ عَبْدُ اللَّهِ هَلْ بَعْدَ الْأَذَانِ وِتْرٌ قَالَ نَعَمْ وَبَعْدَ الْإِقَامَةِ وَحَدَّثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَامَ عَنْ الصَّلَاةِ حَتَّى طَلَعَتْ الشَّمْسُ ثُمَّ صَلَّى","id":"Telah mengabarkan kepada kami [Yahya bin Hakim] dia berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [Bapaknya] bahwa dia pernah berada di masjid Amru bin Syurahbil, lalu dikumandangkanlah adzan untuk shalat, maka mereka pun menunggunya (Abdullah). Kemudian dia datang dan berkatas \"Aku tadi sedang shalat witir.\" la (Muntasyir) berkata; ['Abdullah] pun ditanya; 'Apakah ada shalat witir setelah adzan? ' la menjawab; `Ya, ada. Juga setelah iqamah'. Kemudian ia menyampaikan hadits dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah tertidur dari shalat (Subuh) hingga matahari terbit, kemudian beliau mengerjakan shalat.\""},"1636":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى الرَّاحِلَةِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah bin Al Akhnas] dari [Nafi'] dari [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan witir di atas unta tunggangannya."},"1637":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ الْحَسَنِ بْنِ الْحُرِّ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ يُوتِرُ عَلَى بَعِيرِهِ وَيَذْكُرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah mengabarkan kepadaku ['Abdullah bin Muhammad bin 'Ali] dia berkata; telah menceritakan kepada kami [Zuhair] dari [Al Hasan bin Al Hurr] dari [Nafi'] bahwasanya [Ibnu 'Umar] melaksanakan witir di atas untanya, dan dia berkata; Bahwa Nabi shallallahu 'alaihi wasallam pernah melakukan demikian."},"1638":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي بَكْرِ بْنِ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ سَعِيدِ بْنِ يَسَارٍ قَالَ قَالَ لِي ابْنُ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى الْبَعِيرِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Malik] dari [Abu Bakr bin 'Umar bin 'Abdurrahman bin 'Abdullah bin 'Umar bin Al Khaththab] dari [Sa'id bin Yasar] dia berkata; [Ibnu 'Umar] berkata kepadaku; \"Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan witir di atas untanya.\""},"1639":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Wahb bin Jarir] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Abu Mijlaz] dari [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Witir itu satu raka? t pada akhir malam.\""},"1640":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى وَمُحَمَّدٌ قَالَا حَدَّثَنَا ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dan [Muhammad], mereka berkata; telah menceritakan kepada kami -kemudian dia menyebutkan kalimat yang maknanya- [Syu'bah] dari [Qatadah] dari [Abu Mijlaz] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Witir itu satu raka? t (yang dilaksanakan) pada akhir malam.\""},"1641":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ عَنْ عَفَّانَ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا مِنْ أَهْلِ الْبَادِيَةِ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ قَالَ مَثْنَى مَثْنَى وَالْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad] dari ['Affan] dia berkata; telah menceritakan kepada kami [Hammam] dia berkata; telah menceritakan kepada kami [Qatadah] dari ['Abdullah bin Syaqiq] dari [Ibnu 'Umar] bahwa seorang badui bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam? Lalu beliau bersabda: \"Shalat malam itu dua rakaat-dua rakaat, sedangkan shalat witir satu rakaat pada akhir malam.\""},"1642":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا أَرَدْتَ أَنْ تَنْصَرِفَ فَارْكَعْ بِوَاحِدَةٍ تُوتِرُ لَكَ مَا قَدْ صَلَّيْتَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Hajjaj bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amru bin Al Harits] dari ['Abdurrahman bin Al Qasim], telah menceritakan kepadanya [bapaknya] dari ['Abdullah bin 'Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat malam dua rakaat-dua rakaat. jika kamu hendak menyelesaikan maka shalatlah satu rakaat, sebagai witir bagi shalat yang telah kamu kerjakan.\""},"1643":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا خَالِدُ بْنُ زِيَادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى وَالْوِتْرُ رَكْعَةٌ وَاحِدَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Khalid bin Ziyad] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua rakaat-dua rakaat, dan shalat witir itu satu rakaat'.\""},"1644":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ وَعَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خَشِيَ أَحَدُكُمْ الصُّبْحَ صَلَّى رَكْعَةً وَاحِدَةً تُوتِرُ لَهُ مَا قَدْ صَلَّى","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya lafazh ini darinya, dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dan ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar] bahwa ada seorang lelaki yang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam? Lalu Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Shalat malam itu dua rakaat-dua rakaat. Jika salah seorang dari kalian khawatir datangnya waktu shalat Subuh maka hendaklah ia shalat satu rakaat, sebagai witir untuk shalat yang telah dikerjakan.\""},"1645":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ حَدَّثَنَا مُعَاوِيَةُ وَهُوَ ابْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَنَافِعٌ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَمِعَهُ يَقُولُ صَلَاةُ اللَّيْلِ رَكْعَتَيْنِ رَكْعَتَيْنِ فَإِذَا خِفْتُمْ الصُّبْحَ فَأَوْتِرُوا بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Fadhalah bin Ibrahim] dia berkata; telah menceritakan kepada kami [Muhammad bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepada kami [Abu Salamah bin 'Abdurrahman] dan [Nafi'] dari [Ibnu 'Umar] dari Rasulullah shallallahu 'alaihi wasallam, bahwa ia (Ibnu Umar) mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua rakaat-dua rakaat. Jika kalian khawatir dengan datangnya waktu shalat Subuh, maka shalatlah witir satu rakaat.\""},"1646":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ إِحْدَى عَشْرَةَ رَكْعَةً يُوتِرُ مِنْهَا بِوَاحِدَةٍ ثُمَّ يَضْطَجِعُ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dia berkata; [Malik] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] Bahwa Nabi shallallahu 'alaihi wasallam shalat malam sebelas rakaat, dengan shalat witir satu rakaat. kemudian berbaring miring ke sebelah kanan."},"1647":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ أَخْبَرَهُ أَنَّهُسَأَلَ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ كَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ قَالَتْ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ فِي رَمَضَانَ وَلَا غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّ�� أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ قَالَ يَا عَائِشَةُ إِنَّ عَيْنِي تَنَامُ وَلَا يَنَامُ قَلْبِي","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya, lafazh ini darinya dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Salamah bin 'Abdurrahman] dia mengabarkan kepadanya bahwa dia pernah bertanya kepada [Aisyah] tentang cara shalat Rasulullah shallallahu 'alaihi wasallam pada bulan Ramadhan? Lalu Aisyah menjawab; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah shalat lebih dari sebelas rakaat, tidak pada bulan Ramadlan dan juga bulan lainnya. Beliau shallallahu 'alaihi wasallam shalat empat rakaat, kamu jangan bertanya tentang baik dan lamanya. Kemudian shalat empat rakaat lagi, juga kamu jangan bertanya tentang baik dan lamanya, lalu Beliau shalat witir tiga rakaat'.\" Aisyah berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, apakah engkau tidur sebelum shalat witir?\" Beliau bersabda: 'Wahai Aisyah, mataku tidur namun hatiku tidak tidur.'"},"1648":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يُسَلِّمُ فِي رَكْعَتَيْ الْوِتْرِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] bahwasanya ['Aisyah] berkata kepadanya; \"Rasulullah Shallallahu'alaihi wa Sallam tidak mengucapkan salam pada rakaat kedua shalat witir.\""},"1649":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِثَلَاثِ رَكَعَاتٍ كَانَ يَقْرَأُ فِي الْأُولَى بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَيَقْنُتُ قَبْلَ الرُّكُوعِ فَإِذَا فَرَغَ قَالَ عِنْدَ فَرَاغِهِ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ يُطِيلُ فِي آخِرِهِنَّ","id":"Telah mengabarkan kepada kami ['Ali bin Maimun] dia berkata; telah menceritakan kepada kami [Makhlad bin Yazid] dari [Sufyan] dari [Zubaid] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] dari [Ubay bin Ka'ab] bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat witir tiga rakaat, pada rakaat pertama beliau membaca: \": Sabbihisma rabbikal a'laa (surah Al A'la).\" Pada rakaat kedua membaca: \"Qul ya ayyuhal kafirun (surah Al Kaafiruun), \" dan pada rakaat ketiga beliau membaca \"Qul huwallahu ahad (surah Al Ikhlas).\" Lalu beliau qunut sebelum ruku'. Setelah selesai beliau membaca \"Subbhanal Malikil Quddus\" tiga kali. Beliau memanjangkan pada yang terakhir kalinya."},"1650":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى مِنْ الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Isa bin Yunus] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] dari [Ubay bin Ka'b] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pada rakaat pertama dalam shalat witir membaca surah Al A'laa'. Pada rakaat kedua membaca surah Al Kaafiruun', dan pada rakaat ketiga membaca surah Al Ikhlash.\""},"1651":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُوسَى قَالَ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ خَالِدٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الرَّكْعَةِ الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَلَا يُسَلِّمُ إِلَّا فِي آخِرِهِنَّ وَيَقُولُ يَعْنِي بَعْدَ التَّسْلِيمِ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Yahya bin Musa] dia berkata; telah memberitakan kepada kami ['Abdul 'Aziz bin Khalid] dia berkata; telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari ['Azrah] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] dari [Ubay bin Ka'ab] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam ketika shalat witir membaca surah Al A'Iaa, pada rakaat kedua membaca surah Al Kaafiruun, dan pada rakaat ketiga membaca surah Al Ikhlash. Beliau tidak mengucapkan salam kecuali pada rakaat terakhir. Setelah selesai salam beliau lalu membaca doa: `Subhaanal malikul qudduus' tiga kali.\""},"1652":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثٍ يَقْرَأُ فِي الْأُولَى بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌأَوْقَفَهُ زُهَيْرٌ","id":"Telah mengabarkan kepada kami [Al Husain bin 'Isa] dia berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepada kami [Zakaria bin Abu Zaidah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir tiga rakaat. Pada rakaat pertama beliau membaca surah Al A'laa, pada rakaat kedua membaca surah Al Kaafiruun, dan pada rakaat ketiga beliau membaca Qul Huwallahu ahad.\""},"1653":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ كَانَ يُوتِرُ بِثَلَاثٍ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dia berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] bahwa dia mengerjakan shalat witir dengan tiga rakaat. Pada rakaat pertama dia membaca surah Al A'laa, pada rakaat kedua membaca surah Al Kaafiruun, dan pada rakaat ketiga beliau membaca Qul Huwallahu ahad.\""},"1654":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ مِنْ اللَّيْلِ فَاسْتَنَّ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ نَامَ ثُمَّ قَامَ فَاسْتَنَّ ثُمَّ تَوَضَّأَ فَصَلَّى رَكْعَتَيْنِ حَتَّى صَلَّى سِتًّا ثُمَّ أَوْتَرَ بِثَلَاثٍ وَصَلَّى رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Muhammad bin 'Ali] dari [Bapaknya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bangun malam lalu bersiwak, kemudian shalat dua rakaat. Lalu tidur lagi. Kemudian bangun dan bersiwak, lalu berwudlu, dan shalat dua rakaat hingga enam rakaat, kemudian witir tiga rakaat. Setelah itu shalat dua rakaat lagi."},"1655":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ حُصَيْنٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَتَوَضَّأَ وَاسْتَاكَ وَهُوَ يَقْرَأُ هَذِهِ الْآيَةَ حَتَّى فَرَغَ مِنْهَا{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُولِي الْأَلْبَابِ }ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ عَادَ فَنَامَ حَتَّى سَمِعْتُ نَفْخَهُ ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَاكَ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ نَامَ ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَاكَ وَصَلَّى رَكْعَتَيْنِ وَأَوْتَرَ بِثَلَاثٍأَخْبَرَنَا مُحَمَّدُ بْنُ جَبَلَةَ قَالَ حَدَّثَنَا مَعْمَرُ بْنُ مَخْلَدٍ ثِقَةٌ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ ابْنِ عَبَّاسٍ قَالَ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَنَّ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Hushain] dari [Habib bin Abu Tsabit] dari [Muhammad bin 'Ali bin 'Abdullah bin 'Abbas] dari [Bapaknya] dari [kakeknya], dia berkata; \"Aku di sisi Rasulullah shallallahu 'alaihi wasallam, beliau bangun dan bersiwak, lalu membaca ayat ini (hingga selesai): Sesungguhnya dalam penciptaan langit dan bumi, silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal'. (Qs. Ali 'Imraan (3): 190) kemudian beliau melaksanakan shalat dua rakaat, kemudian kembali ke tempatnya dan tidur, sampai aku mendengar dengkur beliau. Kemudian beliau bangun, berwudlu, menggosok gigi, lalu shalat dua rakaat kemudian tidur kembali lalu bangun, berwudlu dan shalat dua rakaat dan melakukan witir sebanyak tiga rakaat. Telah mengabarkan kepadaku [Muhammad bin Jabalah] ia berkata, telah menceritakan kepada kami [Ma'mar bin Makhlad] tsiqah, ia berkata, telah menceritakan kepadaku [Ubaidullah bin 'Amru] dari [Zaid] dari [Habib bin Abu Tsabit] dari [Muhammad bin 'Ali] dari [Ibnu Abbas] ia berkata, Rasulullah shallallahu 'alaihi wasallam bangun kemudian melakukan sunnah... Ibnu Abbas memamaparkan hadits."},"1656":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا أَبُو بَكْرٍ النَّهْشَلِيُّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَمَانَ رَكَعَاتٍ وَيُوتِرُ بِثَلَاثٍ وَيُصَلِّي رَكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِخَالَفَهُ عَمْرُو بْنُ مُرَّةَ فَرَوَاهُ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ أُمِّ سَلَمَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Abu Bakr An Nahsyali] dari [Habib bin Abu Tsabit] dari [Yahya bin Al Jazzar] dari [Ibnu 'Abbas] dia berkata; Bahwa Rasulullah shallallahu 'alaihi wasallam shalat malam delapan rakaat dan shalat witir tiga rakaat. Lalu beliau shalat dua rakaat sebelum shalat Fajar. Amru bin Murrah menyelisihinya, dia meriwayatkan dari Yahya bin Al Jazzar dari Ummu Salamah dari Rasulullah shallallahu 'alaihi wasallam."},"1657":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثَ عَشْرَةَ رَكْعَةً فَلَمَّا كَبِرَ وَضَعُفَ أَوْتَرَ بِتِسْعٍخَالَفَهُ عُمَارَةُ بْنُ عُمَيْرٍ فَرَوَاهُ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ عَائِشَةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari ['Amru bin Murrah] dari [Yahya bin Al Jazzar] dari [Ummu Salamah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir tiga belas rakaat. Setelah bertambah tua dan lemah beliau shalat witir sembilan rakaat. Umarah bin Umair menyelisihinya, dia meriwayatkan dari Yahya bin Al Jazzar dari Aisyah."},"1658":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ تِسْعًا فَلَمَّا أَسَنَّ وَثَقُلَ صَلَّى سَبْعًا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Sulaiman] dari ['Umarah bin 'Umair] dari [Yahya bin Al Jazzar] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat malam sembilan rakaat, dan setelah usianya bertambah dan kondisinya semakin lemah beliau shalat tujuh rakaat.\""},"1659":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي ضُبَارَةُ بْنُ أَبِي السَّلِيلِ قَالَ حَدَّثَنِي دُوَيْدُ بْنُ نَافِعٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ قَالَ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ عَنْ أَبِي أَيُّوبَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ حَقٌّ فَمَنْ شَاءَ أَوْتَرَ بِسَبْعٍ وَمَنْ شَاءَ أَوْتَرَ بِخَمْسٍ وَمَنْ شَاءَ أَوْتَرَ بِثَلَاثٍ وَمَنْ شَاءَ أَوْتَرَ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dia berkata; telah menceritakan kepadaku [Dlubarah bin Abu As Salil] dia berkata; telah menceritakan kepadaku [Duwaid bin Nafi'] dia berkata; telah mengabarkan kepadaku [Ibnu Syihab] dia berkata; telah menceritakan kepada kami ['Atha bin Yazid] dari [Abu Ayyub], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat witir itu benar. Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya tujuh rakaat. Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya lima rakaat. Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya tiga rakaat, dan Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya satu rakaat.\""},"1660":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ قَالَ حَدَّثَنَا عَطَاءُ بْنُ يَزِيدَ عَنْ أَبِي أَيُّوبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ حَقٌّ فَمَنْ شَاءَ أَوْتَرَ بِخَمْسٍ وَمَنْ شَاءَ أَوْتَرَ بِثَلَاثٍ وَمَنْ شَاءَ أَوْتَرَ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Al Walid bin Mazid] dia berkata; [bapakku] telah mengabarkan kepadaku, dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepadaku [Az Zuhri] dia berkata; telah menceritakan kepada kami ['Atha bin Yazid] dari [Abu Ayyub], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat witir itu benar. Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya lima rakaat. Barangsiapa hendak shalat witir, maka ia boleh mengerjakannya tiga rakaat, dan barangsiapa hendak shalat witir, maka ia boleh mengerjakannya satu rakaat.\""},"1661":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنِي أَبُو مُعَيْدٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ أَنَّهُ سَمِعَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ يَقُولُالْوِتْرُ حَقٌّ فَمَنْ أَحَبَّ أَنْ يُوتِرَ بِخَمْسِ رَكَعَاتٍ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يُوتِرَ بِثَلَاثٍ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يُوتِرَ بِوَاحِدَةٍ فَلْيَفْعَلْ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Dawud] dia berkata; telah menceritakan kepada kami ['Abdullah bin Yusuf] dia berkata; telah menceritakan kepada kami [Al Haitsam bin Humaid] dia berkata; telah menceritakan kepadaku [Abu Mu'aid] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku ['Atha bin Yazid] bahwasanya ia mendengar [Abu Ayyub Al Anshari] berkata; \"Shalat witir itu hak. Barangsiapa suka shalat witir lima rakaat maka hendaklah ia mengerjakannya. Barangsiapa suka shalat witir tiga rakaat, maka hendaklah ia mengerjakannya, dan barangsiapa suka shalat witir satu rakaat, maka hendaklah ia mengerjakanlah.\""},"1662":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي أَيُّوبَ قَالَمَنْ شَاءَ أَوْتَرَ بِسَبْعٍ وَمَنْ شَاءَ أَوْتَرَ بِخَمْسٍ وَمَنْ شَاءَ أَوْتَرَ بِثَلَاثٍ وَمَنْ شَاءَ أَوْتَرَ بِوَاحِدَةٍ وَمَنْ شَاءَ أَوْمَأَ إِيمَاءً","id":"Telah berkata [Al Harits bin Miskin] secara baca dan aku mendengarnya dari [Sufyan] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Ayyub] dia berkata; \"Barangsiapa ingin, hendaklah ia shalat witir tujuh rakaat. Barangsiapa ingin. hendaklah ia shalat witir lima rakaat. Barangsiapa ingin, hendaklah ia shalat witir tiga rakaat. Barangsiapa ingin, hendaklah ia shalat witir satu rakaat, dan barangsiapa ingin hanya sekedar dengan isyarat maka hendaklah ia menggunakan isyarat.\""},"1663":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِخَمْسٍ وَبِسَبْعٍ لَا يَفْصِلُ بَيْنَهَا بِسَلَامٍ وَلَا بِكَلَامٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Miqsam] dari [Ummu Salamah] dia berkata; Rasulullah shallallahu 'alaihi wasallam shalat witir dengan lima dan tujuh rakaat beliau tidak memisahkan rakaatnya dengan salam ataupun perkataan."},"1664":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبْعٍ أَوْ بِخَمْسٍ لَا يَفْصِلُ بَيْنَهُنَّ بِتَسْلِيمٍ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria bin Dinar] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Israil] dari [Manshur] dari [Al Hakam] dari [Miqsam] dari [Ibnu 'Abbas] dari [Ummu Salamah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir lima rakaat atau tujuh rakaat tanpa memisahkan diantara rakaat-rakaatnya dengan salam.\""},"1665":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ الْحُسَيْنِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ قَالَالْوِتْرُ سَبْعٌ فَلَا أَقَلَّ مِنْ خَمْسٍ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ عَمَّنْ ذَكَرَهُ قُلْتُ لَا أَدْرِي قَالَ الْحَكَمُ فَحَجَجْتُ فَلَقِيتُ مِقْسَمًا فَقُلْتُ لَهُ عَمَّنْ قَالَعَنْ الثِّقَةِ عَنْ عَائِشَةَ وَعَنْ مَيْمُونَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dari [Yazid] dia berkata; telah menceritakan kepada kami [Sufyan bin Al Husain] dari [Al Hakam] dari [Miqsam] dia berkata; \"Shalat witir itu tujuh rakaat, maka jangan kurang dari lima rakaat.\" Lalu aku (Miqsam) menceritakan hal itu kepada Ibrahim, maka ia bertanya; \"Dari siapa ia menyebutkan hal itu?\" Aku menjawab; \"Aku tidak tahu.\" Al Hakam berkata; \"Aku pergi haji dan berjumpa dengan Miqsam, lalu aku bertanya kepadanya, 'Dari siapa kamu menyebutkannya? ' la menjawab. 'Dari [orang yang tsiqah] (terpercaya), dari [Aisyah] dan [Maimunah'].\""},"1666":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِخَمْسٍ وَلَا يَجْلِسُ إِلَّا فِي آخِرِهِنَّ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam pernah shalat witir lima rakaat dan beliau tidak duduk (tasyahud) kecuali pada rakaat terakhir."},"1667":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أَسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَ اللَّحْمَ صَلَّى سَبْعَ رَكَعَاتٍ لَا يَقْعُدُ إِلَّا فِي آخِرِهِنَّ وَصَلَّى رَكْعَتَيْنِ وَهُوَ قَاعِدٌ بَعْدَ مَا يُسَلِّمُ فَتِلْكَ تِسْعٌ يَا بُنَيَّ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَحَبَّ أَنْ يُدَاوِمَ عَلَيْهَا مُخْتَصَرٌخَالَفَهُ هِشَامٌ الدَّسْتُوَائِيُّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'ad bin Hisyam] dari ['Aisyah] dia berkata; \"Setelah Rasulullah shallallahu 'alaihi wasallam berusia lanjut dan mulai gemuk, beliau shalat tujuh rakaat tanpa duduk, kecuali pada akhir rakaat. Lalu shalat dua rakaat sambil duduk setelah salam (dari yang tujuh rakaat), sehingga semuanya berjumlah sembilan rakaat. Wahai anakku! Bila Rasulullah shallallahu 'alaihi wasallam mengerjakan suatu shalat, maka beliau suka untuk melakukannya secara kontinyu.\" Hisyam Ad Dastuwai menyelisihinya."},"1668":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوْتَرَ بِتِسْعِ رَكَعَاتٍ لَمْ يَقْعُدْ إِلَّا فِي الثَّامِنَةِ فَيَحْمَدُ اللَّهَ وَيَذْكُرُهُ وَيَدْعُو ثُمَّ يَنْهَضُ وَلَا يُسَلِّمُ ثُمَّ يُصَلِّي التَّاسِعَةَ فَيَجْلِسُ فَيَذْكُرُ اللَّهَ عَزَّ وَجَلَّ وَيَدْعُو ثُمَّ يُسَلِّمُ تَسْلِيمَةً يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَلَمَّا كَبِرَ وَضَعُفَ أَوْتَرَ بِسَبْعِ رَكَعَاتٍ لَا يَقْعُدُ إِلَّا فِي السَّادِسَةِ ثُمَّ يَنْهَضُ وَلَا يُسَلِّمُ فَيُصَلِّي السَّابِعَةَ ثُمَّ يُسَلِّمُ تَسْلِيمَةً ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir sembilan rakaat maka beliau melakukannya tanpa duduk, kecuali pada rakaat kedelapan. Lalu memuji Allah, berdzikir, dan berdoa kepada-Nya. Kemudian beliau bangun lagi tanpa salam (pada rakaat kedelapan tersebut). Kemudian shalat rakaat yang ke sembilan, lalu duduk dan berdzikir kepada Allah Azza wa Jalla. Setelah itu berdoa kemudian mengucapkan salam yang terdengar oleh kami. lalu beliau shalat dua rakaat sambil duduk. Setelah tua dan lemah, beliau shalat witir tujuh rakaat, beliau tidak duduk kecuali pada rakaat yang keenam, lalu beliau bangkit lagi dan tidak mengucapkan salam untuk melaknjutkan rakaat yang ketujuh. Setelah itu beliau salam. Kemudian beliau shalat dua rakaat sambil duduk.\""},"1669":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ عَنْ عَبْدَةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ أَنَّ عَائِشَةَ قَالَتْكُنَّا نُعِدُّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ عَزَّ وَجَلَّ لِمَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَسْتَاكُ وَيَتَوَضَّأُ وَيُصَلِّي تِسْعَ رَكَعَاتٍ لَا يَجْلِسُ فِيهِنَّ إِلَّا عِنْدَ الثَّامِنَةِ وَيَحْمَدُ اللَّهَ وَيُصَلِّي عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَدْعُو بَيْنَهُنَّ وَلَا يُسَلِّمُ تَسْلِيمًا ثُمَّ يُصَلِّي التَّاسِعَةَ وَيَقْعُدُ وَذَكَرَ كَلِمَةً نَحْوَهَا وَيَحْمَدُ اللَّهَ وَيُصَلِّي عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَدْعُو ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ قَاعِدٌ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dari ['Abdah] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] bahwasanya ['Aisyah] berkata; \"Kami mempersiapkan siwak Rasulullah shallallahu 'alaihi wasallam dan alat bersucinya, lalu Allah Azza wa Jalla membangunkannya sekehendak Dia membangunkan pada malam hari. kemudian beliau bersiwak dan berwudlu, lalu shalat sembilan rakaat tanpa duduk kecuali pada rakaat kedelapan. Setelah itu beliau memuji Allah dan mengucapkan shalawat kepada Nabi shallallahu 'alaihi wasallam, dan berdoa di antara rakaat-rakaat tersebut tanpa salam. Kemudian shalat rakaat yang kesembilan, lalu duduk ia (perawi) menyebutkan suatu kalimat yang semakna dan memuji Allah serta bershalawat kepada Nabi shallallahu 'alaihi wasallam lalu berdoa, kemudian salam yang terdengar oleh kami. Setelah itu beliau shalat lagi dua rakaat sambil duduk.\""},"1670":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى أَنَّ سَعْدَ بْنَ هِشَامِ بْنِ عَامِرٍلَمَّا أَنْ قَدِمَ عَلَيْنَا أَخْبَرَنَا أَنَّهُ أَتَى ابْنَ عَبَّاسٍ فَسَأَلَهُ عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكَ أَوْ أَلَا أُنَبِّئُكَ بِأَعْلَمِ أَهْلِ الْأَرْضِ بِوِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ مَنْ قَالَ عَائِشَةُ فَأَتَيْنَاهَا فَسَلَّمْنَا عَلَيْهَا وَدَخَلْنَا فَسَأَلْنَاهَا فَقُلْتُ أَنْبِئِينِي عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنَّا نُعِدُّ لَهُ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ عَزَّ وَجَلَّ مَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيَتَوَضَّأُ ثُمَّ يُصَلِّي تِسْعَ رَكَعَاتٍ لَا يَقْعُدُ فِيهِنَّ إِلَّا فِي الثَّامِنَةِ فَيَحْمَدُ اللَّهَ وَيَذْكُرُهُ وَيَدْعُو ثُمَّ يَنْهَضُ وَلَا يُسَلِّمُ ثُمَّ يُصَلِّي التَّاسِعَةَ فَيَجْلِسُ فَيَحْمَدُ اللَّهَ وَيَذْكُرُهُ وَيَدْعُو ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَتِلْكَ إِحْدَى عَشْرَةَ رَكْعَةً يَا بُنَيَّ فَلَمَّا أَسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَ اللَّحْمَ أَوْتَرَ بِسَبْعٍ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ مَا يُسَلِّمُ فَتِلْكَ تِسْعًا أَيْ بُنَيَّ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَحَبَّ أَنْ يُدَاوِمَ عَلَيْهَا","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Qatadah] dari [Zurarah bin Aufa] bahwasanya [Sa'd bin Hisyam bin 'Amir] setelah datang kepada kami mengabarkan, bahwa dia pernah datang kepada Ibnu Abbas lalu bertanya tentang cara shalat witir Rasulullah shallallahu 'alaihi wasallam, maka (Ibnu Abbas) berkata; \"Maukah aku beri tahu penghuni bumi ini yang sangat mengetahui cara shalat witir Rasulullah shallallahu 'alaihi wasallam\"?\" Dia menjawab, \"Siapa?\" Ibnu Abbas berkata, 'Aisyah.\" Lalu kami datang dengan mengucapkan salam kepadanya kemudian masuk dan bertanya; \"Wahai Ummul Mukminin, kabarkanlah kepadaku tentang -cara- shalat witir Rasulullah shallallahu 'alaihi wasallam?\" [Aisyah] lalu berkata; \"Kami dulu mempersiapkan siwak dan air wudlunya. lalu Allah Azza Wa Jalla membangunkannya sekehendak-Nya pada malam hari. Kemudian beliau shallallahu 'alaihi wasallam bersiwak dan berwudlu, lalu mengerjakan shalat sembilan rakaat tanpa ada duduk kecuali pada rakaat kedelapan. Beliau memuji Allah, berdzikir, dan berdoa kepada-Nya, lalu bangkit tanpa salam. Kemudian shalat rakaat yang kesembilan, lalu duduk dan memuji Allah, berdzikir, serta berdoa kepada-Nya, kemudian mengucapkan salam yang diperdengarkan kepada kami. Setelah itu beliau shalat lagi dua rakaat sambil duduk, sehingga shalatnya berjumlah sebelas rakaat. Setelah Rasulullah shallallahu 'alaihi wasallam mencapai umur senja dan bertambah gemuk. beliau mengerjakan witir tujuh rakaat, lalu shalat dua rakaat sambil duduk setelah salam, sehingga semuanya berjumlah sembilan rakaat. Wahai anakku, bila Rasulullah shallallahu 'alaihi wasallam mengerjakan suatu shalat, maka beliau senang untuk melakukannya secara kontinyu.\""},"1671":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ قَالَ أَخْبَرَنِي سَعْدُ بْنُ هِشَامٍ عَنْ عَائِشَةَ أَنَّهُ سَمِعَهَا تَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِتِسْعِ رَكَعَاتٍ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَلَمَّا ضَعُفَ أَوْتَرَ بِسَبْعِ رَكَعَاتٍ ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Qatadah] dari [Al Hasan] dia berkata; telah mengabarkan kepadaku [Sa'd bin Hisyam] dari ['Aisyah], bahwa dia (Sa'ad bin Hisyam) mendengar Aisyah berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir sembilan rakaat, kemudian shalat dua rakaat sambil duduk. Setelah beliau lemah, beliau mengerjakan shalat witir tujuh rakaat, kemudian shalat dua rakaat sambil duduk.\""},"1672":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِتِسْعٍ وَيَرْكَعُ رَكْعَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Al Hasan] dari [Sa'd bin Hisyam] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir sembilan rakaat, lalu shalat dua rakaat sambil duduk."},"1673":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخَلَنْجِيُّ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ يَعْنِي مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا حُصَيْنُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا الْحَسَنُ عَنْ سَعْدِ بْنِ هِشَامٍأَنَّهُ وَفَدَ عَلَى أُمِّ الْمُؤْمِنِينَ عَائِشَةَ فَسَأَلَهَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يُصَلِّي مِنْ اللَّيْلِ ثَمَانَ رَكَعَاتٍ وَيُوتِرُ بِالتَّاسِعَةِ وَيُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Khalanji] dia berkata; telah menceritakan kepada kami [Abu Sa'id] -budak bani Hasyim- dia berkata; telah menceritakan kepada kami [Hushain bin Nafi'] dia berkata; telah menceritakan kepada kami [Al Hasan] dari [Sa'ad bin Hisyam] bahwa dia pernah datang kepada [Aisyah], lalu bertanya kepadanya tentang cara shalat Rasulullah shallallahu 'alaihi wasallam, maka ia (Aisyah) menjawab; \"Beliau shalat delapan rakaat pada malam hari, lalu witir dengan rakaat yang kesembilan, dan shalat lagi dua rakaat sambil duduk.\""},"1674":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ الْأَعْمَشِ أُرَاهُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ تِسْعَ رَكَعَاتٍ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abul Ahwash] dari [Al A'masy] aku mengiranya dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat pada malam hari sembilan rakaat.\""},"1675":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ إِحْدَى عَشْرَةَ رَكْعَةً وَيُوتِرُ مِنْهَا بِوَاحِدَةٍ ثُمَّ يَضْطَجِعُ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat pada malam hari sebelas rakaat dan shalat witir satu rakaat di antara sebelas rakaat tersebut, kemudian berbaring ke sebelah kanan."},"1676":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثَ عَشْرَةَ رَكْعَةً فَلَمَّا كَبِرَ وَضَعُفَ أَوْتَرَ بِتِسْعٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari ['Amr bin Murrah] dari [Yahya bin Al Jazzar] dari [Ummu Salamah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat witir tiga belas rakaat, dan setelah tua dan lemah beliau shalat witir sembilan rakaat.\""},"1677":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي مِجْلَزٍ أَنَّ أَبَا مُوسَىكَانَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَصَلَّى الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ قَامَ فَصَلَّى رَكْعَةً أَوْتَرَ بِهَا فَقَرَأَ فِيهَا بِمِائَةِ آيَةٍ مِنْ النِّسَاءِ ثُمَّ قَالَ مَا أَلَوْتُ أَنْ أَضَعَ قَدَمَيَّ حَيْثُ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدَمَيْهِ وَأَنَا أَقْرَأُ بِمَا قَرَأَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Abu An Nu'man] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim Al Ahwal] dari [Abu Mijlaz] bahwasanya [Abu Musa] pernah berada di antara Makkah dan Madinah, dia shalat Isya' dua rakaat, kemudian berdiri, lalu shalat satu rakaat sebagai witir dengan membaca seratus ayat dari surah An-Nisaa'. Kemudian dia berkata: \"Aku tidak menyia-nyiakan untuk menapakkan telapak kakiku dimana Rasulullah shallallahu 'alaihi wasallam menapakkan telapak kakinya, dan aku membaca sebagaimana Rasulullah shallallahu 'alaihi wasallam membacanya.\""},"1678":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ بْنِ إِشْكَابَ النَّسَائِيُّ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ قَالَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا سَلَّمَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Husain bin Ibrahim bin Isykab An Nasa'i] dia berkata; telah memberitakan kepada kami [Muhammad bin Abu 'Ubaidah] dia berkata; [bapakku] telah menceritakan kepada kami dari [Al A'masy] dari [Thalhah] dari [Dzarr] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dari [Ubay bin Ka'ab] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al lkhlas dalam shalat witir. Jika telah salam maka beliau membaca: 'Subhaanal malikil qudduus' tiga kali'.\""},"1679":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الْأَعْمَشِ عَنْ زُبَيْدٍ وَطَلْحَةَ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌخَالَفَهُمَا حُصَيْنٌ فَرَوَاهُ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Yahya bin Musa] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Sa'd] dari telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Al A'masy] dari [Zubaid] dan [Thalhah] dari [Dzarr] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dari [Ubay bin Ka'b] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa. surah Al Kaafiruun, dan surah Al Ikhlaash.\" Hushain menyelisihi kedua Hadist di atas, dia meriwayatkan dari Abu Dzar dari Abdurrahman bin Abza dari Bapaknya dari Nabi shallallahu 'alaihi wasallam."},"1680":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ عَنْ حُصَيْنِ بْنِ نُمَيْرٍ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dari [Hushain bin Numair] dari [Hushain bin 'Abdurrahman] dari [Dzarr] dari [Ibnu 'Abdurrahman bin Abza] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlaash dalam shalat Witir."},"1681":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ وَزُبَيْدٍ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَكَانَ يَقُولُ إِذَا سَلَّمَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا وَيَرْفَعُ صَوْتَهُ بِالثَّالِثَةِ","id":"Telah mengabarkan kepada kami ['Amr bin Yazid] dia berkata; telah menceritakan kepada kami [Bahz bin Asad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Salamah] dan [Zubaid] dari [Dzarr] dari [Ibnu 'Abdurrahman bin Abza] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlas. Jika beliau telah mengucapkan salam, maka beliau membaca doa, \"Subhaanal malikil qudduus\" tiga kali, dan mengeraskan suaranya pada yang ketiga kalinya."},"1682":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي سَلَمَةُ وَزُبَيْدٌ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ عَبْدِ الرَّحْمَنِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ ثُمَّ يَقُولُ إِذَا سَلَّمَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ وَيَرْفَعُ بِسُبْحَانَ الْمَلِكِ الْقُدُّوسِ صَوْتَهُ بِالثَّالِثَةِرَوَاهُ مَنْصُورٌ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ وَلَمْ يَذْكُرْ ذَرًّا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Salamah] dan [Zubaid] dari [Dzarr] dari [Ibnu 'Abdurrahman bin Abza] dari ['Abdurrahman] bahwa Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlaash. Jika beliau telah mengucapkan salam maka beliau membaca, \"Subhaanal malikil qudduus\" dan mengeraskan suaranya saat membaca \"Subhaanal malikil qudduus\" yang ketiga kalinya. Manshur telah meriwayatkannya dari Salamah bin Kuhail dan dia tidak menyebutkan Dzar."},"1683":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَكَانَ إِذَا سَلَّمَ وَفَرَغَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا طَوَّلَ فِي الثَّالِثَةِوَرَوَاهُ عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ زُبَيْدٍ وَلَمْ يَذْكُرْ ذَرًّا","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Salamah bin Kuhail] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah AI A'laa, surah Al Kaafiruun, dan surah Al lkhlas. Jika beliau telah mengucapkan salam dan selesai maka beliau membaca: \"Subhaanal malikil qudduus\" tiga kali, dan memanjangkan suaranya pada yang ketiga kalinya. Abdul Malik bin Abu Sulaiman telah meriwayatkannya dari Zubaid, dan dia tidak menyebutkan Dzar."},"1684":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌوَرَوَاهُ مُحَمَّدُ بْنُ جُحَادَةَ عَنْ زُبَيْدٍ وَلَمْ يَذْكُرْ ذَرًّا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ubaid] dia berkata; telah menceritakan kepada kami ['Abdul Malik bin Abu Sulaiman] dari [Zubaid] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlas. Muhammad bin Juhadah telah meriwatkannya dari Zubaid, dan dia tidak menyebutkan Dzar."},"1685":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ زُبَيْدٍ عَنْ ابْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا فَرَغَ مِنْ الصَّلَاةِ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dia berkata; telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Zubaid] dari [Ibnu Abza] dari [bapaknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah AI A'laa, surah Al Kaafiruun, dan surah Al Ikhlas. Setelah selesai beliau membaca, 'Subhanaal malikil quddus' tiga kali.\""},"1686":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ حَرْبٍ عَنْ مَالِكٍ عَنْ زُبَيْدٍ عَنْ ابْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌأَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكٌ عَنْ زُبَيْدٍ عَنْ ذَرٍّ عَنْ ابْنِ أَبْزَى مُرْسَلٌ وَقَدْ رَوَاهُ عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin 'Ubaidullah] dia berkata; telah menceritakan kepada kami [Syu'aib bin Harb] dari [Malik] dari [Zubaid] dari [Ibnu Abza] dari [bapaknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam dalam shalat witir membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al lkhlaash.\" Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Malik] dari [Zubaid] dari [Dzar] dari [Ibnu Abza] secara mursal. Dan telah meriwayatkan pula Atha bin As Saib dari Sa'id bin Abdurrahman bin Abza dari Bapaknya."},"1687":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا رَوْحُ بْنُ الْقَاسِمِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Ash Shabbah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Habib] dia berkata; telah menceritakan kepada kami [Rauh bin Al Qasim] dari ['Atha bin As Saib] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam dalam shalat witir membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlaash."},"1688":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ عَزْرَةَ يُحَدِّثُ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا فَرَغَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; Aku mendengar ['Azrah] menceritakan dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlaash. Setelah selesai beliau membaca, \"Suhhaanal malikil qudduus\" tiga kali.\""},"1689":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَىعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا فَرَغَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا وَيَمُدُّ فِي الثَّالِثَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah] dari ['Abdurrahman bin Abza], dari Rasulullah shallallahu 'alaihi wasallam, beliau shalat witir dengan membaca surah AI A'laa, surah Al Kaafiruun dan surah Al Ikhlas. Setelah selesai beliau membaca, \"Subhanal malikil yudduus\" tiga kali, dan beliau memanjangkannya pada yang ketiga."},"1690":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ زُرَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَىخَالَفَهُمَا شَبَابَةُ فَرَوَاهُ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Qatadah] menceritakan dari [Zurarah] dari ['Abdurrahman bin Abza], bahwa Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa. Syababah menyelisih kedua Hadits diatas, dia meriwayatkan dari Qatadah dari Zurarah bin Aufa dari 'Imran bin Hushain."},"1691":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا شَبَابَةُ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْتَرَ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَىقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا تَابَعَ شَبَابَةَ عَلَى هَذَا الْحَدِيثِ خَالَفَهُ يَحْيَى بْنُ سَعِيدٍ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; telah menceritakan kepada kami [Syababah] dari [Syu'bah] dari [Qatadah] dari [Zurarah bin Aufa] dari ['Imran bin Hushain] bahwasanya Nabi shallallahu 'alaihi wasallam shalat witir dengan Sabbihis Marabbikal A'la, Abu Abdurrahman berkata aku tidak mengetahui seorang pun yang mengikuti Syababah pada hadits ini, Yahya bin Said menyelisihinya."},"1692":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَرَأَ رَجُلٌ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فَلَمَّا صَلَّى قَالَ مَنْ قَرَأَ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى قَالَ رَجُلٌ أَنَا قَالَ قَدْ عَلِمْتُ أَنَّ بَعْضَهُمْ خَالَجَنِيهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Zurarah] dari ['Imran bin Hushain] dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam shalat Zhuhur, ada seorang lelaki yang membaca surah Al A'laa. Setelah selesai shalat, Rasulullah shallallahu 'alaihi wasallam bertanya: `Siapa tadi yang membaca surah AI A'laa? ' Seseorang menjawab; `Aku'. Lalu beliau shallallahu 'alaihi wasallam bersabda: 'Aku sudah tahu bahwa sebagian mereka telah menyelisihiku dengan bacaannya'.\""},"1693":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدٍ عَنْ أَبِي الْحَوْرَاءِ قَالَ قَالَ الْحَسَنُعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي الْوِتْرِ فِي الْقُنُوتِ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ إِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Buraid] dari [Abul Haura'] dia berkata; [Al Hasan] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajarkan kepadaku beberapa kalimat yang harus aku ucapkan dalam shalat witir ketika berdoa, yaitu doa qunut: 'Ya Allah, berilah aku petunjuk sebagaimana orang-orang yang Engkau beri petunjuk. Berilah aku kesehatan sebagaimana orang-orang yang telah Engkau beri kesehatan. Sayangilah aku sebagaimana orang-orang yang Engkau sayangi. Berilah berkah apa yang Engkau berikan kepadaku. Jagalah aku dari kejahatan yang telah Engkau tetapkan..Sesungguhnya Engkaulah yang menetapkan (memberi hukuman), dan tidak ada yang menetapkan kepada-Mu. Sesungguhnya tidak akan hina orang yang Engkau bela. Maha Suci Rabb kami dan Maha Tinggi Engkau'.\""},"1694":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ سَالِمٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيٍّ عَنْ الْحَسَنِ بْنِ عَلِيٍّ قَالَعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَؤُلَاءِ الْكَلِمَاتِ فِي الْوِتْرِ قَالَ قُلْ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ فَإِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَ وَصَلَّى اللَّهُ عَلَى النَّبِيِّ مُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yahya bin 'Abdullah bin Salim] dari [Musa bin 'Uqbah] dari ['Abdullah bin 'Ali] dari [Al Hasan bin 'Ali] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajarkan kepadaku beberapa kalimat dalam shalat witir ketika berdoa, yaitu: 'Ya Allah, berilah aku petunjuk sebagaimana orang-orang yang Engkau beri petunjuk. Berilah berkah apa yang Engkau berikan kepadaku. Sayangilah aku sebagaimana orang-orang yang Engkau sayangi. Jagalah aku dari kejahatan yang telah Engkau tetapkan.. Sesungguhnya Engkaulah yang menetapkan (memberi hukuman), dan tidak ada yang menetapkan kepada-Mu. Sesungguhnya tidak akan hina orang yang Engkau bela. Maha Suci Rabb kami dan Maha Tinggi Engkau'. Dan shalawat Allah senantiasa tercurah atas Nabi shallallahu 'alaihi wasallam.\""},"1695":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَهِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عَمْرٍو الْفَزَارِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي آخِرِ وِتْرِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَبِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Sulaiman bin Harb] dan [Hisyam bin 'Abdul Malik] mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Amr Al Fazari] dari ['Abdurrahman bin Al Harits bin Hisyam] dari ['Ali bin Abu Thalib] bahwa Nabi shallallahu 'alaihi wasallam pada akhir shalat witir mengucapkan: \"Ya Allah, Aku berlindung kepada-Mu dengan keridlaan-Mu dari kemurkaan-Mu, dengan maaf-Mu dari siksa-Mu, dan aku berlindung dengan-Mu dari-Mu. Aku tidak bisa menghitung pujian kepada-Mu sebagaimana Engkau telah memuji diri-Mu sendiri.\""},"1696":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ دُعَائِهِ إِلَّا فِي الِاسْتِسْقَاءِقَالَ شُعْبَةُ فَقُلْتُ لِثَابِتٍ أَنْتَ سَمِعْتَهُ مِنْ أَنَسٍ قَالَ سُبْحَانَ اللَّهِ قُلْتُ سَمِعْتَهُ قَالَ سُبْحَانَ اللَّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Syu'bah] dari [Tsabit Al Banani] dari [Anas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak mengangkat kedua tangannya sedikitpun dalam berdoa, kecuali ketika Shalat Istiqa'.\" Syu'bah berkata; \"Aku berkata kepada Tsabit, 'Apakah engkau mendengarnya dari Anas\" la menjawab, `Subhanallah'. Aku ulangi lagi, `Engkau mendengar darinya? ' la menjawab, 'Subhanallah'.\""},"1697":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِحْدَى عَشْرَةَ رَكْعَةً فِيمَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ إِلَى الْفَجْرِ بِاللَّيْلِ سِوَى رَكْعَتَيْ الْفَجْرِ وَيَسْجُدُ قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; telah menceritakan kepada kami [Laits] dia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sebelas rakaat antara selesai shalat Isya' sampai dengan waktu shalat Fajar, selain dua rakaar sebelum fajar. Beliau juga shalat witir satu rakaat, dan sujud yang lamanya seukuran dengan salah seorang dari kalian membaca lima puluh ayat.\""},"1698":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَيَقُولُ بَعْدَ مَا يُسَلِّمُ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ يَرْفَعُ بِهَا صَوْتَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; telah menceritakan kepada kami [Qasim] dari [Sufyan] dari [Zubaid] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau mengerjakan shalat witir dengan membaca surah Al A'laa, surah AI Kaafiruun dan surah AI lkhlas. Setelah salam beliau membaca: \"Subhanal malikil qudduus\" tiga kali dengan suara yang keras."},"1699":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ سُفْيَانَ الثَّوْرِيِّ وَعَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ زُبَيْدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَيَقُولُ بَعْدَ مَا يُسَلِّمُ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ يَرْفَعُ بِهَا صَوْتَهُخَالَفَهُمَا أَبُو نُعَيْمٍ فَرَوَاهُ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ ذَرٍّ عَنْ سَعِيدٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Sufyan Ats Tsauri] dan ['Abdul Malik bin Abu Sulaiman] dari [Zubaid] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlas. Setelah selesai salam beliau membaca: `Subhanal Malikil qudduus\" tiga kali dengan mengeraskan suaranya.\" Abu Nu'aim menyelisihi kedua Hadist di atas, dia meriwayatkan dari Sufyan dari Zubaid dari Dzar dari Sa'id"},"1700":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ أَبِي نُعَيْمٍ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا أَرَادَ أَنْ يَنْصَرِفَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا يَرْفَعُ بِهَا صَوْتَهُقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو نُعَيْمٍ أَثْبَتُ عِنْدَنَا مِنْ مُحَمَّدِ بْنِ عُبَيْدٍ وَمِنْ قَاسِمِ بْنِ يَزِيدَ وَأَثْبَتُ أَصْحَابِ سُفْيَانَ عِنْدَنَا وَاللَّهُ أَعْلَمُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ ثُمَّ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ ثُمَّ وَكِيعُ بْنُ الْجَرَّاحِ ثُمَّ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ثُمَّ أَبُو نُعَيْمٍ ثُمَّ الْأَسْوَدُ فِي هَذَا الْحَدِيثِ وَرَوَاهُ جَرِيرُ بْنُ حَازِمٍ عَنْ زُبَيْدٍ فَقَالَ يَمُدُّ صَوْتَهُ فِي الثَّالِثَةِ وَيَرْفَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dari [Abu Nu'aim] dari [Sufyan] dari [Zubaid] dari [Dzarr] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al Ikhlas. Apabila beliau hendak beranjak maka beliau membaca: 'Subhaanal Malikil Quddus' tiga kali dengan mengeraskan suaranya. Abu Abdurrahman berkata; 'Menurut kami Abu Nu? im lebih tsiqah dari pada Muhammad bin Ubaid dan Qasim bin Yazid. sedangkan sahabat-sahabat Sufyan yang menurut kami lebih kuat mengenai Hadits ini adalah, Yahya bin Sa'id Al Qattan, Abdullah bin Al Mubaarak, Waki'bin Al Jarrah, Abdurrahman bin Mahdi, Abu Nu'aim, kemudian Al Aswad Wallahu A'lam. Dan telah meriwayatkan pula Jarir bin Hazim dari Zubaid dia berkata; 'Beliau memanjangkan dan mengeraskan suaranya pada yang ketiga kali.'"},"1701":{"ar":"أَخْبَرَنَا حَرَمِيُّ بْنُ يُونُسَ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا جَرِيرٌ قَالَ سَمِعْتُ زُبَيْدًا يُحَدِّثُ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِ��ُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَإِذَا سَلَّمَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ يَمُدُّ صَوْتَهُ فِي الثَّالِثَةِ ثُمَّ يَرْفَعُ","id":"Telah mengabarkan kepada kami [Harami bin Yunus bin Muhammad] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Jarir] dia berkata; aku mendengar [Zubaid] menceritakan dari [Dzarr] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah Al Kaafiruun, dan surah Al lkhlas. Setelah salam beliau membaca: `Subhanal malikil qudduus\" tiga kali, dan pada yang ketiga kalinya beliau memanjangkan dan mengeraskan suaranya.\""},"1702":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا فَرَغَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِأَرْسَلَهُ هِشَامٌ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ أَبِي عَامِرٍ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdush Shamad] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari ['Azrah] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca surah Al A'laa, surah AI Kaafiruun, dan surah Al lkhlas. Setelah selesai beliau membaca, \"Subhanal Malikil Qudduus.\" Hisyam telah memursalkan Hadits ini, telah mengabarkan kepada kami [Muhammad bin Ismail bin Ibrahim] dari [Abu Amir] dari [Hisyam] dari [Qatadah] dari [? zrah] dari [Sa'id bin Abdurrahman bin Abza] bahwa Nabi shallallahu 'alaihi wasallam shalat witir dan seterusnya sebagaimana Hadits diatas."},"1703":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ الْمُبَارَكِ الصُّورِيَّ قَالَ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ فَقَالَتْ كَانَ يُصَلِّي ثَلَاثَ عَشْرَةَ رَكْعَةً تِسْعَ رَكَعَاتٍ قَائِمًا يُوتِرُ فِيهَا وَرَكْعَتَيْنِ جَالِسًا فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَرَكَعَ وَسَجَدَ وَيَفْعَلُ ذَلِكَ بَعْدَ الْوِتْرِ فَإِذَا سَمِعَ نِدَاءَ الصُّبْحِ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Fadhalah bin Ibrahim] dia berkata; telah menceritakan kepada kami [Muhammad bin Al Mubarak Ash Shuri] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] bahwasanya ia bertanya kepada ['Aisyah] tentang shalat Rasulullah shallallahu 'alaihi wasallam pada malam hari, lalu Aisyah menjawab; \"Beliau shalat tiga belas rakaat, sembilan rakaat dengan berdiri, termasuk witir di dalamnya, lalu dua rakaat sambil duduk. Bila hendak ruku' maka beliau berdiri, lalu ruku' dan sujud. Hal tersebut dilakukan setelah witir. Jika sudah mendengar adzan Subuh maka beliau berdiri lalu shalat dua rakaat yang ringan.\""},"1704":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَدَعُ أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِخَالَفَهُ عَامَّةُ أَصْحَابِ شُعْبَةَ مِمَّنْ رَوَى هَذَا الْحَدِيثَ فَلَمْ يَذْكُرُوا مَسْرُوقًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Utsman bin 'Umar] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhammad] dari [bapaknya] dari [Masruq] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan shalat empat rakaat sebelum Zhuhur dan dua rakaat sebelum Fajar. Kebanyakan para pengikut Syu'bah menyelisihi riwayat Hadits ini, mereka tidak menyebutkan Masruq."},"1705":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ أَنَّهُ سَمِعَ أَبَاهُ يُحَدِّثُ أَنَّهُ سَمِعَ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدَعُ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ قَبْلَ الصُّبْحِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ عِنْدَنَا وَحَدِيثُ عُثْمَانَ بْنِ عُمَرَ خَطَأٌ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepadaku [Ahmad bin 'Abdullah bin Al Hakam] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhammad] ia mendengar [bapaknya] bercerita, bahwa ia mendengar ['Aisyah] berkata; bahwa Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan shalat empat rakaat sebelum Zhuhur dan dua rakaat sebelum subuh. Abu Abdurrahman berkata; 'Menurut kami Hadits ini lebih shahih. Sedangkan Hadits Utsman bin Umar adalah salah. Wallahu Ta'ala A'lam."},"1706":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَكْعَتَا الْفَجْرِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dia berkata; telah menceritakan kepada kami ['Abdah] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dia berkata; dari Nabi shallallahu 'alaihi wasallam, beliau shallallahu 'alaihi wasallam bersabda: \"Shalat Fajar dua rakaat lebih baik daripada dunia dan seisinya.\""},"1707":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا نُودِيَ لِصَلَاةِ الصُّبْحِ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ يَقُومَ إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] dari Rasulullah shallallahu 'alaihi wasallam bahwa apabila adzan shalat Subuh telah dikumandangkan, maka beliau shalat dua rakaat yang ringan, sebelum berdiri untuk shalat Subuh."},"1708":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَمْرٌو عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَ أَخْبَرَتْنِي حَفْصَةُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَضَاءَ لَهُ الْفَجْرُ صَلَّى رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami ['Amr] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dia berkata; telah mengabarkan kepadaku [Hafshah], \"Bahwa apabila Fajar telah meneranginya, maka Nabi shallallahu 'alaihi wasallam shalat dua rakaat.\""},"1709":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكَتَ الْمُؤَذِّنُ بِالْأُولَى مِنْ صَلَاةِ الْفَجْرِ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ بَعْدَ أَنْ يَتَبَيَّنَ الْفَجْرُ ثُمَّ يَضْطَجِعُ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami ['Ali bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah] dari ['Aisyah] dia berkata; \"Bila muadzin telah diam pada adzan yang pertama untuk shalat Fajar, maka beliau berdiri untuk Shalat dua rakaat yang ringan sebelum shalat Fajar setelah Fajar nampak jelas, kemudian berbaring pada bagian kanannya.\""},"1710":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُنْ مِثْلَ فُلَانٍ كَانَ يَقُومُ اللَّيْلَ فَتَرَكَ قِيَامَ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari ['Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Janganlah engkau menjadi seperti fulan, ia bangun pada malam hari, namun ia tidak melakukan shalat malam.\""},"1711":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ قَالَ حَدَّثَنِي الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عُمَرَ بْنِ الْحَكَمِ بْنِ ثَوْبَانَ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُنْ يَا عَبْدَ اللَّهِ مِثْلَ فُلَانٍ كَانَ يَقُومُ اللَّيْلَ فَتَرَكَ قِيَامَ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Al Harits bin Asad] dia berkata; telah menceritakan kepada kami [Bisyr bin Bakr] dia berkata; telah menceritakan kepadaku [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dari ['Umar bin Al Hakam bin Tsauban] dia berkata; telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] dari ['Abdullah bin 'Amru] dia berkata; 'Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: 'Janganlah kamu seperti si Fulan yang bangun malam, tetapi ia tidak mengerjakan shalat malam', \""},"1712":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْبَصْرِيُّ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ قَرَأْتُ عَلَى عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ نَافِعٍ عَنْ صَفِيَّةَ عَنْ حَفْصَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي رَكْعَتَيْ الْفَجْرِ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim Al Bashri] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; Aku membacakan kepada ['Abdul Hamid bin Ja'far] dari [Nafi'] dari [Shafiyyah] dari [Hafshah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau mengerjakan shalat Fajar dua rakaat yang ringan."},"1713":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا يَحْيَى قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكَعُ بَيْنَ النِّدَاءِ وَالصَّلَاةِ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat yang ringan diantara adzan dan shalat.\""},"1714":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ حَمْزَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ هُوَ وَنَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَيْنَ النِّدَاءِ وَالْإِقَامَةِ رَكْعَتَيْنِ خَفِيفَتَيْنِ رَكْعَتَيْ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dia berkata; telah menceritakan kepada kami [Yahya bin Hamzah] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Salamah] dia berkata; dia dan [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat yang ringan diantara adzan dan shalat, yakni shalat Fajar dua rakaat."},"1715":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ قَالَ إِسْمَعِيلُ حَدَّثَنَا عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَ أَخْبَرَتْنِي حَفْصَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الصُّبْحِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Yahya bin Muhammad] dia berkata; telah menceritakan kepada kami [Muhammad bin Jahdham], dia berkata; [Isma'il] telah menceritakan kepada kami dari ['Umar bin Nafi'] dari [bapaknya] dari [Ibnu 'Umar] dia berkata; [Hafshah] mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat sebelum Subuh."},"1716":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ أَنْبَأَنَا إِسْحَقُ بْنُ الْفُرَاتِ عَنْ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ أَنَّهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا نُودِيَ لِصَلَاةِ الصُّبْحِ سَجَدَ سَجْدَتَيْنِ قَبْلَ صَلَاةِ الصُّبْحِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dia berkata; telah memberitakan kepada kami [Ishaq bin Al Furat] dari [Yahya bin Ayyub] dia berkata; telah menceritakan kepadaku [Yahya bin Sa'id] dia berkata; telah memberitakan kepada kami [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] bahwa ia mengabarkan kepadanya, apabila Rasulullah shallallahu 'alaihi wasallam (mendengar) seruan untuk shalat Subuh maka beliau sujud dua kali (shalat dua rakaat) sebelum shalat Subuh."},"1717":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ إِسْحَقَ عَنْ أَبِي عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَكَتَ الْمُؤَذِّنُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami ['Abdullah bin Ishaq] dari [Abu 'Ashim] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafshah Ummul Mu'minin] ia mengabarkan kepadanya bahwa apabila muadzin telah diam (selesai adzan) maka beliau shalat dua rakaat yang ringan."},"1718":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَ حَدَّثَتْنِي أُخْتِي حَفْصَةُأَنَّهُ كَانَ يُصَلِّي قَبْلَ الْفَجْرِ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari ['Abdullah] dia berkata; telah menceritakan kepadaku saudara perempuanku [Hafshah] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat ringan sebelum Fajar."},"1719":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي رَكْعَتَيْنِ إِذَا طَلَعَ الْفَجْرُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Juwairiyah bin Asma] dari [Nafi'] dari ['Abdullah bin 'Umar] dari [Hafshah] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat ringan jika fajar telah terbit."},"1720":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا نُودِيَ لِصَلَاةِ الصُّبْحِ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ يَقُومَ إِلَى الصَّلَاةِوَرَوَى سَالِمٌ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa jika adzan shalat Subuh telah dikumandangkan maka beliau mengerjakan shalat dua rakaat ringan sebelum berdiri untuk shalat. Dan telah meriwayatkan pula Salim dari Ibnu Umar dari Hafshah."},"1721":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ قَالَ ابْنُ عُمَرَ أَخْبَرَتْنِي حَفْصَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْكَعُ رَكْعَتَيْنِ قَبْلَ الْفَجْرِ وَذَلِكَ بَعْدَ مَا يَطْلُعُ الْفَجْرُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim]; [Ibnu 'Umar] berkata; telah mengabarkan kepadaku [Hafshah] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat sebelum shalat fajar (subuh). Hal itu dilakukan setelah terbit fajar."},"1722":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ رَجُلٍ عِنْدَهُ رِضًى أَخْبَرَهُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ امْرِئٍ تَكُونُ لَهُ صَلَاةٌ بِلَيْلٍ فَغَلَبَهُ عَلَيْهَا نَوْمٌ إِلَّا كَتَبَ اللَّهُ لَهُ أَجْرَ صَلَاتِهِ وَكَانَ نَوْمُهُ صَدَقَةً عَلَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Muhammad bin Al Munkadir] dari [Sa'id bin Jubair] dari [seseorang yang lapang hatinya], dia mengabarkan kepadanya dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang biasa shalat malam lalu ia dikalahkan oleh tidurnya melainkan Allah akan menuliskan pahala shalatnya, dan tidurnya merupakan sedekah baginya.\""},"1723":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ صَلَاةٌ صَلَّاهَا مِنْ اللَّيْلِ فَنَامَ عَنْهَا كَانَ ذَلِكَ صَدَقَةً تَصَدَّقَ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِ وَكَتَبَ لَهُ أَجْرَ صَلَاتِهِأَخْبَرَنَا أَحْمَدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو جَعْفَرٍ الرَّازِيُّ لَيْسَ بِالْقَوِيِّ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Muhammad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Muhammad bin Al Munkadir] dari [Sa'id bin Jubair] dari [Al Aswad bin Yazid] dari ['Aisyah] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa biasa mengerjakan shalat malam, lalu ia tertidur (tidak sempat shalat), maka tidurnya tersebut merupakan sedekah yang Allah Azza wa Jalla sedekahkan kepadanya, dan Allah menuliskan pahala baginya.\" Telah mengabarkan [Ahmad bin Nashr] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Bukair] dia berkata; Telah menceritakan kepada kami [Abu Ja'far Ar Raazi] dari [Muhammad bin Al Munkadir] dari [Sa'id bin Jubair] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, -kemudian dia menyebutkan Hadits di atas-. Abu Abdurrahman berkata; Abu Ja'far Ar Raazi, orangnya lemah."},"1724":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ أَبِي الدَّرْدَاءِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى فِرَاشَهُ وَهُوَ يَنْوِي أَنْ يَقُومَ يُصَلِّي مِنْ اللَّيْلِ فَغَلَبَتْهُ عَيْنَاهُ حَتَّى أَصْبَحَ كُتِبَ لَهُ مَا نَوَى وَكَانَ نَوْمُهُ صَدَقَةً عَلَيْهِ مِنْ رَبِّهِ عَزَّ وَجَلَّخَالَفَهُ سُفْيَانُ أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَبْدَةَ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ عَنْ أَبِي ذَرٍّ وَأَبِي الدَّرْدَاءِ مَوْقُوفًا","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] dari [Sulaiman] dari [Habib bin Abu Tsabit] dari ['Abdah bin Abu Lubabah] dari [Suwaid bin Ghafalah] dari [Abu Ad Darda'] yang sampai kepada Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang hendak tidur dan ia berniat untuk shalat malam, lalu ia tertidur hingga datang waktu subuh maka ia mendapat pahala apa yang ia niatkan, dan tidurnya adalah sedekah baginya dari Allah Azza wa Jalla.\" Sufyan menyelisihinya. Telah mengabarkan kepada kami [Suwaid bin Nasr] ia berkata; Telah menceritakan kepada kami [Abdullah] ia berkata; dari [Sufyan Attsauri] dari [Abdah] ia berkata, Aku mendengar [Suwaid bin Ghaflah] dari [Abu Dzar] dan [Abu Darda'] secara mauquf."},"1725":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا لَمْ يُصَلِّ مِنْ اللَّيْلِ مَنَعَهُ مِنْ ذَلِكَ نَوْمٌ أَوْ وَجَعٌ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah] dari [Sa'ad bin Hisyam] dari ['Aisyah] bahwa apabila Rasulullah shallallahu 'alaihi wasallam tidak mengerjakan shalat malam karena tertidur atau sakit, maka beliau shallallahu 'alaihi wasallam shalat dua belas rakaat pada siang harinya."},"1726":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو صَفْوَانَ عَبْدُ ال��َّهِ بْنُ سَعِيدِ بْنِ عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ وَعُبَيْدَ اللَّهِ أَخْبَرَاهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ عَنْ شَيْءٍ مِنْهُ فَقَرَأَهُ فِيمَا بَيْنَ صَلَاةِ الْفَجْرِ وَصَلَاةِ الظُّهْرِ كُتِبَ لَهُ كَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu Shafwan 'Abdullah bin Sa'id bin 'Abdul Malik bin Marwan] dari [Yunus] dari [Ibnu Syihab] bahwasanya [As Saib bin Yazid] dan ['Ubaidullah] mengabarkan kepadanya, dari ['Abdurrahman bin 'Abdul Qari] berkata; Aku mendengar ['Umar bin Al Khaththab] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tertidur dari shalat sunnah malam, lalu ia mengqadhanya diantara waktu shalat Fajar dan shalat Zhuhur, maka dituliskan baginya pahala seolah-olah ia mengerjakannya pada malam hari tersebut'.\""},"1727":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ قَالَ جُزْئِهِ مِنْ اللَّيْلِ فَقَرَأَهُ فِيمَا بَيْنَ صَلَاةِ الصُّبْحِ إِلَى صَلَاةِ الظُّهْرِ فَكَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abdurrahman bin 'Abdul Qari] bahwasanya ['Umar bin Al Khaththab] berkata; \"Barangsiapa tertidur dari shalat sunnah malam, lalu ia mengqadlanya diantara waktu shalat Fajar dan shalat Zhuhur, maka seolah-olah ia mengerjakannya pada malam hari tersebut'.\""},"1728":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ الْأَعْرَجِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَمَنْ فَاتَهُ حِزْبُهُ مِنْ اللَّيْلِ فَقَرَأَهُ حِينَ تَزُولُ الشَّمْسُ إِلَى صَلَاةِ الظُّهْرِ فَإِنَّهُ لَمْ يَفُتْهُ أَوْ كَأَنَّهُ أَدْرَكَهُرَوَاهُ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ مَوْقُوفًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Dawud bin Al Hushain] dari [Al A'raj] dari ['Abdurrahman bin 'Abdul Qari] bahwasanya ['Umar bin Al Khaththab] berkata; dia berkata; \"Barangsiapa kehilangan kesempatan pada malam hari, lalu ia mengqadlanya ketika matahari tergelincir sampai shalat Zhuhur, maka ia tidak kehilangannya atau seolah-olah ia mendapatkannya.\" Abdurrahman bin Auf telah meriwayatkannya secara mauquf."},"1729":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَمَنْ فَاتَهُ وِرْدُهُ مِنْ اللَّيْلِ فَلْيَقْرَأْهُ فِي صَلَاةٍ قَبْلَ الظُّهْرِ فَإِنَّهَا تَعْدِلُ صَلَاةَ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Syu'bah] dari [Sa'd bin Ibrahim] dari [Humaid bin 'Abdurrahman] dia berkata; \"Barangsiapa kehilangan kesempatan shalat pada malam hari maka hendaklah ia mengerjakannya sebelum Zhuhur, itu menyamai shalat malam.\""},"1730":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُغِيرَةُ بْنُ زِيَادٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ثَابَرَ عَلَى اثْنَتَيْ عَشْرَةَ رَكْعَةً فِي الْيَوْمِ وَاللَّيْلَةِ دَخَلَ الْجَنَّةَ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur bin Ja'far An Naisaburi] dia berkata; telah menceritakan kepada kami [Ishaq bin Sulaiman] dia berkata; telah menceritakan kepada kami [Mughirah bin Ziyad] dari ['Atha] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat dua belas rakaat secara kontinyu pada malam dan siang, maka dia akan masuk surga. Empat rakaat sebelum Zhuhur dan dua rakaat sesudahnya, dua rakaat setelah Maghrib dan dua rakaat setelah Isya, serta dua rakaat sebelum Fajar.\""},"1731":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا أَبُو يَحْيَى إِسْحَقُ بْنُ سُلَيْمَانَ الرَّازِيُّ عَنْ الْمُغِيرَةِ بْنِ زِيَادٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ثَابَرَ عَلَى اثْنَتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ عَزَّ وَجَلَّ لَهُ بَيْتًا فِي الْجَنَّةِ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya] dia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] dia berkata; telah menceritakan kepada kami [Abu Yahya Ishaq bin Sulaiman Ar Razi] dari [Al Mughirah bin Ziyad] dari ['Atha bin Abu Rabah] dari ['Aisyah Radliallahu? nha] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat dua belas rakaat secara kontinyu, maka Allah Azza wa Jalla akan membangunkan rumah untuknya di dalam surga. Empat rakaat sebelum Zhuhur dan dua rakaat sesudah Zhuhur, dua rakaat setelah Maghrib dan dua rakaat setelah Isya, serta dua rakaat sebelum Fajar.'"},"1732":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا مَعْقِلٌ عَنْ عَطَاءٍ قَالَ أُخْبِرْتُ أَنَّ أُمَّ حَبِيبَةَ بِنْتَ أَبِي سُفْيَانَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَكَعَ ثِنْتَيْ عَشْرَةَ رَكْعَةً فِي يَوْمِهِ وَلَيْلَتِهِ سِوَى الْمَكْتُوبَةِ بَنَى اللَّهُ لَهُ بِهَا بَيْتًا فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dah bin 'Isa] dia berkata; telah menceritakan kepada kami [Al Hasan bin A'yan] dia berkata; telah menceritakan kepada kami [Ma'qil] dari ['Atha] dia berkata; Aku diberi kabar bahwasanya [Ummu Habibah bintu Abu Sufyan] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa mengerjakan dua belas rakaat pada siang dan malamnya selain shalat wajib, Allah membangunkan baginya sebuah rumah di surga'.\""},"1733":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ قُلْتُ لِعَطَاءٍبَلَغَنِي أَنَّكَ تَرْكَعُ قَبْلَ الْجُمُعَةِ اثْنَتَيْ عَشْرَةَ رَكْعَةً مَا بَلَغَكَ فِي ذَلِكَ قَالَ أُخْبِرْتُ أَنَّ أُمَّ حَبِيبَةَ حَدَّثَتْ عَنْبَسَةَ بْنَ أَبِي سُفْيَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَكَعَ اثْنَتَيْ عَشْرَةَ رَكْعَةً فِي الْيَوْمِ وَاللَّيْلَةِ سِوَى الْمَكْتُوبَةِ بَنَى اللَّهُ عَزَّ وَجَلَّ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; [Ibnu Juraij] berkata; \"Aku berkata kepada [Atha'], 'Telah sampai kepadaku bahwa engkau shalat dua belas rakaat sebelum shalat Jum'at! Apa yang telah sampai kepadamu? ' Ia menjawab; `Aku diberitahu bahwa [Ummu Habibah] menceritakan kepada Anbasah bin Abu Sufyan bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa mengerjakan shalat dua belas rakaat pada siang dan malamnya selain shalat wajib, maka Allah Azza wa Jalla akan membangunkan baginya sebuah rumah di surga.\""},"1734":{"ar":"أَخْبَرَنَا أَيُّوبُ بْنُ مُحَمَّدٍ قَالَ أَنْبَأَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ حِبَّانَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ عَزَّ وَجَلَّ لَهُ بَيْتًا فِي الْجَنَّةِقَالَ أَبُو عَبْد الرَّحْمَنِ عَطَاءٌ لَمْ يَسْمَعْهُ مِنْ عَنْبَسَةَ","id":"Telah mengabarkan kepada kami [Ayyub bin Muhammad] dia berkata; telah memberitakan kepada kami [Mu'ammar bin Sulaiman] dia berkata; telah menceritakan kepada kami [Zaid bin Hibban] dari [Ibnu Juraij] dari ['Atha] dari ['Anbasah bin Abu Sufyan] dari [Ummu Habibah] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat dua belas raka'at maka Allah Azza wa Jalla akan membangunkan untuknya sebuah rumah di surga'.\" Abu Abdurrahman berkata; 'Atha tidak mendengar dari dari 'Anbasah.'"},"1735":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ سَعِيدٍ الطَّائِفِيُّ قَالَ حَدَّثَنَا عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قَدِمْتُ الطَّائِفَ فَدَخَلْتُ عَلَى عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ وَهُوَ بِالْمَوْتِ فَرَأَيْتُ مِنْهُ جَزَعًا فَقُلْتُ إِنَّكَ عَلَى خَيْرٍ فَقَالَ أَخْبَرَتْنِي أُخْتِي أُمُّ حَبِيبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى ثِنْتَيْ عَشْرَةَ رَكْعَةً بِالنَّهَارِ أَوْ بِاللَّيْلِ بَنَى اللَّهُ عَزَّ وَجَلَّ لَهُ بَيْتًا فِي الْجَنَّةِخَالَفَهُمْ أَبُو يُونُسَ الْقُشَيْرِيُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Zaid bin Hubab] dia berkata; telah menceritakan kepadaku [Muhammad bin Sa'id Ath Thaifi] dia berkata; telah menceritakan kepada kami ['Atha bin Abu Rabah] dari [Ya'la bin Umayyah] dia berkata; \"Aku memasuki Thaif, maka aku menemui ['Ansabah bin Abu Sufyan] yang waktu itu dia sedang menghadapi kematian (sakaratul maut). Aku melihatnya lagi kesakitan, Aku berkata kepadanya; 'Engkau berada dalam kebaikan', lalu dia berkata; 'Saudara perempuanku, [Ummu Habibah], memberitahukanku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat dua belas rakaat pada siang dan malamnya, Allah Azza wa Jalla akan membangunkan baginya sebuah rumah di surga.\" Abu Yunus Al Qusyairi menyelisihinya."},"1736":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ حَدَّثَنَا حِبَّانُ وَمُحَمَّدُ بْنُ مَكِّيٍّ قَالَا أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي يُونُسَ الْقُشَيْرِيِّ عَنْ ابْنِ أَبِي رَبَاحٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ حَدَّثَهُ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ قَالَتْمَنْ صَلَّى ثِنْتَيْ عَشْرَةَ رَكْعَةً فِي يَوْمٍ فَصَلَّى قَبْلَ الظُّهْرِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim] dia berkata; telah menceritakan kepada kami [Hibban] dan [Muhammad bin Makki] mereka berkata; telah memberitakan kepada kami ['Abdullah] dari [Abu Yunus Al Qusyairi] dari [Ibnu Abu Rabah] dari [Syahr bin Hausyab], dia menceritakannya dari [Ummu Habibah bintu Abu Sufyan] dia berkata; \"Barangsiapa mengerjakan shalat dua belas rakaat dalam sehari, lalu shalat sebelum Zhuhur, Allah akan membangun sebuah rumah untuknya di surga.\""},"1737":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا أَبُو الْأَسْوَدِ قَالَ حَدَّثَنِي بَكْرُ بْنُ مُضَرَ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي إِسْحَقَ الْهَمْدَانِيِّ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اثْنَتَا عَشْرَةَ رَكْعَةً مَنْ صَلَّاهُنَّ بَنَى اللَّهُ لَهُ بَيْت��ا فِي الْجَنَّةِ أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الظُّهْرِ وَرَكْعَتَيْنِ قَبْلَ الْعَصْرِ وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ قَبْلَ صَلَاةِ الصُّبْحِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah memberitakan kepada kami [Abul Aswad] dia berkata; telah menceritakan kepadaku [Bakr bin Mudhar] dari [Ibnu 'Ajlan] dari [Abu Ishaq Al-Hamdani] dari ['Amru bin Aus] dari ['Ansabah bin Abu Sufyan] dari [Ummu Habibah] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Ada dua belas raka'at yang barang siapa mengerjakannya, maka Allah akan membangunkan baginya rumah di surga.\" Yaitu empat raka'at sebelum zhuhur, dua raka'at sesudahnya, dua raka'at sebelum ashar, dua raka'at sesudah maghrib dan dua raka'at sebelum shalat subuh.\""},"1738":{"ar":"أَخْبَرَنَا أَبُو الْأَزْهَرِ أَحْمَدُ بْنُ الْأَزْهَرِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا فُلَيْحٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِي إِسْحَقَ عَنْ الْمُسَيَّبِ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى اثْنَتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ أَرْبَعًا قَبْلَ الظُّهْرِ وَاثْنَتَيْنِ بَعْدَهَا وَاثْنَتَيْنِ قَبْلَ الْعَصْرِ وَاثْنَتَيْنِ بَعْدَ الْمَغْرِبِ وَاثْنَتَيْنِ قَبْلَ الصُّبْحِقَالَ أَبُو عَبْد الرَّحْمَنِ فُلَيْحُ بْنُ سُلَيْمَانَ لَيْسَ بِالْقَوِيِّ","id":"Telah mengabarkan kepada kami [Abul Azhar Ahmad bin Al Azhar An Naisaburi] dia berkata; telah menceritakan kepada kami [Yunus bin Muhammad] dia berkata; telah menceritakan kepada kami [Fulaih] dari [Suhail bin Abu Shalih] dari [Abu Ishaq] dari [Al Musayyab] dari ['Anbasah bin Abu Sufyan] dari [Ummu Habibah] dia berkata; \"Ada dua belas raka'at yang barang siapa mengerjakannya, Allah membangunkan baginya rumah di surga.\" Yaitu empat raka'at sebelum zhuhur, dua raka'at sesudahnya, dua raka'at sebelum ashar, dua raka'at sesudah maghrib dan dua raka'at sebelum shalat subuh.\" Abu Abdurrahman berkata; ' Fulaih bin Sulaiman orangnya lemah.'"},"1739":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ أَنْبَأَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَنْبَسَةَ أَخِي أُمِّ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ قَالَتْمَنْ صَلَّى فِي الْيَوْمِ وَاللَّيْلَةِ ثِنْتَيْ عَشْرَةَ رَكْعَةً سِوَى الْمَكْتُوبَةِ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَثِنْتَيْنِ قَبْلَ الْعَصْرِ وَثِنْتَيْنِ بَعْدَ الْمَغْرِبِ وَثِنْتَيْنِ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dia berkata; telah memberitakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Al Musayyab bin Rafi'] dari ['Ansabah] -saudara Ummu Habibah- dari [Ummu Habibah] dia berkata; \"Barang siapa mengerjakan shalat dalam sehari semalam dua belas raka? t selain shalat wajib, maka akan dibangunkan baginya sebuah rumah di surga. Yaitu empat raka'at sebelum zhuhur, dua raka'at sesudahnya, dua raka'at sebelum ashar, dua raka'at sesudah maghrib dan dua raka'at sebelum shalat subuh.\""},"1740":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى فِي الْيَوْمِ وَاللَّيْلَةِ ثِنْتَيْ عَشْرَةَ رَكْعَةً بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Al Musayyab bin Rafi'] dari ['Ansabah bin Abu Sufyan] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa mengerjakan shalat dalam sehari semalam dua belas raka? t, maka akan dibangunkan baginya sebuah rumah di surga.\""},"1741":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْمَنْ صَلَّى فِي اللَّيْلِ وَالنَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً سِوَى الْمَكْتُوبَةِ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ya'la] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Al Musayyab bin Rafi'] dari ['Ansabah bin Abu Sufyan] dari [Ummu Habibah] dia berkata; \"Barang siapa mengerjakan shalat dalam sehari semalam dua belas raka? t selain shalat wajib, akan dibangunkan baginya sebuah rumah di surga.\""},"1742":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا وَهْبٌ قَالَ حَدَّثَنَا خَالِدٌ عَنْ حُصَيْنٍ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ أَبِي صَالِحٍ ذَكْوَانَ قَالَ حَدَّثَنِي عَنْبَسَةُ بْنُ أَبِي سُفْيَانَ أَنَّ أُمَّ حَبِيبَةَ حَدَّثَتْهُأَنَّهُ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Wahb] dia berkata; telah menceritakan kepada kami [Khalid] dari [Hushain] dari [Al Musayyab bin Rafi'] dari [Abu Shalih Dzakwan] dia berkata; Telah menceritakan kepadaku ['Ansabah bin Abu Sufyan] bahwasanya [Ummu Habibah] berkata kepadanya; \"Barang siapa mengerjakan shalat dalam sehari semalam dua belas raka? t selain shalat wajib, akan dibangunkan untuknya sebuah rumah di surga.\""},"1743":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبٍ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أُمِّ حَبِيبَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً سِوَى الْفَرِيضَةِ بَنَى اللَّهُ لَهُ أَوْ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib] dia berkata; telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Abu Shalih] dari [Ummu Habibah] dia berkata; \"Barangsiapa mengerjakan shalat dalam sehari dua belas rakaat selain shalat wajib, Allah membangunkannya atau akan dibangunkan untuknya sebuah rumah di surga.\""},"1744":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْمُثَنَّى عَنْ سُوَيْدِ بْنِ عَمْرٍو قَالَ حَدَّثَنِي حَمَّادٌ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أُمِّ حَبِيبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى ثِنْتَيْ عَشْرَةَ رَكْعَةً فِي يَوْمٍ وَلَيْلَةٍ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami ['Ali bin Al Mutsanna] dari [Suwaid bin 'Amr] dia berkata; telah menceritakan kepadaku [Hammad] dari ['Ashim] dari [Abu Shalih] dari [Ummu Habibah] dia berkata; \"Barangsiapa mengerjakan shalat dalam sehari semalam dua belas rakaat, Allah membangunkan untuknya sebuah rumah di surga.\""},"1745":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً سِوَى الْفَرِيضَةِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَمُحَمَّدُ بْنُ سُلَيْمَانَ ضَعِيفٌ هُوَ ابْنُ الْأَصْبَهَانِيِّ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ أَوْجُهٍ سِوَى هَذَا الْوَجْهِ بِغَيْرِ اللَّفْظِ الَّذِي تَقَدَّمَ ذِكْرُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Yahya bin Ishaq] dia berkata; telah menceritakan kepada kami [Muhammad bin Sulaiman] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa mengerjakan shalat dalam sehari dua belas rakaat selain shalat fardlu maka Allah akan membangun untuknya sebuah rumah disurga.\" Abu Abdurrahman berkata; Ini salah, Muhammad bin Sulaiman itu lemah ia adalah putra Al Ashbahani dan hadits ini telah diriwayatkan dari beberapa jalan selain jalan ini tanpa lafadz yang telah disebutkan."},"1746":{"ar":"أَخْبَرَنِي يَزِيدُ بْنُ مُحَمَّدِ بْنِ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا هِشَامٌ الْعَطَّارُ قَالَ حَدَّثَنِي إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ بْنِ سَمَاعَةَ عَنْ مُوسَى بْنِ أَعْيَنَ عَنْ أَبِي عَمْرٍو الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَ لَمَّا نُزِلَ بِعَنْبَسَةَ جَعَلَ يَتَضَوَّرُ فَقِيلَ لَهُ فَقَالَ أَمَا إِنِّي سَمِعْتُ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ رَكَعَ أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعًا بَعْدَهَا حَرَّمَ اللَّهُ عَزَّ وَجَلَّ لَحْمَهُ عَلَى النَّارِ فَمَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ","id":"Telah mengabarkan kepadaku [Yazid bin Muhammad bin 'Abdush Shamad] dia berkata; telah menceritakan kepada kami [Hisyam Al 'Aththar] dia berkata; telah menceritakan kepadaku [Isma'il bin 'Abdullah bin Sama'ah] dari [Musa bin A'yan] dari [Abu 'Amru Al Auza'i] dari [Hassan bin 'Athiyyah] dia berkata; \"Ketika ajal [Anbasah] sudah dekat, ia ditanya, maka ia menjawab; 'Aku pernah mendengar [Ummu Habibah] -istri Nabi shallallahu 'alaihi wasallam- menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa mengerjakan shalat empat rakaat sebelum Zhuhur dan empat rakaat sesudahnya, Allah Azza wa Jalla mengharamkan dagingnya disentuh oleh api neraka\".' Setelah aku mendengarnya maka aku tidak pernah meninggalkannya.\""},"1747":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَاصِحٍ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ مَنْ صَلَّى أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعًا بَعْدَهَا حَرَّمَهُ اللَّهُ عَزَّ وَجَلَّ عَلَى النَّارِ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashih] dia berkata; telah menceritakan kepada kami [Marwan bin Muhammad] dari [Sa'id bin 'Abdul 'Aziz] dari [Sulaiman bin Musa] dari [Makhul] dari ['Ansabah bin Abu Sufyan] dari [Ummu Habibah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat empat rakaat sebelum Zhuhur dan empat rakaat sesudahnya, Allah Azza wa Jalla mengharamkannya masuk ke dalam neraka.\""},"1748":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ عَنْ مَرْوَانَ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَال مَرْوَانُ وَكَانَ سَعِيدٌ إِذَا قُرِئَ عَلَيْهِ عَنْ أُمِّ حَبِيبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَرَّ بِذَلِكَ وَلَمْ يُنْكِرْهُ وَإِذَا حَدَّثَنَا بِهِ هُوَ لَمْ يَرْفَعْهُقَالَتْ مَنْ رَكَعَ أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعًا بَعْدَهَا حَرَّمَهُ اللَّهُ عَلَى النَّارِقَالَ أَبُو عَبْد الرَّحْمَنِ مَكْحُولٌ لَمْ يَسْمَعْ مِنْ عَنْبَسَةَ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid] dari [Marwan bin Muhammad] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Abdul 'Aziz] dari [Sulaiman bin Musa] dari [Makhul] dari ['Ansabah bin Abu Sufyan] dari [Ummu Habibah], Marwan berkata; - dan dia merasa senang jika dibacakan kepadanya- Dari Ummu Habibah dari Nabi shallallahu 'alaihi wasallam beliau tidak memungkirinya, Ummu Habibah berkata; \"Barangsiapa mengerjakan shalat empat rakaat sebelum Zhuhur dan empat rakaat sesudahnya, Allah wa Jalla mengharamkannya masuk ke dalam neraka.\" Abu Abdurrahman berkata; ' Makhul tidak pernah mendengar dari 'Anbasah sedikitpun.'"},"1749":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ مُوسَى يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ أَبِي سُفْيَانَ قَالَ لَمَّا نَزَلَ بِهِ الْمَوْتُ أَخَذَهُ أَمْرٌ شَدِيدٌ فَقَالَ حَدَّثَتْنِي أُخْتِي أُمُّ حَبِيبَةَ بِنْتُ أَبِي سُفْيَانَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَافَظَ عَلَى أَرْبَعِ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعٍ بَعْدَهَا حَرَّمَهُ اللَّهُ تَعَالَى عَلَى النَّارِ","id":"Telah mengabarkan kepada kami ['Abdullah bin Ishaq] dia berkata; telah menceritakan kepada kami [Abu 'Ashim] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Abdul 'Aziz] dia berkata; Aku mendengar [Sulaiman bin Musa] menceritakan dari [Muhammad bin Abu Sufyan] dia berkata; -tatkala kematian hendak menjemputnya yang waktu itu dia sedang dalam kesakitan- dia berkata; 'Telah menceritakan kepadaku saudariku [Ummu Habibah binti Abu Sufyan] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa senantiasa menjaga shalat empat rakaat sebelum zhuhur dan empat rakaat sesudahnya, Allah Ta'ala mengharamkannya masuk ke dalam neraka.\""},"1750":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَمَنَّيَنَّ أَحَدٌ مِنْكُمْ الْمَوْتَ إِمَّا مُحْسِنًا فَلَعَلَّهُ أَنْ يَزْدَادَ خَيْرًا وَإِمَّا مُسِيئًا فَلَعَلَّهُ أَنْ يَسْتَعْتِبَ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah]; telah menceritakan kepada kami [Ma'an] dia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berharap untuk mati. Adakalanya dia adalah orang yang baik, maka barangkali akan bertambah baik; dan adakalanya ia adalah orang yang -selalu berbuat- jelek, maka barangkali ia tidak akan mengulangi perbuatan jelek dan bertaubat.\""},"1751":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي الزُّبَيْدِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ إِمَّا مُحْسِنًا فَلَعَلَّهُ أَنْ يَعِيشَ يَزْدَادُ خَيْرًا وَهُوَ خَيْرٌ لَهُ وَإِمَّا مُسِيئًا فَلَعَلَّهُ أَنْ يَسْتَعْتِبَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dia berkata; telah menceritakan kepadaku [Az Zubaidi] dia berkata; telah menceritakan kepadaku [Az Zuhri] dari [Abu 'Ubaid] -budak 'Abdurrahman bin 'Auf- bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali salah seorang di antara kalian berharap mati. Adakalanya dia adalah orang yang baik, maka barangkali ia akan hidup bertambah baik, dan itu lebih baik baginya; dan adakalanya ia adalah orang yang -selalu berbuat- jelek, maka barang kali ia akan tidak mengulangi perbuatan jelek dan bertaubat.\""},"1752":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ لِضُرٍّ نَزَلَ بِهِ فِي الدُّنْيَا وَلَكِنْ لِيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Humaid] dari [Anas] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian berharap mati karena bahaya (musibah) yang menimpanya di dunia, tetapi hendaklah ia berdo'a, 'Ya Allah, hidupkanlah aku selama kehidupan lebih baik bagiku dan wafatkanlah aku jika kematian lebih baik bagiku'.\""},"1753":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ ح وَأَنْبَأَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا يَتَمَنَّى أَحَدُكُمْ الْمَوْتَ لِضُرٍّ نَزَلَ بِهِ فَإِنْ كَانَ لَا بُدَّ مُتَمَنِّيًا الْمَوْتَ فَلْيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي مَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari ['Abdul 'Aziz]. demikian pula diriwayatkan dari jalur lain, dan telah memberitakan kepada kami ['Imran bin Musa] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari ['Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, janganlah salah seorang dari kalian berharap mati karena bahaya (musibah) yang menimpanya. Jika ia harus berhadap mati, maka hendaknya ia berdo'a, 'Ya Allah, hidupkanlah aku selama hidupku lebih baik bagiku, dan wafatkanlah aku selama kematian lebih baik bagiku'.\""},"1754":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحَجَّاجِ وَهُوَ الْبَصْرِيُّ عَنْ يُونُسَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْعُوا بِالْمَوْتِ وَلَا تَتَمَنَّوْهُ فَمَنْ كَانَ دَاعِيًا لَا بُدَّ فَلْيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin 'Abdullah] dia berkata; [bapakku] telah menceritakan kepadaku, dia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Al Hajjaj Al Bashri] dari [Yunus] dari [Tsabit] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berdo'a untuk mati dan janganlah mengharapkannya. Barangsiapa yang harus berdo'a (untuk mati), hendaklah ia berdo'a, 'Ya Allah, hidupkanlah aku selama hidupku lebih baik bagiku, dan wafatkanlah aku selama kematian lebih baik bagiku'.\""},"1755":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنِي قَيْسٌ قَالَدَخَلْتُ عَلَى خَبَّابٍ وَقَدْ اكْتَوَى فِي بَطْنِهِ سَبْعًا وَقَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ دَعَوْتُ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Qais] dia berkata; Aku pernah menemui [Khabbab], dan ia mengobati perutnya dengan besi panas sebanyak tujuh kali. Dia berkata; \"Andai kata Rasulullah shallallahu 'alaihi wasallam tidak melarang kita berdo'a untuk mati, niscaya aku berdo'a untuk mati.\""},"1756":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو ح و أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثِرُوا ذِكْرَ هَاذِمِ اللَّذَّاتِقَالَ أَبُو عَبْد الرَّحْمَنِ مُحَمَّدُ بْنُ إِبْرَاهِيمَ وَالِدُ أَبِي بَكْرِ بْنِ أَبِي شَيْبَةَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Muhammad bin 'Amru]. Dan diriwayatkan pula dari jalur lain, telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah memberitakan kepada kami [Muhammad bin Ibrahim] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perbanyaklah mengingat pemutus kenikmatan -yaitu kematian-.\" Abu Abdurrahman berkata; 'Muhammad bin Ibrahim adalah putra Abu Bakr bin Abu Syaibah.'"},"1757":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى عَنْ الْأَعْمَشِ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ أُمِّ سَلَمَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا حَضَرْتُمْ الْمَرِيضَ فَقُولُوا خَيْرًا فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ فَلَمَّا مَاتَ أَبُو سَلَمَةَ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَقُولُ قَالَ قُولِي اللَّهُمَّ اغْفِرْ لَنَا وَلَهُ وَأَعْقِبْنِي مِنْهُ عُقْبَى حَسَنَةً فَأَعْقَبَنِي اللَّهُ عَزَّ وَجَلَّ مِنْهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Yahya] dari [Al A'masy] dia berkata; telah menceritakan kepadaku [Syaqiq] dari [Ummu Salamah] dia berkata; \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian menjenguk orang yang sedang sakit, maka ucapkanlah kebaikan, karena malaikat mengamini atas apa yang kalian ucapkan.\" Setelah Abu Salamah meninggal dunia, aku bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam! Bagaimana aku berdo'a?\" beliau menjawab: \"Berdo'alah, 'Ya Allah, berilah ampunan untuk kami dan umatnya dan berilah balasan untuku darinya dengan balasan yang baik, maka Allah -Azza wa Jalla- menggantikan untukku darinya dengan Nabi Muhammad shallallahu 'alaihi wasallam'.\""},"1758":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ عُمَارَةَ قَالَ سَمِعْتُ أَبَا سَعِيدٍ ح وَأَنْبَأَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dia berkata; telah menceritakan kepada kami ['Umarah bin Ghaziyyah] dia berkata; telah menceritakan kepada kami [Yahya bin 'Umarah] dia berkata; Aku mendengar [Abu Sa'id] dan telah memberitakan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari ['Umarah bin Ghaziyyah] dari [Yahya bin 'Umarah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tuntunlah orang yang akan meninggal dunia diantara kalian dengan -kalimat- 'Laa Ilaaha Illallah'.\""},"1759":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنِي أَحْمَدُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مَنْصُورُ ابْنُ صَفِيَّةَ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا هَلْكَاكُمْ قَوْلَ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepadaku [Ahmad bin Ishaq] dia berkata; telah menceritakan kepada kami [Wuhaib] dia berkata; telah menceritakan kepada kami [Manshur bin Shafiyyah] dari ibunya [Shafiyyah binti Syaibah] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tuntunlah orang yang akan meninggal dunia diantara kalian dengan -kalimat- 'Laa Ilaaha Illallah'.\""},"1760":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْمُثَنَّى بْنِ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَوْتُ الْمُؤْمِنِ بِعَرَقِ الْجَبِينِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dari [Al Mutsanna bin Sa'id] dari [Qatadah] dari ['Abdullah bin Buraidah] dari [bapaknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Tanda) wafat seorang mukmin adalah dengan keringat -yang ada-di dahi.\""},"1761":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا كَهْمَسٌ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُؤْمِنُ يَمُوتُ بِعَرَقِ الْجَبِينِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Yusuf bin Ya'qub] dia berkata; telah menceritakan kepada kami [Kahmas] dari [Ibnu Buraidah] dari [bapaknya] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Seorang mukmin wafat dengan keringat di dahinya'.\""},"1762":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّهُ لَبَيْنَ حَاقِنَتِي وَذَاقِنَتِي فَلَا أَكْرَهُ شِدَّةَ الْمَوْتِ لِأَحَدٍ أَبَدًا بَعْدَ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdullah bin Yusuf] dia berkata; telah menceritakan kepadaku [Al Laits] dia berkata; telah menceritakan kepadaku [Ibnul Had] dari ['Abdurrahman bin Al Qasim] dari [bapaknya] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam wafat, dan beliau berada diantara perut dan daguku, maka aku tidak lagi benci dengan beratnya kematian -yang dialami- oleh seorangpun selamanya setelah aku melihat Rasulullah shallallahu 'alaihi wasallam -wafat-.\""},"1763":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَآخِرُ نَظْرَةٍ نَظَرْتُهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَشْفُ السِّتَارَةِ وَالنَّاسُ صُفُوفٌ خَلْفَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَأَرَادَ أَبُو بَكْرٍ أَنْ يَرْتَدَّ فَأَشَارَ إِلَيْهِمْ أَنْ امْكُثُوا وَأَلْقَى السِّجْفَ وَتُوُفِّيَ مِنْ آخِرِ ذَلِكَ الْيَوْمِ وَذَلِكَ يَوْمُ الِاثْنَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Anas] dia berkata; \"Terakhir aku memandang Rasulullah shallallahu 'alaihi wasallam ketika tabir terbuka dan orang-orang berbaris di belakang Abu Bakar -radliallahu 'anhu-, ketika Abu Bakar hendak mundur, beliau memberi isyarat kepada mereka agar tetap berada di tempat. Beliau melemparkan tabir dan wafat di penghujung hari itu, yaitu hari Senin.\""},"1764":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حُيَيُّ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَمَاتَ رَجُلٌ بِالْمَدِينَةِ مِمَّنْ وُلِدَ بِهَا فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا لَيْتَهُ مَاتَ بِغَيْرِ مَوْلِدِهِ قَالُوا وَلِمَ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ إِنَّ الرَّجُلَ إِذَا مَاتَ بِغَيْرِ مَوْلِدِهِ قِيسَ لَهُ مِنْ مَوْلِدِهِ إِلَى مُنْقَطَعِ أَثَرِهِ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Huyay bin 'Abdullah] dari [Abu 'Abdurrahman Al Hubuli] dari ['Abdullah bin 'Amru] dia berkata; \"Ada salah seorang meninggal dunia di Madinah, ia adalah orang yang terlahir di kota tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalatkannya, kamudian bersabda: 'Duhai, andaikata ia meninggal dunia tidak ditempat kelahirannya! ' Mereka bertanya; 'Mengapa demikian, wahai Rasulullah shallallahu 'alaihi wasallam? ' beliau bersabda: 'Jika seseorang meninggal dunia tidak di tempat kelahirannya maka ia akan diukur di tempat kelahirannya sampai ajal terakhirnya di dalam surga'.\""},"1765":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ قَسَامَةَ بْنِ زُهَيْرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حُضِرَ الْمُؤْمِنُ أَتَتْهُ مَلَائِكَةُ الرَّحْمَةِ بِحَرِيرَةٍ بَيْضَاءَ فَيَقُولُونَ اخْرُجِي رَاضِيَةً مَرْضِيًّا عَنْكِ إِلَى رَوْحِ اللَّهِ وَرَيْحَانٍ وَرَبٍّ غَيْرِ غَضْبَانَ فَتَخْرُجُ كَأَطْيَبِ رِيحِ الْمِسْكِ حَتَّى أَنَّهُ لَيُنَاوِلُهُ بَعْضُهُمْ بَعْضًا حَتَّى يَأْتُونَ بِهِ بَابَ السَّمَاءِ فَيَقُولُونَ مَا أَطْيَبَ هَذِهِ الرِّيحَ الَّتِي جَاءَتْكُمْ مِنْ الْأَرْضِ فَيَأْتُونَ بِهِ أَرْوَاحَ الْمُؤْمِنِينَ فَلَهُمْ أَشَدُّ فَرَحًا بِهِ مِنْ أَحَدِكُمْ بِغَائِبِهِ يَقْدَمُ عَلَيْهِ فَيَسْأَلُونَهُ مَاذَا فَعَلَ فُلَانٌ مَاذَا فَعَلَ فُلَانٌ فَيَقُولُونَ دَعُوهُ فَإِنَّهُ كَانَ فِي غَمِّ الدُّنْيَا فَإِذَا قَالَ أَمَا أَتَاكُمْ قَالُوا ذُهِبَ بِهِ إِلَى أُمِّهِ الْهَاوِيَةِ وَإِنَّ الْكَافِرَ إِذَا احْتُضِرَ أَتَتْهُ مَلَائِكَةُ الْعَذَابِ بِمِسْحٍ فَيَقُولُونَ اخْرُجِي سَاخِطَةً مَسْخُوطًا عَلَيْكِ إِلَى عَذَابِ اللَّهِ عَزَّ وَجَلَّ فَتَخْرُجُ كَأَنْتَنِ رِيحِ جِيفَةٍ حَتَّى يَأْتُونَ بِهِ بَابَ الْأَرْضِ فَيَقُولُونَ مَا أَنْتَنَ هَذِهِ الرِّيحَ حَتَّى يَأْتُونَ بِهِ أَرْوَاحَ الْكُفَّارِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Qasamah bin Zuhair] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila seorang mukmin telah mendekati ajalnya, para malaikat rahmat datang menemuinya dengan membawa sutera putih. Mereka berkata; 'kaluarlah kamu (ruh) dengan ridla dan diridlai menuju rahmat Allah, bau harum dan Rabb yang tidak murka'. Lalu ia keluar dengan bau misik yang paling harum, hingga sebagian mereka berebut dengan sebagian yang lain untuk mendapatkannya, kemudian mereka membawanya hingga pintu langit. Mereka (penduduk langit) berkata; 'Alangkah harumnya bau yang kalian bahwa ini dari bumi! '. Lalu mereka datang dengannya menemui ruh-ruh kaum mukminin. Mereka lebih bergembira (kedatangan) nya daripada seorang di antara kalian yang di datangi orang yang sudah lama tidak bertemu. Lalu mereka bertanya kepadanya; 'Apa yang telah dilakukan oleh si Fulan? Apa yang telah dilakukan si Fulan? ' Mereka berkata; 'Biarlah ia, karena dahulu ia terlena dengan kehidupan di dunia'. Jika ada yang bertanya, 'Tidakkah ia datang menemui kalian? ' mereka menjawab; 'Ia dibawa ke tempat asalnya yang dalam (Neraka Hawiyah), dan seorang yang kafir jika telah datang ajalnya, para malaikat Adzab datang membawa kain kasar. Mereka berkata; 'keluarlah kamu dengan murka dan dimurkai menuju siksa Allah -Azza wa Jalla-. Lalu ia keluar seperti bau bangkai yang paling busuk, kemudian mereka membawanya hingga pintu bumi. Lalu mereka berkata; 'Alangkah busuknya bau ini! ' lalu mereka membawanya menemui ruh orang-orang kafir.\""},"1766":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ أَبِي زُبَيْدٍ وَهُوَ عَبْثَرُ بْنُ الْقَاسِمِ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُقَالَ شُرَيْحٌ فَأَتَيْتُ عَائِشَةَ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ سَمِعْتُ أَبَا هُرَيْرَةَ يَذْكُرُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا إِنْ كَانَ كَذَلِكَ فَقَدْ هَلَكْنَا قَالَتْ وَمَا ذَاكَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ وَلَكِنْ لَيْسَ مِنَّا أَحَدٌ إِلَّا وَهُوَ يَكْرَهُ الْمَوْتَ قَالَتْ قَدْ قَالَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ بِالَّذِي تَذْهَبُ إِلَيْهِ وَلَكِنْ إِذَا طَمَحَ الْبَصَرُ وَحَشْرَجَ الصَّدْرُ وَاقْشَعَرَّ الْجِلْدُ فَعِنْدَ ذَلِكَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah mengabarkan kepada kami [Hannad] dari [Abu Zubaid 'Abtsar bin Al Qasim] dari [Mutharrif] dari ['Amir] dari [Syuraih bin Hani'] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa senang berjumpa dengan Allah, maka Allah pun senang berjumpa dengannya; dan barangsiapa yang benci berjumpa dengan Allah, maka Allah pun benci berjumpa dengannya.\" [Syuraih] berkata; Aku kemudian menemui [Aisyah], lalu aku bertanya; \"Wahai Ummul Mukminin! Aku mendengar Abu Hurairah menyebutkan suatu hadits dari Rasulullah shallallahu 'alaihi wasallam. Jika demikian sungguh kita akan binasa!\" Ia (Aisyah) bertanya, \"Apa itu?\" Syuraikh menjawab; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Siapa senang berjumpa dengan Allah, Allah pun senang berjumpa dengannya dan barangsiapa benci berjumpa dengan Allah, Allah pun benci berjumpa dengannya'. Tetapi tidak ada seorangpun di antara kita kecuali benci dengan kamatian!\" Ia (Aisyah) berkata; \"Sungguh hal itu telah disabdakan oleh Rasulullah shallallahu 'alaihi wasallam, dan tidak seperti yang kamu pahami, tetapi -yang dimaksud adalah- tatkala pandangan terangkat, dada berdetak dan dada menggigil, saat itulah orang yang senang berjumpa dengan Allah, maka Allah pun senang berjumpa dengannya; dan barangsiapa benci berjumpa dengan Allah, maka Allah pun benci berjumpa dengannya?!\""},"1767":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ ح وَأَنْبَأَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْمُغِيرَةُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ تَعَالَى إِذَا أَحَبَّ عَبْدِي لِقَائِي أَحْبَبْتُ لِقَاءَهُ وَإِذَا كَرِهَ لِقَائِي كَرِهْتُ لِقَاءَهُ","id":"[Al Harits bin Miskin] Berkata; -secara baca dan aku mendengarnya dari [Ibnul Qasim]; telah menceritakan kepadaku [Malik]. Dan diriwayatkan pula dari jalur lain, telah memberitakan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Mughirah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: 'Apabila hambaku senang berjumpa denganku, akupun senang berjumpa dengannya dan apabila hambaku benci berjumpa denganku, maka aku pun benci berjumpa dengannya'.\""},"1768":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يُحَدِّثُ عَنْ عُبَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; aku mendengar [Anas] menceritakan dari ['Ubadah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa senang bejumpa dengan Allah, Allah pun senang berjumpa dengannya dan barangsiapa yang benci berjumpa dengan Allah, Allah pun benci berjumpa dengannya.\""},"1769":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; Aku mendengar [bapakku] menceritakan dari [Qatadah] dari [Anas bin Malik] dari ['Ubadah bin Ash Shamit] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa senang berjumpa dengan Allah, maka Allah pun senang berjumpa dengannya dan barangsiapa yang benci berjumpa dengan Allah, maka Allahpun benci berjumpa dengannya.\""},"1770":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا سَعِيدٌ ح و أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ خَالِدِ بْنِ الْحَارِثِ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ زَادَ عَمْرٌو فِي حَدِيثِهِ فَقِيلَ يَا رَسُولَ اللَّهِ كَرَاهِيَةُ لِقَاءِ اللَّهِ كَرَاهِيَةُ الْمَوْتِ كُلُّنَا نَكْرَهُ الْمَوْتَ قَالَ ذَاكَ عِنْدَ مَوْتِهِ إِذَا بُشِّرَ بِرَحْمَةِ اللَّهِ وَمَغْفِرَتِهِ أَحَبَّ لِقَاءَ اللَّهِ وَأَحَبَّ اللَّهُ لِقَاءَهُ وَإِذَا بُشِّرَ بِعَذَابِ اللَّهِ كَرِهَ لِقَاءَ اللَّهِ وَكَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Sa'id]. Dan diriwayatkan pula dari jalur lain, telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Zurarah] dari [Sa'ad bin Hisyam] dari ['Aisyah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa senang bejumpa dengan Allah, maka Allah pun senang berjumpa dengannya dan barangsiapa yang benci berjumpa dengan Allah, maka Allahpun benci berjumpa dengannya.\" Amru menambahkan; Lalu dikatakan, \"Wahai Rasulullah, benci bertemu dengan Allah adalah benci pada kematian! Padahal setiap kita membenci kematian?!\" beliau bersabda: \"Hal itu ketika ia meninggal, apabila diberi kabar gembira dengan rahmat dan ampunan Allah, ia senang berjumpa dengan Allah dan Allah pun senang berjumpa dengannya dan apabila diberi kabar dengan siksa Allah, ia benci berjumpa dengan Allah dan Allah pun benci berjumpa dengannya.\""},"1771":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَبَا بَكْرٍ قَبَّلَ بَيْنَ عَيْنَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مَيِّتٌ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] bahwa Abu Bakar mencium bagian antara kedua mata Nabi shallallahu 'alaihi wasallam, padahal -saat itu- beliau telah meninggal.\""},"1772":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مُوسَى بْنُ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ وَعَنْ عَائِشَةَأَنَّ أَبَا بَكْرٍ قَبَّلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مَيِّتٌ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Musa bin Abu 'Aisyah] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dan dari ['Aisyah] bahwa Abu Bakar mencium Nabi, padahal -saat itu- beliau telah meninggal dunia."},"1773":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ قَالَ مَعْمَرٌ وَيُونُسُ قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ أَبَا بَكْرٍ أَقْبَلَ عَلَى فَرَسٍ مِنْ مَسْكَنِهِ بِالسُّنُحِ حَتَّى نَزَلَ فَدَخَلَ الْمَسْجِدَ فَلَمْ يُكَلِّمْ النَّاسَ حَتَّى دَخَلَ عَلَى عَائِشَةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسَجًّى بِبُرْدٍ حِبَرَةٍ فَكَشَفَ عَنْ وَجْهِهِ ثُمَّ أَكَبَّ عَلَيْهِ فَقَبَّلَهُ فَبَكَى ثُمَّ قَالَ بِأَبِي أَنْتَ وَاللَّهِ لَا يَجْمَعُ اللَّهُ عَلَيْكَ مَوْتَتَيْنِ أَبَدًا أَمَّا الْمَوْتَةُ الَّتِي كَتَبَ اللَّهُ عَلَيْكَ فَقَدْ مِتَّهَا","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah menceritakan kepada kami ['Abdullah] dia berkata; Berkata [Ma'mar] dan [Yunus]; [Az Zuhri] berkata; dan telah mengabarkan kepadaku [Abu Salamah] bahwasanya ['Aisyah] mengabarkan kepadanya; Abu Bakar datang dengan menaiki kuda dan rumahnya -As-Sunuh- hingga ia turun, lalu masuk ke masjid dan tidak berbicara dengan orang-orang, hingga menemui Aisyah dan Rasulullah shallallahu 'alaihi wasallam telah ditutup dengan kain katun bermotif dari Yaman, lalu ia membuka tutup wajahnya, kemudian ia menunduk dengan hati yang sangat sedih, memeluknya dan ia menangis, lalu berkata; \"Bapakku sebagai tebusannya, demi Allah! Allah tidak akan mengumpulkan atas diri engkau dua kematian selamanya, adapun kematian yang telah Allah tuliskan atas diri engkau, sungguh engkau telah menjalaninya.\""},"1774":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ يَقُولُ سَمِعْتُ جَابِرًا يَقُولُجِيءَ بِأَبِي يَوْمَ أُحُدٍ وَقَدْ مُثِّلَ بِهِ فَوُضِعَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سُجِّيَ بِثَوْبٍ فَجَعَلْتُ أُرِيدُ أَنْ أَكْشِفَ عَنْهُ فَنَهَانِي قَوْمِي فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُفِعَ فَلَمَّا رُفِعَ سَمِعَ صَوْتَ بَاكِيَةٍ فَقَالَ مَنْ هَذِهِ فَقَالُوا هَذِهِ بِنْتُ عَمْرٍو أَوْ أُخْتُ عَمْرٍو قَالَ فَلَا تَبْكِي أَوْ فَلِمَ تَبْكِي مَا زَالَتْ الْمَلَائِكَةُ تُظِلُّهُ بِأَجْنِحَتِهَا حَتَّى رُفِعَ","id":"Telah mengabarkan kepadaku [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; Aku mendengar [Ibnul Munkadir] berkata; Aku mendengar [Jabir] berkata; bapakku dibawa pada hari perang uhud dan sungguh dia telah dicincang, lalu diletakkan di hadapan Rasulullah shallallahu 'alaihi wasallam, dalam keadaan telah ditutup dengan satu kain. Aku ingin segera membukanya, namun orang-orang melarangku. Kemudian Nabi shallallahu 'alaihi wasallam menerintahkan hal itu, lalu diangkat. Dan ketika diangkat, beliau mendengar suara seorang wanita yang menangis, lalu beliau bertanya: \"Siapa ini?\" Mereka menjawab; \"Ini adalah puteri Amru -atau saudari Amru-.\" Beliau bersabda: \"Janganlah kamu menangis, -atau mengapa kamu menangis? -, malaikat akan selalu menaunginya dengan sayap-sayapnya hingga diangkat.\""},"1775":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا حُضِرَتْ بِنْتٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَغِيرَةٌ فَأَخَذَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَمَّهَا إِلَى صَدْرِهِ ثُمَّ وَضَعَ يَدَهُ عَلَيْهَا فَقَضَتْ وَهِيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَكَتْ أُمُّ أَيْمَنَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ أَيْمَنَ أَتَبْكِينَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَكِ فَقَالَتْ مَا لِي لَا أَبْكِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَسْتُ أَبْكِي وَلَكِنَّهَا رَحْمَةٌ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ بِخَيْرٍ عَلَى كُلِّ حَالٍ تُنْزَعُ نَفْسُهُ مِنْ بَيْنِ جَنْبَيْهِ وَهُوَ يَحْمَدُ اللَّهَ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari ['Atha bin As Saib] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; Ketika puteri Rasulullah shallallahu 'alaihi wasallam yang masih kecil mendekati ajalnya, Rasulullah mengambilnya lalu mendekapnya di dada beliau, kemudian meletakan tangan beliau pada tubuhnya, lalu meninggal dunia dan ia berada di hadapan Rasulullah shallallahu 'alaihi wasallam. Ummu Aiman pun menangis, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai Ummu Aiman! Apakah kamu menangis, padahal Rasulullah shallallahu 'alaihi wasallam berada di samping kamu?!\" lalu ia berkata; \"Mengapa aku tidak -boleh- menangis padahal Rasulullah shallallahu 'alaihi wasallam menangis?! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak menangis, tetapi adalah rahmat.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimanapun juga, seorang mukmin harus dalam keadaan baik, ruhnya akan dicabut diantara dua pinggulnya dan ia sedang memuji Allah -Azza wa Jalla-.\""},"1776":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ فَاطِمَةَ بَكَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ مَاتَ فَقَالَتْ يَا أَبَتَاهُ مِنْ رَبِّهِ مَا أَدْنَاهُ يَا أَبَتَاهُ إِلَى جِبْرِيلَ نَنْعَاهْ يَا أَبَتَاهُ جَنَّةُ الْفِرْدَوْسِ مَأْوَاهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Tsabit] dari [Anas] Bahwa Fatimah menangisi Rasulullah shallallahu 'alaihi wasallam ketika meninggal dunia. Lalu ia berkata; \"Wahai bapakku, apa yang menjadikannya dekat dengan Rabbnya! Wahai bapakku, kepada Jibril kami memberitahu kematiannya! Wahai bapakku, Surga Firdaus tempat kembalinya! "},"1777":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍأَنَّ أَبَاهُ قُتِلَ يَوْمَ أُحُدٍ قَالَ فَجَعَلْتُ أَكْشِفُ عَنْ وَجْهِهِ وَأَبْكِي وَالنَّاسُ يَنْهَوْنِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْهَانِي وَجَعَلَتْ عَمَّتِي تَبْكِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبْكِيهِ مَا زَالَتْ الْمَلَائِكَةُ تُظِلُّهُ بِأَجْنِحَتِهَا حَتَّى رَفَعْتُمُوهُ","id":"Telah mengabarkan kepada kami ['Amru bin Yazid] dia berkata; telah menceritakan kepada kami [Bahz bin Asad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] dari [Jabir] bahwa bapaknya terbunuh pada perang Uhud. Ia berkata: \"Aku lalu segera membuka wajahnya dan aku pun menangis, orang-orang melarangku, sedang Rasulullah shallallahu 'alaihi wasallam tidak melarangku dan bibikupun menangisinya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menangisinya! Malaikat akan selalu menaunginya dengan sayap-sayapnya hingga kalian mengangkatnya.\""},"1778":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَابِرِ بْنِ عَتِيكٍ أَنَّ عَتِيكَ بْنَ الْحَارِثِ وَهُوَ جَدُّ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَبُو أُمِّهِ أَخْبَرَهُ أَنَّ جَابِرَ بْنَ عَتِيكٍ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ يَعُودُ عَبْدَ اللَّهِ بْنَ ثَابِتٍ فَوَجَدَهُ قَدْ غُلِبَ عَلَيْهِ فَصَاحَ بِهِ فَلَمْ يُجِبْهُ فَاسْتَرْجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ قَدْ غُلِبْنَا عَلَيْكَ أَبَا الرَّبِيعِ فَصِحْنَ النِّسَاءُ وَبَكَيْنَ فَجَعَلَ ابْنُ عَتِيكٍ يُسَكِّتُهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُنَّ فَإِذَا وَجَبَ فَلَا تَبْكِيَنَّ بَاكِيَةٌ قَالُوا وَمَا الْوُجُوبُ يَا رَسُولَ اللَّهِ قَالَ الْمَوْتُ قَالَتْ ابْنَتُهُ إِنْ كُنْتُ لَأَرْجُو أَنْ تَكُونَ شَهِيدًا قَدْ كُنْتَ قَضَيْتَ جِهَازَكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَوْقَعَ أَجْرَهُ عَلَيْهِ عَلَى قَدْرِ نِيَّتِهِ وَمَا تَعُدُّونَ الشَّهَادَةَ قَالُوا الْقَتْلُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهَادَةُ سَبْعٌ سِوَى الْقَتْلِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ الْمَطْعُونُ شَهِيدٌ وَالْمَبْطُونُ شَهِيدٌ وَالْغَرِيقُ شَهِيدٌ وَصَاحِبُ الْهَدَمِ شَهِيدٌ وَصَاحِبُ ذَاتِ الْجَنْبِ شَهِيدٌ وَصَاحِبُ الْحَرَقِ شَهِيدٌ وَالْمَرْأَةُ تَمُوتُ بِجُمْعٍ شَهِيدَةٌ","id":"Telah mengabarkan kepada kami ['Utbah bin 'Abdullah bin 'Utbah] dia berkata; aku membacakan kepada [Malik] dari ['Abdullah bin 'Abdullah bin Jabir bin 'Atik] bahwasanya ['Atik bin Al Harits] -kakek 'Abdullah bin 'Abdullah, bapak dari Ibunya- mengabarkan kepadanya, bahwasanya [Jabir bin 'Atik] mengabarkan kepadanya; Nabi shallallahu 'alaihi wasallam pernah datang menjenguk Abdullah bin Tsabit. Beliau mendapatinya sudah tidak berdaya. Beliau lalu berteriak, namun tidak seorangpun yang menjawabnya. Rasulullah shallallahu 'alaihi wasallam kemudian mengucapkan: -istirja' (mengucapkan Inna lillaahi wa inna ilahi raaji'uun) dan bersabda: \"Allah telah mengambilmu untuk mendahului kami, wahai Abu Rabi'!\" Lalu para wanita berteriak dan menangis, sementara Ibnu Atik berusaha menenangkan mereka. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Biarkan saja mereka! Apabila sudah wajib, maka jangan sampai ada seorang wanita yang menangis.\"Mereka bertanya, \"Apa itu wajib, wahai Rasulullah?\" beliau bersabda: \"kematian\" putrinya berkata, \"Dahulu aku berharap agar engkau mati syahid, sebab engkau telah menghabiskan perbekalanmu!\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sungguhnya Allah -Azza wa Jalla- telah memberikan pahalanya kepadanya sesuai dengan niatnya, apa yang kalian ketahui tentang mati Syahid?!\" Mereka berkata, \"Berperang di jalan Allah -Azza wa Jalla-!\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mati syahid ada tujuh macam selain berperang di jalan Allah Azza wa Jalla; Orang yang mati karena wabah pes adalah syahid, orang yang yang mati karena sakit perut adalah syahid, orang yang mati tenggelam adalah syahid, orang yang mati tertimpa benda keras adalah syahid, orang yang mati karena penyakit lepra adalah syahid, orang yang mati terbakar adalah syahid dan seorang wanita yang mati karena hamil adalah syahidah.\""},"1779":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ قَالَ مُعَاوِيَةُ بْنُ صَالِحٍ وَحَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا أَتَى نَعْيُ زَيْدِ بْنِ حَارِثَةَ وَجَعْفَرِ بْنِ أَبِي طَالِبٍ وَعَبْدِ اللَّهِ بْنِ رَوَاحَةَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَفُ فِيهِ الْحُزْنُ وَأَنَا أَنْظُرُ مِنْ صِئْرِ الْبَابِ فَجَاءَهُ رَجُلٌ فَقَالَ إِنَّ نِسَاءَ جَعْفَرٍ يَبْكِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقْ فَانْهَهُنَّ فَانْطَلَقَ ثُمَّ جَاءَ فَقَالَ قَدْ نَهَيْتُهُنَّ فَأَبَيْنَ أَنْ يَنْتَهِينَ فَقَالَ انْطَلِقْ فَانْهَهُنَّ فَانْطَلَقَ ثُمَّ جَاءَ فَقَالَ قَدْ نَهَيْتُهُنَّ فَأَبَيْنَ أَنْ يَنْتَهِينَ قَالَ فَانْطَلِقْ فَاحْثُ فِي أَفْوَاهِهِنَّ التُّرَابَ فَقَالَتْ عَائِشَةُ فَقُلْتُ أَرْغَمَ اللَّهُ أَنْفَ الْأَبْعَدِ إِنَّكَ وَاللَّهِ مَا تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا أَنْتَ بِفَاعِلٍ","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami ['Abdullah ibn Wahb] dia berkata; [Mu'awiyah bin Shalih] berkata; dan telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Amrah] dari ['Aisyah] dia berkata; \"Tatkala datang berita kematian Zaid bin Haritsah, Ja'far bin Abu Thalib dan Abdullah bin Rawahah, Rasulullah shallallahu 'alaihi wasallam duduk dan terlihat sedih pada raut wajahnya, saat itu aku melihat dari celah pintu, kemudian seseorang mendatanginya, lalu berkata; para istri Ja'far menangis. Maka Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Pergi dan laranglah mereka.\" Lalu ia pergi, kemudian ia datang kembali dan berkata; \"Sungguh aku telah melarang, tapi mereka tidak mau berhenti?\" Beliau bersabda: 'Pergi dan laranglah mereka.' Lalu ia pergi kemudian datang kembali dan berkata; Sungguh aku melarang, tapi mereka tidak mau berhenti? Beliau bersabda: 'Pergi lalu tuangkan debu pada mulut-mulut mereka.' Aisyah mengatakan; 'Aku berkata, 'Sungguh celaka, engkau -demi Allah-, tidaklah engkau meninggalkan Rasulullah shallallahu 'alaihi wasallam, padahal engkau tidak bisa melakukannya! '"},"1780":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dari ['Umar] Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Si mayit akan disiksa karena tangisan keluarganya kepadanya.\""},"1781":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ صُبَيْحٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ سِيرِينَ يَقُولُذُكِرَ عِنْدَ عِمْرَانَ بْنِ حُصَيْنٍ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ الْحَيِّ فَقَالَ عِمْرَانُ قَالَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Abdullah bin Shubaih] dia berkata; Aku mendengar [Muhammad bin Sirin] berkata; Disebutkan hadits di majelis Imran bin Hushain, \"Si mayit akan disiksa karena tangisan orang yang masih hidup?!\" [Imran] berkata; \"Rasulullah shallallahu 'alaihi wasallam yang mengatakannya\"."},"1782":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ سَالِمٌ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ قَالَ عُمَرُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَذَّبُ الْمَيِّتُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Yusuf] dia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia berkata; [bapakku] telah menceritakan kepada kami, dari [Shalih] dari [Ibnu Syihab] dia berkata; [Salim] berkata; Aku mendengar ['Abdullah bin 'Umar] berkata; [Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Si mayit akan disiksa karena tangisan keluarga atas dirinya.\""},"1783":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ حَكِيمِ بْنِ قَيْسٍ أَنَّ قَيْسَ بْنَ عَاصِمٍ قَالَلَا تَنُوحُوا عَلَيَّ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُنَحْ عَلَيْهِمُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Mutharrif] dari [Hakim bin Qais] bahwasanya [Qais bin 'Ashim] berkata; \"Janganlah kalian meratapiku karena Rasulullah shallallahu 'alaihi wasallam tidak diratapi. (secara ringkas)."},"1784":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ عَلَى النِّسَاءِ حِينَ بَايَعَهُنَّ أَنْ لَا يَنُحْنَ فَقُلْنَ يَا رَسُولَ اللَّهِ إِنَّ نِسَاءً أَسْعَدْنَنَا فِي الْجَاهِلِيَّةِ أَفَنُسْعِدُهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا إِسْعَادَ فِي الْإِسْلَامِ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Tsabit] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengambil janji dari kaum wanita ketika membai'at mereka; agar tidak meratapi mayit. Lalu mereka berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, ada sekelompok wanita di zaman Jahiliyyah yang saling meratapi -mayit- kami, apakah boleh kami saling meratapi? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada saling meratapi dalam Islam.\""},"1785":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمَيِّتُ يُعَذَّبُ فِي قَبْرِهِ بِالنِّيَاحَةِ عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu 'Umar] dari ['Umar] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Si mayit akan disiksa dalam kuburnya karena ratapan tangis atas dirinya'.\""},"1786":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا مَنْصُورٌ هُوَ ابْنُ زَاذَانَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَالْمَيِّتُ يُعَذَّبُ بِنِيَاحَةِ أَهْلِهِ عَلَيْهِ فَقَالَ لَهُ رَجُلٌ أَرَأَيْتَ رَجُلًا مَاتَ بِخُرَاسَانَ وَنَاحَ أَهْلُهُ عَلَيْهِ هَاهُنَا أَكَانَ يُعَذَّبُ بِنِيَاحَةِ أَهْلِهِ قَالَ صَدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَبْتَ أَنْتَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman] dia berkata; telah memberitakan kepada kami [Husyaim] dia berkata; telah memberitakan kepada kami [Manshur bin Zadzan] dari [Al Hasan] dari ['Imran bin Hushain] dia berkata; \"Si mayit akan disiksa karena tangisan keluarganya atas dirinya.\" Seseorang berkata kepadanya; 'Bagaimana jika ada seseorang yang meninggal di Khurasan lalu keluarganya yang di sini meratapinya, apakah dia juga akan di adzab karena ratapannya tersebut? Dia menjawab; 'Sungguh benar Rasulullah Shalallahu 'Alaihi Wa Sallam, dan kamu telah berdusta.'"},"1787":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِفَذُكِرَ ذَلِكَ لِعَائِشَةَ فَقَالَتْ وَهِلَ إِنَّمَا مَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ فَقَالَ إِنَّ صَاحِبَ الْقَبْرِ لَيُعَذَّبُ وَإِنَّ أَهْلَهُ يَبْكُونَ عَلَيْهِ ثُمَّ قَرَأَتْ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam] dari [bapaknya] dari [Ibnu 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" si mayit akan disiksa karena tangisan keluarganya atas dirinya.\" Lalu hal itu ditanyakan kepada Aisyah? Ia berkata, \"Ia salah atau lupa! Nabi shallallahu 'alaihi wasallam pernah melewati kuburan, lalu beliau bersabda: ' Penghuni kuburan ini benar-benar sedang di siksa, dan keluarganya sedang menangisinya'. kemudian Aisyah membaca; 'Dan seorang yang berdosa tidak dapat memikul dosa yang lain.'"},"1788":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ أَنَّهَا أَخْبَرَتْهُ أَنَّهَا سَمِعَتْ عَائِشَةَوَذُكِرَ لَهَا أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ الْحَيِّ عَلَيْهِ قَالَتْ عَائِشَةُ يَغْفِرُ اللَّهُ لِأَبِي عَبْدِ الرَّحْمَنِ أَمَا إِنَّهُ لَمْ يَكْذِبْ وَلَكِنْ نَسِيَ أَوْ أَخْطَأَ إِنَّمَا مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى يَهُودِيَّةٍ يُبْكَى عَلَيْهَا فَقَالَ إِنَّهُمْ لَيَبْكُونَ عَلَيْهَا وَإِنَّهَا لَتُعَذَّبُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik bin Anas] dari ['Abdullah bin Abu Bakr] dari [bapaknya] dari ['Amrah] bahwa ia telah mendengar [Aisyah] -dikatakan kepadanya bahwa Abdullah bin Umar berkata; \" si mayit benar-benar akan disiksa karena tangisan orang yang masih hidup atas dirinya.\"-Aisyah berkata; \"Semoga Allah mengampuni Abu Abdurrahman! Sungguh tidaklah ia berdusta, tetapi ia lupa atau melakukan kesalahan! beliau pernah melewati kuburan seorang wanita Yahudi yang sedang di tangisi, lalu beliau bersabda: ' Mereka benar-benar sedang menangisinya dan ia benar-benar sedang di siksa.'"},"1789":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ قَالَ قَصَّهُ لَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يَقُولُ قَالَ ابْنُ عَبَّاسٍ قَالَتْ عَائِشَةُإِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَزِيدُ الْكَافِرَ عَذَابًا بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Abdul Jabbar bin Al 'Ala bin 'Abdul Jabbar] dari [Sufyan] dia berkata; ['Amru bin Dinar] mengisahkannya kepada kami, dia berkata; Aku mendengar [Ibnu Mulaikah] berkata; [Ibnu 'Abbas] berkata; ['Aisyah] berkata; \"Hanya saja Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah -Azza wa Jalla- menambahkan siksa kepada orang kafir karena sebagian tangisan keluarganya atas dirinya'.\""},"1790":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْوَرْدِ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يَقُولُلَمَّا هَلَكَتْ أُمُّ أَبَانَ حَضَرْتُ مَعَ النَّاسِ فَجَلَسْتُ بَيْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ وَابْنِ عَبَّاسٍ فَبَكَيْنَ النِّسَاءُ فَقَالَ ابْنُ عُمَرَ أَلَا تَنْهَى هَؤُلَاءِ عَنْ الْبُكَاءِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِفَقَالَ ابْنُ عَبَّاسٍ قَدْ كَانَ عُمَرُ يَقُولُ بَعْضَ ذَلِكَ خَرَجْتُ مَعَ عُمَرَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ رَأَى رَكْبًا تَحْتَ شَجَرَةٍ فَقَالَ انْظُرْ مَنْ الرَّكْبُ فَذَهَبْتُ فَإِذَا صُهَيْبٌ وَأَهْلُهُ فَرَجَعْتُ إِلَيْهِ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ هَذَا صُهَيْبٌ وَأَهْلُهُ فَقَالَ عَلَيَّ بِصُهَيْبٍ فَلَمَّا دَخَلْنَا الْمَدِينَةَ أُصِيبَ عُمَرُ فَجَلَسَ صُهَيْبٌ يَبْكِي عِنْدَهُ يَقُولُ وَا أُخَيَّاهُ وَا أُخَيَّاهُ فَقَالَ عُمَرُ يَا صُهَيْبُ لَا تَبْكِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ قَالَ فَذَكَرْتُ ذَلِكَ لِعَائِشَةَ فَقَالَتْ أَمَا وَاللَّهِ مَا تُحَدِّثُونَ هَذَا الْحَدِيثَ عَنْ كَاذِبَيْنِ مُكَذَّبَيْنِ وَلَكِنَّ السَّمْعَ يُخْطِئُ وَإِنَّ لَكُمْ فِي الْقُرْآنِ لَمَا يَشْفِيكُمْ أَلَّا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur Al Balkhi] dia berkata; telah menceritakan kepada kami ['Abdul Jabbar bin Al warad]; Aku mendengar [Ibnu Abu Mulaikah] berkata; setelah Ibnu Aban meninggal dunia, aku datang bersama banyak orang, dan aku duduk diantara Abdullah bin Umar dan Ibnu Abbas, lalu para wanita menangis. [Ibnu Umar] berkata; \"Tidakkah engkau melarang mereka untuk menangis? aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" si mayit benar-benar akan disiksa karena tangisan sebagian keluarganya atas dirinya'. [Ibnu Abbas] berkata; \" [Umar] pernah mengatakan sebagian hal itu, -saat itu- aku keluar bersama Umar, hingga tatkala kami berada di Baida, ia melihat rombongan penunggang unta yang berada di bawah pohon, ia berkata; \"Lihatlah siapa penunggang unta tersebut?\" kemudian aku pergi, -untuk melihatnya- ternyata Shuhaib dengan keluarganya, lalu aku kembali, kemudian kukatakan; \"Wahai Amirul Mukminin! Mereka ini adalah Shuhaib dan keluarganya. Ia berkata, \"Datanglah Shuhaib kepadaku.\" Setelah kami masuk ke Madinah Umar tertimpa musibah, lalu Shuhaib duduk disisinya seraya berkata, \"Wahai adikku, wahai adikku! Umar berkata, \"Wahai Shuhaib, janganlah kamu menangis, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: ' si mayit akan disiksa karena tangisan sebagian keluarganya atas dirinya.\" Ia berkata; \"Lalu aku menuturkan hal itu kepada [Aisyah], ia mengatakan; \"Demi Allah! Tidaklah kalian menceritakan hadits ini dari dua orang pendusta yang didustakan, tetapi pendengaran yang salah, di dalam Al-Qur'an benar-benar terdapat sesuatu yang dapat menentramkan bagi kalian, \"Dan seorang yang berdosa tidak dapat memikul dosa orang lain.\" Tetapi Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah benar-benar menambahkan siksa terhadap orang kafir karena sebagian tangis keluarganya atas dirinya'.\""},"1791":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ أَنَّ سَلَمَةَ بْنَ الْأَزْرَقِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَمَاتَ مَيِّتٌ مِنْ آلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَمَعَ النِّسَاءُ يَبْكِينَ عَلَيْهِ فَقَامَ عُمَرُ يَنْهَاهُنَّ وَيَطْرُدُهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُنَّ يَا عُمَرُ فَإِنَّ الْعَيْنَ دَامِعَةٌ وَالْقَلْبَ مُصَابٌ وَالْعَهْدَ قَرِيبٌ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru bin 'Atha] bahwasanya [Salamah bin Al Azraq] berkata; Aku mendengar [Abu Hurairah] berkata; \"Telah meninggal seseorang dari keluarga Rasulullah Shalallahu 'Alaihi Wa Sallam, lalu para wanita berkumpul menangisinya, maka Umar bangkit melarang mereka menangis dan mengusirnya. Kemudian Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Biarkanlah mereka wahai Umar!, mata mereka mudah mencucurkan air mata, hati mudah bersedih, dan kiamat itu dekat.'"},"1792":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى عَنْ الْأَعْمَشِ ح أَنْبَأَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدُعَاءِ الْجَاهِلِيَّةِ وَاللَّفْظُ لِعَلِيٍّ وَقَالَ الْحَسَنُ بِدَعْوَى","id":"Telah mengabarkan kepada kami ['Ali bin Khasyram] dia berkata; telah menceritakan kepada kami ['Isa] dari [Al A'masy]. Demikian juga diriwayatkan dari jalur lain, telah memberitakan kepada kami [Al Hasan bin Isma'il] dia berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Al A'masy] dari ['Abdullah bin Murrah] dari [Masruq] dari ['Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk golongan kami yang menampar pipi, merobek saku dan berseru dengan seruan Jahiliyyah.\" Lafazh ini dari Ali. Al Hasan berkata; -Dengan lafazh -."},"1793":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَوْفٍ عَنْ خَالِدٍ الْأَحْدَبِ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ قَالَأُغْمِيَ عَلَى أَبِي مُوسَى فَبَكَوْا عَلَيْهِ فَقَالَ أَبْرَأُ إِلَيْكُمْ كَمَا بَرِئَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ حَلَقَ وَلَا خَرَقَ وَلَا سَلَقَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Auf] dari [Khalid Al Ahdab] dari [Shafwan bin Muhriz] dia berkata; [Abu Musa] pernah jatuh pingsan, kemudian mereka menangisinya, lalu ia berkata, \"Aku berlepas diri dari kalian sebagaimana Rasulullah shallallahu 'alaihi wasallam berlepas diri dari kami, 'Bukan golongan kami yang mencukur (rambut kepala dan jenggot), merobek (baju) dan meratap -ketika tertimpa musibah-'.\""},"1794":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي زُبَيْدٌ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; [Sufyan] dia berkata; telah menceritakan kepadaku [Zubaid] dari [Ibrahim] dari [Masruq] dari ['Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk golongan kami yang menampar pipi, merobek saku dan berseru dengan seruan Jahiliyyah.\""},"1795":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ أَنْبَأَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو عُمَيْسٍ عَنْ أَبِي صَخْرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ وَأَبِي بُرْدَةَ قَالَالَمَّا ثَقُلَ أَبُو مُوسَى أَقْبَلَتْ امْرَأَتُهُ تَصِيحُ قَالَا فَأَفَاقَ فَقَالَ أَلَمْ أُخْبِرْكِ أَنِّي بَرِيءٌ مِمَّنْ بَرِئَ مِنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَا وَكَانَ يُحَدِّثُهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا بَرِيءٌ مِمَّنْ حَلَقَ وَخَرَقَ وَسَلَقَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Utsman bin Hakim] dia berkata; telah memberitakan kepada kami [Ja'far bin 'Aun] dia berkata; telah menceritakan kepada kami [Abu 'Umais] dari [Abu Shakhrah] dari ['Abdurrahman bin Yazid] dan [Abu Burdah] mereka berkata; \"Setelah [Abu Musa] merasa berat (akan meninggal dunia), istrinya menemuinya lalu berteriak!\" Keduanya berkata lagi; \"Kemudian ia sadar\", ia lalu berkata: \"Bukankah telah kuberitahukan kepadamu bahwa aku berlepas diri dari orang yang Rasulullah shallallahu 'alaihi wasallam berlepas diri darinya?!\" Keduanya berkata, 'Ia menceritakan kepada istrinya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Aku berlepas diri dari orang yang mencukur (rambut kepala dan jenggot), merobek (saku) dan meratap - ketika tertimpa musibah -'.\""},"1796":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زُبَيْدٍ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ وَشَقَّ الْجُيُوبَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Zubaid] dari [Ibrahim] dari [Masruq] dari ['Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bukan termasuk golongan kami orang yang menampar pipi, merobek saku dan berseru dengan seruan Jahiliyyah -ketika tertimpa musibah-.\""},"1797":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ يَزِيدَ بْنِ أَوْسٍ عَنْ أَبِي مُوسَىأَنَّهُ أُغْمِيَ عَلَيْهِ فَبَكَتْ أُمُّ وَلَدٍ لَهُ فَلَمَّا أَفَاقَ قَالَ لَهَا أَمَا بَلَغَكِ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهَا فَقَالَتْ قَالَ لَيْسَ مِنَّا مَنْ سَلَقَ وَحَلَقَ وَخَرَقَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Yazid bin Aus] dari [Abu Musa] bahwa ia pernah jatuh pingsan, kemudian istrinya menangis, setelah sadar, ia berkata kepadanya: \"Bukankah telah sampai kepadamu apa yang disabdakan Rasulullah shallallahu 'alaihi wasallam?!\" lalu kami bertanya -hal itu- kepada istrinya? Kemudian ia menjawab, beliau bersabda: \"Bukan termasuk golongan kami orang yang meratap, mencukur (rambut kepala dan jenggot) dan merobek (saku) -ketika tertimpa musibah.\""},"1798":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ يَزِيدَ بْنِ أَوْسٍ عَنْ أُمِّ عَبْدِ اللَّهِ امْرَأَةِ أَبِي مُوسَى عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ حَلَقَ وَسَلَقَ وَخَرَقَ","id":"Telah mengabarkan kepada kami ['Abdah bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Israil] dari [Manshur] dari [Ibrahim] dari [Yazid bin Aus] dari [Ummu 'Abdullah] -istri Abu Musa- dari [Abu Musa] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk golongan kami orang yang mencukur (rambut kepala dan jenggot), merobek (saku) dan meratap -ketika tertimpa musibah-.\""},"1799":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ سَهْمِ بْنِ مِنْجَابٍ عَنْ الْقَرْثَعِ قَالَلَمَّا ثَقُلَ أَبُو مُوسَى صَاحَتْ امْرَأَتُهُ فَقَالَ أَمَا عَلِمْتِ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ بَلَى ثُمَّ سَكَتَتْ فَقِيلَ لَهَا بَعْدَ ذَلِكَ أَيُّ شَيْءٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ مَنْ حَلَقَ أَوْ سَلَقَ أَوْ خَرَقَ","id":"Telah mengabarkan kepada kami [Hannad] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Sahm bin Minjab] dari [Al Qartsa'] dia berkata; \"Tatkala [Abu Musa] telah merasa berat (akan meninggal dunia), istrinya berteriak! Maka ia berkata, 'Tidakkah engkau tahu apa yang telah disabdakan Rasulullah shallallahu 'alaihi wasallam?! ' ia menjawab; 'Ya', kemudian ia diam. Lalu setelah ditanyakan kepadanya, 'Apa yang telah disabdakan oleh Rasulullah shallallahu 'alaihi wasallam?!\" ia menjawab, ' Rasulullah shallallahu 'alaihi wasallam melaknat orang yang mencukur (rambut kepala), meratap atau merobek (saku) -ketika tertimpa musibah-.\""},"1800":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ قَالَ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ قَالَأَرْسَلَتْ بِنْتُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ أَنَّ ابْنًا لِي قُبِضَ فَأْتِنَا فَأَرْسَلَ يَقْرَأُ السَّلَامَ وَيَقُولُ إِنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَ اللَّهِ بِأَجَلٍ مُسَمًّى فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَأَرْسَلَتْ إِلَيْهِ تُقْسِمُ عَلَيْهِ لَيَأْتِيَنَّهَا فَقَامَ وَمَعَهُ سَعْدُ بْنُ عُبَادَةَ وَمُعَاذُ بْنُ جَبَلٍ وَأُبَيُّ بْنُ كَعْبٍ وَزَيْدُ بْنُ ثَابِتٍ وَرِجَالٌ فَرُفِعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّبِيُّ وَنَفْسُهُ تَقَعْقَعُ فَفَاضَتْ عَيْنَاهُ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ مَا هَذَا قَالَ هَذَا رَحْمَةٌ يَجْعَلُهَا اللَّهُ فِي قُلُوبِ عِبَادِهِ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari ['Ashim bin Sulaiman] dari [Abu 'Utsman] dia berkata; telah menceritakan kepadaku [Usamah bin Zaid] dia berkata; \"Putri Nabi shallallahu 'alaihi wasallam mengutus seseorang kepada beliau, 'Bahwa anaku telah meninggal dunia, maka datanglah kepada kami! ' lalu beliau mengirim seseorang untuk mengucapkan salam dan mengatakan: \" milik Allah apa yang telah ia ambil dan miliknya apa yang telah diberikan, segala sesuatu telah ditentukan ajalnya disisi Allah, maka hendaknya bersabar dan berharap pahala.\" Lalu ia mengutus seseorang kepada beliau agar bersumpah akan mendatanginya. Kemudian beliau bangkit dan bersamanya Sa'd bin Ubadah, Mu'adz bin Jabal, Ubay bin Ka'b, Zaid bin Tsabit dan beberapa orang laki-laki. Lalu anak kecil itu dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam, jiwanya berdetak dan kedua matanya meneteskan air mata. Kemudian Sa'd berkata; \"Wahai Rasulullah, apa ini?\" beliau bersabda: \"Ini adalah rahmat yang Allah tumbuhkan didalam hati hamba-hamba-Nya, Allah mengasihi hamba-hamba-Nya yang berbelas kasih.\""},"1801":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Tsabit] dia berkata; Aku mendengar [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sabar adalah ketika mendapat tekanan (gejolak, hantaman) pertama kali.\""},"1802":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَبُو إِيَاسٍ وَهُوَ مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ ابْنٌ لَهُ فَقَالَ لَهُ أَتُحِبُّهُ فَقَالَ أَحَبَّكَ اللَّهُ كَمَا أُحِبُّهُ فَمَاتَ فَفَقَدَهُ فَسَأَلَ عَنْهُ فَقَالَ مَا يَسُرُّكَ أَنْ لَا تَأْتِيَ بَابًا مِنْ أَبْوَابِ الْجَنَّةِ إِلَّا وَجَدْتَهُ عِنْدَهُ يَسْعَى يَفْتَحُ لَكَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Abu Iyas Mu'awiyah bin Qurrah] dari [bapaknya] radliallahu 'anhu bahwa seseorang menemui Nabi shallallahu 'alaihi wasallam dengan membawa anaknya, beliau bertanya kepadanya: \"Apakah engkau mencintainya?\" ia menjawab: Kiranya Allah mencintaimu sebagaimana aku mencintainya. Kemudian hari anak itu meninggal dan ia pun merasa kehilangan. Lantas Ia bertanya tentang keadaan anaknya kepada beliau, lalu beliau bersabda: \"Tidaklah engkau ingin mendatangi pintu surga kecuali telah engkau dapatkan anakmu membukanya untukmu.\""},"1803":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ أَنْبَأَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ أَنَّ عَمْرَو بْنَ شُعَيْبٍ كَتَبَ إِلَى عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ يُعَزِّيهِ بِابْنٍ لَهُ هَلَكَ وَذَكَرَ فِي كِتَابِهِ أَنَّهُ سَمِعَ أَبَاهُ يُحَدِّثُ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَرْضَى لِعَبْدِهِ الْمُؤْمِنِ إِذَا ذَهَبَ بِصَفِيِّهِ مِنْ أَهْلِ الْأَرْضِ فَصَبَرَ وَاحْتَسَبَ وَقَالَ مَا أُمِرَ بِهِ بِثَوَابٍ دُونَ الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dia berkata; telah memberitakan kepada kami ['Umar bin Sa'id bin Abu Husain] bahwa [Amru bin Syu'aib] menulis untuk Abdullah bin Abdurrahman bin Abu Husain yang menyatakan bela sungkawa kepadanya karena anaknya telah meninggal dunia. Dalam tulisan tersebut disebutkan; bahwa ia pernah mendengar [bapaknya] bercerita, dari kakeknya, [Abdullah bin Amru bin Al Ash], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah tidak ridha terhadap hamba-Nya yang beriman apabila sahabat karibnya dari penduduk bumi meninggal dunia, -lalu ia bersabar dan mengharap pahala.\" Beliau bersabda: \" memperoleh ganjaran yang diperintahkan baginya selain surga.\""},"1804":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عَمْرٌو قَالَ حَدَّثَنِي بُكَيْرُ بْنُ عَبْدِ اللَّهِ عَنْ عِمْرَانَ بْنِ نَافِعٍ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ احْتَسَبَ ثَلَاثَةً مِنْ صُلْبِهِ دَخَلَ الْجَنَّةَ فَقَامَتْ امْرَأَةٌ فَقَالَتْ أَوْ اثْنَانِ قَالَ أَوْ اثْنَانِ قَالَتْ الْمَرْأَةُ يَا لَيْتَنِي قُلْتُ وَاحِدًا","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku ['Amru] dia berkata; telah menceritakan kepadaku [Bukair bin 'Abdullah] dari ['Imran bin Nafi'] dari [Hafsh bin 'Ubaidullah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa berharap pahala dari ketiga anak kandungnya -yang telah meninggal dunia-, maka ia akan masuk surga.\" Lalu ada seorang wanita berdiri, ia berkata, \"Bagaimana dengan dua anak?\" beliau bersabda: \"Atau dua anak. Wanita itu berkata; \"Duhai andai kata aku mengatakan, 'Satu'.\""},"1805":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ حَمَّادٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يُتَوَفَّى لَهُ ثَلَاثَةٌ مِنْ الْوَلَدِ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُ اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ إِيَّاهُمْ","id":"Telah mengabarkan kepada kami [Yusuf bin Hammad] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dari ['Abdul 'Aziz] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim yang ditinggal mati ketiga anaknya yang belum berusia dewasa, kecuali Allah akan memasukannya ke surga, karena keutamaan rahmat-Nya kepada mereka.\""},"1806":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ صَعْصَعَةَ بْنِ مُعَاوِيَةَ قَالَ لَقِيتُ أَبَا ذَرٍّقُلْتُ حَدِّثْنِي قَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمَيْنِ يَمُوتُ بَيْنَهُمَا ثَلَاثَةُ أَوْلَادٍ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا غَفَرَ اللَّهُ لَهُمَا بِفَضْلِ رَحْمَتِهِ إِيَّاهُمْ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Yunus] dari [Al Hasan] dari [Sha'sha'ah bin Mu'awiyah] dia berkata; Aku bertemu dengan [Abu Dzarr], Aku pernah bertemu dengan Abu Dzar, aku lalu berkata; \"Sampaikanlah hadits kepadaku?\" ia berkata; \"Ya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dua orang muslim meninggal dunia, di antara keduanya ada tiga orang anak (mereka adalah tiga bersaudara) yang belum berusia dewasa, kecuali Allah akan memasukkan keduanya ke surga dengan keutamaan rahmatNya kepada mereka.\""},"1807":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِأَحَدٍ مِنْ الْمُسْلِمِينَ ثَلَاثَةٌ مِنْ الْوَلَدِ فَتَمَسَّهُ النَّارُ إِلَّا تَحِلَّةَ الْقَسَمِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ibnu Syihab] dari [Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah tiga anak milik salah seorang dari kaum Muslimin meninggal dunia, lalu ia tersentuh api neraka, kecuali sebatas melewatinya saja, yang Allah telah bersumpah siapapun akan melewatinya.\""},"1808":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ ابْنِ عُلَيَّةَ وَعَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا إِسْحَقُ وَهُوَ الْأَزْرَقُ عَنْ عَوْفٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمَيْنِ يَمُوتُ بَيْنَهُمَا ثَلَاثَةُ أَوْلَادٍ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُمَا اللَّهُ بِفَضْلِ رَحْمَتِهِ إِيَّاهُمْ الْجَنَّةَ قَالَ يُقَالُ لَهُمْ ادْخُلُوا الْجَنَّةَ فَيَقُولُونَ حَتَّى يَدْخُلَ آبَاؤُنَا فَيُقَالُ ادْخُلُوا الْجَنَّةَ أَنْتُمْ وَآبَاؤُكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim bin 'Ulayyah] dan ['Abdurrahman bin Muhammad] mereka berkata; telah menceritakan kepada kami [Ishaq Al Azraq] dari ['Auf] dari [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah dua orang muslim meninggal dunia, di antara keduanya ada tiga orang anak (mereka adalah tiga bersaudara) yang belum berusia dewasa, kecuali Allah akan memasukkan keduanya ke surga dengan keutamaan rahmatNya kepada mereka.\" Beliau bersabda: \"Dikatakan kepada mereka; 'Masuklah kalian ke surga', lalu mereka berkata, '-Kami tidak akan masuk- hingga bapak-bapak kami masuk! ' lalu dikatakan; 'Masuklah kalian dan bapak-bapak kalian ke surga'.\""},"1809":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا جَرِيرٌ قَالَ حَدَّثَنِي طَلْقُ بْنُ مُعَاوِيَةَ وَحَفْصُ بْنُ غِيَاثٍ قَالَ حَدَّثَنِي جَدِّي طَلْقُ بْنُ مُعَاوِيَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا يَشْتَكِي فَقَالَتْ يَا رَسُولَ اللَّهِ أَخَافُ عَلَيْهِ وَقَدْ قَدَّمْتُ ثَلَاثَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ احْتَظَرْتِ بِحِظَارٍ شَدِيدٍ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami [Jarir] dia berkata; telah menceritakan kepadaku [Thalq bin Mu'awiyah] dan [Hafsh bin Ghiyats] dia berkata; kakekku [Thalq bin Mu'awiyah] menceritakan kepadaku dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; Seorang wanita datang menemui Rasulullah shallallahu 'alaihi wasallam dengan membawa anaknya yang sedang sakit dan mengeluh. Lalu ia berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, aku khawatir terhadapnya, dan sungguh aku telah mempersembahkan tiga anak'. maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh engkau telah terhalang dengan tabir yang kuat dari api neraka'.\""},"1810":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى زَيْدًا وَجَعْفَرًا قَبْلَ أَنْ يَجِيءَ خَبَرُهُمْ فَنَعَاهُمْ وَعَيْنَاهُ تَذْرِفَانِ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami [Sulaiman bin Harb] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Humaid bin Hilal] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam mengumumkan kematian Zaid dan Ja'far sebelum datang berita mereka, beliau mengumumkan kematian mereka dan beliau meneteskan air mata.\""},"1811":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ وَابْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لَهُمَا النَّجَاشِيَّ صَاحِبَ الْحَبَشَةِ الْيَوْمَ الَّذِي مَاتَ فِيهِ وَقَالَ اسْتَغْفِرُوا لِأَخِيكُمْ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Ya'qub] dia berkata; [bapakku] telah menceritakan kepada kami dari [Shalih] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Abu Salamah] dan [Ibnul Musayyab] bahwasanya [Abu Hurairah] mengabarkan kepada keduanya; \"Rasulullah shallallahu 'alaihi wasallam mengumumkan kematian An-Najasyi, penguasa Habasyah, pada hari wafatnya dan bersabda: \"Mintakanlah ampunan untuk saudara kalian.\""},"1812":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ هُوَ ابْنُ يَزِيدَ الْمُقْرِئُ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِيءُ قَالَ حَدَّثَنَا أَبِي قَالَ سَعِيدٌ حَدَّثَنِي رَبِيعَةُ بْنُ سَيْفٍ الْمَعَافِرِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَبَيْنَمَا نَحْنُ نَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ بَصُرَ بِامْرَأَةٍ لَا تَظُنُّ أَنَّهُ عَرَفَهَا فَلَمَّا تَوَسَّطَ الطَّرِيقَ وَقَفَ حَتَّى انْتَهَتْ إِلَيْهِ فَإِذَا فَاطِمَةُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا مَا أَخ��رَجَكِ مِنْ بَيْتِكِ يَا فَاطِمَةُ قَالَتْ أَتَيْتُ أَهْلَ هَذَا الْمَيِّتِ فَتَرَحَّمْتُ إِلَيْهِمْ وَعَزَّيْتُهُمْ بِمَيِّتِهِمْ قَالَ لَعَلَّكِ بَلَغْتِ مَعَهُمْ الْكُدَى قَالَتْ مَعَاذَ اللَّهِ أَنْ أَكُونَ بَلَغْتُهَا وَقَدْ سَمِعْتُكَ تَذْكُرُ فِي ذَلِكَ مَا تَذْكُرُ فَقَالَ لَهَا لَوْ بَلَغْتِهَا مَعَهُمْ مَا رَأَيْتِ الْجَنَّةَ حَتَّى يَرَاهَا جَدُّ أَبِيكِقَالَ أَبُو عَبْد الرَّحْمَنِ رَبِيعَةُ ضَعِيفٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Fadhalah bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri']. Demikkian juga diriwayatkan dari jalur lain, telah memberitakan kepada kami [Muhammad bin 'Abdullah bin Yazid Al Muqri'] dia berkata; [bapakku] telah menceritakan kepada kami, [Sa'id] berkata; telah menceritakan kepada kami [Rabi'ah bin Saif Al Ma'afiri] dari [Abu 'Abdurrahman Al Hubuli] dari ['Abdullah bin 'Amru] dia berkata; \"Ketika kami sedang berjalan bersama Rasulullah Shalallahu 'Alaihi Wa Sallam, tiba-tiba aku melihat seorang perempuan yang aku tidak menyangka kalau beliau mengenalinya. Tatkala beliau berjalan di tengah tiba-tiba beliau berhenti hingga wanita itu bertemu dengannya. Ternyata wanita itu adalah Fathimah binti Rasulullah Shalallahu 'Alaihi Wa Sallam. Lalu beliau berkata kepadanya; 'Kenapa kamu keluar dari rumah wahai Fathimah? Fathimah menjawab; 'Aku baru menjenguk keluarga Mayit ini dan aku merasa kasihan terhadap mereka sekaligus berta'ziyah. Rasulullah Shalallahu 'Alaihi Wa Sallam berkata kepadanya; 'Semoga kamu juga menyusul mereka ke kuburan.' Fathimah menjawab; 'Na'udzubillah kalau aku harus menyusul mereka, aku telah mendengar engkau menyebutkan tentang kuburan.' Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Kalau kamu menyusul mereka, kamu tidak akan melihat surga hingga kamu melihat kakek bapakmu.' Abu Abdurrahman berkata; 'Rabi'ah orangnya lemah.'"},"1813":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ أَنَّ أُمَّ عَطِيَّةَ الْأَنْصَارِيَّةَ قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَتْ ابْنَتُهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَعْطَانَا حَقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ayub] dari [Muhammad bin Sirin] bahwasanya [Ummu 'Athiyyah Al Anshariah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah masuk menemui kami ketika puterinya meninggal dunia, lalu beliau bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan bidara, dan pada bagian terakhir -di campur- dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai kami memberitahukan kepada beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\""},"1814":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْحَسَنِ مَوْلَى أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ عَنْ أُمِّ قَيْسٍ قَالَتْتُوُفِّيَ ابْنِي فَجَزِعْتُ عَلَيْهِ فَقُلْتُ لِلَّذِي يَغْسِلُهُ لَا تَغْسِلْ ابْنِي بِالْمَاءِ الْبَارِدِ فَتَقْتُلَهُ فَانْطَلَقَ عُكَّاشَةُ بْنُ مِحْصَنٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِقَوْلِهَا فَتَبَسَّمَ ثُمَّ قَالَ مَا قَالَتْ طَالَ عُمْرُهَا فَلَا نَعْلَمُ امْرَأَةً عَمِرَتْ مَا عَمِرَتْ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abul Hasan] -budak Ummu Qais bintu Mihshan- dari [Ummu Qais] dia berkata; \"Anakku meninggal maka aku sangat bersedih, aku katakan kepada yang memandikannya; 'Jangan kamu mandikan anakku dengan air dingin, karena jika demikan berarti kamu berarti telah membunuhnya. Ukasyah bin Mihsan lalu pergi menemui Rasulullah shallallahu 'alaihi wasallam mengabarkan perkataannya Ummu Qais. Rasulullah pun tersenyum kemudian bersabda: 'Apa yang dikatakannya akan memanjangkan umurnya.' maka kami tidak mengetahui seorang wanita yang lebih panjang umurnya dari dia.'"},"1815":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَيُّوبُ سَمِعْتُ حَفْصَةَ تَقُولُ حَدَّثَتْنَا أُمُّ عَطِيَّةَأَنَّهُنَّ جَعَلْنَ رَأْسَ ابْنَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ قُرُونٍ قُلْتُ نَقَضْنَهُ وَجَعَلْنَهُ ثَلَاثَةَ قُرُونٍ قَالَتْ نَعَمْ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; [Ayyub] aku mendengar [Hafshah] berkata; telah menceritakan kepada kami [Ummu 'Athiyyah] bahwa para wanita mengepang rambut kepala putri Nabi shallallahu 'alaihi wasallam menjadi tiga kepangan. Aku berkata; \"Kami mengurainya dan mengepangnya menjadi tiga kepangan?\" ia menjawab, \"Ya.\""},"1816":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ خَالِدٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي غَسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Khalid] dari [Hafshah] dari [Ummu 'Athiyyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda tentang memandikan puterinya, \"Mulailah dengan bagian-bagian kanan tubuh dan tempat wudlu dari dirinya.\""},"1817":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَتْنَا حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ قَالَتْمَاتَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْنَا فَقَالَ اغْسِلْنَهَا بِمَاءٍ وَسِدْرٍ وَاغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا إِنْ رَأَيْتُنَّ ذَلِكِ وَاجْعَلْنَ فِي الْآخِرَةِ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ وَمَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ وَأَلْقَيْنَاهَا مِنْ خَلْفِهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Hisyam] dia berkata; telah menceritakan kepada kami [Hafshah] dari [Ummu 'Athiyyah] dia berkata; \"Salah seorang puteri Nabi shallallahu 'alaihi wasallam meninggal dunia, lalu beliau mengutus kami, seraya bersabda: \"Mandikanlah ia dengan air dan bidara, dan mandikanlah dengan bilangan ganjil, tiga kali, lima kali atau tujuh kali -jika hal itu kalian anggap perlu-, dan pada terakhir kali dengan sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah selesai, kami memberitahu beliau, lalu beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\" Kami mengepangnya menjadi tiga kepangan dan kami letakkan di belakangnya.\""},"1818":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ يَزِيدَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Yazid] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin] dari [Ummu 'Athiyyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam masuk menemui kami yang waktu itu kami sedang memandikan puterinya, lalu beliau bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan daun bidara, dan pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai, kami memberitahukan beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\""},"1819":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْنَا فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُأَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] dia berkata; \"Salah seorang puteri Nabi shallallahu 'alaihi wasallam meninggal dunia, lalu beliau mengutus kami, lalu beliau bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan daun bidara, dan pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai, kami memberitahukan beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\" Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah] sebagaimana Hadits diatas, namun berbeda pada kalimat, \"Mandikanlah ia tiga kali, lima kali, atau lebih dari itu -jika hal itu kalian pandang perlu.\" Dengan menambahkan tujuh kali."},"1820":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ عَنْ سَلَمَةَ بْنِ عَلْقَمَةَ عَنْ مُحَمَّدٍ عَنْ بَعْضِ إِخْوَتِهِ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ ابْنَةٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنَا بِغَسْلِهَا فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ قَالَتْ قُلْتُ وِتْرًا قَالَ نَعَمْ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَعْطَانَا حِقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr] dari [Salamah bin 'Alqamah] dari [Muhammad] dari [sebagian saudaranya] dari [Ummu 'Athiyyah] dia berkata; Salah seorang puteri Nabi shallallahu 'alaihi wasallam meninggal dunia, lalu beliau menyuruh kami untuk memandikannya, beliau bersabda: \"Mandikanlah ia tiga kali, lima kali, tujuh kali atau lebih dari itu -jika hal itu kalian pandang perlu- Aku berkata; 'Dengan bilangannya yang ganjil?, beliau menjawab: Ya. Beliau melanjutkan; Dan hendaklah pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai, kami memberitahukan beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\""},"1821":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ قَالَ أَوْ قَالَتْ حَفْصَةُ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًاقَالَ وَقَالَتْ أُمُّ عَطِيَّةَ مَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ قَالَ أَخْبَرَتْنِي حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ قَالَتْ وَجَعَلْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَقَالَتْ حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ وَجَعَلْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam menemui kami yang waktu itu kami sedang memandikan putrinya, lalu beliau bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan daun bidara, dan pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai, kami memberitahukan beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\" Ummu 'Athiyyah berkata; 'Mandikanlah ia tiga kali, lima kali, atau tujuh kali. Dan Ummu 'Athiyyah berkata; 'kami mengepangnya dengan tiga kepangan.' Telah mengabarkan kepada kami Muhammad bin Manshur dia berkata; Telah menceritakan kepada kami Sufyan dia berkata; Telah menceritakan kepada kami Ayyub dari Muhammad dia berkata; Telah mengabarkan kepadaku Hafshah dari Ummu 'Athiyyah dia berkata; 'Kami menjadikan rambut kepalanya tiga kepangan. Telah mengabarkan kepada kami Qutaibah bin Sa'id dia berkata; telah menceritakan kepada kami Hammad dari Ayyub dan Hafshah berkata; dari Ummu Athiyyah; 'Kami menjadikan rambut kepalanya menjadi tiga kepangan.'"},"1822":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَيُّوبُ بْنُ أَبِي تَمِيمَةَ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ سِيرِينَ يَقُولُكَانَتْ أُمُّ عَطِيَّةَ امْرَأَةٌ مِنْ الْأَنْصَارِ قَدِمَتْ تُبَادِرُ ابْنًا لَهَا فَلَمْ تُدْرِكْهُ حَدَّثَتْنَا قَالَتْ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا أَلْقَى إِلَيْنَا حِقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُ وَلَمْ يَزِدْ عَلَى ذَلِكَقَالَ لَا أَدْرِي أَيُّ بَنَاتِهِ قَالَ قُلْتُ مَا قَوْلُهُ أَشْعِرْنَهَا إِيَّاهُ أَتُؤَزَّرُ بِهِ قَالَ لَا أُرَاهُ إِلَّا أَنْ يَقُولَ الْفُفْنَهَا فِيهِ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Ayyub bin Abu Tamimah] bahwasanya ia mendengar [Muhammad bin Sirin] berkata; bahwasanya [Ummu 'Athiyyah] -seorang wanita Anshar- datang hendak menyusul anaknya, tetapi tidak mendapatkannya! Ia telah menceritakan kepada kami seraya berkata; 'Nabi shallallahu 'alaihi wasallam masuk menemui kami pada saat kami memandikan puterinya, lalu bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan daun bidara, dan pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Setelah kami selesai kami memberitahukan beliau, kemudian beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.' Dan tidak lebih dari itu.\" Muhammad bin Sirrin berkata; \"Aku tidak mengetahui putri beliau yang mana?\" ia berkata; \"Aku bertanya, 'Apa maksud sabda beliau: 'Bungkuslah ia dengan kain ini? Apakah ia diberi pakaian bawah dengan kain tersebut? '.\" Ia menjawab, \"Aku tidak mengetahuinya kecuali beliau hanya bersabda: \"Balutlah ia dengan kain ini.\""},"1823":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ النَّسَائِيُّ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ وَاغْسِلْنَهَا بِالسِّدْرِ وَالْمَاءِ وَاجْعَلْنَ فِي آخِرِ ذَلِكِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي قَالَتْ فَآذَنَّاهُ فَأَلْقَى إِلَيْنَا حِقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf An Nasaa'i] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Ummu 'Athiyyah] dia berkata; \"Salah seorang putri Nabi shallallahu 'alaihi wasallam meninggal dunia, lalu beliau bersabda: \"Mandikanlah ia tiga kali, lima kali atau lebih dari itu -jika hal itu kalian pandang perlu- dengan air dan daun bidara, dan pada bagian terakhir kali dengan kapur barus atau sedikit kapur barus, jika kalian telah selesai, maka beritahulah aku.\" Ummu Abu Athahiyyah berkata; Setelah selesai kami memberitahukan beliau, lalu beliau memberikan kainnya kepada kami seraya bersabda: \"Bungkuslah ia dengan kain ini.\""},"1824":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ الرَّقِّيُّ الْقَطَّانُ وَيُوسُفُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ قَالَ أَنْبَأَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ رَجُلًا مِنْ أَصْحَابِهِ مَاتَ فَقُبِرَ لَيْلًا وَكُفِّنَ فِي كَفَنٍ غَيْرِ طَائِلٍ فَزَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْبَرَ إِنْسَانٌ لَيْلًا إِلَّا أَنْ يُضْطَرَّ إِلَى ذَلِكَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلِيَ أَحَدُكُمْ أَخَاهُ فَلْيُحَسِّنْ كَفْنَهُ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Khalid Ar Raqqi Al Qaththan] dan [Yusuf bin Sa'id] -dan lafadz ini miliknya- dia berkata; telah memberitakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir] berkata; \"Rasulullah shallallahu 'alaihi wasallam berkhutbah, beliau menyebutkan salah seorang dari sahabatnya yang meninggal, lalu dikubur pada malam hari dan dikafani dengan kain kafan yang tidak besar, maka Rasulullah shallallahu 'alaihi wasallam mencegah seseorang di kubur di malam hari, kecuali jika mendesak. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengurusi saudaranya (yang meninggal), maka hendaknya ia membaguskan kain kafannya'.\""},"1825":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ أَبِي عَرُوبَةَ يُحَدِّثُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَسُوا مِنْ ثِيَابِكُمْ الْبَيَاضَ فَإِنَّهَا أَطْهَرُ وَأَطْيَبُ وَكَفِّنُوا فِيهَا مَوْتَاكُمْ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah memberitakan kepada kami [Yahya bin Sa'id] dia berkata; aku mendengar [Sa'id bin Abu 'Arubah] menceritakan dari [Ayyub] dari [Abu Qibalah] dari [Abul Muhallab] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pakailah baju kalian yang berwarna putih, karena itu lebih suci dan lebih baik, dan kafanilah orang-orang yang meninggal diantara kalian dengan kain tersebut.\""},"1826":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُفِّنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ سُحُولِيَّةٍ بِيضٍ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Nabi shallallahu 'alaihi wasallam dikafani dengan tiga lembar kain putih yang terbuat dari katun.\""},"1827":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ سُحُولِيَّةٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam dikafani dengan tiga lembar kain putih yang terbuat dari katun, tanpa ada baju dan serban.\""},"1828":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَفْصٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ يَمَانِيَةٍ كُرْسُفٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ فَذُكِرَ لِعَائِشَةَ قَوْلُهُمْ فِي ثَوْبَيْنِ وَبُرْدٍ مِنْ حِبَرَةٍ فَقَالَتْ قَدْ أُتِيَ بِالْبُرْدِ وَلَكِنَّهُمْ رَدُّوهُ وَلَمْ يُكَفِّنُوهُ فِيهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hafsh] dari [Hisyam] dari [bapaknya] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam dikafani dengan tiga lembar kain putih buatan Yaman berbahan dari katun, tanpa ada baju dan serban.\" Lalu perkataan mereka disebutkan kepada Aisyah, \"(dengan dua kain dan satu kain dari katun bermotif dari Yaman!) \" ia berkata; \"kain katun dengan motif itu telah dibawakan, namun mereka menolaknya dan mereka tidak mengkafani beliau dengan kain itu.\""},"1829":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اعْطِنِي قَمِيصَكَ حَتَّى أُكَفِّنَهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ قَمِيصَهُ ثُمَّ قَالَ إِذَا فَرَغْتُمْ فَآذِنُونِي أُصَلِّي عَلَيْهِ فَجَذَبَهُ عُمَرُ وَقَالَ قَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيرَتَيْنِ قَالَ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ فَصَلَّى عَلَيْهِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dia berkata; telah menceritakan kepada kami [Nafi'] dari ['Abdullah bin 'Umar] dia berkata; Setelah Abdullah bin Ubai meninggal dunia, anaknya datang menemui Nabi shallallahu 'alaihi wasallam, lalu ia berkata; 'Berikanlah baju engkau kepadaku hingga aku mengkafaninya dengan baju itu, shalatkanlah ia dan mintalah ampunan untuknya!\"lalu beliau memberikan bajunya kepada anak tersebut. Kemudian beliau bersabda: \"Jika kalian telah selesai, beritahulah aku, aku akan menshalatkannya. Lalu Umar menariknya seraya berkata; 'Sungguh Allah telah melarang engkau untuk menshalatkan orang-orang munafik'. Maka beliau bersabda: \"Aku berada diantara dua pilihan 'mintalah ampunan untuk mereka atau engkau tidak meminta ampunan untuk mereka', maka beliau menshalatkannya. Kemudian Allah Ta'ala menurunkan ayat, Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati diantara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya'. maka beliaupun akhirnya tidak lagi menshalatkan mereka.\""},"1830":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرًا يَقُولُأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرَ عَبْدِ اللَّهِ بْنِ أُبَيٍّ وَقَدْ وُضِعَ فِي حُفْرَتِهِ فَوَقَفَ عَلَيْهِ فَأَمَرَ بِهِ فَأُخْرِجَ لَهُ فَوَضَعَهُ عَلَى رُكْبَتَيْهِ وَأَلْبَسَهُ قَمِيصَهُ وَنَفَثَ عَلَيْهِ مِنْ رِيقِهِ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Abdul Jabbar bin Al 'Ala bin 'Abdul Jabbar] dari [Sufyan] dari ['Amru] dia berkata; Aku mendengar [Jabir] berkata; \"Nabi shallallahu 'alaihi wasallam pernah mendatangi kuburan Abdullah bin Ubai -sementara ia telah diletakkan didekat lahadnya- lalu beliau berdiri di sampingnya, beliau kemudian menyuruh untuk mengeluarkannya, lalu diletakkan diatas lututnya, beliau kemudian memakaikan bajunya dan meniup sedikit air liurnya.\" Wallahhu Ta'ala A'lam."},"1831":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ الْبَصْرِىُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرًا يَقُولُوَكَانَ الْعَبَّاسُ بِالْمَدِينَةِ فَطَلَبَتْ الْأَنْصَارُ ثَوْبًا يَكْسُونَهُ فَلَمْ يَجِدُوا قَمِيصًا يَصْلُحُ عَلَيْهِ إِلَّا قَمِيصَ عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَكَسَوْهُ إِيَّاهُ","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad bin 'Abdurrahman Az Zuhri Al Bashri] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr], dia mendengar [Jabir] berkata; ketika itu Abbas berada di Madinah, orang-orang Anshar meminta pakaian agar dipakai olehnya, namun mereka tidak mendapatkan pakaian yang cocok untuknya kecuali pakaian Abdullah bin Ubay maka mereka pun memakaikannya."},"1832":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَعْمَشِ ح و أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ قَالَ سَمِعْتُ الْأَعْمَشَ قَالَ سَمِعْتُ شَقِيقًا قَالَ حَدَّثَنَا خَبَّابٌ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبْتَغِي وَجْهَ اللَّهِ تَعَالَى فَوَجَبَ أَجْرُنَا عَلَى اللَّهِ فَمِنَّا مَنْ مَاتَ لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ فَلَمْ نَجِدْ شَيْئًا نُكَفِّنُهُ فِيهِ إِلَّا نَمِرَةً كُنَّا إِذَا غَطَّيْنَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا بِهَا رِجْلَيْهِ خَرَجَتْ رَأْسُهُ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُغَطِّيَ بِهَا رَأْسَهُ وَنَجْعَلَ عَلَى رِجْلَيْهِ إِذْخِرًا وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَاوَاللَّفْظُ لِإِسْمَعِيلَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Al A'masy]. Demikian juga diriwayatkan dari jalur lain, telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dia berkata; Aku mendengar [Al A'masy] dia berkata; Aku mendengar [Syaqiq] dia berkata; telah menceritakan kepada kami [Khabbab] dia berkata; \"kami berhijrah bersama Rasulullah shallallahu 'alaihi wasallam dengan mengharap ridla Allah ta'ala, maka Allah akan memberi ganjaran kepada kami, diantara kami ada yang meninggal dan belum mendapatkan ganjaran sedikitpun, diantaranya adalah Mush'ab bin Umair yang terbunuh pada perang Uhud, dan kami tidak mendapatkan sesuatu untuk mengkafaninya kecuali sepotong kain; jika kami menutup kepalanya, kedua kakinya keluar dari kain (terlihat) dan jika kami menutup kakinya, kepalanya keluar dari kain (terlihat). Maka Rasulullah shallallahu 'alaihi wasallam menyuruh kami untuk menutup kepalanya dengan kain tersebut dan menutup kakinya dengan idzkhir (rumput-rumputan berbau harum: penerj). Juga diantara kami ada yang memliki buah yang sudah masak dan ia memetiknya.\" Lafazh ini dari Ismail."},"1833":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يُونُسُ بْنُ نَافِعٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوا الْمُحْرِمَ فِي ثَوْبَيْهِ اللَّذَيْنِ أَحْرَمَ فِيهِمَا وَاغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْهِ وَلَا تُمِسُّوهُ بِطِيبٍ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ مُحْرِمًا","id":"Telah mengabarkan kepada kami ['Utbah bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Yunus bin Nafi'] dari ['Amru bin Dinar] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandikanlah orang yang berihram itu dengan dua pakaian yang ia kenakan untuk berihram dan mandikanlah ia dengan air dan daun bidara, kafanilah ia dengan dua kainnya, janganlah diberi wangi-wangian (parfum) dan jangan ditutup kepalanya, karena kelak ia akan dibangkitkan pada hari kiamat dalam keadaan berihram.\""},"1834":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ وَشَبَابَةُ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ خُلَيْدِ بْنِ جَعْفَرٍ سَمِعَ أَبَا نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْيَبُ الطِّيبِ الْمِسْكُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Dawud] dan [Syababah] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Khulaid bin Ja'far] dia mendengar [Abu Nadlrah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Parfum yang paling harum adalah misik.\""},"1835":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ الدِّرْهَمِيُّ قَالَ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ عَنْ الْمُسْتَمِرِّ بْنِ الرَّيَّانِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْرِ طِيبِكُمْ الْمِسْكُ","id":"Telah mengabarkan kepada kami ['Ali bin Al Husain Ad Dirhami] dia berkata; telah menceritakan kepada kami [Umayyah bin Khalid] dari [Al Mustamir bin Ar Rayyan] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara parfum kalian yang paling wangi adalah misik.\""},"1836":{"ar":"أَخْبَرَنَا قُتَيْبَةُ فِي حَدِيثِهِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ أَنَّهُ أَخْبَرَهُأَنَّ مِسْكِينَةً مَرِضَتْ فَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَرَضِهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُ الْمَسَاكِينَ وَيَسْأَلُ عَنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَاتَتْ فَآذِنُونِي فَأُخْرِجَ بِجَنَازَتِهَا لَيْلًا وَكَرِهُوا أَنْ يُوقِظُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُخْبِرَ بِالَّذِي كَانَ مِنْهَا فَقَالَ أَلَمْ آمُرْكُمْ أَنْ تُؤْذِنُونِي بِهَا قَالُوا يَا رَسُولَ اللَّهِ كَرِهْنَا أَنْ نُوقِظَكَ لَيْلًا فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى صَفَّ بِالنَّاسِ عَلَى قَبْرِهَا وَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dalam haditsnya dari [Malik] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl bin Hunaif] bahwasanya ia mengabarkan kepadanya bahwa seorang wanita miskin sakit, lalu hal itu dikabarkan kepada Rasulullah shallallahu 'alaihi wasallam, dan Rasulullah shallallahu 'alaihi wasallam biasa mengunjungi para fakir miskin serta bertanya tentang keadaan mereka. kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ia meninggal dunia maka beritahulah aku\". Lalu jenazah wanita itu dikeluarkan di malam hari, dan mereka tidak ingin membangunkan Rasulullah shallallahu 'alaihi wasallam (karena takut mengganggu). Pada pagi harinya Rasulullah shallallahu 'alaihi wasallam diberitahukan tentang sesuatu yang terjadi pada wanita itu. Maka beliau bersabda: \"Bukankah aku telah menyuruh kalian untuk memberitahukan kepadaku tentangnya?\" mereka menjawab; \"Wahai Rasulullah shallallahu 'alaihi wasallam kami tidak ingin membangunkan engkau di malam hari\". Lalu Rasulullah shallallahu 'alaihi wasallam keluar hingga orang-orang berbaris bersama beliau di atas kuburannya dan beliau bertakbir empat kali (shalat jenazah).\""},"1837":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مِهْرَانَ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا وُضِعَ الرَّجُلُ الصَّالِحُ عَلَى سَرِيرِهِ قَالَ قَدِّمُونِي قَدِّمُونِي وَإِذَا وُضِعَ الرَّجُلُ يَعْنِي السُّوءَ عَلَى سَرِيرِهِ قَالَ يَا وَيْلِي أَيْنَ تَذْهَبُونَ بِي","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] dari ['Abdurrahman bin Mihran] bahwasanya [Abu Hurairah] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika jenazah orang shalih diletakkan di atas keranda, ia akan mengatakan, \"Segerakanlah aku, Segerakanlah aku! Jika jenazah itu -orang jelek- telah di letakan, ia akan mengatakan, 'celakalah aku! Kemanakah kalian akan membawaku? '.\""},"1838":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَتْ الْجَنَازَةُ فَاحْتَمَلَهَا الرِّجَالُ عَلَى أَعْنَاقِهِمْ فَإِنْ كَانَتْ صَالِحَةً قَالَتْ قَدِّمُونِي قَدِّمُونِي وَإِنْ كَانَتْ غَيْرَ صَالِحَةٍ قَالَتْ يَا وَيْلَهَا إِلَى أَيْنَ تَذْهَبُونَ بِهَا يَسْمَعُ صَوْتَهَا كُلُّ شَيْءٍ إِلَّا الْإِنْسَانَ وَلَوْ سَمِعَهَا الْإِنْسَانُ لَصَعِقَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [bapaknya] bahwasanya ia mendengar [Abu Sa'id Al Khudri] dia berkata; \"Jika jenazah telah diletakkan, maka orang-orang membawanya diatas pundak-pundak mereka. Jika orang baik maka akan berkata; \"Segeralah aku, Segeralah aku! Jika jenazah itu bukan orang shalih ia akan mengatakan, 'celakalah aku! Kemanakah kalian akan membawanya?! ' segala sesuatu akan mendengar suaranya kecuali manusia! andaikata manusia mendengarnya, pasti akan pingsan.\""},"1839":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْرِعُوا بِالْجَنَازَةِ فَإِنْ تَكُ صَالِحَةً فَخَيْرٌ تُقَدِّمُونَهَا إِلَيْهِ وَإِنْ تَكُ غَيْرَ ذَلِكَ فَشَرٌّ تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] haditsnya telah sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bergegaslah dalam membawa jenazah -menuju kuburan-, jika jenazahnya orang shalih maka menyegerakannya itu lebih baik. Namun jika bukan orang shalih, maka sungguh buruk jika kalian meletakkannya di pundak kalian.\""},"1840":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلٍ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَسْرِعُوا بِالْجَنَازَةِ فَإِنْ كَانَتْ صَالِحَةً قَدَّمْتُمُوهَا إِلَى الْخَيْرِ وَإِنْ كَانَتْ غَيْرَ ذَلِكَ كَانَتْ شَرًّا تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Yunus] dari [Az Zuhri] dia berkata; telah menceritakan kepada kami [Abu Umamah bin Sahl] bahwasanya [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergegaslah dalam membawa jenazah -menuju kuburan-, jika jenazahnya orang shalih maka menyegerakannya itu lebih baik. Namun jika bukan orang shalih, maka sungguh buruk jika kalian meletakkannya di pundak kalian.\""},"1841":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ أَنْبَأَنَا عُيَيْنَةُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ يُونُسَ قَالَ حَدَّثَنِي أَبِي قَالَشَهِدْتُ جَنَازَةَ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ وَخَرَجَ زِيَادٌ يَمْشِي بَيْنَ يَدَيْ السَّرِيرِ فَجَعَلَ رِجَالٌ مِنْ أَهْلِ عَبْدِ الرَّحْمَنِ وَمَوَالِيهِمْ يَسْتَقْبِلُونَ السَّرِيرَ وَيَمْشُونَ عَلَى أَعْقَابِهِمْ وَيَقُولُونَ رُوَيْدًا رُوَيْدًا بَارَكَ اللَّهُ فِيكُمْ فَكَانُوا يَدِبُّونَ دَبِيبًا حَتَّى إِذَا كُنَّا بِبَعْضِ طَرِيقِ الْمِرْبَدِ لَحِقَنَا أَبُو بَكْرَةَ عَلَى بَغْلَةٍ فَلَمَّا رَأَى الَّذِي يَصْنَعُونَ حَمَلَ عَلَيْهِمْ بِبَغْلَتِهِ وَأَهْوَى إِلَيْهِمْ بِالسَّوْطِ وَقَالَ خَلُّوا فَوَالَّذِي أَكْرَمَ وَجْهَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّا لَنَكَادُ نَرْمُلُ بِهَا رَمَلًا فَانْبَسَطَ الْقَوْمُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah memberitakan kepada kami ['Uyainah bin 'Abdurrahman bin Yunus] dia berkata; [bapakku] telah menceritakan kepadaku, dia berkata; \"Aku menyaksikan jenazah Abdurrahman bin Sammurah, dan Ziyad keluar berjalan di depan keranda, lalu orang-orang dari keluarga Abdurrahman dan budak-budak mereka segera menyambut keranda tersebut dengan berjalan kaki. Mereka berkata; \"Pelan-pelan semoga Allah memberkati kalian.\" Lalu mereka berjalan perlahan-lahan, hingga ketika kami berada di dalam Mirbad, kami bertemu dengan [Abu Bakrah] sedang berada di atas bighal (kuda kecil). Setelah melihat apa yang mereka perbuat, ia membawa mereka di atas bighalnya dan mengulurkan cambuknya untuk manuntun mereka seraya berkata; 'Minggirlah, demi Dzat yang telah memulyakan wajah Abul Qasim shallallahu 'alaihi wasallam, aku mendapatkan kami bersama Rasulullah shallallahu 'alaihi wasallam, dan kami hampir membawanya (jenazah) dengan cepat.' Maka orang-orang pun bergembira.\""},"1842":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ وَهُشَيْمٌ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَلَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّا لَنَكَادُ نَرْمُلُ بِهَا رَمَلًاوَاللَّفْظُ حَدِيثُ هُشَيْمٍ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dari [Isma'il] dan [Husyaim] dari ['Uyainah bin 'Abdurrahman] dari [bapaknya] dari [Abu Bakrah] dia berkata; \"Sungguh aku telah melihat kami bersama Rasulullah shallallahu 'alaihi wasallam dan saat itu kami hampir berjalan cepat dengan -membawa- jenazah.\" Lafazh ini dari Hadits Husyaim."},"1843":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ عَنْ يَحْيَى أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَّتْ بِكُمْ جَنَازَةٌ فَقُومُوا فَمَنْ تَبِعَهَا فَلَا يَقْعُدْ حَتَّى تُوضَعَ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] dia berkata; telah menceritakan kepada kami [Abu Isma'il] dari [Yahya] bahwasanya [Abu Salamah] menceritakan kepadanya dari [Abu Sa'id] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika sebuah jenazah melewati kalian maka berdirilah, barangsiapa yang mengikutinya janganlah ia duduk hingga jenazah itu dikuburkan.\""},"1844":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَى أَحَدُكُمْ الْجَنَازَةَ فَلَمْ يَكُنْ مَاشِيًا مَعَهَا فَلْيَقُمْ حَتَّى تُخَلِّفَهُ أَوْ تُوضَعَ مِنْ قَبْلِ أَنْ تُخَلِّفَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang di antara kalian melihat jenazah dan tidak mengiringinya, hendaknya berdiri hingga jenazah melewatinya atau jenazah diletakkan sebelum melewatinya.\""},"1845":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ عَامِرِ بْنِ رَبِيعَةَ الْعَدَوِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا حَتَّى تُخَلِّفَكُمْ أَوْ تُوضَعَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] dari ['Amir bin Rabi'ah Al 'Adawi] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika kalian melihat jenazah, berdirilah hingga jenazah melewati kalian atau jenazah diletakkan.\""},"1846":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ هِشَامٍ ح و أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا فَمَنْ تَبِعَهَا فَلَا يَقْعُدْ حَتَّى تُوضَعَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Hisyam]. Demikian juga diriwayatkan dari jalur lain, telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Sa'id] dia berkata; \"Jika kalian melihat jenazah, berdirilah, barang siapa yang mengikutinya, maka janganlah ia duduk sampai jenazah diletakkan.\""},"1847":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ قَالَامَا رَأَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهِدَ جَنَازَةً قَطُّ فَجَلَسَ حَتَّى تُوضَعَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dari [Ibnu 'Ajlan] dari [Sa'id] dari [Abu Hurairah] dan [Abu Sa'id] mereka berkata; \"Tidaklah kami melihat Rasulullah shallallahu 'alaihi wasallam menyaksikan jenazah kemudian duduk, hingga jenazah tersebut di letakkan.\""},"1848":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا زَكَرِيَّا عَنْ الشَّعْبِيِّ قَالَ قَالَ أَبُو سَعِيدٍ ح و أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ يُحَدِّثُ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرُّوا عَلَيْهِ بِجَنَازَةٍ فَقَامَ وَقَالَ عَمْرٌو إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّتْ بِهِ جَنَازَةٌ فَقَامَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Zakaria] dari [Asy Sya'bi] dia berkata; [Abu Sa'id] berkata; 'Demikian juga diriwayatkan dari jalur lain, telah mengabarkan kepada kami [Ibrahim bin Ya'qub bin Ishaq] dia berkata; telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Abdullah bin Abu As Safar] dia berkata; Aku mendengar [Asy Sya'bi] menceritakan dari [Abu Sa'id] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati jenazah, beliau lalu berdiri. Amru berkata; \"Bahwa satu jenazah -diusung- lewat di hadapan Rasulullah shallallahu 'alaihi wasallam, lalu beliau berdiri.\""},"1849":{"ar":"أَخْبَرَنِي أَيُّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ عَنْ عَمِّهِ يَزِيدَ بْنِ ثَابِتٍأَنَّهُمْ كَانُوا جُلُوسًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَلَعَتْ جَنَازَةٌ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ مَنْ مَعَهُ فَلَمْ يَزَالُوا قِيَامًا حَتَّى نَفَذَتْ","id":"Telah mengabarkan kepadaku [Ayyub bin Muhammad Al Wazzan] dia berkata; telah menceritakan kepada kami [Marwan] dia berkata; telah menceritakan kepada kami ['Utsman bin Hakim] dia berkata; telah mengabarkan kepadaku [Kharijah bin Zaid bin Tsabit] dari pamannya [Yazid bin Tsabit] bahwa ketika mereka duduk bersama Nabi shallallahu 'alaihi wasallam, ada jenazah muncul (melewatinya), maka Rasulullah shallallahu 'alaihi wasallam berdiri dan orang-orang yang bersamanya pun ikut berdiri. Mereka terus berdiri hingga jenazah itu lewat.\""},"1850":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَكَانَ سَهْلُ ابْنُ حُنَيْفٍ وَقَيْسُ بْنُ سَعْدِ بْنِ عُبَادَةَ بِالْقَادِسِيَّةِ فَمُرَّ عَلَيْهِمَا بِجَنَازَةٍ فَقَامَا فَقِيلَ لَهُمَا إِنَّهَا مِنْ أَهْلِ الْأَرْضِ فَقَالَا مُرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَنَازَةٍ فَقَامَ فَقِيلَ لَهُ إِنَّهُ يَهُودِيٌّ فَقَالَ أَلَيْسَتْ نَفْسًا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari ['Abdurrahman bin Abu Laila] dia berkata; [Sahl bin Hunaif] dan [Qais bin Sa'd bin 'Ubadah] berada di Qadisiyyah, lalu sebuah jenazah melewati mereka, kemudian keduanya berdiri, lalu dikatakan kepada mereka berdua ia adalah penduduk asli. keduanya berkata; telah melewati sebuah jenazah di depan Rasulullah shallallahu 'alaihi wasallam, lalu beliau berdiri dan dikatakan kepada beliau bahwa ia adalah seorang Yahudi kemudian beliau bersabda: \"Bukankah ia juga orang?.\""},"1851":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ هِشَامٍ ح و أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَمَرَّتْ بِنَا جَنَازَةٌ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْنَا مَعَهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا هِيَ جَنَازَةُ يَهُودِيَّةٍ فَقَالَ إِنَّ لِلْمَوْتِ فَزَعًا فَإِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوااللَّفْظُ لِخَالِدٍ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Hisyam]. Demikian juga diriwayatkan dari jalur lain, dan telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari ['Ubaidullah bin Miqsam] dari [Jabir bin 'Abdullah] dia berkata; \"Sebuah jenazah lewat didepan kami lalu Rasulullah shallallahu 'alaihi wasallam berdiri dan kami berdiri bersama beliau, aku berkata; 'Ya Rasulullah ia adalah jenazah seorang wanita Yahudi.' Beliau bersabda: \" Sungguh kematian membawa ketakutan, jika kalian melihat jenazah maka berdirilah.\" Lafazh ini dari Khalid."},"1852":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ قَالَكُنَّا عِنْدَ عَلِيٍّ فَمَرَّتْ بِهِ جَنَازَةٌ فَقَامُوا لَهَا فَقَالَ عَلِيٌّ مَا هَذَا قَالُوا أَمْرُ أَبِي مُوسَى فَقَالَ إِنَّمَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجَنَازَةِ يَهُودِيَّةٍ وَلَمْ يَعُدْ بَعْدَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dia berkata; \"Kami pernah berada di tempat [Ali], lalu ada jenazah lewat di hadapannya, maka mereka berdiri demi jenazah tersebut, lalu Ali bertanya: \"Apa ini?\" mereka menjawab; \"Urusan Abu Musa\". Ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berdiri karena ada jenazah seorang Yahudi dan setelah itu beliau tidak melakukan lagi'.\""},"1853":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍأَنَّ جَنَازَةً مَرَّتْ بِالْحَسَنِ بْنِ عَلِيٍّ وَابْنِ عَبَّاسٍ فَقَامَ الْحَسَنُ وَلَمْ يَقُمْ ابْنُ عَبَّاسٍ فَقَالَ الْحَسَنُ أَلَيْسَ قَدْ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجَنَازَةِ يَهُودِيٍّ قَالَ ابْنُ عَبَّاسٍ نَعَمْ ثُمَّ جَلَسَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad]; bahwasanya sebuah jenazah -diusung- lewat di hadapan [Hasan bin Ali] dan [Ibnu Abbas], lalu Hasan berdiri dan Ibnu Abbas tidak berdiri, kemudian Hasan berkata, \"Bukankah Rasulullah shallallahu 'alaihi wasallam berdiri untuk jenazah seorang wanita Yahudi?!\" Ibnu Abbas berkata; \"Benar, kemudian beliau duduk.\""},"1854":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا مَنْصُورٌ عَنْ ابْنِ سِيرِينَ قَالَمُرَّ بِجَنَازَةٍ عَلَى الْحَسَنِ بْنِ عَلِيٍّ وَابْنِ عَبَّاسٍ فَقَامَ الْحَسَنُ وَلَمْ يَقُمْ ابْنُ عَبَّاسٍ فَقَالَ الْحَسَنُ لِابْنِ عَبَّاسٍ أَمَا قَامَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ عَبَّاسٍ قَامَ لَهَا ثُمَّ قَعَدَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah memberitakan kepada kami [Manshur] dari [Ibnu Sirin] dia berkata; \"Ada jenazah diusung melewati [Al Hasan bin Ali] dan [Ibnu Abbas], lalu Al Hasan berdiri namun Ibnu Abbas tidak berdiri, Maka Al Hasan bertanya kepada Ibnu Abbas; 'Bukankah Rasulullah shallallahu 'alaihi wasallam berdiri karena ada jenazah? ' Ibnu Abbas berkata; 'Beliau berdiri untuknya, kemudian duduk.'"},"1855":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ عُلَيَّةَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ وَالْحَسَنِ بْنِ عَلِيٍّمَرَّتْ بِهِمَا جَنَازَةٌ فَقَامَ أَحَدُهُمَا وَقَعَدَ الْآخَرُ فَقَالَ الَّذِي قَامَ أَمَا وَاللَّهِ لَقَدْ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَامَ قَالَ لَهُ الَّذِي جَلَسَ لَقَدْ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَلَسَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Ibnu 'Ulayyah] dari [Sulaiman At Taimi] dari [Abu Mijlaz] dari [Ibnu 'Abbas] dan [Al Hasan bin 'Ali], ada jenazah -diusung- lewat dihadapan mereka berdua, lalu salah satu dari keduanya berdiri dan yang lain duduk. Orang yang berdiri berkata; \"Demi Allah! Sungguh aku mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam berdiri?!\" Orang yang duduk berkata kepadanya; 'Sungguh aku mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam duduk.'"},"1856":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ هَارُونَ الْبَلْخِيُّ قَالَ حَدَّثَنَا حَاتِمٌ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ أَنَّ الْحَسَنَ بْنَ عَلِيٍّكَانَ جَالِسًا فَمُرَّ عَلَيْهِ بِجَنَازَةٍ فَقَامَ النَّاسُ حَتَّى جَاوَزَتْ الْجَنَازَةُ فَقَالَ الْحَسَنُ إِنَّمَا مُرَّ بِجَنَازَةِ يَهُودِيٍّ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى طَرِيقِهَا جَالِسًا فَكَرِهَ أَنْ تَعْلُوَ رَأْسَهُ جَنَازَةُ يَهُودِيٍّ فَقَامَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Harun Al Balkhi] dia berkata; telah menceritakan kepada kami [Hatim] dari [Ja'far bin Muhammad] dari [bapaknya] bahwasanya [Al Hasan bin 'Ali] Bahwa Al Hasan bin Ali sedang duduk, lalu ada jenazah -diusung- melewatinya, orang-orang berdiri hingga jenazah itu lewat. Lalu Al Hasan berkata: \"Jenazah seorang Yahudi diusung, sementara Rasulullah shallallahu 'alaihi wasallam sedang duduk di jalan yang dilewatinya, beliau tidak senang ada jenazah seorang yahudi berada di atas kepalanya, lalu beliau berdiri!\""},"1857":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجَنَازَةِ يَهُودِيٍّ مَرَّتْ بِهِ حَتَّى تَوَارَتْو أَخْبَرَنِي أَبُو الزُّبَيْرِ أَيْضًا أَنَّهُ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ لِجَنَازَةِ يَهُودِيٍّ حَتَّى تَوَارَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dia berkata; Telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir] berkata; \"Nabi shallallahu 'alaihi wasallam berdiri karena ada jenazah seorang Yahudi yang diusung melewati beliau hingga jenazah tersebut tidak terlihat.\""},"1858":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ جَنَازَةً مَرَّتْ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَقِيلَ إِنَّهَا جَنَازَةُ يَهُودِيٍّ فَقَالَ إِنَّمَا قُمْنَا لِلْمَلَائِكَةِ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami [An Nadhr] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Qatadah] dari [Anas] bahwa ada jenazah diusung melewati Rasulullah shallallahu 'alaihi wasallam, beliau berdiri, lalu dikatakan, \" Jenazah itu adalah seorang yahudi?! beliau bersabda: \" kami berdiri karena ada malaikat.\""},"1859":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ بْنِ رِبْعِيٍّ أَنَّهُ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّ عَلَيْهِ بِجَنَازَةٍ فَقَالَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ فَقَالُوا مَا الْمُسْتَرِيحُ وَمَا الْمُسْتَرَاحُ مِنْهُ قَالَ الْعَبْدُ الْمُؤْمِنُ يَسْتَرِيحُ مِنْ نَصَبِ الدُّنْيَا وَأَذَاهَا وَالْعَبْدُ الْفَاجِرُ يَسْتَرِيحُ مِنْهُ الْعِبَادُ وَالْبِلَادُ وَالشَّجَرُ وَالدَّوَابُّ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Muhammad bin 'Amr bin Halhalah] dari [Ma'bad bin Ka'b bin Malik] dari [Abu Qatadah bin Rib'i] ia bercerita bahwa Rasulullah shallallahu 'alaihi wasallam pernah dilewati jenazah, beliau kemudian bersabda: \"Dia beristirahat atau -sesuatu- diistirahatkan darinya.\" Lalu mereka bertanya, \"apa yang dimaksud dengan 'dia sedang beristirahat' dan apa yang dimaksud dengan 'diistirahatkan darinya? ' beliau bersabda: \"Seorang hamba yang beriman beristirahat dari penderitaan dunia dan penganiayaannya, sedangkan seorang hamba yang kafir (banyak berbuat dosa), para hamba, negeri, pohon dan binatang diistirahatkan darinya.\""},"1860":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبِ بْنِ أَبِي كَرِيمَةَ الْحَرَّانِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَهُوَ الْحَرَّانِيُّ عَنْ أَبِي عَبْدِ الرَّحِيمِ حَدَّثَنِي زَيْدٌ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ مَعْبَدِ بْنِ كَعْبٍ عَنْ أَبِي قَتَادَةَ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ طَلَعَتْ جَنَازَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ الْمُؤْمِنُ يَمُوتُ فَيَسْتَرِيحُ مِنْ أَوْصَابِ الدُّنْيَا وَنَصَبِهَا وَأَذَاهَا وَالْفَاجِرُ يَمُوتُ فَيَسْتَرِيحُ مِنْهُ الْعِبَادُ وَالْبِلَادُ وَالشَّجَرُ وَالدَّوَابُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb bin Abu Karimah Al Harrani] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Abu 'Abdurrahim]; telah menceritakan kepadaku [Zaid] dari [Wahb bin Kaisan] dari [Ma'bad bin Ka'b] dari [Abu Qatadah] dia berkata; \"Kami pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba ada jenazah -yang diusung- muncul, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia beristirahat atau -sesuatu- diistirahatkan darinya.\" Jika seorang mukmin meninggal dunia, ia beristirahat dari beban berat dunia, penderitaan dan penganiayaannya, dan jika seorang yang fajir meninggal dunia, para hamba, negeri, pohon dan binatang diistirahatkan darinya.\""},"1861":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ وَمُرَّ بِجَنَازَةٍ أُخْرَى فَأُثْنِيَ عَلَيْهَا شَرًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ فَقَالَ عُمَرُ فِدَاكَ أَبِي وَأُمِّي مُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرًا فَقُلْتَ وَجَبَتْ وَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا شَرًّا فَقُلْتَ وَجَبَتْ فَقَالَ مَنْ أَثْنَيْتُمْ عَلَيْهِ خَيْرًا وَجَبَتْ لَهُ الْجَنَّةُ وَمَنْ أَثْنَيْتُمْ عَلَيْهِ شَرًّا وَجَبَتْ لَهُ النَّارُ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ","id":"Telah mengabarkan kepadaku [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari [Anas] dia berkata; \"Ada jenazah -di usung- melewati Nabi shallallahu 'alaihi wasallam, lalu jenazah tersebut dipuji dengan kebaikan. Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib.\" Dan ada jenazah yang lain -diusung- melewati beliau, lalu jenazah itu dikecam dengan keburukan, Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib.\" Umar kemudian berkata, \"Demi bapak dan ibuku sebagai tebusannya! Ada jenazah -diusung- melewati beliau, lalu dikecam dengan keburukan, kemudian engkau bersabda: \"Wajib.\" beliau bersabda: \"Barang siapa yang kalian puji dengan kebaikan, wajib baginya surga dan barang siapa yang kalian kecam dengan keburukan, wajib baginya neraka. Kalian adalah saksi Allah di bumi.\""},"1862":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ إِبْرَاهِيمَ بْنَ عَامِرٍ وَجَدَّهُ أُمَيَّةُ بْنُ خَلَفٍ قَالَ سَمِعْتُ عَامِرَ بْنَ سَعْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَرُّوا بِجَنَازَةٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَثْنَوْا عَلَيْهَا خَيْرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ ثُمَّ مَرُّوا بِجَنَازَةٍ أُخْرَى فَأَثْنَوْا عَلَيْهَا شَرًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ قَالُوا يَا رَسُولَ اللَّهِ قَوْلُكَ الْأُولَى وَالْأُخْرَى وَجَبَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَلَائِكَةُ شُهَدَاءُ اللَّهِ فِي السَّمَاءِ وَأَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Abdul Malik] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; Aku mendengar [Ibrahim bin 'Amir] -dan kakeknya Umayyah bin Khalaf- berkata; Aku mendengar ['Amir bin Sa'd] dari [Abu Hurairah] dia berkata; \"Ada jenazah -diusung- melewati Nabi shallallahu 'alaihi wasallam, lalu mereka memujinya dengan kebaikan! Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib, \" kemudian ada jenazah lain yang -di usung- melewati beliau, lalu mereka mengacamnya dengan keburukan, Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib, \" lalu mereka berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam perkataan engkau kepada yang pertama dan yang lainnya adalah \"Wajib?\" Nabi shallallahu 'alaihi wasallam bersabda: \"Malaikat adalah saksi Allah di langit dan manusia adalah saksi Allah di bumi.\""},"1863":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ وَعَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَا حَدَّثَنَا دَاوُدُ بْنُ أَبِي الْفُرَاتِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدِّيْلِيِّ قَالَأَتَيْتُ الْمَدِينَةَ فَجَلَسْتُ إِلَى عُمَرَ بْنِ الْخَطَّابِ فَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَى صَاحِبِهَا خَيْرًا فَقَالَ عُمَرُ وَجَبَتْ ثُمَّ مُرّ�� بِأُخْرَى فَأُثْنِيَ عَلَى صَاحِبِهَا خَيْرًا فَقَالَ عُمَرُ وَجَبَتْ ثُمَّ مُرَّ بِالثَّالِثِ فَأُثْنِيَ عَلَى صَاحِبِهَا شَرًّا فَقَالَ عُمَرُ وَجَبَتْ فَقُلْتُ وَمَا وَجَبَتْ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ قُلْتُ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُسْلِمٍ شَهِدَ لَهُ أَرْبَعَةٌ قَالُوا خَيْرًا أَدْخَلَهُ اللَّهُ الْجَنَّةَ قُلْنَا أَوْ ثَلَاثَةٌ قَالَ أَوْ ثَلَاثَةٌ قُلْنَا أَوْ اثْنَانِ قَالَ أَوْ اثْنَانِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Abdul Malik] dan ['Abdullah bin Yazid] mereka berkata; telah menceritakan kepada kami [Dawud bin Abul Furat] dia berkata; telah menceritakan kepada kami ['Abdullah bin Buraidah] dari [Abul Aswad Ad Daili] dia berkata; Aku datang ke madinah, lalu aku duduk di hadapan [Umar Al Khattab], kemudian ada jenazah diusung -lewat- di hadapannya dan jenazah itu dipuji dengan kebaikan, Umar lalu berkata; \"Wajib\". Kemudian ada jenazah lain yang di usung -lewat- di hadapannya dan jenazah itu dikecam dengan keburukan, umar lalu berkata; \"Wajib.\" Kemudian ada jenazah ketiga -diusung- lewat di hadapannya dan jenazah tersebut dicekam dengan keburukan, Umar lalu berkata; \"Wajib.\" Aku bertanya, \"Apa yang wajib, wahai amirul mukminin?\" ia menjawab, \"Aku mengatakan sebagaimana Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang muslim mana saja yang disaksikan untuk dirinya oleh empat orang, dan mereka mengatakan kebaikan, Allah akan memasukannya ke dalam surga, \" kami berkata, \"Atau tiga.\" Beliau bersabda: \"Atau tiga.\" Kami berkata; \"Atau dua.\" Beliau bersabda: \"Atau dua.\""},"1864":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنِي أَحْمَدُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَالِكٌ بِسُوءٍ فَقَالَ لَا تَذْكُرُوا هَلْكَاكُمْ إِلَّا بِخَيْرٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepadaku [Ahmad bin Ishaq] dia berkata; telah menceritakan kepada kami [Wuhaib] dia berkata; telah menceritakan kepada kami [Manshur bin 'Abdurrahman] dari [ibunya] dari ['Aisyah] dia berkata; \"Kejelekan seorang yang telah meninggal dunia pernah disebutkan di hadapan Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian menyebutkan orang-orang yang telah meninggal dunia di antara kalian kecuali dengan kebaikan.\""},"1865":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ بِشْرٍ وَهُوَ ابْنُ الْمُفَضَّلِ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الْأَمْوَاتَ فَإِنَّهُمْ قَدْ أَفْضَوْا إِلَى مَا قَدَّمُوا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Bisyr bin Al Mufadldlal] dari [Syu'bah] dari [Sulaiman Al A'masy] dari [Mujahid] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencela orang-orang yang telah meninggal dunia, karena mereka telah sampai kepada apa yang mereka lakukan (pembalasan amal).\""},"1866":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتْبَعُ الْمَيِّتَ ثَلَاثَةٌ أَهْلُهُ وَمَالُهُ وَعَمَلُهُ فَيَرْجِعُ اثْنَانِ أَهْلُهُ وَمَالُهُ وَيَبْقَى وَاحِدٌ عَمَلُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Bakr] dia berkata; Aku mendengar [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga hal yang akan menyertai mayit; Keluarganya, hartanya dan amal perbuatannya, lalu yang dua kembali yaitu keluarganya dan hartanya, dan satu yang tetap bersamanya, yaitu amal perbuatannya.\""},"1867":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْمُؤْمِنِ عَلَى الْمُؤْمِنِ سِتُّ خِصَالٍ يَعُودُهُ إِذَا مَرِضَ وَيَشْهَدُهُ إِذَا مَاتَ وَيُجِيبُهُ إِذَا دَعَاهُ وَيُسَلِّمُ عَلَيْهِ إِذَا لَقِيَهُ وَيُشَمِّتُهُ إِذَا عَطَسَ وَيَنْصَحُ لَهُ إِذَا غَابَ أَوْ شَهِدَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Muhammad bin Musa] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak orang mukmin terhadap mukmin yang lainnya ada enam hal: menjenguknya jika ia sakit, menyaksikannya jika ia meninggal dunia, memenuhi panggilannya jika ia mengundang, mengucapkan salam kepadanya jika bertemu, mendo'akannya jika ia bersin dan menasehatinya jika ia tidak nampak atau hadir.\""},"1868":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ ح وَأَنْبَأَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَشْعَثَ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍ قَالَ هَنَّادٌ قَالَ الْبَرَاءُ بْنُ عَازِبٍ وَقَالَ سُلَيْمَانُ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِعِيَادَةِ الْمَرِيضِ وَتَشْمِيتِ الْعَاطِسِ وَإِبْرَارِ الْقَسَمِ وَنُصْرَةِ الْمَظْلُومِ وَإِفْشَاءِ السَّلَامِ وَإِجَابَةِ الدَّاعِي وَاتِّبَاعِ الْجَنَائِزِ وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ وَعَنْ آنِيَةِ الْفِضَّةِ وَعَنْ الْمَيَاثِرِ وَالْقَسِّيَّةِ وَالْإِسْتَبْرَقِ وَالْحَرِيرِ وَالدِّيبَاجِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur Al Balkhi] dia berkata; telah menceritakan kepada kami [Abul Ahwash]. Demikian juga diriwayatkan dari jalur lain, dan telah memberitakan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abul Ahwash] dari [Asy'ats] dari [Mu'awiyah bin Suwaid]; berkata [Hannad]; berkata [Al Barra' bin 'Azib]; dan berkata [Sulaiman] dari [Al Barra' bin 'Azib] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kita untuk melakukan tujuh hal dan melarang kita dari tujuh hal: menyuruh kita untuk menjenguk orang-orang sakit, mendo'akan yang bersin, melaksanakan sesuai sumpah, memenuhi undangan serta mengikuti jenazah, dan melarang kita dari cincin yang terbuat dari emas, tempat minum yang terbuat dari perak, pelana yang terbuat dari sutra, Qasiyyah (pakaian bergaris yang ada sutranya), Istabrq (sutra tebal), sutra tipis, dan diybaj (pakaian yang serat kainnya terbuat dari sutra).\""},"1869":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ بُرْدٍ أَخِي يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَبِعَ جَنَازَةً حَتَّى يُصَلَّى عَلَيْهَا كَانَ لَهُ مِنْ الْأَجْرِ قِيرَاطٌ وَمَنْ مَشَى مَعَ الْجَنَازَةِ حَتَّى تُدْفَنَ كَانَ لَهُ مِنْ الْأَجْرِ قِيرَاطَانِ وَالْقِيرَاطُ مِثْلُ أُحُدٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abtsar] dari [Burd] -saudara Yazid bin Abu Ziyad- dari [Al Musayyab bin Rafi'] dia berkata; aku mendengar [Al Barra' bin 'Azib] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengiringi jenazah hingga menshalatkannya, baginya pahala satu qirath, dan barangsiapa yang berjalan bersama jenazah hingga dikuburkan, baginya pahala dua qirah dan satu qirah seperti gunung Uhud.\""},"1870":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ الْمُغَفَّلِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَبِعَ جِنَازَةً حَتَّى يُفْرَغَ مِنْهَا فَلَهُ قِيرَاطَانِ فَإِنْ رَجَعَ قَبْلَ أَنْ يُفْرَغَ مِنْهَا فَلَهُ قِيرَاطٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari ['Abdullah bin Al Mughaffal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengantar jenazah hingga selesai penguburannya ia mendapatkan dua qirath, namun jika ia kembali sebelum selesai dari penguburannya ia mendapatkan satu qirath.\""},"1871":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ اللَّهِ وَأَخُوهُ الْمُغِيرَةُ جَمِيعًا عَنْ زِيَادِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّاكِبُ خَلْفَ الْجَنَازَةِ وَالْمَاشِي حَيْثُ شَاءَ مِنْهَا وَالطِّفْلُ يُصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami ['Abdul Wahid bin Washil] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Ubaidullah] -dan juga saudaranya yakni [Al Mughirah] - dari [Ziyad bin Jubair] dari [bapaknya] dari [Al Mughirah bin Syu'bah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang menaiki kendaraan ia di belakang jenazah, sedangkan orang yang berjalan ia di tempat mana saja yang ia kehendaki, dan anak kecil di shalatkan -jika meninggal dunia-.\""},"1872":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ بَكَّارٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ عَنْ سَعِيدٍ الثَّقَفِيِّ عَنْ عَمِّهِ زِيَادِ بْنِ جُبَيْرِ بْنِ حَيَّةَ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّاكِبُ خَلْفَ الْجَنَازَةِ وَالْمَاشِي حَيْثُ شَاءَ مِنْهَا وَالطِّفْلُ يُصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepadaku [Ahmad bin Bakkar Al Harrani] dia berkata; telah menceritakan kepada kami [Bisyr bin As Sari] dari [Sa'id Ats Tsaqafi] dari pamannya [Ziyad bin Jubair bin Hayyah] dari [bapaknya] dari [Al Mughirah bin Syu'bah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang menaiki kendaraan ia di belakang jenazah, sedangkan orang yang berjalan ia di tempat mana saja yang ia kehendaki, dan anak kecil di shalatkan -jika meninggal dunia-.\""},"1873":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ حُجْرٍ وَقُتَيْبَةُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَمْشُونَ أَمَامَ الْجَنَازَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan ['Ali bin Hujr] dan [Qutaibah] dari [Sufyan] dari [Az Zuhri] dari [Salim] dari [bapaknya] bahwasanya ia melihat Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar Radliallahu'anhuma berjalan di depan jenazah."},"1874":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا سُفْيَانُ وَمَنْصُورٌ وَزِيَادٌ وَبَكْرٌ هُوَ ابْنُ وَائِلٍ كُلُّهُمْ ذَكَرُوا أَنَّهُمْ سَمِعُوا مِنَ الزُّهْرِيِّ يُحَدِّثُ أَنَّ سَالِمًا أَخْبَرَهُ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ يَمْشُونَ بَيْنَ يَدَيْ الْجَنَازَةِ بَكْرٌ وَحْدَهُ لَمْ يَذْكُرْ عُثْمَانَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Hammam] dia berkata; telah menceritakan kepada kami [Sufyan] dan [Manshur] dan [Ziyad] dan [Bakr bin Wail], mereka menyebutkan bahwasanya mereka mendengar dari [Az Zuhri] bercerita, [Salim] telah mengabarkan kepadanya, [Bapaknya] telah mengabarkan kepadanya bahwa ia melihat Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman berjalan di depan jenazah. Hanya Bakr saja yang tidak menyebutkan Utsman. Abu Abdurrahman berkata; 'Ini salah, yang benar hadits ini mursal.'"},"1875":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ وَعَمْرُو بْنُ زُرَارَة�� النَّيْسَابُورِيُّ قَالَا حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكُمْ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dan ['Amru bin Zurarah An Naisaburi] mereka berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Qilabah] dari [Abul Muhallab] dari ['Imran bin Hushain] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" saudara kalian telah meninggal dunia, berdirilah kemudian shalatkanlah atasnya.\""},"1876":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ عَمَّتِهِ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ خَالَتِهَا أُمِّ الْمُؤْمِنِينَ عَائِشَةَ قَالَتْأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ مِنْ صِبْيَانِ الْأَنْصَارِ فَصَلَّى عَلَيْهِ قَالَتْ عَائِشَةُ فَقُلْتُ طُوبَى لِهَذَا عُصْفُورٌ مِنْ عَصَافِيرِ الْجَنَّةِ لَمْ يَعْمَلْ سُوءًا وَلَمْ يُدْرِكْهُ قَالَ أَوَ غَيْرُ ذَلِكَ يَا عَائِشَةُ خَلَقَ اللَّهُ عَزَّ وَجَلَّ الْجَنَّةَ وَخَلَقَ لَهَا أَهْلًا وَخَلَقَهُمْ فِي أَصْلَابِ آبَائِهِمْ وَخَلَقَ النَّارَ وَخَلَقَ لَهَا أَهْلًا وَخَلَقَهُمْ فِي أَصْلَابِ آبَائِهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur]; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Thalhah bin Yahya] dari bibinya ['Aisyah binti Thalhah] dari sepupunya [Ummul Mu'minin 'Aisyah] dia berkata; Bayi dari Anshar yang telah meninggal dunia dibawa ke Rasulullah shallallahu 'alaihi wasallam, lalu beliau melaksanakan shalat atasnya. Aisyah berkata lagi; \"Aku mengatakan; 'Berbahagialah bayi ini, ia adalah salah satu burung-burung kecil di surga, dia belum pernah melakukan kejelekan dan belum pernah menemuinya'.\" Beliau bersabda: \"Bahkan tidak seperti itu wahai Aisyah, Allah -Azza wa jalla- telah menciptakan surga, menciptakan penghuninya dan menciptakan mereka dari tulang rusuk bapak mereka. Serta menciptakan neraka, menciptakan penghuninya dan menciptakan mereka dari tulang rusuk bapak mereka.\""},"1877":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ زِيَادَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ أَنَّهُ ذَكَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّاكِبُ خَلْفَ الْجَنَازَةِ وَالْمَاشِي حَيْثُ شَاءَ مِنْهَا وَالطِّفْلُ يُصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Ubaidullah] dia berkata; Aku mendengar [Ziyad bin Jubair] menceritakan dari [bapaknya] dari [Al Mughirah bin Syu'bah] dia menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang menaiki kendaraan ia di belakang jenazah, sedangkan orang yang berjalan ia di tempat mana saja yang ia kehendaki, dan anak kecil di shalatkan -jika meninggal dunia-.\""},"1878":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah mengabarkan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha bin Yazid Al Laitsi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang anak-anak kaum Musyrikin? lalu beliau bersabda: \"Allah maha mengetahui terhadap apa yang mereka perbuat.\""},"1879":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسٍ هُوَ ابْنُ سَعْدٍ عَنْ طَاوُسٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Al Aswad bin 'Amir] dia berkata; telah menceritakan kepada kami [Hammad] dari [Qais bin Sa'd] dari [Thawus] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam ditanya tentang anak-anak kaum Musyrikin? lalu beliau bersabda: \"Allah maha mengetahui terhadap apa yang mereka perbuat.\""},"1880":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ خَلَقَهُمْ اللَّهُ حِينَ خَلَقَهُمْ وَهُوَ يَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang anak-anak kaum musyrikin? Lalu beliau bersabda: \"Allah menciptakan mereka, dan Dia maha mengetahui terhadap apa yang mereka perbuat.\""},"1881":{"ar":"أَخْبَرَنِي مُجَاهِدُ بْنُ مُوسَى عَنْ هُشَيْمٍ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَرَارِيِّ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah mengabarkan kepadaku [Mujahid bin Musa] dari [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Nabi shallallahu 'alaihi wasallam ditanya tentang anak cucu kaum musyrikin, lalu beliau bersabda: \"Allah maha mengetahui terhadap apa yang mereka perbuat.\""},"1882":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عِكْرِمَةُ بْنُ خَالِدٍ أَنَّ ابْنَ أَبِي عَمَّارٍ أَخْبَرَهُ عَنْ شَدَّادِ بْنِ الْهَادِأَنَّ رَجُلًا مِنْ الْأَعْرَابِ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآمَنَ بِهِ وَاتَّبَعَهُ ثُمَّ قَالَ أُهَاجِرُ مَعَكَ فَأَوْصَى بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ أَصْحَابِهِ فَلَمَّا كَانَتْ غَزْوَةٌ غَنِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْيًا فَقَسَمَ وَقَسَمَ لَهُ فَأَعْطَى أَصْحَابَهُ مَا قَسَمَ لَهُ وَكَانَ يَرْعَى ظَهْرَهُمْ فَلَمَّا جَاءَ دَفَعُوهُ إِلَيْهِ فَقَالَ مَا هَذَا قَالُوا قِسْمٌ قَسَمَهُ لَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَهُ فَجَاءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا هَذَا قَالَ قَسَمْتُهُ لَكَ قَالَ مَا عَلَى هَذَا اتَّبَعْتُكَ وَلَكِنِّي اتَّبَعْتُكَ عَلَى أَنْ أُرْمَى إِلَى هَاهُنَا وَأَشَارَ إِلَى حَلْقِهِ بِسَهْمٍ فَأَمُوتَ فَأَدْخُلَ الْجَنَّةَ فَقَالَ إِنْ تَصْدُقْ اللَّهَ يَصْدُقْكَ فَلَبِثُوا قَلِيلًا ثُمَّ نَهَضُوا فِي قِتَالِ الْعَدُوِّ فَأُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحْمَلُ قَدْ أَصَابَهُ سَهْمٌ حَيْثُ أَشَارَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهُوَ هُوَ قَالُوا نَعَمْ قَالَ صَدَقَ اللَّهَ فَصَدَقَهُ ثُمَّ كَفَّنَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جُبَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَدَّمَهُ فَصَلَّى عَلَيْهِ فَكَانَ فِيمَا ظَهَرَ مِنْ صَلَاتِهِ اللَّهُمَّ هَذَا عَبْدُكَ خَرَجَ مُهَاجِرًا فِي سَبِيلِكَ فَقُتِلَ شَهِيدًا أَنَا شَهِيدٌ عَلَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Ikrimah bin Khalid] bahwasanya [Ibnu Abu 'Ammar] mengabarkan kepadanya dari [Syaddad bin Al Had] bahwa seorang laki-laki dari seorang badui datang menemui Nabi shallallahu 'alaihi wasallam, lalu ia beriman dan mengikuti beliau. Kemudian dia berkata, \"Aku akan berhijrah bersama engkau?\" beliau berwasiat dengan orang tersebut kepada sebagian sahabat beliau. Setelah terjadi perang, Nabi shallallahu 'alaihi wasallam mendapatkan ghanimah (harta rampasan perang) berupa tawanan, beliau membagikan dan membagi untuknya, lalu beliau memberikan kepada para sahabat beliau sesuatu yang beliau bagi untuknya dan ia sendiri sedang mengatur urusan mereka. Setelah ia datang, ia memberikannya kepada orang itu, lalu ia berkata; \"Apa ini?\" mereka menjawab; \"Bagian yang telah Nabi shallallahu 'alaihi wasallam bagi untukmu.\" Kemudian ia mengambilnya dan membawanya menemui Nabi shallallahu 'alaihi wasallam, lalu bertanya; \"Apa ini?\" beliau bersabda: 'Aku telah membaginya untukmu.' Ia berkata; \"Bukan untuk hal ini aku mengikuti engkau. Tapi aku mengikuti engkau agar aku dilemparkan ke sini -ia mengisyaratkan tombaknya ke tenggorokannya- lalu aku mati dan masuk surga.\" beliau bersabda: \"Jika jujur kepada Allah, niscaya Allah akan membalas sikap kejujuranmu.\" Lalu mereka diam sejenak, kemudian bangkit melawan musuh, orang tersebut dibawa ke tempat Nabi shallallahu 'alaihi wasallam dengan cara diangkut, ia terkena tombak yang diisyaratkan, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ia orangnya?!\" mereka menjawab; \"ya.\" Beliau bersabda: \"Dia benar dalam berjanji kepada Allah, Allah membalasnya dengan kebenaran.\" Kemudian Nabi shallallahu 'alaihi wasallam mengkafaninya dengan jubah beliau shallallahu 'alaihi wasallam, beliau mengajukan dan menshalatkannya. Do'a yang nampak dalam Shalat beliau yaitu, \"Ya Allah, inilah hamba-Mu, ia telah keluar jihad di jalan-Mu, lalu ia terbunuh dalam keadaan Syahid, aku menjadi saksi atas hal tersebut.\""},"1883":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا فَصَلَّى عَلَى أَهْلِ أُحُدٍ صَلَاتَهُ عَلَى الْمَيِّتِ ثُمَّ انْصَرَفَ إِلَى الْمِنْبَرِ فَقَالَ إِنِّي فَرَطٌ لَكُمْ وَأَنَا شَهِيدٌ عَلَيْكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid] dari [Abul Khair] dari ['Uqbah] bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam keluar untuk menshalatkan para sahabat yang gugur dalam perang Uhud, beliau menshalatinya sebagaimana menshalati mayit, kemudian beliau naik mimbar, lalu bersabda: \" Aku pendahulu bagi kalian dan aku sebagai saksi atas kalian.\""},"1884":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ ثُمَّ يَقُولُ أَيُّهُمَا أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ إِلَى أَحَدِهِمَا قَدَّمَهُ فِي اللَّحْدِ قَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ وَأَمَرَ بِدَفْنِهِمْ فِي دِمَائِهِمْ وَلَمْ يُصَلِّ عَلَيْهِمْ وَلَمْ يُغَسَّلُوا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Abdurrahman bin Ka'b bin Malik], [Jabir bin 'Abdullah] mengabarkan kepadanya; bahwa Rasulullah shallallahu 'alaihi wasallam menggabungkan (menghimpun) dua orang yang gugur pada perang Uhud dalam satu kain, kemudian beliau bersabda: \"Manakah diantara keduanya yang paling banyak hapalan Al-Qur'an?\" ketika diisyaratkan kepada salah satu dari keduanya, beliau mendahulukannya ketika memasukkan kedalam lahd, beliau bersabda: \"Aku adalah saksi atas mereka.\" Dan beliau menyuruh mereka untuk menguburkan mereka dengan darah yang ada pada diri mereka, mereka tidak dishalatkan dan tidak dimandikan."},"1885":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى وَنُوحُ بْنُ حَبِيبٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَ��ِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا مِنْ أَسْلَمَ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَرَفَ بِالزِّنَا فَأَعْرَضَ عَنْهُ ثُمَّ اعْتَرَفَ فَأَعْرَضَ عَنْهُ ثُمَّ اعْتَرَفَ فَأَعْرَضَ عَنْهُ حَتَّى شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ مَرَّاتٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبِكَ جُنُونٌ قَالَ لَا قَالَ أَحْصَنْتَ قَالَ نَعَمْ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ فَرَّ فَأُدْرِكَ فَرُجِمَ فَمَاتَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا وَلَمْ يُصَلِّ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] dan [Nuh bin Habib] mereka berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir bin 'Abdullah] bahwa ada seorang laki-laki dari suku Aslam datang menemui Nabi shallallahu 'alaihi wasallam, ia mengaku telah berbuat zina, beliau berpaling darinya. Kemudian ia mengaku lagi, dan beliau berpaling darinya. Kemudian ia mengaku lagi-telah melakukan zina-, dan beliau berpaling darinya hingga dia bersaksi atas dirinya empat kali. Lalu Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah kamu gila?\"ia menjawab, \"tidak.\" Beliau bertanya: \"Apakah kamu telah menikah?\" ia menjawab; \"Ya.\" Nabi shallallahu 'alaihi wasallam menyuruh orang tersebut untuk dirajam. Setelah batu-batu menimpanya dan ia merasa tidak sanggup dan lemah, ia berlari, lalu ditangkap dan dirajam lagi, lalu ia meninggal dunia. kemudian Nabi shallallahu 'alaihi wasallam berkoemntar kebaikan terhadapnya dan tidak menshalatkannya."},"1886":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ امْرَأَةً مِنْ جُهَيْنَةَ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي زَنَيْتُ وَهِيَ حُبْلَى فَدَفَعَهَا إِلَى وَلِيِّهَا فَقَالَ أَحْسِنْ إِلَيْهَا فَإِذَا وَضَعَتْ فَأْتِنِي بِهَا فَلَمَّا وَضَعَتْ جَاءَ بِهَا فَأَمَرَ بِهَا فَشُكَّتْ عَلَيْهَا ثِيَابُهَا ثُمَّ رَجَمَهَا ثُمَّ صَلَّى عَلَيْهَا فَقَالَ لَهُ عُمَرُ أَتُصَلِّي عَلَيْهَا وَقَدْ زَنَتْ فَقَالَ لَقَدْ تَابَتْ تَوْبَةً لَوْ قُسِمَتْ بَيْنَ سَبْعِينَ مِنْ أَهْلِ الْمَدِينَةِ لَوَسِعَتْهُمْ وَهَلْ وَجَدْتَ تَوْبَةً أَفْضَلَ مِنْ أَنْ جَادَتْ بِنَفْسِهَا لِلَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Abul Muhallab] dari ['Imran bin Hushain] bahwa seorang wanita dari Juhainah datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata; \"Sungguh aku telah berzina!\" sedangkan ia dalam keadaan hamil, lalu beliau menyerahkan wanita tersebut kepada walinya seraya bersabda: \"Berbuatlah baiknya terhadapnya, jika ia telah melahirkan, datanglah engkau kepadaku bersamanya.\" Setelah ia melahirkan, walinya datang bersamanya, lalu beliau memerintahkan (untuk merajamnya), dan beliau menshalatinya. Lalu Umar berkata pada Nabi shallallahu 'alaihi wasallam: \"Apakah engkau menshalatinya padahal dia berbuat zina?\" beliau bersabda: \"Sungguh ia telah bertaubat, andaikata taubatnya dibagikan antara tujuh puluh penduduk Madinah, niscaya akan mencukupi mereka. Apakah engkau menemukan taubat yang lebih mulia darinya yang telah mendern dirinya kepada Allah -Azza wa Jalla? -\""},"1887":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا هُشَيْمٌ عَنْ مَنْصُورٍ وَهُوَ ابْنُ زَاذَانَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا أَعْتَقَ سِتَّةً مَمْلُوكِينَ لَهُ عِنْدَ مَوْتِهِ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرَهُمْ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَضِبَ مِنْ ذَلِكَ وَقَالَ لَقَدْ هَمَمْتُ أَنْ لَا أُصَلِّيَ عَلَيْهِ ثُمَّ دَعَا مَمْلُوكِيهِ فَجَزَّأَهُمْ ثَلَاثَةَ أَجْزَاءٍ ثُمَّ أَقْرَعَ بَيْنَهُمْ فَأَعْتَقَ اثْنَيْنِ وَأَرَقَّ أَرْبَعَةً","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Husyaim] dari [Manshur bin Zadzan] dari [Al Hasan] dari ['Imran bin Hushain] bahwa seorang laki-laki telah memerdekakan enam budak miliknya ketika akan meninggal dunia, padahal ia tidak memiliki harta selain mereka. Lalu hal itu sampai kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau marah atas hal itu dan bersabda: \"Sungguh semula aku telah berminat untuk tidak menshalatkannya.\" Kemudian beliau memanggil para budaknya dan membagi mereka menjadi tiga bagian, lalu mengundi di antara mereka. Beliau memerdekakan dua orang dan menjadikan empat orang tetap sebagai budak."},"1888":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ قَالَمَاتَ رَجُلٌ بِخَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا عَلَى صَاحِبِكُمْ إِنَّهُ غَلَّ فِي سَبِيلِ اللَّهِ فَفَتَّشْنَا مَتَاعَهُ فَوَجَدْنَا فِيهِ خَرَزًا مِنْ خَرَزِ يَهُودَ مَا يُسَاوِي دِرْهَمَيْنِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id Al Anshari] dari [Muhammad bin Yahya bin Habbab] dari [Abu 'Amrah] dari [Zaid bin Khalid] dia berkata; \"Seorang laki-laki meninggal pada perang Khaibar, lalu Nabi shallallahu 'alaihi wasallam bersabda: 'Shalatlah kalian atas kematian sahabat kalian, dia telah berbuat curang. kemudian kami memeriksa harta yang dia miliki, dan kami mendapatkan darinya tombak Yahudi yang senilai dua dirham'.\" "},"1889":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ يُحَدِّثُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِرَجُلٍ مِنْ الْأَنْصَارِ لِيُصَلِّيَ عَلَيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا عَلَى صَاحِبِكُمْ فَإِنَّ عَلَيْهِ دَيْنًا قَالَ أَبُو قَتَادَةَ هُوَ عَلَيَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْوَفَاءِ قَالَ بِالْوَفَاءِ فَصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Utsman bin 'Abdullah bin Mauhab]; Aku mendengar ['Abdullah bin Abu Qatadah] menceritakan dari [bapaknya] bahwa jenazah laki-laki dari kaum Anshar dibawa kepada Rasulullah shallallahu 'alaihi wasallam agar baliau menshalatinya, lalu beliau bersabda: \"Shalatilah sahabat kalian, karena ia masih memiliki utang.\" Abu Qatadah berkata; \"Utang itu menjadi utangku.\" Nabi shallallahu 'alaihi wasallam bertanya; 'Untuk melunasinya? ' ia menjawab, 'Untuk melunasinya.' Lalu beliau menshalatinya.\""},"1890":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ قَالَ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْأَكْوَعِ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَنَازَةٍ فَقَالُوا يَا نَبِيَّ اللَّهِ صَلِّ عَلَيْهَا قَالَ هَلْ تَرَكَ عَلَيْهِ دَيْنًا قَالُوا نَعَمْ قَالَ هَلْ تَرَكَ مِنْ شَيْءٍ قَالُوا لَا قَالَ صَلُّوا عَلَى صَاحِبِكُمْ قَالَ رَجُلٌ مِنْ الْأَنْصَارِ يُقَالُ لَهُ أَبُو قَتَادَةَ صَلِّ عَلَيْهِ وَعَلَيَّ دَيْنُهُ فَصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Yazid bin Abu 'Ubaid] dia berkata; telah menceritakan kepada kami [Salamah bin Al Akwa'] dia berkata; \"Seorang jenazah pernah dibawa kepada Nabi shallallahu 'alaihi wasallam, lalu mereka berkata; \"Wahai Nabi Allah, shalatilah ia.\" Beliau bertanya: 'Apakah ia meninggalkan sesuatu? ' mereka menjawab; \"tidak.\" Beliau bersabda: 'Shalatilah shahabat kalian.' Seorang laki-laki Anshar yang bernama Abu Qatadah berkata; 'Shalatilah ia dan utangnya menjadi tanggunganku.' Lalu beliau menshalatinya.\""},"1891":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ الْقُوْمَسِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي عَلَى رَجُلٍ عَلَيْهِ دَيْنٌ فَأُتِيَ بِمَيْتٍ فَسَأَلَ أَعَلَيْهِ دَيْنٌ قَالُوا نَعَمْ عَلَيْهِ دِينَارَانِ قَالَ صَلُّوا عَلَى صَاحِبِكُمْ قَالَ أَبُو قَتَادَةَ هُمَا عَلَيَّ يَا رَسُولَ اللَّهِ فَصَلَّى عَلَيْهِ فَلَمَّا فَتَحَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ مَنْ تَرَكَ دَيْنًا فَعَلَيَّ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib Al Qumasi] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir] dia berkata; Nabi shallallahu 'alaihi wasallam tidak pernah menshalati jenazah yang memiliki utang lalu didatangkan kepada beliau seorang yang telah meninggal, beliau bertanya; \"Apakah ia masih memiliki utang?\" mereka menjawab, \"ya, ia memiliki utang dua dinar.\" Beliau bersabda: \"Shalatilah sahabat kalian.\" Abu Qatadah berkata; \"Dua dinar itu menjadi tanggunganku wahai Rasulullah!\" lalu beliau menshalatinya. Setelah Allah memberi kemenangan kepada Rasul-Nya shallallahu 'alaihi wasallam, beliau bersabda: \"Aku lebih berhak terhadap setiap mu'min dari dirinya sendiri, barangsiapa meninggalkan utang, menjadi tanggunganku dan barang siapa yang meninggalkan harta, untuk ahli warisnya.\""},"1892":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ وَابْنُ أَبِي ذِئْبٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا تُوُفِّيَ الْمُؤْمِنُ وَعَلَيْهِ دَيْنٌ سَأَلَ هَلْ تَرَكَ لِدَيْنِهِ مِنْ قَضَاءٍ فَإِنْ قَالُوا نَعَمْ صَلَّى عَلَيْهِ وَإِنْ قَالُوا لَا قَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَلَمَّا فَتَحَ اللَّهُ عَزَّ وَجَلَّ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ تُوُفِّيَ وَعَلَيْهِ دَيْنٌ فَعَلَيَّ قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَهُوَ لِوَرَثَتِهِ","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dan [Ibnu Abu Dzi'b] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] bahwa ketika seorang mukmin meninggal dunia dan ia memiliki hutang, Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah ia meninggalkan sesuatu yang bisa dipakai untuk melunasi utangnya?\" Jika mereka menjawab, \"Ya.\" Beliau menshalatinya. Jika mereka menjawab, \"Tidak.\" Beliau bersabda: \"shalatilah sahabat kalian.\" Setelah Allah memberi kemenangan kepada Rasul-Nya shallallahu 'alaihi wasallam, beliau bersabda: \"Aku lebih berhak terhadap setiap mukmin dari mereka sendiri, barangsiapa meninggal dunia dan ia memiliki utang, menjadi kewajibanku untuk melunasinya dan barangsiapa yang meninggalkan harta, hal itu untuk ahli warisnya.\""},"1893":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا أَبُو خَيْثَمَةَ زُهَيْرٌ قَالَ حَدَّثَنَا سِمَاكٌ عَنْ ابْنِ سَمُرَةَأَنَّ رَجُلًا قَتَلَ نَفْسَهُ بِمَشَاقِصَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَلَا أُصَلِّي عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami [Abul Walid] dia berkata; telah menceritakan kepada kami [Abu Khaitsamah Zuhair] dia berkata; telah menceritakan kepada kami [Simak] dari [Ibnu Samurah] bahwa seorang laki-laki bunuh diri dengan mata tombak, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun aku, tidak akan menshalatinya.\""},"1894":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ ذَكْوَانَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَدَّى مِنْ جَبَلٍ فَقَتَلَ نَفْسَهُ فَهُوَ فِي نَارِ جَهَنَّمَ يَتَرَدَّى خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ تَحَسَّى سُمًّا فَقَتَلَ نَفْسَهُ فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ ثُمَّ انْقَطَعَ عَلَيَّ شَيْءٌ خَالِدٌ يَقُولُ كَانَتْ حَدِيدَتُهُ فِي يَدِهِ يَجَأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman]; Aku mendengar [Dzakwan] menceritakan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Siapa yang menjatuhkan diri dari gunung, lalu meninggal dunia, ia akan jatuh ke neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya. Barangsiapa yang menegak racun, lalu meninggal dunia, racunnya ada di tangannya, ia akan menegaknya di neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya. Dan barang siapa yang bunuh diri dengan besi, besi itu akan ada di tangannya, dengannya ia akan menghujamkan ke perutnya di neraka jahannam, ia kekal dan abadi di dalamnya selama-lamanya.\""},"1895":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي قَدْ خُيِّرْتُ فَاخْتَرْتُ فَلَوْ عَلِمْتُ أَنِّي لَوْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ عَلَيْهَا فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari ['Abdullah bin 'Abbas] dari ['Umar bin Al Khaththab] dia berkata; Setelah Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau menshalati Ibnu Ubbay, padahal ia telah mengatakan hari ini dan itu begini dan itu begitu?! Aku menyebut kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu, kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah 9: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},"1896":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الْوَاحِدِ بْنِ حَمْزَةَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سُهَيْلِ ابْنِ بَيْضَاءَ إِلَّا فِي الْمَسْجِدِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan ['Ali bin Hujr] mereka berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Abdul Wahid bin Hamzah] dari ['Abbad bin 'Abdullah bin Az Zubair] dari ['Aisyah] dia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam menshalati Suhail bin Baidla' melainkan di dalam masjid.\""},"1897":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ الْوَاحِدِ بْنِ حَمْزَةَ أَنَّ عَبَّادَ بْنَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَخْبَرَهُ أَنَّ عَائِشَةَ قَالَتْمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سُهَيْلِ ابْنِ بَيْضَاءَ إِلَّا فِي جَوْفِ الْمَسْجِدِ","id":"Telah mengabarkan kepada kami [Suwaid bin Naslr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Musa bin 'Uqbah] dari ['Abdul Wahid bin Hamzah], ['Abbad bin 'Abdullah bin Az Zubair] mengabarkan kepadanya bahwasanya ['Aisyah] dia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam menshalati Suhail bin Baidla' melainkan di dalam masjid.\""},"1898":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ أَنَّهُ قَالَاشْتَكَتْ امْرَأَةٌ بِالْعَوالِي مِسْكِينَةٌ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُمْ عَنْهَا وَقَالَ إِنْ مَاتَتْ فَلَا تَدْفِنُوهَا حَتَّى أُصَلِّيَ عَلَيْهَا فَتُوُفِّيَتْ فَجَاءُوا بِهَا إِلَى الْمَدِينَةِ بَعْدَ الْعَتَمَةِ فَوَجَدُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَامَ فَكَرِهُوا أَنْ يُوقِظُوهُ فَصَلَّوْا عَلَيْهَا وَدَفَنُوهَا بِبَقِيعِ الْغَرْقَدِ فَلَمَّا أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءُوا فَسَأَلَهُمْ عَنْهَا فَقَالُوا قَدْ دُفِنَتْ يَا رَسُولَ اللَّهِ وَقَدْ جِئْنَاكَ فَوَجَدْنَاكَ نَائِمًا فَكَرِهْنَا أَنْ نُوقِظَكَ قَالَ فَانْطَلِقُوا فَانْطَلَقَ يَمْشِي وَمَشَوْا مَعَهُ حَتَّى أَرَوْهُ قَبْرَهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفُّوا وَرَاءَهُ فَصَلَّى عَلَيْهَا وَكَبَّرَ أَرْبَعًا","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Umamah bin Sahl bin Hunaif] bahwasanya dia berkata; \"Ada seorang wanita -miskin- yang tinggal di dataran tinggi mengadu kesakitan, Rasulullah shallallahu 'alaihi wasallam bertanya kepada mereka tentang keadaannya dan bersabda: \"Jika ia meninggal dunia, janganlah kalian menguburkannya hingga aku menshalatinya.\" Kemudian ia meninggal dunia dan mereka membawanya ke Madinah setelah hari nampak gelap (setelah shalat 'Isya), saat itu mereka mendapatkan Rasulullah shallallahu 'alaihi wasallam telah tidur, mereka enggan untuk membangunkan beliau, lalu mereka menshalatinya dan menguburkannya di Baqi' Al Gharqad. Saat pagi harinya mereka datang menemui Rasulullah shallallahu 'alaihi wasallam, lalu beliau bertanya kepada mereka tentang wanita itu. Mereka menjawab; \"Ia telah dikuburkan wahai Rasulullah shallallahu 'alaihi wasallam, sungguh kami telah datang untuk menemui engkau, namun kami mendapatkan engkau sedang tidur, kami tidak ingin membangunkan engkau, beliau bersabda: \"Berangkatlah.\" Lalu beliau berangkat dengan berjalan kaki dan mereka berjalan bersama beliau, hingga mereka memperlihatkan kuburannya kepada Nabi. Lalu Rasulullah shallallahu 'alaihi wasallam berdiri dan mereka berdiri di belakang beliau, kemudian beliau melaksanakan shalat atasnya dan bertakbir empat kali.\""},"1899":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخَاكُمْ النَّجَاشِيَّ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ فَقَامَ فَصَفَّ بِنَا كَمَا يُصَفُّ عَلَى الْجَنَازَةِ وَصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid] dari [Hafsh bin Ghiyats] dari [Ibnu Juraij] dari ['Atha] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saudara kalian An Najasyi telah meninggal dunia, berdirilah dan shalatilah ia.\" Lalu beliau berdiri dan berbaris bersama kami seperti berbaris untuk melaksanakan shalat jenazah dan beliau pun melaksanakan shalat atasnya.\""},"1900":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لِلنَّاسِ النَّجَاشِيَّ الْيَوْمَ الَّذِي مَاتَ فِيهِ ثُمَّ خَرَجَ بِهِمْ إِلَى الْمُصَلَّى فَصَفَّ بِهِمْ فَصَلَّى عَلَيْهِ وَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah mengabarkan kepada kami [Suwaid bin Naslr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam memberitahukan kematian An Najazyi kepada orang-orang di hari kematiannya, beliau keluar bersama mereka ke tempat shalat, lalu berbaris, kemudian melaksanakan shalat atasnya dan bertakbir empat kali takbir.\""},"1901":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَعَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجَاشِيَّ لِأَصْحَابِهِ بِالْمَدِينَةِ فَصَفُّوا خَلْفَهُ فَصَلَّى عَلَيْهِ وَكَبَّرَ أَرْبَعًاقَالَ أَبُو عَبْد الرَّحْمَنِ ابْنُ الْمُسَيَّبِ إِنِّي لَمْ أَفْهَمْهُ كَمَا أَرَدْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnul Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memberitahukan kematian An Najasyi kepada para sahabat di Madinah, lalu mereka berbaris di belakang beliau, kemudian menshalatinya dan bertakbir empat kali.\" Abu Abdurrahman berkata; 'Aku belum mengerti tentang Ibnu Musayyab sebagaimana yang kamu maksudkan.'"},"1902":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخَاكُمْ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ فَصَفَفْنَا عَلَيْهِ صَفَّيْنِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saudara kalian telah meninggal dunia, berdirilah dan laksanakanlah shalat atasnya.\" Lalu mereka berbaris menjadi dua barisan.\""},"1903":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ سَمِعْتُ شُعْبَةَ يَقُولُ السَّاعَةَ يَخْرُجُ السَّاعَةَ يَخْرُجُ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَكُنْتُ فِي الصَّفِّ الثَّانِي يَوْمَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّجَاشِيِّ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Abu Dawud]; Aku mendengar [Syu'bah] berkata; \"Sekarang Abu Jubair akan keluar (dari rumahnya), sekarang Abu Jubair akan keluar (dari rumahnya). Telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] dia berkata; \"Aku berada di barisan kedua di hari ketika Rasulullah shallallahu 'alaihi wasallam menshalati An Najasyi.\""},"1904":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا يُونُسُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكُمْ النَّجَاشِيَّ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ قَالَ فَقُمْنَا فَصَفَفْنَا عَلَيْهِ كَمَا يُصَفُّ عَلَى الْمَيِّتِ وَصَلَّيْنَا عَلَيْهِ كَمَا يُصَلَّى عَلَى الْمَيِّتِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dia berkata; telah menceritakan kepada kami [Yunus] dari [Muhammad bin Sirin] dari [Abul Muhallab] dari ['Imran bin Hushain] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saudara kalian meninggal dunia, berdirilah dan laksanakanlah shalat atasnya.\" Ia berkata: \"Lalu kami berbaris seperti saat berbaris untuk menshalati mayit dan kami menshalatinya seperti menshalati mayit.\""},"1905":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ ابْنِ بُرَيْدَةَ عَنْ سَمُرَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُمِّ كَعْبٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ فِي وَسَطِهَا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari ['Abdul Warits] dia berkata; telah menceritakan kepada kami [Husain] dari [Ibnu Buraidah] dari [Samurah] dia berkata; \"Aku menshalati Ummu Ka'ab bersama Rasulullah shallallahu 'alaihi wasallam disaat darah nifasnya keluar. Lalu Rasulullah shallallahu 'alaihi wasallam berdiri dalam shalat pada posisi tengah jenazah tersebut.\""},"1906":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَمَّارٍ قَالَحَضَرَتْ جَنَازَةُ صَبِيٍّ وَامْرَأَةٍ فَقُدِّمَ الصَّبِيُّ مِمَّا يَلِي الْقَوْمَ وَوُضِعَتْ الْمَرْأَةُ وَرَاءَهُ فَصَلَّى عَلَيْهِمَا وَفِي الْقَوْمِ أَبُو سَعِيدٍ الْخُدْرِيُّ وَابْنُ عَبَّاسٍ وَأَبُو قَتَادَةَ وَأَبُو هُرَيْرَةَ فَسَأَلْتُهُمْ عَنْ ذَلِكَ فَقَالُوا السُّنَّةُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Sa'id] dia berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari ['Atha bin Abu Rabah] dari ['Ammar] dia berkata; \"-Saat- jenazah bayi laki-laki dan seorang wanita datang, jenazah bayi laki-laki dikedepankan di dekat kaum dan wanita tersebut diletakkan di belakangnya, lalu keduanya dishalati dan diantara kaum tersebut ada [Abu Sa'id Al Khudri], [Ibnu Abbas], [Abu Qatadah] dan [Abu Hurairah], lalu aku bertanya tentang hal itu? mereka mengatakan; \"Itu adalah sunnah.\""},"1907":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ نَافِعًا يَزْعُمُأَنَّ ابْنَ عُمَرَ صَلَّى عَلَى تِسْعِ جَنَائِزَ جَمِيعًا فَجَعَلَ الرِّجَالَ يَلُونَ الْإِمَامَ وَالنِّسَاءَ يَلِينَ الْقِبْلَةَ فَصَفَّهُنَّ صَفًّا وَاحِدًا وَوُضِعَتْ جَنَازَةُ أُمِّ كُلْثُومِ بِنْتِ عَلِيٍّ امْرَأَةِ عُمَرَ بْنِ الْخَطَّابِ وَابْنٍ لَهَا يُقَالُ لَهُ زَيْدٌ وُضِعَا جَمِيعًا وَالْإِمَامُ يَوْمَئِذٍ سَعِيدُ بْنُ الْعَاصِ وَفِي النَّاسِ ابْنُ عُمَرَ وَأَبُو هُرَيْرَةَ وَأَبُو سَعِيدٍ وَأَبُو قَتَادَةَ فَوُضِعَ الْغُلَامُ مِمَّا يَلِي الْإِمَامَ فَقَالَ رَجُلٌ فَأَنْكَرْتُ ذَلِكَ فَنَظَرْتُ إِلَى ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ وَأَبِي قَتَادَةَ فَقُلْتُ مَا هَذَا قَالُوا هِيَ السُّنَّةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dia berkata; Aku mendengar [Nafi'] menganggap bahwa [Ibnu Umar] pernah menshalati Sembilan orang jenazah secara bersama. Mereka meletakkan jenazah laki-laki di dekat Imam dan jenazah wanita di dekat kiblat, lalu mensejajarkan jenazah wanita menjadi satu barisan sambil diletakkan jenazah Ummu Kulstum binti Ali istri Umar bin Al Khattab dan anaknya yang bernama Zaid, keduanya diletakkan secara bersamaan. Dan yang menjadi Imam pada saat itu adalah Sa'id bin Al Ash sedangkan di antara para makmum terdapat Ibnu Umar, Abu Hurairah, Abu Sa'id dan Abu Qatadah. Lalu diletakan anak kecil tersebut di dekat imam. Ada seorang yang mengatakan; \" Aku mengingkari hal itu, kamudian aku melihat kearah [Ibnu Abbas], [Abu Hurairah], [Abu Sa'id] dan [Abu Qatadah]. Lalu aku berkata.\"Apa-apaan ini!\" mereka mengatakan; \"Inilah sunnah.\""},"1908":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ وَالْفَضْلُ بْنُ مُوسَى ح و أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حُسَيْنٍ الْمُكْتِبِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى أُمِّ فُلَانٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ فِي وَسَطِهَا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dan [Al Fadhl bin Musa]. Dan diriwayatkan pula dari jalur lain, telah mengabarkan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Husain Al Muktib] dari ['Abdullah bin Buraidah] dari [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam menshalati Ummu fulan -yang meninggal dalam keadaan nifas-. lalu Rasulullah shallallahu 'alaihi wasallam berdiri di posisi tengah jenazah tersebut."},"1909":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لِلنَّاسِ النَّجَاشِيَّ وَخَرَجَ بِهِمْ فَصَفَّ بِهِمْ وَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam memberitahukan kematian An Najasyi kepada orang-orang, lalu beliau keluar bersama mereka kemudian berbaris bersama mereka dan bertakbir empat kali takbir."},"1910":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ قَالَمَرِضَتْ امْرَأَةٌ مِنْ أَهْلِ الْعَوَالِي وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ شَيْءٍ عِيَادَةً لِلْمَرِيضِ فَقَالَ إِذَا مَاتَتْ فَآذِنُونِي فَمَاتَتْ لَيْلًا فَدَفَنُوهَا وَلَمْ يُعْلِمُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ سَأَلَ عَنْهَا فَقَالُوا كَرِهْنَا أَنْ نُوقِظَكَ يَا رَسُولَ اللَّهِ فَأَتَى قَبْرَهَا فَصَلَّى عَلَيْهَا وَكَبَّرَ أَرْبَعًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Umamah bin Sahl] dia berkata; Seorang wanita dari penduduk daratan tinggi sakit, sementara Nabi shallallahu 'alaihi wasallam adalah orang yang paling baik dalam urusan menjenguk orang sakit, lalu beliau bersabda: \"Jika ia meninggal dunia, beritahulah aku.\" Lalu ia meninggal dunia di malam hari dan mereka menguburnya tanpa memberitahu Nabi shallallahu 'alaihi wasallam saat pagi harinya, beliau bertanya tentang wanita itu, mereka menjawab; \"Kami tidak ingin membangunkanmu wahai Rasulullah!\" Kontan beliau mendatangi kuburannya, menshalatinya dan bertakbir empat kali (melakukan shalat jenazah)."},"1911":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى أَنَّ زَيْدَ بْنَ أَرْقَمَصَلَّى عَلَى جَنَازَةٍ فَكَبَّرَ عَلَيْهَا خَمْسًا وَقَالَ كَبَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepadaku ['Amru bin Murrah] dari [Ibnu Abu Laila] bahwasanya [Zaid bin Arqam] menshalati seorang jenazah, lalu ia bertakbir lima kali dan berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah melakukannya -seperti ini-.\""},"1912":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَبِي حَمْزَةَ بْنِ سُلَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى جَنَازَةٍ يَقُولُ اللَّهُمَّ اغْفِرْ لَهُ وَارْحَمْهُ وَاعْفُ عَنْهُ وَعَافِهِ وَأَكْرِمْ نُزُلَهُ وَوَسِّعْ مُدْخَلَهُ وَاغْسِلْهُ بِمَاءٍ وَثَلْجٍ وَبَرَدٍ وَنَقِّهِ مِنْ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ وَأَبْدِلْهُ دَارًا خَيْرًا مِنْ دَارِهِ وَأَهْلًا خَيْرًا مِنْ أَهْلِهِ وَزَوْجًا خَيْرًا مِنْ زَوْجِهِ وَقِهِ عَذَابَ الْقَبْرِ وَعَذَابَ النَّارِقَالَ عَوْفٌ فَتَمَنَّيْتُ أَنْ لَوْ كُنْتُ الْمَيِّتَ لِدُعَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِذَلِكَ الْمَيِّتِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] dari [Ibnu Wahab] dia berkata; telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Abu Hamzah bin Sulaim] dari ['Abdurrahman bin Jubair] dari [bapaknya] dari ['Auf bin Malik] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam menshalati jenazah dengan berdo'a: \"Ya Allah, berilah ampunan kepadanya. Kasihilah ia, maafkanlah ia dan selamatkanlah ia. Muliakanlah saat turunnya, luaskanlah kuburannya, mandikanlah ia dengan air, salju dan embun, bersihkanlah ia dari kotoran seperti baju putih yang dibersihkan dari kotoran, gantikan rumah yang lebih baik dari rumahnya, istri yang lebih baik dari istrinya, dan lindungilah dari adzab kubur dan adzab Neraka.\" Auf berkata; \"Aku pun berharap, andaikata aku menjadi mayit itu, karena doa Rasulullah shallallahu 'alaihi wasallam untuk mayit tersebut.\""},"1913":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ حَبِيبِ بْنِ عُبَيْدٍ الْكَلَاعِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ قَالَ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى مَيِّتٍ فَسَمِعْتُ فِي دُعَائِهِ وَهُوَ يَقُولُ اللَّهُمَّ اغْفِرْ لَهُ وَارْحَمْهُ وَعَافِهِ وَاعْفُ عَنْهُ وَأَكْرِمْ نُزُلَهُ وَوَسِّعْ مُدْخَلَهُ وَاغْسِلْهُ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ وَنَقِّهِ مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَأَبْدِلْهُ دَارًا خَيْرًا مِنْ دَارِهِ وَأَهْلًا خَيْرًا مِنْ أَهْلِهِ وَزَوْجًا خَيْرًا مِنْ زَوْجِهِ وَأَدْخِلْهُ الْجَنَّةَ وَنَجِّهِ مِنْ النَّارِ أَوْ قَالَ وَأَعِذْهُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Ma'n] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Habib bin 'Ubaid Al Kala'i] dari [Jubair bin Nufair Al Hadlrami] dia berkata; aku mendengar ['Auf bin Malik] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam menshalati mayit, lalu aku mendengar dalam do'anya beliau mengucapkan: \"Ya Allah, ampunilah ia, kasihanilah ia, selamatkan dan maafkanlah ia. Muliakanlah saat turunnya, luaskanlah kuburannya, mandikanlah ia dengan air, salju dan embun, bersihkanlah kesalahan darinya seperti baju putih yang dibersihkan dari kotoran, gantikanlah rumah yang lebih baik dari rumahnya, istri yang lebih baik dari istrinya, masukkanlah ia ke dalam surga, selamatkanlah ia dari neraka -atau beliau bersabda: - dan lindungilah ia dari siksa kubur.\""},"1914":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ رُبَيِّعَةَ السُّلَمِيِّ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عُبَيْدِ بْنِ خَالِدٍ السُّلَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخَى بَيْنَ رَجُلَيْنِ فَقُتِلَ أَحَدُهُمَا وَمَاتَ الْآخَرُ بَعْدَهُ فَصَلَّيْنَا عَلَيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُلْتُمْ قَالُوا دَعَوْنَا لَهُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ اللَّهُمَّ أَلْحِقْهُ بِصَاحِبِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ صَلَاتُهُ بَعْدَ صَلَاتِهِ وَأَيْنَ عَمَلُهُ بَعْدَ عَمَلِهِ فَلَمَا بَيْنَهُمَا كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِقَالَ عَمْرُو بْنُ مَيْمُونٍ أَعْجَبَنِي لِأَنَّهُ أَسْنَدَ لِي","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; Aku mendengar ['Amru bin Maimun] menceritakan dari ['Abdullah bin Rubai'ah As Sulami] -dan dia termasuk sahabat Rasulullah shallallahu 'alaihi wasallam- dari ['Ubaid bin Khalid As Sulami] bahwa Rasulullah shallallahu 'alaihi wasallam mensaudarakan antara dua orang, lalu salah satu dari keduanya terbunuh dan yang lain meniggal dunia setelahnya. Kemudian kami menshalatinya. Nabi shallallahu 'alaihi wasallam bertanya: \"Apa yang kalian ucapkan?\" mereka menjawab, \"kami berdo'a untuknya; \"Ya Allah, berilah ampunan kepadanya, ya Allah, rahmatilah ia, ya Allah, pertemukanlah ia dengan sahabatnya!\" Nabi shallallahu 'alaihi wasallam bersabda: \"Dimanakah letak keistimewaan shalatnya dibandingkan shalat kawannya (kawan yang meninggal duluan)? Dan dimanakah letak amalannya dibandingkan amalan (kawan yang meninggal duluan)? Perbedaan antara keduanya bagaikan antara langit dan bumi.\""},"1915":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي إِبْرَاهِيمَ الْأَنْصَارِيِّ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الصَّلَاةِ عَلَى الْمَيِّتِ اللَّهُمَّ اغْفِرْ لِحَيِّنَا وَمَيِّتِنَا وَشَاهِدِنَا وَغَائِبِنَا وَذَكَرِنَا وَأُنْثَانَا وَصَغِيرِنَا وَكَبِيرِنَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Hisyam bin Abu 'Abdullah] dari [Yahya bin Abu Katsir] dari [Abu Ibrahim Al Anshari] dari [bapaknya] bahwasanya ia mendengar Nabi shallallahu 'alaihi wasallam berdo'a saat menshalati mayit, \"Ya Allah berilah ampunan bagi yang masih hidup di antara kami dan yang sudah meninggal dunia, orang yang hadir di antara kami dan yang tidak hadir, kaum laki-laki di antara kami dan kaum wanita, orang yang masih muda di antara kami dan orang yang sudah tua.\""},"1916":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ وَهُوَ ابْنُ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ قَالَصَلَّيْتُ خَلْفَ ابْنِ عَبَّاسٍ عَلَى جَنَازَةٍ فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ وَجَهَرَ حَتَّى أَسْمَعَنَا فَلَمَّا فَرَغَ أَخَذْتُ بِيَدِهِ فَسَأَلْتُهُ فَقَالَ سُنَّةٌ وَحَقٌّ","id":"Telah mengabarkan kepada kami [Al Haitsam bin Ayyub] dia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dia berkata; [bapakku] telah menceritakan kepada kami dari [Thalhah bin 'Abdullah bin 'Auf] dia berkata; \"Aku pernah menshalati jenazah di belakang [Ibnu Abbas], lalu ia membaca surah Al Fatihah dan surah lain, ia mengeraskan (bacaannya) hingga terdengar oleh kami. Setelah selesai, kutarik tangannya, lalu aku bertanya kepadanya? Ia menjawab, \"Ini adalah sunnah dan kebenaran.\""},"1917":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ قَالَصَلَّيْتُ خَلْفَ ابْنِ عَبَّاسٍ عَلَى جَنَازَةٍ فَسَمِعْتُهُ يَقْرَأُ بِفَاتِحَةِ الْكِتَابِ فَلَمَّا انْصَرَفَ أَخَذْتُ بِيَدِهِ فَسَأَلْتُهُ فَقُلْتُ تَقْرَأُ قَالَ نَعَمْ إِنَّهُ حَقٌّ وَسُنَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Thalhah bin 'Abdullah] dia berkata; \"Aku pernah menshalati jenazah di belakang [Ibnu Abbas], lalu aku mendengar ia membaca surah Al Fatihah, setelah selesai, kutarik tangannya, lalu aku bertanya kepadanya dengan berkata; \"Engkau membaca -surah setelah Al Fatihah-?\" ia menjawab; \"Ya, ini adalah kebenaran dan sunnah.\""},"1918":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ أَنَّهُ قَالَالسُّنَّةُ فِي الصَّلَاةِ عَلَى الْجَنَازَةِ أَنْ يَقْرَأَ فِي التَّكْبِيرَةِ الْأُولَى بِأُمِّ الْقُرْآنِ مُخَافَتَةً ثُمَّ يُكَبِّرَ ثَلَاثًا وَالتَّسْلِيمُ عِنْدَ الْآخِرَةِأَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ سُوَيْدٍ الدِّمَشْقِيِّ الْفِهْرِيِّ عَنْ الضَّحَّاكِ بْنِ قَيْسٍ الدِّمَشْقِيِّ بِنَحْوِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Umamah] bahwasanya ia berkata; \"Yang sesuai sunnah pada shalat jenazah adalah membaca Al Fatihah pada takbir pertama dengan suara pelan, kemudian bertakbir tiga kali dan mengucapkan salam pada rakaat terakhir.\" Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Muhammad bin Suwaid Ad Dimasyqi Al Fihri] dari [Dlahhak bin Qais Ad Dimasyqi] seperti itu juga."},"1919":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ سَلَّامِ بْنِ أَبِي مُطِيعٍ الدِّمَشْقِيِّ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ رَضِيعِ عَائِشَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مَيِّتٍ يُصَلِّي عَلَيْهِ أُمَّةٌ مِنْ الْمُسْلِمِينَ يَبْلُغُونَ أَنْ يَكُونُوا مِائَةً يَشْفَعُونَ إِلَّا شُفِّعُوا فِيهِقَالَ سَلَّامٌ فَحَدَّثْتُ بِهِ شُعَيْبَ بْنَ الْحَبْحَابِ فَقَالَ حَدَّثَنِي بِهِ أَنَسُ بْنُ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Sallam bin Abu Muthi' Ad Dimasyqi] dari [Ayyub] dari [Abu Qibalah] dari ['Abdullah bin Yazid] -saudara sepersusuan 'Aisyah- dari ['Aisyah Radliyatul anha], dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidaklah seorang mayit dishalati oleh umat dari kalangan kaum Muslimin yang jumlah mereka mencapai seratus, semuanya memberikan kesaksian baik, kecuali akan diberi syafa'at padanya.\" [Sallam] berkata; ' hal itu aku ceritakan kepada [Syu'aib bin Al Habhab] lalu ia berkata; ' [Anas bin Malik] telah menceritakan hal itu kepadaku dari Nabi shallallahu 'alaihi wasallam.'"},"1920":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ رَضِيعٍ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ أَحَدٌ مِنْ الْمُسْلِمِينَ فَيُصَلِّي عَلَيْهِ أُمَّةٌ مِنْ النَّاسِ فَيَبْلُغُوا أَنْ يَكُونُوا مِائَةً فَيَشْفَعُوا إِلَّا شُفِّعُوا فِيهِ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Qilabah] dari ['Abdullah bin Yazid] -saudara sepersusuan 'Aisyah- dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang dari kaum Muslimin meninggal dunia kemudian dishalati oleh umat manusia yang jumlah mereka seratus, lalu kemudian mereka memberi kesaksian baik, kecuali akan diberi syafa'at padanya.\""},"1921":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ سَوَاءٍ أَبُو الْخَطَّابِ قَالَ حَدَّثَنَا أَبُو بَكَّارٍ الْحَكَمُ بْنُ فَرُّوخَ قَالَ صَلَّى بِنَا أَبُو الْمَلِيحِ عَلَى جَنَازَةٍ فَظَنَنَّا أَنَّهُ قَدْ كَبَّرَ فَأَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ أَقِيمُوا صُفُوفَكُمْ وَلْتَحْسُنْ شَفَاعَتُكُمْ قَالَ أَبُو الْمَلِيحِ حَدَّثَنِي عَبْدُ اللَّهِ وَهُوَ ابْنُ سَلِيطٍ عَنْ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ وَهِيَ مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْأَخْبَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مَيِّتٍ يُصَلِّي عَلَيْهِ أُمَّةٌ مِنْ النَّاسِ إِلَّا شُفِّعُوا فِيهِفَسَأَلْتُ أَبَا الْمَلِيحِ عَنْ الْأُمَّةِ فَقَالَ أَرْبَعُونَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Muhammad bin Sawa Abul Khaththab] dia berkata; telah menceritakan kepada kami [Abu Bakkar Al Hakam bin Farrukh] dia berkata; \"Abul Malih pernah menshalati jenazah bersama kami, lalu kami mengira beliau telah bertakbir! Kemudian beliau menghadapkan wajahnya ke arah kami seraya berkata; \"Luruskan barisan dan berikanlah kesaksian baik kalian.\" [Abul Malih] berkata: Telah menceritakan kepadaku [Abdullah] -yakni Ibnu Salith-dari salah seorang Ibu para Mukminin -yaitu [Maimunah] istri Nabi shallallahu 'alaihi wasallam-, ia berkata: \"Nabi shallallahu 'alaihi wasallam mengabarkan kepadaku, beliau bersabda: \"Tidaklah seseorang meninggal dunia, kemudian mati dishalati oleh segolongan umat manusia, kecuali akan diberi syafa'at'.\" Lalu aku bertanya kepada Abul Mulih apa maksud tentang segolongan umat? Ia menjawab; \"Empat puluh orang.\""},"1922":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَى جَنَازَةٍ فَلَهُ قِيرَاطٌ وَمَنْ انْتَظَرَهَا حَتَّى تُوضَعَ فِي اللَّحْدِ فَلَهُ قِيرَاطَانِ وَالْقِيرَاطَانِ مِثْلُ الْجَبَلَيْنِ الْعَظِيمَيْنِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib] dia berkata; telah memberitakan kepada kami ['Abdurrazaaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menshalati jenazah, baginya pahala satu qirath dan barang siapa yang menunggunya sampai dimasukkan ke dalam liang lahad, baginya pahala dua qirath. Dua qirath besarnya seperti dua gunung yang besar.\""},"1923":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ الْأَعْرَجُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَهِدَ جَنَازَةً حَتَّى يُصَلَّى عَلَيْهَا فَلَهُ قِيرَاطٌ وَمَنْ شَهِدَ حَتَّى تُدْفَنَ فَلَهُ قِيرَاطَانِ قِيلَ وَمَا الْقِيرَاطَانِ يَا رَسُولَ اللَّهِ قَالَ مِثْلُ الْجَبَلَيْنِ الْعَظِيمَيْنِ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah mengabarkan kepada kami ['Abdullah] dari [Yunus] dari [Az Zuhri] dia berkata; telah memberitakan kepada kami ['Abdurrahman Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menyaksikan jenazah hingga menshalatinya, baginya pahala satu qirath dan barang siapa yang menyaksikan hingga dikubur, baginya pahala dua qirath.\" "},"1924":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ عَوْفٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَبِعَ جَنَازَةَ رَجُلٍ مُسْلِمٍ احْتِسَابًا فَصَلَّى عَلَيْهَا وَدَفَنَهَا فَلَهُ قِيرَاطَانِ وَمَنْ صَلَّى عَلَيْهَا ثُمَّ رَجَعَ قَبْلَ أَنْ تُدْفَنَ فَإِنَّهُ يَرْجِعُ بِقِيرَاطٍ مِنْ الْأَجْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah kami [Muhammad bin Ja'far] dari ['Auf] dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengiringi jenazah seorang muslim dengan mengharap pahala, lalu menshalatinya dan menguburkannya, baginya pahala dua qirath, dan barangsiapa yang menshalatinya, kemudian pulang sebelum dikubur, dia pulang dengan membawa pahala satu qirath.\""},"1925":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ قَالَ حَدَّثَنَا مَسْلَمَةُ بْنُ عَلْقَمَةَ قَالَ أَنْبَأَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَبِعَ جَنَازَةً فَصَلَّى عَلَيْهَا ثُمَّ انْصَرَفَ فَلَهُ قِيرَاطٌ مِنْ الْأَجْرِ وَمَنْ تَبِعَهَا فَصَلَّى عَلَيْهَا ثُمَّ قَعَدَ حَتَّى يُفْرَغَ مِنْ دَفْنِهَا فَلَهُ قِيرَاطَانِ مِنْ الْأَجْرِ كُلُّ وَاحِدٍ مِنْهُمَا أَعْظَمُ مِنْ أُحُدٍ","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dia berkata; telah menceritakan kepada kami [Maslamah bin 'Alqamah] dia berkata; telah memberitakan kepada kami [Dawud] dari ['Amir] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengikuti jenazah, lalu menshalatinya kemudian pulang, baginya pahala satu qirath. Dan barangsiapa yang mengikutinya, lalu menshalatinya, kemudian duduk hingga selesai dari penguburannya, baginya pahala dua qirath, masing-masing dari keduanya lebih besar dari gunung Uhud.\""},"1926":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامٍ وَالْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا وَمَنْ تَبِعَهَا فَلَا يَقْعُدَنَّ حَتَّى تُوضَعَ","id":"Telah mengabarkan kepada kami [Suwaid bin Naslr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Hisyam] dan [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salalmah] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian melihat jenazah, berdirilah dan apabila mengiringinya, janganlah ia duduk hingga jenazah itu diletakkan."},"1927":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ وَاقِدٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ مَسْعُودِ بْنِ الْحَكَمِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّهُ ذُكِرَ الْقِيَامُ عَلَى الْجَنَازَةِ حَتَّى تُوضَعَ فَقَالَ عَلِيُّ بْنُ أَبِي طَالِبٍ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَعَدَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Waqid] dari [Nafi' bin Jubair] dari [Mas'ud bin Al Hakam] dari ['Ali bin Abu Thalib], disebutkan tentang berdiri ketika ada jenazah hingga diletakkan! Ali bin Abu Thalib berkata; \"Rasulullah shallallahu 'alaihi wasallam berdiri kemudian duduk.\""},"1928":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ مَسْعُودِ بْنِ الْحَكَمِ عَنْ عَلِيٍّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَقُمْنَا وَرَأَيْنَاهُ قَعَدَ فَقَعَدْنَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Muhammad bin Al Munkadir] dari [Mas'ud bin Al Hakam] dari ['Ali] dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berdiri, lalu kami pun berdiri dan kami melihat beliau duduk, lalu kami pun duduk.\""},"1929":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ زَاذَانَ عَنْ الْبَرَاءِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةٍ فَلَمَّا انْتَهَيْنَا إِلَى الْقَبْرِ وَلَمْ يُلْحَدْ فَجَلَسَ وَجَلَسْنَا حَوْلَهُ كَأَنَّ عَلَى رُءُوسِنَا الطَّيْرَ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dia berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari ['Amru bin Qais] dari [Al Minhal bin 'Amru] dari [Zadzan] dari [Al Barra'] dia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam -rangka mengiringi- jenazah. Setelah kami berhenti di kuburan -namun kuburan belum di gali-, beliau duduk dan kami pun duduk di sekitar beliau, seolah-olah di kepala kami ada burung.\""},"1930":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقَتْلَى أُحُدٍ زَمِّلُوهُمْ بِدِمَائِهِمْ فَإِنَّهُ لَيْسَ كَلْمٌ يُكْلَمُ فِي اللَّهِ إِلَّا يَأْتِي يَوْمَ الْقِيَامَةِ يَدْمَى لَوْنُهُ لَوْنُ الدَّمِ وَرِيحُهُ رِيحُ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Hannad] dari [Ibnul Mubarak] dari [Ma'mar] dari [Az Zuhri] dari ['Abdullah bin Tsa'labah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda untuk orang-orang yang terbunuh dalam perang Uhud, \"Selimutilah mereka bersama darah yang ada pada tubuh mereka, sungguh tidak ada luka yang tergores di jalan Allah kecuali pada hari kiamat dia akan datang dengan berlumuran darah, warnanya seperti warna darah dan baunya adalah bau misik.\""},"1931":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدّ��ثَنَا سَعِيدُ بْنُ السَّائِبِ عَنْ رَجُلٍ يُقَالُ لَهُ عُبَيْدُ اللَّهِ بْنُ مُعَيَّةَ قَالَأُصِيبَ رَجُلَانِ مِنْ الْمُسْلِمِينَ يَوْمَ الطَّائِفِ فَحُمِلَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ أَنْ يُدْفَنَا حَيْثُ أُصِيبَا وَكَانَ ابْنُ مُعَيَّةَ وُلِدَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sa'id bin As Saib] dari seorang lelaki yang bernama ['Ubaidullah bin Mu'ayyah] dia berkata; \"Dua orang dari kaum Muslimin gugur pada perang Thaif, lalu mereka berdua dibawa kepada Nabi shallallahu 'alaihi wasallam, beliau memerintahkan agar mereka dikubur sebagaimana mereka meninggal, dan Ibnu Mu'ayyah dilahirkan pada masa Rasulullah shallallahu 'alaihi wasallam.\""},"1932":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلَى أُحُدٍ أَنْ يُرَدُّوا إِلَى مَصَارِعِهِمْ وَكَانُوا قَدْ نُقِلُوا إِلَى الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Al Aswad bin Qais] dari [Nubaih Al 'Anazi] dari [Jabir bin 'Abdullah] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan orang-orang yang terbunuh dalam perang Uhud agar dikembalikan ke tempat mereka terbunuh, padahal mereka telah dipindahkan ke Madinah.\""},"1933":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِىِّ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ادْفِنُوا الْقَتْلَى فِي مَصَارِعِهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Al Aswad bin Qais] dari [Nubaih Al? nazi] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Kuburkanlah orang-orang yang terbunuh di tempat mereka terbunuh.\""},"1934":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ نَاجِيَةَ بْنِ كَعْبٍ عَنْ عَلِيٍّ قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَمَّكَ الشَّيْخَ الضَّالَّ مَاتَ فَمَنْ يُوَارِيهِ قَالَ اذْهَبْ فَوَارِ أَبَاكَ وَلَا تُحْدِثَنَّ حَدَثًا حَتَّى تَأْتِيَنِي فَوَارَيْتُهُ ثُمَّ جِئْتُ فَأَمَرَنِي فَاغْتَسَلْتُ وَدَعَا لِي وَذَكَرَ دُعَاءً لَمْ أَحْفَظْهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Abu Ishaq] dari [Najiyah bin Ka'ab] dari ['Ali] dia berkata; \"Aku pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, \" paman engkau, orang tua yang sesat telah meninggal dunia! Siapa yang menguburkannya?\" beliau bersabda: \"Pergilah, lalu kuburkan bapakmu dan janganlah sekali-kali kamu melakukan suatu hal, hingga kamu datang menemuiku.\" Kemudian aku menguburkannya dan datang menemuinya, lalu beliau memerintahkanku untuk mandi, aku mandi dan beliau berdoa untukku. Beliau menyebutkan suatu doa yang tidak aku hafal.\""},"1935":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ سَعْدٍ قَالَأَلْحِدُوا لِي لَحْدًا وَانْصِبُوا عَلَيَّ نَصْبًا كَمَا فُعِلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami ['Abdullah bin Ja'far] dari [Isma'il bin Muhammad bin Sa'ad] dari [bapaknya] dari [Sa'ad] dia berkata; \"Galilah lahd untukku, dan tegakkan (gundukkan tanah) di atasku, sebagaimana telah dibuatkan untuk Rasulullah shallallahu 'alaihi wasallam.\""},"1936":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو عَامِرٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدٍ عَنْ عَامِرِ بْنِ سَعْدٍأَنَّ سَعْدًا لَمَّا حَضَرَتْهُ الْوَفَاةُ قَالَ أَلْحِدُوا لِي لَحْدًا وَانْصِبُوا عَلَيَّ نَصْبًا كَمَا فُعِلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Abu 'Amir] dari ['Abdullah bin Ja'far] dari [Isma'il bin Muhammad] dari ['Amir bin Sa'd] bahwasanya [Sa'd] ketika menjelang wafatnya berkata; \"Galilah lahd untukku dan tegakkan (gundukkan tanah) di atasku, sebagaimana telah dibuatkan untuk Rasulullah shallallahu 'alaihi wasallam.\""},"1937":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَبُو عَبْدِ الرَّحْمَنِ الْأَذْرَمِيُّ عَنْ حُكَّامِ بْنِ سَلْمٍ الرَّازِيِّ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّحْدُ لَنَا وَالشَّقُّ لِغَيْرِنَا","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad Abu 'Abdurrahman Al Adzrami] dari [Hukkam bin Salm Ar Razi] dari ['Ali bin 'Abdul A'la] dari [bapaknya] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Liang lahad (galian yang dimiringkan) ditanah adalah untuk kita sedangkan Syaq (galian yang sekelilingnya di semen) adalah untuk selain kita.\""},"1938":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَقُلْنَا يَا رَسُولَ اللَّهِ الْحَفْرُ عَلَيْنَا لِكُلِّ إِنْسَانٍ شَدِيدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَعْمِقُوا وَأَحْسِنُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي قَبْرٍ وَاحِدٍ قَالُوا فَمَنْ نُقَدِّمُ يَا رَسُولَ اللَّهِ قَالَ قَدِّمُوا أَكْثَرَهُمْ قُرْآنًا قَالَ فَكَانَ أَبِي ثَالِثَ ثَلَاثَةٍ فِي قَبْرٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Ishaq bin Yusuf] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Humaid bin Hilal] dari [Hisyam bin 'Amir] dia berkata; kami mengadu kepada Rasulullah shallallahu 'alaihi wasallam pada perang Uhud, kami berkata ya Rasulullah perintah untuk membuat kuburan setiap seorang diantara kami teramat sulit, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \" Buatlah kuburan, perdalam dan perbaguslah lalu kuburkan dua atau tiga orang pada satu kubur, \" mereka bertanya siapa yang kami dahulukan ya Rasulullah, beliau menjawab: \"Dahulukan diantara mereka yang paling banyak hafalan Qur'annya, \" ia berkata dan ayahku adalah yang ketiga dari tiga orang yang dikubur di satu kuburan.Hisyam berkata; \"Bapakku adalah orang ketiga dari tiga orang yang dimasukkan dalam satu lahd.\""},"1939":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ حُمَيْدَ بْنَ هِلَالٍ عَنْ سَعْدِ بْنِ هِشَامِ بْنِ عَامِرٍ عَنْ أَبِيهِ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ أُصِيبَ مَنْ أُصِيبَ مِنْ الْمُسْلِمِينَ وَأَصَابَ النَّاسَ جِرَاحَاتٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًا","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Wahb bin Jarir] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; Aku mendengar [Humaid bin Hilal] dari [Sa'd bin Hisyam bin 'Amir] dari [bapaknya] dia berkata; \"Setelah terjadi perang Uhud, ada beberapa orang muslimin yang tertimpa musibah dan banyak orang yang terluka, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gali, perluas dan kuburkanlah dua dan tiga orang dalam satu kuburan, serta dahulukan di antara mereka yang paling banyak hafalan Al Qur'annya.\""},"1940":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجُعِلَ تَحْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دُفِنَ قَطِيفَةٌ حَمْرَاءُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] dari [Ibnu 'Abbas] dia berkata; \"Satu lembar kain yang terbuat dari kapas berwarna merah diletakkan di bawah jenazah Rasulullah shallallahu 'alaihi wasallam ketika beliau dikubur.\""},"1941":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مُوسَى بْنُ عَلِيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ قَالَثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَزُولَ الشَّمْسُ وَحِينَ تَضَيَّفُ الشَّمْسُ لِلْغُرُوبِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Musa bin 'Ali bin Rabah] dia berkata; aku mendengar [bapakku] berkata; aku mendengar ['Uqbah bin 'Amir Al Juhani] dia berkata; \"Ada tiga waktu yang ketiganya kita dilarang Rasulullah shallallahu 'alaihi wasallam untuk shalat pada waktu tersebut, atau menguburkan orang-orang yang telah meninggal di antara kita, yaitu: ketika terbit matahari hingga naik, ketika siang hari hingga tergelincir dan ketika matahari mendekati terbenam.\""},"1942":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ الْقَطَّانُ الرَّقِّيُّ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ رَجُلًا مِنْ أَصْحَابِهِ مَاتَ فَقُبِرَ لَيْلًا وَكُفِّنَ فِي كَفَنٍ غَيْرِ طَائِلٍ فَزَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْبَرَ إِنْسَانٌ لَيْلًا إِلَّا أَنْ يُضْطَرَّ إِلَى ذَلِكَ","id":"Telah mengabarkan kepadaku ['Abdurrahman bin Khalid Al Qaththan Ar Raqqi] dia berkata; telah menceritakan kepada kami [Hajjaj]; berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah, lalu menyebutkan salah seorang dari sahabatnya yang meninggal dunia, kemudian di kubur pada malam hari yang dikafani dengan kain kafan yang tidak besar, Rasulullah shallallahu 'alaihi wasallam mencegah jenazah dikubur di malam hari, kecuali terpaksa melakukan hal itu.\""},"1943":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ أَصَابَ النَّاسَ جَهْدٌ شَدِيدٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي قَبْرٍ فَقَالُوا يَا رَسُولَ اللَّهِ فَمَنْ نُقَدِّمُ قَالَ قَدِّمُوا أَكْثَرَهُمْ قُرْآنًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dari [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal] dari [Hisyam bin 'Amir] dia berkata; setelah perang Uhud, orang-orang merasa sangat letih, Nabi shallallahu 'alaihi wasallam bersabda: \"Gali, perluas dan kuburkanlah dua dan tiga orang dalam satu kuburan.\" Mereka bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, siapa yang kita dahulukan?\" Beliau menjawab: \"Dahulukan di antara mereka yang paling banyak hafalan Al Qur'annya.\""},"1944":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ سَعْدِ بْنِ هِشَامِ بْنِ عَامِرٍ عَنْ أَبِيهِ قَالَاشْتَدَّ الْجِرَاحُ يَوْمَ أُحُدٍ فَشُكِيَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ احْفِرُوا وَأَوْسِعُوا وَأَحْسِنُوا وَادْفِنُوا فِي الْقَبْرِ الِاثْنَيْنِ وَالثَّلَاثَةَ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًا","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; telah memberitakan kepada kami [Sulaiman bin Harb] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Humaid bin Hilal] dari [Sa'd bin Hisyam bin 'Amir] dari [bapaknya], dia berkata; \"Luka semakin parah pada saat perang Uhud, hal itu diadukan kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Gali, perluas, baguskan dan kuburkanlah dua dan tiga orang dalam satu kuburan, serta dahulukan di antara mereka yang paling banyak hafalan Al Qur'annya.\""},"1945":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي الدَّهْمَاءِ عَنْ هِشَامِ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْفِرُوا وَأَحْسِنُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Musaddad] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dari [Ayyub] dari [Humaid bin Hilal] dari [Abu Ad Dahma'] dari [Hisyam bin 'Amir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gali, baguskan dan kuburkanlah dua dan tiga orang dalam satu kuburan, serta dahulukan di antara mereka yang paling banyak hafalan Al Qur'annya.\""},"1946":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَقُتِلَ أَبِي يَوْمَ أُحُدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَأَحْسِنُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًافَكَانَ أَبِي ثَالِثَ ثَلَاثَةٍ وَكَانَ أَكْثَرَهُمْ قُرْآنًا فَقُدِّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Hisyam bin 'Amir] dia berkata; \"Bapakku terbunuh pada perang Uhud, Nabi shallallahu 'alaihi wasallam bersabda: \"Gali, perluas, baguskan dan kuburkanlah dua dan tiga orang dalam satu kuburan, serta dahulukan di antara mereka yang paling banyak hafalan Al Qur'annya.\" Bapakku adalah orang ketiga dari tiga orang (yang dimasukkan dalam satu lubang), ia adalah yang paling banyak hafalan Al Qur'annya, dia didahulukan.\""},"1947":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ سُفْيَانَ قَالَ سَمِعَ عَمْرٌو جَابِرًا يَقُولُأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ بَعْدَ مَا أُدْخِلَ فِي قَبْرِهِ فَأَمَرَ بِهِ فَأُخْرِجَ فَوَضَعَهُ عَلَى رُكْبَتَيْهِ وَنَفَثَ عَلَيْهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ وَاللَّهُ أَعْلَمُ","id":"Berkata [Al Harits bin Miskin] secara baca, dan aku mendengarnya dari [Sufyan] dia berkata; ['Amru] mendengar dari [Jabir] dia berkata; \"Nabi shallallahu 'alaihi wasallam mendatangi kuburan Abdullah bin Ubai, setelah ia dimasukkan ke dalam kuburannya, lalu beliau memerintahkan untuk dikeluarkan, dan beliau meletakkannya di atas lutut beliau, lalu beliau meniup sedikit air liur padanya dan memakaikan baju beliau.\" Wallahu A'lam."},"1948":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرًا يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِعَبْدِ اللَّهِ بْنِ أُبَيٍّ فَأَخْرَجَهُ مِنْ قَبْرِهِ فَوَضَعَ رَأْسَهُ عَلَى رُكْبَتَيْهِ فَتَفَلَ فِيهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ قَالَ جَابِرٌ وَصَلَّى عَلَيْهِ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Al Fadl bin Musa] dari [Al Hasan bin Waqid] dia berkata; telah menceritakan kepada kami ['Amru bin Dinar] dia berkata; Aku mendengar [Jabir] berkata; \"Nabi shallallahu 'alaihi wasallam menyuruh untuk mengeluarkannya Abdullah bin Ubai dari kuburannya, lalu beliau meletakkan kepalanya di atas lutut beliau kemudian meniupkan sedikit air liur dan memakaikan baju beliau.\" Jabir berkata; \"Dan menshalatinya.\" Wallahu A'lam."},"1949":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ عَنْ سَعِيدِ بْنِ عَامِرٍ عَنْ شُعْبَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَدُفِنَ مَعَ أَبِي رَجُلٌ فِي الْقَبْرِ فَلَمْ يَطِبْ قَلْبِي حَتَّى أَخْرَجْتُهُ وَدَفَنْتُهُ عَلَى حِدَةٍ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin 'Abdul 'Azhim] dari [Sa'id bin 'Amir] dari [Syu'bah] dari [Ibnu Abu Najih] dari ['Atha] dari [Jabir] dia berkata; \"Seseorang dikubur bersama ayahku dalam satu kubur, namun hatiku tidak nyaman hingga aku mengeluarkannya dan aku menguburkannya pada kuburan yang lain.\""},"1950":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو قُدَامَةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ عَمِّهِ يَزِيدَ بْنِ ثَابِتٍأَنَّهُمْ خَرَجُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَرَأَى قَبْرًا جَدِيدًا فَقَالَ مَا هَذَا قَالُوا هَذِهِ فُلَانَةُ مَوْلَاةُ بَنِي فُلَانٍ فَعَرَفَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَتْ ظُهْرًا وَأَنْتَ نَائِمٌ قَائِلٌ فَلَمْ نُحِبَّ أَنْ نُوقِظَكَ بِهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَّ النَّاسَ خَلْفَهُ وَكَبَّرَ عَلَيْهَا أَرْبَعًا ثُمَّ قَالَ لَا يَمُوتُ فِيكُمْ مَيِّتٌ مَا دُمْتُ بَيْنَ أَظْهُرِكُمْ إِلَّا آذَنْتُمُونِي بِهِ فَإِنَّ صَلَاتِي لَهُ رَحْمَةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id Abu Qudamah] dia berkata; telah menceritakan kepada kami ['Abdullah bin Numair] dia berkata; telah menceritakan kepada kami ['Utsman bin Hakim] dari [Kharijah bin Zaid bin Tsabit] dari pamannya [Yazid bin Tsabit] bahwasanya mereka keluar bersama Rasulullah shallallahu 'alaihi wasallam pada suatu hari, lalu beliau melihat kuburan baru, beliau bertanya kuburan siapa ini?\" para sahabat menjawab ini adalah kuburan fulanah, budak Bani Fulan, Rasulullah shallallahu 'alaihi wasallam mengetahui wanita itu yang mati pada waktu dluhur. Engkau sedang tidur siang, kami tidak ingin membangunkanmu karena kematiannya, kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan orang-orang membuat shaf di belakang beliau, lalu beliau bertakbir atasnya empat kali, kemudian beliau bersabda: \"Tidaklah seseorang mati diantara kalian selama aku masih berada ditengah-tengah kalian kecuali kabarkan aku tentangnya, karena shalatku adalah rahmat baginya.\""},"1951":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّأَخْبَرَنِي مَنْ مَرَّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ مُنْتَبِذٍ فَأَمَّهُمْ وَصَفَّ خَلْفَهُ قُلْتُ مَنْ هُوَ يَا أَبَا عَمْرٍو قَالَ ابْنُ عَبَّاسٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Sulaiman Asy Syaibani] dari [Asy Sya'bi]; telah mengabarkan kepadaku orang yang pernah bersama Nabi shallallahu 'alaihi wasallam melewati sebuah kuburan yang asing, lalu beliau menshalatinya dan para sahabat berbaris di belakang beliau. Aku bertanya; 'Siapakah dia wahai Abu Amru? ' Ia menjawab; \" [Ibnu Abbas].\""},"1952":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ الشَّيْبَانِيُّ أَنْبَأَنَا عَنْ الشَّعْبِيِّ قَالَأَخْبَرَنِي مَنْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِقَبْرٍ مُنْتَبِذٍ فَصَلَّى عَلَيْهِ وَصَفَّ أَصْحَابَهُ خَلْفَهُ قِيلَ مَنْ حَدَّثَكَ قَالَ ابْنُ عَبَّاسٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; [Asy Syaibani] telah memberitakan kepada kami, dari [Asy Sya'bi] dia berkata; telah mengabarkan kepadaku seseorang yang melihat Nabi shallallahu 'alaihi wasallam melewati kuburan yang terasing, kemudian beliau melaksanakan shalat untuknya dan para sahabatnya berbaris di belakang beliau mengabarkan kepadaku.\" Ketika ditanyakan, 'Siapa yang menceritakan kepadamu' Ia menjawab; \" [Ibnu Abbas].\""},"1953":{"ar":"أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا زَيْدُ بْنُ عَلِيٍّ وَهُوَ أَبُو أُسَامَةَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ حَبِيبِ بْنِ أَبِي مَرْزُوقٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى قَبْرِ امْرَأَةٍ بَعْدَ مَا دُفِنَتْ","id":"Telah mengabarkan kepada kami [Al Mughirah bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Zaid bin 'Ali] yaitu Abu Usmah dia berkata; telah menceritakan kepada kami [Ja'far bin Burqan] dari [Habib bin Abu Marzuq] dari ['Atha] dari [Jabir] bahwasanya Nabi shallallahu 'alaihi wasallam shalat jenazah atas kuburan seorang wanita setelah ia dimakamkan."},"1954":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ وَيَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَنَازَةِ أَبِي الدَّحْدَاحِ فَلَمَّا رَجَعَ أُتِيَ بِفَرَسٍ مُعْرَوْرًى فَرَكِبَ وَمَشَيْنَا مَعَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dan [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Malik bin Mighwal] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar untuk mengiringi jenazah Abu Ad Dahdah, setelah kembali beliau ditawari -untuk menunggangi- kuda yang tidak berpelana, lalu beliau menungganginya dan kami berjalan bersamanya."},"1955":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا حَفْصٌ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى وَأَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبْنَى عَلَى الْقَبْرِ أَوْ يُزَادَ عَلَيْهِ أَوْ يُجَصَّصَ زَادَ سُلَيْمَانُ بْنُ مُوسَى أَوْ يُكْتَبَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dia berkata; telah menceritakan kepada kami [Hafsh] dari [Ibnu Juraij] dari [Sulaiman bin Musa] dan [Abu Az Zubair] dari [Jabir] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang bangunan diatas kuburan, diberi tambah-tambahan, disemen atau diberi tulisan-tulisan.\""},"1956":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَقْصِيصِ الْقُبُورِ أَوْ يُبْنَى عَلَيْهَا أَوْ يَجْلِسَ عَلَيْهَا أَحَدٌ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menembok kuburan, mendirikan bangunan di atasnya atau seseorang duduk di atasnya.\""},"1957":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَجْصِيصِ الْقُبُورِ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menembok kuburan.\""},"1958":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ ثُمَامَةَ بْنَ شُفَيٍّ حَدَّثَهُ قَالَكُنَّا مَعَ فَضَالَةَ بْنِ عُبَيْدٍ بِأَرْضِ الرُّومِ فَتُوُفِّيَ صَاحِبٌ لَنَا فَأَمَرَ فَضَالَةُ بِقَبْرِهِ فَسُوِّيَ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِتَسْوِيَتِهَا","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amru bin Al Harits] bahwasanya [Tsumamah bin Syufayyi] berkata; kami bersama [Fadlalah bin 'Ubaid] di Negeri Romawi lalu teman kami meninggal dunia. Maka Fadlalah menyuruh untuk menguburkannya dengan meratakan tanah, kemudian ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam menyuruh untuk meratakannya.\""},"1959":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي الْهَيَّاجِ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُأَلَا أَبْعَثُكَ عَلَى مَا بَعَثَنِي عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَعَنَّ قَبْرًا مُشْرِفًا إِلَّا سَوَّيْتَهُ وَلَا صُورَةً فِي بَيْتٍ إِلَّا طَمَسْتَهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; [Sufyan] dari [Habib] dari [Abu Wail] dari [Abul Hayyaj] dia berkata; ['Ali radliallahu 'anhu] berkata; \"Maukah kamu aku utus untuk melakukan sesuatu sebagaimana Rasulullah shallallahu 'alaihi wasallam mengutusku untuk melakukannya?! Janganlah engkau membiarkan kuburan yang tinggi kecuali engkau meratakannya dan tidak pula sebuah gambar di dalam rumah kecuali engkau musnahkan.\""},"1960":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ ابْنِ فُضَيْلٍ عَنْ أَبِي سِنَانٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثَةِ أَيَّامٍ فَامْسِكُوا مَا بَدَا لَكُمْ وَنَهَيْتُكُمْ عَنْ النَّبِيذِ إِلَّا فِي سِقَاءٍ فَاشْرَبُوا فِي الْأَسْقِيَةِ كُلِّهَا وَلَا تَشْرَبُوا مُسْكِرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Ibnu Fudlail] dari [Abu Sinan] dari [Muharib bin Ditsar] dari ['Abdullah bin Buraidah] dari [bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah melarang kalian berziarah kubur, maka -sekarang- ziarahlah kubur, dan aku pernah melarang kalian -memakan- daging kurban lebih dari tiga hari, maka simpanlah apa yang kalian kehendaki -dari daging-daging tersebut- dan aku pernah melarang kalian dari nabidz (minuman yang terbuat dari anggur) kecuali yang terdapat dalam tempat minum, maka minumlah yang ada dalam semua tempat minum dan janganlah kalian minum sesuatu yang memabukkan.\""},"1961":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ أَبِي فَرْوَةَ عَنْ الْمُغِيرَةِ بْنِ سُبَيْعٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِأَنَّهُ كَانَ فِي مَجْلِسٍ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي كُنْتُ نَهَيْتُكُمْ أَنْ تَأْكُلُوا لُحُومَ الْأَضَاحِيِّ إِلَّا ثَلَاثًا فَكُلُوا وَأَطْعِمُوا وَادَّخِرُوا مَا بَدَا لَكُمْ وَذَكَرْتُ لَكُمْ أَنْ لَا تَنْتَبِذُوا فِي الظُّرُوفِ الدُّبَّاءِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَالْحَنْتَمِ انْتَبِذُوا فِيمَا رَأَيْتُمْ وَاجْتَنِبُوا كُلَّ مُسْكِرٍ وَنَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَمَنْ أَرَادَ أَنْ يَزُورَ فَلْيَزُرْ وَلَا تَقُولُوا هُجْرًا","id":"Telah mengabarkan kepadaku [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Abu Farwah] dari [Al Mughirah bin Subai']; telah menceritakan kepadaku ['Abdullah bin Buraidah] dari [bapaknya] bahwasanya ia pernah berada dalam suatu majelis dimana Rasulullah shallallahu 'alaihi wasallam ada di dalamnya, lalu beliau bersabda: \" Aku pernah melarang kalian memakan kurban kecuali -tidak lebih dari- tiga hari, maka sekarang makanlah, berikan makan dan simpanlah apa yang kalian kehendaki -dari daging-daging tersebut-, kuingatkan kalian agar tidak membuat minuman keras dalam batok (ad-duba'), wadah yang dicet dengan gala-gala (ter, zaft), pangkal pohon kurma yang dilubangi (an-naqir) serta wadah yang terbuat dari tanah liat atau rambut (al-hantam), namun buatlah minuman pada apa yang kalian ketahui serta jauhilah segala yang memabukkan, dan aku juga pernah melarang kalian berziarah kubur, barangsiapa yang ingin berziarah, maka berziarahlah dan jangan mengucapkan kata-kata kotor.\""},"1962":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَزَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرَ أُمِّهِ فَبَكَى وَأَبْكَى مَنْ حَوْلَهُ وَقَالَ اسْتَأْذَنْتُ رَبِّي عَزَّ وَجَلَّ فِي أَنْ أَسْتَغْفِرَ لَهَا فَلَمْ يُؤْذَنْ لِي وَاسْتَأْذَنْتُ فِي أَنْ أَزُورَ قَبْرَهَا فَأَذِنَ لِي فَزُورُوا الْقُبُورَ فَإِنَّهَا تُذَكِّرُكُمْ الْمَوْتَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menziarahi kuburan ibunya, lalu beliau menangis dan menjadikan orang-orang di sekitarnya ikut menangis, kemudian beliau bersabda: \"Aku telah meminta izin kepada Rabbku -Azza wa Jalla- untuk meminta ampunan baginya, tetapi Allah tidak mengizinkanku dan ketika aku meminta izin untuk menziarahi kuburannya, Dia mengizinkanku. Maka berziarahlah kalian ke kuburan, karena hal itu dapat mengingatkan kalian akan kematian.\""},"1963":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى كَانَ آخِرُ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' satu kalimat yang dengannya aku akan berhujah untukmu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" dan keduanya tetap mangatakan hal itu kepadanya, hingga kalimat terakhir yang ia ucapkan kepada mereka ialah, bahwa ia tetap berpegang pada agama Abdul Muthalib! Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik.\" (Qs. At Taubah 9; 113) Dan turun ayat, \" Kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi.\" (Qs. Al Qashash 28: 56)."},"1964":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْخَلِيلِ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَجُلًا يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ فَقُلْتُ أَتَسْتَغْفِرُ لَهُمَا وَهُمَا مُشْرِكَانِ فَقَالَ أَوَ لَمْ يَسْتَغْفِرْ إِبْرَاهِيمُ لِأَبِيهِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَنَزَلَتْ{ وَمَا كَانَ اسْتِغْفَارُ إِبْرَاهِيمَ لِأَبِيهِ إِلَّا عَنْ مَوْعِدَةٍ وَعَدَهَا إِيَّاهُ }","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Abul Khalil] dari ['Ali] dia berkata; Aku mendengar seseorang memintakan ampunan bagi kedua orang tuanya sedang keduanya musyrik, maka aku bertanya kepadanya; \"Apakah engkau memintakan ampunan untuk mereka berdua, padahal mereka musyrik?\" ia menjawab, \"Bukankah Nabi Ibrahim juga memintakan ampunan untuk bapaknya?\" lalu aku menemui Nabi shallallahu 'alaihi wasallam dan aku ceritakan hal itu kepada beliau, lalu turunlah ayat, \"Dan permintaan ampun dari Ibrahim (kepada Allah) untuk bapaknya tidak lain hanyalah karena suatu janji yang telah diikrarkannya kepada bapaknya itu.\" (Qs. At Taubah 9: 114)"},"1965":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ قَيْسِ بْنِ مَخْرَمَةَ يَقُولُ سَمِعْتُ عَائِشَةَ تُحَدِّثُ قَالَتْأَلَا أُحَدِّثُكُمْ عَنِّي وَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا بَلَى قَالَتْ لَمَّا كَانَتْ لَيْلَتِي الَّتِي هُوَ عِنْدِي تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْقَلَبَ فَوَضَعَ نَعْلَيْهِ عِنْدَ رِجْلَيْهِ وَبَسَطَ طَرَفَ إِزَارِهِ عَلَى فِرَاشِهِ فَلَمْ يَلْبَثْ إِلَّا رَيْثَمَا ظَنَّ أَنِّي قَدْ رَقَدْتُ ثُمَّ انْتَعَلَ رُوَيْدًا وَأَخَذَ رِدَاءَهُ رُوَيْدًا ثُمَّ فَتَحَ الْبَابَ رُوَيْدًا وَخَرَجَ رُوَيْدًا وَجَعَلْتُ دِرْعِي فِي رَأْسِي وَاخْتَمَرْتُ وَتَقَنَّعْتُ إِزَارِي وَانْطَلَقْتُ فِي إِثْرِهِ حَتَّى جَاءَ الْبَقِيعَ فَرَفَعَ يَدَيْهِ ثَلَاثَ مَرَّاتٍ فَأَطَالَ ثُمَّ انْحَرَفَ فَانْحَرَفْتُ فَأَسْرَعَ فَأَسْرَعْتُ فَهَرْوَلَ فَهَرْوَلْتُ فَأَحْضَرَ فَأَحْضَرْتُ وَسَبَقْتُهُ فَدَخَلْتُ فَلَيْسَ إِلَّا أَنْ اضْطَجَعْتُ فَدَخَلَ فَقَالَ مَا لَكِ يَا عَائِشَةُ حَشْيَا رَابِيَةً قَالَتْ لَا قَالَ لَتُخْبِرِنِّي أَوْ لَيُخْبِرَنِّي اللَّطِيفُ الْخَبِيرُ قُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي فَأَخْبَرْتُهُ الْخَبَرَ قَالَ فَأَنْتِ السَّوَادُ الَّذِي رَأَيْتُ أَمَامِي قَالَتْ نَعَمْ فَلَهَزَنِي فِي صَدْرِي لَهْزَةً أَوْجَعَتْنِي ثُمَّ قَالَ أَظَنَنْتِ أَنْ يَحِيفَ اللَّهُ عَلَيْكِ وَرَسُولُهُ قُلْتُ مَهْمَا يَكْتُمُ النَّاسُ فَقَدْ عَلِمَهُ اللَّهُ قَالَ فَإِنَّ جِبْرِيلَ أَتَانِي حِينَ رَأَيْتِ وَلَمْ يَدْخُلْ عَلَيَّ وَقَدْ وَضَعْتِ ثِيَابَكِ فَنَادَانِي فَأَخْفَى مِنْكِ فَأَجَبْتُهُ فَأَخْفَيْتُهُ مِنْكِ فَظَنَنْتُ أَنْ قَدْ رَقَدْتِ وَكَرِهْتُ أَنْ أُوقِظَكِ وَخَشِيتُ أَنْ تَسْتَوْحِشِي فَأَمَرَنِي أَنْ آتِيَ الْبَقِيعَ فَأَسْتَغْفِرَ لَهُمْ قُلْتُ كَيْفَ أَقُولُ يَا رَسُولَ اللَّهِ قَالَ قُولِي السَّلَامُ عَلَى أَهْلِ الدِّيَارِ مِنْ الْمُؤْمِنِينَ وَالْمُسْلِمِينَ يَرْحَمُ اللَّهُ الْمُسْتَقْدِمِينَ مِنَّا وَالْمُسْتَأْخِرِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Abdullah bin Abu Mulaikah] bahwasanya ia mendengar [Muhammad bin Qais bin Makhramah] berkata; Aku mendengar ['Aisyah] bercerita, dia berkata; \"Maukah kuceritakan kepada kalian tentangku dan Nabi shallallahu 'alaihi wasallam?\" Kami menjawab, \"Ya.\" Dia berkata; \"Ketika malam hari -yang menjadi giliranku- yang ketika itu beliau berada bersamaku -yakni: Nabi shallallahu 'alaihi wasallam-, setelah pulang dari melaksanakan shalat Isya', beliau lalu meletakkan kedua sandal beliau di di depan kaki beliau dan membentangkan ujung kainnya di atas kasurnya. Tidak lama kemudian, beliau mengira bahwa aku telah tidur, beliau memakai sandal dan mengambil serbannya pelan-pelan, membuka pintu dan keluar pelan-pelan. Aku segera memakai baju di kepalaku, memakai kerudung, memakai kain bawah, lalu aku bergerak mengikuti jejak beliau, hingga sampai ke Baqi'. Kemudian beliau mengangkat kedua tangannya tiga kali dalam waktu yang lama, lalu pulang, maka aku pun pulang, beliau cepat-cepat -jalannya- dan aku pun cepat-cepat, beliau berjalan setengah berlari, lalu beliau sampai dan aku pun sampai, namun aku mendahului beliau, lalu aku masuk. Tidak lama setelah aku berbaring beliau masuk seraya berkata: \"Apa yang terjadi padamu wahai Aisyah, nafasmu terengah-engah\", ia berkata; \"Tidak.\" Beliau bersabda: \"Sungguh engkau akan memberitahuku atau Dzat yang maha lembut lagi maha mengetahui yang akan memberitahukan kepadaku!\" Aku berkata; \"Wahai Rasulullah! Demi bapak dan ibuku sebagai tebusannya!, aku yang akan memberitahukan berita yang terjadi.\" Beliau bertanya; \"Apakah kamu adalah orang berpakaian hitam yang ku lihat di depanku?\" Aku menjawab, \"Ya\". Lantas nabi shallallahu 'alaihi wasallam memukulku yang cukup menjadikanku kesakitan.\" Kemudian beliau bersabda: \"Apakah kamu mengira bahwa Allah dan rasul-Nya berbuat zhalim kepadamu?\" Aku menjawab, \"Bagaimanapun manusia merahasiakannya, sungguh Allah mengetahuinya.\" Beliau bersabda: \" Jibril menemuiku ketika kamu melihatnya dan ia tidak masuk menemuiku, sebab saat itu kamu melepas pakaianmu, lalu ia memanggilku, maka aku bersembunyi darimu. Aku kira kamu telah tidur, aku tidak ingin membangunkanmu dan aku khawatir akan mengagetkanmu, lalu Allah menyuruhku untuk pergi ke Baqi' dan memintakan ampunan untuk mereka.\" Aku bertanya; \"Apa yang harus aku ucapkan wahai Rasulullah shallallahu 'alaihi wasallam?\" Beliau menjawab: \"Ucapkanlah: \"Semoga kesejahteraan terlimpahkan kepada penghuni kubur dari kaum mukminin dan muslimin. Semoga Allah memberikan rahmat kepada orang-orang terdahulu di antara kita dan orang-orang yang akan datang kemudian, dan kami insya Allah akan bertemu kalian.\""},"1966":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَلْقَمَةَ بْنِ أَبِي عَلْقَمَةَ عَنْ أُمِّهِ أَنَّهَا سَمِعَتْ عَائِشَةَ تَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَلَبِسَ ثِيَابَهُ ثُمَّ خَرَجَ قَالَتْ فَأَمَرْتُ جَارِيَتِي بَرِيرَةَ تَتْبَعُهُ فَتَبِعَتْهُ حَتَّى جَاءَ الْبَقِيعَ فَوَقَفَ فِي أَدْنَاهُ مَا شَاءَ اللَّهُ أَنْ يَقِفَ ثُمَّ انْصَرَفَ فَسَبَقَتْهُ بَرِيرَةُ فَأَخْبَرَتْنِي فَلَمْ أَذْكُرْ لَهُ شَيْئًا حَتَّى أَصْبَحْتُ ثُمَّ ذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنِّي بُعِثْتُ إِلَى أَهْلِ الْبَقِيعِ لِأُصَلِّيَ عَلَيْهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca, dan aku mendengarnya, lafazh ini miliknya, dari [Ibnu Al Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari ['Alqamah bin Abu 'Alqamah] dari [ibunya] bahwasanya ia mendengar ['Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam bangun pada suatu malam, lalu beliau mengenakan pakaiannya kemudian keluar, lalu aku menyuruh budakku Barirah untuk membuntutinya, iapun mengikutinya hingga beliau sampai di Baqi' kemudian beliau berdiri didekatnya sebagaimana yang Allah kehendaki, lalu beliau kembali, namun Barirah telah mendahului beliau dan mengabarkan kepadaku, aku tidak menceritakan sesuatupun kepada beliau hingga pagi, kemudian aku bertanya kepada beliau akan hal itu dan beliau bersabda: \" Aku diutus kepada penduduk Baqi' agar aku shalat untuk mereka.\""},"1967":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا شَرِيكٌ وَهُوَ ابْنُ أَبِي نَمِرٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا كَانَتْ لَيْلَتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ فِي آخِرِ اللَّيْلِ إِلَى الْبَقِيعِ فَيَقُولُ السَّلَامُ عَلَيْكُمْ دَارَ قَوْمٍ مُؤْمِنِينَ وَإِنَّا وَإِيَّاكُمْ مُتَوَاعِدُونَ غَدًا أَوْ مُوَاكِلُونَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ اللَّهُمَّ اغْفِرْ لِأَهْلِ بَقِيعِ الْغَرْقَدِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Syarik bin Abu Namir] dari ['Atha] dari ['Aisyah] dia berkata; \"Setiap kali Rasulullah shallallahu 'alaihi wasallam bermalam di tempat Aisyah, beliau keluar ketika malam telah berlalu menuju ke Baqi', lalu berdoa: Semoga kesejahteraan terlimpahkan kepada penghuni rumah kaum mukminin, bagi kami dan kalian apa yang telah dijanjikan kelak, atau saling memberi syafa'at dan persaksian, dan kami insya Allah akan menyusul kalian. Ya Allah, ampunilah penghuni kubur Baqi' Al Gharqad.\""},"1968":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَد�� عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَتَى عَلَى الْمَقَابِرِ فَقَالَ السَّلَامُ عَلَيْكُمْ أَهْلَ الدِّيَارِ مِنْ الْمُؤْمِنِينَ وَالْمُسْلِمِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ أَنْتُمْ لَنَا فَرَطٌ وَنَحْنُ لَكُمْ تَبَعٌ أَسْأَلُ اللَّهَ الْعَافِيَةَ لَنَا وَلَكُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Harami bin 'Umarah] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam jika mendatangi kuburan, beliau berdoa: \"Semoga kesejahteraan terlimpahkan kepada kalian wahai penghuni kubur dari kaum Mukminin dan Muslimin, dan kami insya Allah akan bertemu kalian, kalian bagi kami sebagai pendahulu dan kami bagi kalian sebagai pengikut. Aku memohon keselamatan kepada Allah bagi kami dan kalian.\""},"1969":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا مَاتَ النَّجَاشِيُّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَغْفِرُوا لَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Setelah An Najasyi meninggal dunia, Nabi shallallahu 'alaihi wasallam bersabda: 'Mintakanlah ampunan untuknya'!\""},"1970":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ وَابْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لَهُمْ النَّجَاشِيَّ صَاحِبَ الْحَبَشَةِ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ فَقَالَ اسْتَغْفِرُوا لِأَخِيكُمْ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Ya'qub] dia berkata; [bapakku] telah menceritakan kepada kami dari [Shalih] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Abu Salamah] dan [Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam memberitahukan kepada mereka kematian An Najasyi (penguasa Habsyah) kepada mereka di hari kematiannya, lalu beliau bersabda: \"Mintakanlah ampunan untuk saudara kalian.\""},"1971":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ أَبِي صَالِحٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَائِرَاتِ الْقُبُورِ وَالْمُتَّخِذِينَ عَلَيْهَا الْمَسَاجِدَ وَالسُّرُجَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul Warits bin Sa'id] dari [Muhammad bin Juhadah] dari [Abu Shalih] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah melaknat para wanita yang berziarah kubur, Orang-orang yang menjadikan kuburan sebagai masjid dan memasang lampu-lampu disekitar kuburan.\" "},"1972":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَجْلِسَ أَحَدُكُمْ عَلَى جَمْرَةٍ حَتَّى تَحْرُقَ ثِيَابَهُ خَيْرٌ لَهُ مِنْ أَنْ يَجْلِسَ عَلَى قَبْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dari [Waki'] dari [Sufyan] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Duduknya seseorang diantara kalian diatas kobaran api hingga ia terbakar lebih baik baginya daripada ia duduk diatas kuburan.\""},"1973":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ النَّضْرِ بْنِ عَبْدِ اللَّهِ السَّلَمِيِّ عَنْ عَمْرِو بْنِ حَزْمٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقْعُدُوا عَلَى الْقُبُورِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dia berkata; telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Abu Bakr bin Hazm] dari [An Nadlr bin 'Abdullah As Salami] dari ['Amru bin Hazm] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \" Janganlah kalian duduk diatas kuburan.\""},"1974":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ قَوْمًا اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat suatu kaum yang menjadikan kuburan para Nabi mereka sebagai masjid.\""},"1975":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى صَاعِقَةُ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْيَهُودَ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdurrahim Abu Yahya Sha'iqah] dia berkata; telah menceritakan kepada kami [Abu Salamah Al Khuza'i] dia berkata; telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Al Had] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat orang-orang Yahudi dan Nasrani yang telah menjadikan kuburan Nabi mereka sebagai masjid.\""},"1976":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ الْأَسْوَدِ بْنِ شَيْبَانَ وَكَانَ ثِقَةً عَنْ خَالِدِ بْنِ سُمَيْرٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ أَنَّ بَشِيرَ ابْنَ الْخَصَاصِيَةِ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّ عَلَى قُبُورِ الْمُسْلِمِينَ فَقَالَ لَقَدْ سَبَقَ هَؤُلَاءِ شَرًّا كَثِيرًا ثُمَّ مَرَّ عَلَى قُبُورِ الْمُشْرِكِينَ فَقَالَ لَقَدْ سَبَقَ هَؤُلَاءِ خَيْرًا كَثِيرًا فَحَانَتْ مِنْهُ الْتِفَاتَةٌ فَرَأَى رَجُلًا يَمْشِي بَيْنَ الْقُبُورِ فِي نَعْلَيْهِ فَقَالَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ أَلْقِهِمَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dari [Al Aswad bin Syaiban] -dan dia adalah seorang yang tsiqah- dari [Khalid bin Sumair] dari [Basyir bin Nahik] bahwasanya [Basyir bin Al Khashashiyah] berkata; \"Aku pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam melewati kuburan kaum Muslimin, lalu beliau bersabda: \"Sungguh banyak kejahatan yang tak terkejar oleh mereka.\" Kemudian melewati kuburan kaum musyrikin, lalu beliau bersabda; \"Sungguh banyak kebaikan yang tak terkejar mereka.\" Kemudian beliau menoleh sebentar, tiba-tiba beliau melihat seorang laki-laki berjalan di antara kuburan dengan memakai sandalnya, lalu beliau bersabda; \"Wahai orang yang memakai sandal kulit, buang kedua sandalmu.\""},"1977":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ أَبِي عُبَيْدِ اللَّهِ الْوَرَّاقُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Abu 'Ubaidullah Al Warraq] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \" Seorang hamba jika diletakkan di dalam kuburannya dan para sahabatnya telah pulang, sungguh mayit itu benar-benar mendengar suara terompah (sandal) mereka.\""},"1978":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ وَإِبْرَاهِيمُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ قَالَا حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ شَيْبَانَ عَنْ قَتَادَةَ أَنْبَأَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ قَالَ فَيَأْتِيهِ مَلَكَانِ فَيُقْعِدَانِهِ فَيَقُولَانِ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ فَيَقُولُ أَشْهَدُ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ فَيُقَالُ لَهُ انْظُرْ إِلَى مَقْعَدِكَ مِنْ النَّارِ قَدْ أَبْدَلَكَ اللَّهُ بِهِ مَقْعَدًا مِنْ الْجَنَّةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَرَاهُمَا جَمِيعًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dan [Ibrahim bin Ya'qub bin Ishaq] mereka berkata; telah menceritakan kepada kami [Yunus bin Muhammad] dari [Syaiban] dari [Qatadah]; telah memberitakan kepada kami [Anas bin Malik] dia berkata; Nabiyullah shallallahu 'alaihi wasallam bersabda: \" Seorang hamba jika telah diletakkan di dalam kuburannya dan para sahabatnya telah berpaling, ia benar-benar mendengar suara terompah mereka.\" Beliau bersabda lagi: \"Lalu dua malaikat mendatanginya, keduanya mendudukkan orang tersebut lalu berkata kepadanya; 'Apa yang kamu katakan tentang orang ini? ' Adapun orang Mukmin, maka ia menjawab; 'Aku bersaksi bahwa ia adalah hamba Allah dan rasul-Nya', lalu dikatakan kepada orang tersebut, 'Lihatlah tempat tinggalmu di neraka, sungguh Allah telah menggantikannya dengan tempat tinggal di surga'.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Maka ia sekaligus melihat kedua-duanya.\""},"1979":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ أَبِي عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ أَتَاهُ مَلَكَانِ فَيُقْعِدَانِهِ فَيَقُولَانِ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا الْمُؤْمِنُ فَيَقُولُ أَشْهَدُ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ فَيُقَالُ لَهُ انْظُرْ إِلَى مَقْعَدِكَ مِنْ النَّارِ قَدْ أَبْدَلَكَ اللَّهُ بِهِ مَقْعَدًا خَيْرًا مِنْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَرَاهُمَا جَمِيعًا وَأَمَّا الْكَافِرُ أَوْ الْمُنَافِقُ فَيُقَالُ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ فَيَقُولُ لَا أَدْرِي كُنْتُ أَقُولُ كَمَا يَقُولُ النَّاسُ فَيُقَالُ لَهُ لَا دَرَيْتَ وَلَا تَلَيْتَ ثُمَّ يُضْرَبُ ضَرْبَةً بَيْنَ أُذُنَيْهِ فَيَصِيحُ صَيْحَةً يَسْمَعُهَا مَنْ يَلِيهِ غَيْرُ الثَّقَلَيْنِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abu 'Ubaidullah] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \" Seorang hamba jika telah di letakkan di dalam kuburannya dan para sahabatnya telah berpaling darinya, ia benar-benar mendengar suara terompah mereka.\" Beliau bersabda lagi: \"Lalu dua malaikat mendatanginya, keduanya mendudukkan orang tersebut lalu bertanya kepadanya, 'Apa yang kamu katakan tentang orang ini - yaitu Muhammad shallallahu 'alaihi wasallam? - \"Adapun orang mukmin ia akan menjawab; 'Aku bersaksi bahwa ia adalah hamba Allah dan rasul-Nya', lalu dikatakan kepada orang tersebut, 'Lihatlah kepada tempat tinggalmu berupa Neraka, sungguh Allah telah menggantikan dengannya tempat tinggal berupa surga'.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka dia melihat keduanya.\" Adapun orang kafir atau munafik, maka dikatakan kepadanya; \"Apa yang kamu katakan tentang orang ini?\" maka ia akan menjawab; \"Aku tidak tahu. Dahulu aku hanya mengatakan sebagaimana yang dikatakan oleh banyak orang.\" Lalu dikatakan kepadanya; \"Engkau tidak tahu dan engkau tidak membaca.\" Kemudian ia dipukul dengan sekali pukulan dibagian antara kedua telinganya, hingga ia menjerit dengan jeritan yang dapat didengar oleh makhluk lain selain jin dan manusia.\""},"1980":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي جَامِعُ بْنُ شَدَّادٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَسَارٍ قَالَكُنْتُ جَالِسًا وَسُلَيْمَانُ بْنُ صُرَدٍ وخَالِدُ بْنُ عُرْفُطَةَ فَذَكَرُوا أَنَّ رَجُلًا تُوُفِّيَ مَاتَ بِبَطْنِهِ فَإِذَا هُمَا يَشْتَهِيَانِ أَنْ يَكُونَا شُهَدَاءَ جَنَازَتِهِ فَقَالَ أَحَدُهُمَا لِلْآخَرِ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَقْتُلْهُ بَطْنُهُ فَلَنْ يُعَذَّبَ فِي قَبْرِهِ فَقَالَ الْآخَرُ بَلَى","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dia berkata; telah mengabarkan kepadaku [Jami' bin Syaddad] dia berkata; aku mendengar ['Abdullah bin Yasar] dia berkata; Aku pernah duduk bersama [Sulaiman bin Shard] dan [Khalid bin 'Urfuthah], lalu mereka menyebutkan tentang seseorang yang mati karena sakit perut, dan mereka ingin menyaksikan jenazahnya, seorang diantara mereka berkata kepada yang lain bukankah Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Barangsiapa yang terbunuh karena sakit perut maka ia tidak akan disiksa dikuburnya?\" kemudian yang lain menjawab, 'Benar'."},"1981":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ لَيْثِ بْنِ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ أَنَّ صَفْوَانَ بْنَ عَمْرٍو حَدَّثَهُ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا بَالُ الْمُؤْمِنِينَ يُفْتَنُونَ فِي قُبُورِهِمْ إِلَّا الشَّهِيدَ قَالَ كَفَى بِبَارِقَةِ السُّيُوفِ عَلَى رَأْسِهِ فِتْنَةً","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Laits bin Sa'd] dari [Mu'awiyah bin Shalih] bahwasanya [Shafwan bin 'Amru] menceritakan kepadanya dari [Rasyid bin Sa'd] dari [seorang lelaki] dari sahabat Nabi shallallahu 'alaihi wasallam bahwa seseorang berkata; \"Wahai Rasulullah, Mengapa kaum mukminin diuji (ditanya) di dalam kuburan mereka kecuali orang yang mati syahid?\" beliau bersabda: \"Cukuplah dengan kilatan pedang di atas kepalanya (orang yang mati syahid) sebagai ujian baginya.\" "},"1982":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَالطَّاعُونُ وَالْمَبْطُونُ وَالْغَرِيقُ وَالنُّفَسَاءُ شَهَادَةٌ قَالَ وَحَدَّثَنَا أَبُو عُثْمَانَ مِرَارًا وَرَفَعَهُ مَرَّةً إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [At Taimi] dari [Abu 'Utsman] dari ['Amir bin Malik] dari [Shafwan bin Umayyah] dia berkata; \"Orang yang mati terkena penyakit wabah pes, sakit perut, tenggelam dan wanita-wanita yang sedang nifas adalah Syahid.\" Dan telah menceritakan kepada kami Abu Utsman berulang kali, dan dia pernah menyandarkannya kepada Nabi shallallahu 'alaihi wasallam sekali."},"1983":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ الْعَنْقَزِيُّ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا الَّذِي تَحَرَّكَ لَهُ الْعَرْشُ وَفُتِحَتْ لَهُ أَبْوَابُ السَّمَاءِ وَشَهِدَهُ سَبْعُونَ أَلْفًا مِنْ الْمَلَائِكَةِ لَقَدْ ضُمَّ ضَمَّةً ثُمَّ فُرِّجَ عَنْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Amru bin Muhammad Al 'Anqazi] dia berkata; telah menceritakan kepada kami [Ibnu Idris] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Inilah orang yang karenanya arsy bergerak, pintu-pintu langit dibuka dan tujuh puluh ribu malaikat menyaksikannya. Sungguh ia telah di himpit dengan sekali himpitan kemudian dilepaskan.\""},"1984":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ خَيْثَمَةَ عَنْ الْبَرَاءِ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [bapaknya] dari [Khaitsamah] dari [Al Barra'] dia berkata; \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Dia berkata; 'Ayat ini turun menerangkan tentang siksa kubur.'"},"1985":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَدِينِي دِينُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Al Barra' bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Beliau bersabda: 'Ayat ini turun menerangkan tentang siksa kubur.' Dikatakan kepadanya; \"Siapakah Rabbmu?\" lalu ia menjawab, \"Rabbku Allah dan agamaku adalah agamanya Nabi Muhammad shallallahu 'alaihi wasallam.\" Maka itulah yang sesuai dengan firman-Nya, \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27)"},"1986":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ صَوْتًا مِنْ قَبْرٍ فَقَالَ مَتَى مَاتَ هَذَا قَالُوا مَاتَ فِي الْجَاهِلِيَّةِ فَسُرَّ بِذَلِكَ وَقَالَ لَوْلَا أَنْ لَا تَدَافَنُوا لَدَعَوْتُ اللَّهَ أَنْ يُسْمِعَكُمْ عَذَابَ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Suwaid bin Naslr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah mendengar suara dari dalam kuburan, lalu beliau bertanya; \"kapan orang ini meninggal dunia?\" mereka menjawab; \"Ia meninggal dunia di zaman jahiliyah\", maka beliau bergembira karenanya dan bersabda: \"Kalaulah bukan karena kekhawatiranku jangan-jangan kalian tidak saling menguburkan, niscaya aku akan berdoa kepada Allah agar memperdengarkan siksa kubur kepada kalian.\""},"1987":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ عَنْ الْبَرَاءِ بْنِ عَازِبِ عَنْ أَبِي أَيُّوبَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ فَسَمِعَ صَوْتًا فَقَالَ يَهُودُ تُعَذَّبُ فِي قُبُورِهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; telah mengabarkan kepadaku ['Aun bin Abu Juhaifah] dari [bapaknya] dari [Al Barra' bin 'Azib] dari [Abu Ayyub] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar setelah matahari terbenam, lalu beliau mendengar suara maka beliau bersabda: \"Orang-orang Yahudi disiksa di kuburnya.\""},"1988":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ النَّارِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] dia berkata; telah menceritakan kepada kami [Abu Isma'il] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] bahwasanya [Abu Salamah] menceritakan kepadanya dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Ya Allah aku berlindung kepada-Mu dari siksa kubur, aku berlindung kepada-Mu dari siksa neraka, aku berlindung kepada-Mu dari fitnah kehidupan dan kematian, dan aku berlindung kepada-Mu dari fitnah Al Masih Ad Dajjal.\""},"1989":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ يَسْتَعِيذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami ['Amru bin Sawwad bin Al Aswad bin 'Amru] dari [Ibnu Wahb] dia berkata; telah menceritakan kepada kami [Yunus bin Yazid] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] dia berkata; \"Aku mendengar setelah itu Rasulullah shallallahu 'alaihi wasallam meminta perlindungan dari siksa kubur.\""},"1990":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُ سَمِعَ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ تَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْفِتْنَةَ الَّتِي يُفْتَنُ بِهَا الْمَرْءُ فِي قَبْرِهِ فَلَمَّا ذَكَرَ ذَلِكَ ضَجَّ الْمُسْلِمُونَ ضَجَّةً حَالَتْ بَيْنِي وَبَيْنَ أَنْ أَفْهَمَ كَلَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا سَكَنَتْ ضَجَّتُهُمْ قُلْتُ لِرَجُلٍ قَرِيبٍ مِنِّي أَيْ بَارَكَ اللَّهُ لَكَ مَاذَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ قَوْلِهِ قَالَ قَدْ أُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ قَرِيبًا مِنْ فِتْنَةِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab]; telah mengabarkan kepadaku ['Urwah bin Zubair] bahwasanya ia mendengar [Asma bintu Abu Bakr] berkata; Rasulullah shallallahu 'alaihi wasallam berdiri, lalu menyebutkan fitnah yang akan melanda seseorang dalam kuburnya. Setelah beliau menyebutkan hal itu, kaum muslimin berteriak dengan keras, sehingga menghalangiku untuk memahami sabda Rasulullah shallallahu 'alaihi wasallam. Setelah teriakan mereka tenang, aku bertanya kepada seseorang yang berada didekatku; \"Hai, semoga Allah memberkahimu! Apa yang diucapkan oleh Rasulullah shallallahu 'alaihi wasallam di akhir sabda beliau?\" Ia bersabda: \"Sungguh telah diwahyukan kepadaku bahwa kalian akan menghadapi ujian di dalam kubur kalian yang menyerupai ujian Ad Dajjal.\""},"1991":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ هَذَا الدُّعَ��ءَ كَمَا يُعَلِّمُهُمْ السُّورَةَ مِنْ الْقُرْآنِ قُولُوا اللَّهُمَّ إِنَّا نَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zubair] dari [Thawus] dari ['Abdullah bin 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam mengajarkan doa ini kepada mereka, sebagaimana beliau mengajarkan kepada mereka surat dari Al Qur'an; \"Ucapkanlah, 'Ya Allah, aku berlindung kepada-Mu dari siksa neraka Jahanam, aku berlindung kepada-Mu dari siksa kubur, aku berlindung kepada-Mu dari fitnah Al Masih Ad Dajjal dan aku berlindung kepada-Mu dari fitnah kehidupan serta kematian.\""},"1992":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي امْرَأَةٌ مِنْ الْيَهُودِ وَهِيَ تَقُولُ إِنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ فَارْتَاعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّمَا تُفْتَنُ يَهُودُ وَقَالَتْ عَائِشَةُ فَلَبِثْنَا لَيَالِيَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ أُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ قَالَتْ عَائِشَةُ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ يَسْتَعِيذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku ['Urwah] bahwasanya ['Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam masuk menemuiku, dan di sampingku ada seorang wanita dari kaum Yahudi, ia berkata; \" kalian akan di fitnah (diuji oleh dua malaikat) di dalam kubur\", maka Rasulullah shallallahu 'alaihi wasallam terkejut dan bersabda: ' kaum Yahudi yang akan difitnah.' Aisyah berkata; \"Lalu kami diam beberapa malam.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \" telah diwahyukan kepadaku bahwa kalian akan difitnah di dalam kubur.\" Aisyah berkata; \"Lalu setelah itu aku mendengar Rasulullah shallallahu 'alaihi wasallam meminta perlindungan dari siksa kubur.\""},"1993":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَعِيذُ مِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الدَّجَّالِ وَقَالَ إِنَّكُمْ تُفْتَنُونَ فِي قُبُورِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya] dari ['Amrah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam meminta perlindungan dari siksa kubur dan dari fitnah Ad Dajjal, beliau bersabda: \" kalian akan mendapat ujian di dalam kubur kalian.\""},"1994":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَدَخَلَتْ يَهُودِيَّةٌ عَلَيْهَا فَاسْتَوْهَبَتْهَا شَيْئًا فَوَهَبَتْ لَهَا عَائِشَةُ فَقَالَتْ أَجَارَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ قَالَتْ عَائِشَةُ فَوَقَعَ فِي نَفْسِي مِنْ ذَلِكَ حَتَّى جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّهُمْ لَيُعَذَّبُونَ فِي قُبُورِهِمْ عَذَابًا تَسْمَعُهُ الْبَهَائِمُ","id":"Telah mengabarkan kepada kami [Hannad] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Masruq] dari ['Aisyah], Seorang Yahudi masuk menemuinya, lalu ia meminta sesuatu kepada Aisyah, maka Aisyah memberikan kepadanya, dan ia berkata; \"Semoga Allah melindungimu dari siksa kubur!\" Aisyah berkata; \"Aku merasakan sesuatu pada diriku karena hal itu, hingga Rasulullah shallallahu 'alaihi wasallam datang lalu kuceritakan hal itu kepada beliau, beliau kemudian bersabda: \" Mereka akan disiksa di dalam kubur dengan siksaan yang bisa didengar oleh binatang.\""},"1995":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْدَخَلَتْ عَلَيَّ عَجُوزَتَانِ مِنْ عُجُزِ يَهُودِ الْمَدِينَةِ فَقَالَتَا إِنَّ أَهْلَ الْقُبُورِ يُعَذَّبُونَ فِي قُبُورِهِمْ فَكَذَّبْتُهُمَا وَلَمْ أَنْعَمْ أَنْ أُصَدِّقَهُمَا فَخَرَجَتَا وَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ عَجُوزَتَيْنِ مِنْ عُجُزِ يَهُودِ الْمَدِينَةِ قَالَتَا إِنَّ أَهْلَ الْقُبُورِ يُعَذَّبُونَ فِي قُبُورِهِمْ قَالَ صَدَقَتَا إِنَّهُمْ يُعَذَّبُونَ عَذَابًا تَسْمَعُهُ الْبَهَائِمُ كُلُّهَا فَمَا رَأَيْتُهُ صَلَّى صَلَاةً إِلَّا تَعَوَّذَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Masruq] dari ['Aisyah] dia berkata; \"Dua orang wanita tua dari kaum Yahudi Madinah menemuiku, lalu keduanya berkata; ' para penghuni kubur akan disiksa di dalam kubur mereka, lalu aku mendustakan mereka berdua dan aku tidak senang mempercayai mereka berdua! kemudian keduanya keluar dan Rasulullah shallallahu 'alaihi wasallam masuk menemuiku. Lalu aku berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, ada dua wanita tua dari kaum Yahudi Madinah mengatakan; \" para penghuni kubur akan disiksa di dalam kubur mereka?\" beliau bersabda: \"Keduanya benar, mereka akan disiksa dengan siksaan yang bisa didengar oleh semua binatang.\" Lalu aku tidak melihat beliau melakukan shalat kecuali beliau berlindung dari siksa kubur."},"1996":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَائِطٍ مِنْ حِيطَانِ مَكَّةَ أَوْ الْمَدِينَةِ سَمِعَ صَوْتَ إِنْسَانَيْنِ يُعَذَّبَانِ فِي قُبُورِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ ثُمَّ قَالَ بَلَى كَانَ أَحَدُهُمَا لَا يَسْتَبْرِئُ مِنْ بَوْلِهِ وَكَانَ الْآخَرُ يَمْشِي بِالنَّمِيمَةِ ثُمَّ دَعَا بِجَرِيدَةٍ فَكَسَرَهَا كِسْرَتَيْنِ فَوَضَعَ عَلَى كُلِّ قَبْرٍ مِنْهُمَا كِسْرَةً فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ لِمَ فَعَلْتَ هَذَا قَالَ لَعَلَّهُ أَنْ يُخَفَّفَ عَنْهُمَا مَا لَمْ يَيْبَسَا أَوْ إِلَى أَنْ يَيْبَسَا","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melewati salah satu perkebunan di Mekkah atau Madinah, beliau mendengar dua orang sedang di siksa di dalam kubur mereka, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keduanya sedang disiksa dan keduanya tidak disiksa karena dosa besar.\" Kemudian beliau bersabda: \"Benar, salah seorang di antara keduanya tidak membersihkan dari kencingnya dan yang lainnya melakukan adu domba.\" Kemudian beliau meminta pelepah (kurma) lalu memecahnya menjadi dua dan meletakkan di atas kuburan masing-masing satu pecahan pelepah. Ditanyakan, \"Wahai Rasulullah shallallahu 'alaihi wasallam, mengapa engkau melakukan hal ini?\" Beliau menjawab: \"Barangkali itu bisa meringankan - adzab - dari mereka berdua selama dua pelepah ini belum kering. Atau sampai dua pelepah ini kering.\""},"1997":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَبْرِئُ مِنْ بَوْلِهِ وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ ثُمَّ أَخَذَ جَرِيدَةً رَطْبَةً فَشَقَّهَا نِصْفَيْنِ ثُمَّ غَرَزَ فِي كُلِّ قَبْرٍ وَاحِدَةً فَقَالُوا يَا رَسُولَ اللَّهِ لِمَ صَنَعْتَ هَذَا فَقَالَ لَعَلَّهُمَا أَنْ يُخَفَّفَ عَنْهُمَا مَا لَمْ يَيْبَسَا","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Mu'awiyah] dari [Al A'masy] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melewati dua kuburan, lalu beliau bersabda: \"Sungguh keduanya sedang disiksa dan keduanya tidak disiksa karena dosa besar. Adapun salah seorang di antara keduanya tidak membersihkan diri dari air kencingnya dan yang lainnya selalu melakukan adu domba.\" Kemudian beliau mengambil pelepah (kurma) yang masih basah, lalu membelahnya menjadi dua, kemudian menancapkannya pada masing-masing kuburan satu belahan pelepah.\" Maka mereka bertanya, \"Wahai Rasulullah shallallahu 'alaihi wasallam, mengapa engkau melakukan hal ini?\" beliau menjawab: \"Barangkali dua pelepah ini bisa meringankan mereka berdua selama belum kering.\""},"1998":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا إِنَّ أَحَدَكُمْ إِذَا مَاتَ عُرِضَ عَلَيْهِ مَقْعَدُهُ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ أَهْلِ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ حَتَّى يَبْعَثَهُ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, salah seorang kalian - jika meninggal dunia - akan diperlihatkan tempat tinggalnya di waktu pagi dan sore. Jika ia termasuk penghuni surga, maka ia menjadi penghuni surga dan jika ia termasuk penghuni neraka, maka ia menjadi penghuni neraka, hingga Allah Azza wa Jalla membangkitkannya pada hari kiamat.\""},"1999":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ يُحَدِّثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُعْرَضُ عَلَى أَحَدِكُمْ إِذَا مَاتَ مَقْعَدُهُ مِنْ الْغَدَاةِ وَالْعَشِيِّ فَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ قِيلَ هَذَا مَقْعَدُكَ حَتَّى يَبْعَثَكَ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Al Mu'tamir] dia berkata; Aku mendengar ['Ubaidullah] menceritakan dari [Nafi'] dari [Ibnu 'Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Salah seorang kalian jika meninggal dunia akan diperlihatkan tempat tinggalnya di waktu pagi dan sore. Jika ia termasuk penghuni neraka, maka ia menjadi penghuni neraka.\" Dikatakan, \"Inilah tempat tinggalmu hingga Allah Azza wa Jalla membangkitkanmu pada hari kiamat.\""},"2000":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَاتَ أَحَدُكُمْ عُرِضَ عَلَى مَقْعَدِهِ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ أَهْلِ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ فَيُقَالُ هَذَا مَقْعَدُكَ حَتَّى يَبْعَثَكَ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya, lafazh ini miliknya, dari [Ibnul Qasim]; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang di antara kalian meninggal dunia, maka akan diperlihatkan tempat tinggalnya di waktu pagi dan sore. Jika ia termasuk peghuni surga, maka ia menjadi penghuni surga dan jika ia termasuk penghuni neraka, maka ia menjadi penghuni neraka, lalu dikatakan, \"Inilah tempat tinggalmu hingga Allah -Azza wa Jalla - membangkitkan pada hari kiamat.\""}};
